// 자동 생성 파일. npm run generate:handbook 이 갱신한다. 직접 수정 금지.
export const SEARCH_INDEX = [{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch1","code":"HOME-01","title":"AI Native 개발자 역량 지도","summary":"이 핸드북의 큰그림은 많은 기술을 나열하는 것이 아니라, 기능 하나를 끝까지 책임지는 개발자 를 만드는 것입니다. 기본기, 제품 구현, 운영 책임, AI Native 실행, 사용자 경험, 반복 작업 자동화, 커리어 증거가 서로 끊기지 않아야 합니다."},{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch2","code":"HOME-02","title":"전체 로드맵","summary":"전체 흐름은 CS·시스템·런타임·측정 기본기에서 출발해, 화면과 서버, 데이터와 운영, LLM/AX 실행 체계, 제품 경험 설계, 커리어 증거로 확장됩니다."},{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch3","code":"HOME-03","title":"학습 순서","summary":"순서대로 읽되, 모든 문서를 한 번에 끝내려 하지 말고 현재 프로젝트에서 바로 검증할 수 있는 주제부터 실험합니다."},{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch4","code":"HOME-04","title":"메뉴별 목적","summary":""},{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch5","code":"HOME-05","title":"핸드북 사용법","summary":"이 문서는 읽는 자료라기보다 작업 전에 확인하고, 작업 중에 기준으로 삼고, 작업 후에 회고하는 체크리스트에 가깝습니다."},{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch6","code":"HOME-06","title":"실전 루프","summary":"한 주 단위로 아래 루프를 반복하면 읽은 지식이 프로젝트 판단으로 전환됩니다."},{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch7","code":"HOME-07","title":"메뉴 바로가기","summary":"상단 메뉴 구조를 그대로 따라가되, 자주 시작하는 문서만 먼저 열 수 있게 묶었습니다. 처음 읽을 때는 각 묶음의 첫 문서로 들어가고, 작업 중에는 목적에 맞는 대표 문서로 바로 이동합니다."},{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch8","code":"HOME-08","title":"AI Native 빠른 진단","summary":"AI Native 역량은 도구 사용 경험이 아니라 재현 가능한 증거로 판정합니다. 아래 질문에 산출물로 답하지 못하면 해당 역량은 아직 훈련 대상입니다."},{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch9","code":"HOME-09","title":"훈련 트랙","summary":"모든 문서를 순서대로 소비하지 않습니다. 현재 목표에 맞는 트랙을 고르고, 각 트랙의 산출물로 완료 여부를 판단합니다."},{"docId":"home","docLabel":"00 홈","groupLabel":"홈","sectionId":"ch10","code":"HOME-10","title":"완료 산출물 지도","summary":"핸드북을 읽었다는 증거는 요약문이 아니라 다음 작업에서 재사용 가능한 산출물입니다."},{"docId":"engineering-cs-foundations","docLabel":"00 CS 기초와 알고리즘 사고","groupLabel":"개발 핸드북","sectionId":"spine","code":"CS-01","title":"CS FOUNDATION SPINE","summary":"알고리즘 선택은 \"가장 빠른 알고리즘\"을 찾는 일이 아닙니다. 실제 입력 분포, 메모리 한계, 캐시 지역성, 구현 위험, 운영 관측성을 함께 보며 충분히 좋은 선택을 고정하는 일입니다."},{"docId":"engineering-cs-foundations","docLabel":"00 CS 기초와 알고리즘 사고","groupLabel":"개발 핸드북","sectionId":"complexity","code":"CS-02","title":"복잡도와 비용 모델","summary":"Big-O는 증가율의 언어입니다. 실무에서 쓸모 있으려면 두 가지 환산이 필요합니다: 표기를 연산 수 자릿수 로, 연산 수를 시간 예산 으로. 이 절의 모든 숫자는 \"단순 연산 1회 ≈ 10ns (10⁸ ops/s)\"라는 보수적 비용 모델 기준의 자릿수 감각이며, 실제 상수는 연산 종류에 따라 10~100배 달라집니다."},{"docId":"engineering-cs-foundations","docLabel":"00 CS 기초와 알고리즘 사고","groupLabel":"개발 핸드북","sectionId":"structures","code":"CS-03","title":"자료구조 선택","summary":"자료구조는 불변식을 저장하는 방식입니다. 어떤 연산을 빠르게 만들면 보통 다른 연산, 메모리, 구현 복잡도가 비용으로 따라옵니다. 선택 기준은 \"무슨 연산이 몇 번 일어나는가\"이지 익숙함이 아닙니다."},{"docId":"engineering-cs-foundations","docLabel":"00 CS 기초와 알고리즘 사고","groupLabel":"개발 핸드북","sectionId":"proof","code":"CS-04","title":"INVARIANT PROOF DRILL","summary":"증명은 형식 논문이 아니라 \"왜 이 코드가 깨지지 않는지\"를 짧게 설명하는 훈련입니다. 실무에서는 불변식, 초기화, 보존, 종료를 PR 설명에 넣을 수 있으면 충분합니다. 아래 binary search는 이 네 단계가 코드 주석으로 그대로 들어간 예입니다."},{"docId":"engineering-cs-foundations","docLabel":"00 CS 기초와 알고리즘 사고","groupLabel":"개발 핸드북","sectionId":"production","code":"CS-05","title":"PRODUCTION ALGORITHM DECISION","summary":"프로덕션 알고리즘 선택은 \"교과서상 최적\"보다 \"충분히 빠르고, 설명 가능하며, 장애 시 완화 가능한가\"가 중요합니다. 그리고 대부분의 회귀는 새 알고리즘이 아니라 데이터가 자라서 예전 결정이 무효가 되는 것 에서 옵니다."},{"docId":"engineering-cs-foundations","docLabel":"00 CS 기초와 알고리즘 사고","groupLabel":"개발 핸드북","sectionId":"benchmark","code":"CS-06","title":"BENCHMARK EVIDENCE PACKET","summary":"벤치마크는 숫자를 만드는 절차가 아니라 결정을 방어하는 증거 패킷입니다. 재현 가능하고, 비교 조건이 공정하며, 실제 입력을 닮아야 합니다. 아래 harness는 그대로 파일에 붙여 node bench.mjs 로 실행됩니다."},{"docId":"engineering-cs-foundations","docLabel":"00 CS 기초와 알고리즘 사고","groupLabel":"개발 핸드북","sectionId":"failure","code":"CS-07","title":"실패 모드와 운영 방어선","summary":"알고리즘 장애는 대부분 큰 입력, 나쁜 분포, 동시성, 메모리 증가에서 터집니다. \"정답을 계산한다\"와 \"서비스가 계속 산다\"는 별개의 요구입니다. CS-02에서 계산한 \"허용 n\"은 문서가 아니라 코드 경계에서 강제돼야 방어선이 됩니다."},{"docId":"engineering-computer-systems","docLabel":"01 컴퓨터 시스템·OS·네트워크 기초","groupLabel":"개발 핸드북","sectionId":"spine","code":"SYS-01","title":"COMPUTER SYSTEMS SPINE","summary":"애플리케이션 요청은 CPU 명령, 메모리 접근, 커널 syscall, 파일/소켓 I/O, 스케줄링 대기, 네트워크 왕복으로 분해됩니다. 시스템을 이해한다는 것은 이 비용의 위치를 구분하는 능력입니다."},{"docId":"engineering-computer-systems","docLabel":"01 컴퓨터 시스템·OS·네트워크 기초","groupLabel":"개발 핸드북","sectionId":"cpu-cache","code":"SYS-02","title":"CPU CACHE LOCALITY","summary":"CPU는 메모리보다 훨씬 빠릅니다. 그래서 성능은 종종 연산 횟수보다 데이터를 얼마나 캐시에 잘 올려 쓰는지로 갈립니다."},{"docId":"engineering-computer-systems","docLabel":"01 컴퓨터 시스템·OS·네트워크 기초","groupLabel":"개발 핸드북","sectionId":"memory","code":"SYS-03","title":"메모리와 가상 메모리","summary":"프로세스는 자신만의 연속된 주소 공간을 가진 것처럼 보지만 실제 물리 메모리는 OS가 page 단위로 매핑합니다. 이 추상화가 보호와 격리를 만들고, 동시에 page fault와 OOM의 원인이 됩니다."},{"docId":"engineering-computer-systems","docLabel":"01 컴퓨터 시스템·OS·네트워크 기초","groupLabel":"개발 핸드북","sectionId":"process-thread","code":"SYS-04","title":"PROCESS THREAD SCHEDULING","summary":"프로세스는 자원 격리 단위이고, 스레드는 실행 스케줄링 단위입니다. 동시성 문제는 CPU를 더 쓰는 문제가 아니라 대기, 경합, context switch를 관리하는 문제입니다."},{"docId":"engineering-computer-systems","docLabel":"01 컴퓨터 시스템·OS·네트워크 기초","groupLabel":"개발 핸드북","sectionId":"syscall","code":"SYS-05","title":"FILE SOCKET SYSCALL TRACE","summary":"파일과 소켓은 애플리케이션에서 객체처럼 보이지만 커널에서는 file descriptor입니다. 읽기, 쓰기, 연결, accept는 user mode에서 kernel mode로 넘어가는 syscall입니다."},{"docId":"engineering-computer-systems","docLabel":"01 컴퓨터 시스템·OS·네트워크 기초","groupLabel":"개발 핸드북","sectionId":"resources","code":"SYS-06","title":"RESOURCE LIMIT PLAYBOOK","summary":"운영 장애는 무제한 큐, 무제한 스레드, 무제한 파일, 무제한 메모리에서 시작합니다. limit은 성능 저하가 아니라 장애 반경을 줄이는 안전장치입니다."},{"docId":"engineering-computer-systems","docLabel":"01 컴퓨터 시스템·OS·네트워크 기초","groupLabel":"개발 핸드북","sectionId":"network","code":"SYS-07","title":"네트워크 기본","summary":"네트워크 문제는 애플리케이션 에러처럼 보입니다. DNS, TCP handshake, TLS, HTTP, load balancer, socket pool 중 어느 단계인지 나눠야 합니다."},{"docId":"engineering-language-runtime","docLabel":"02 프로그래밍 언어·런타임","groupLabel":"개발 핸드북","sectionId":"spine","code":"LR-01","title":"LANGUAGE RUNTIME SPINE","summary":"언어 런타임을 이해하면 \"왜 타입 에러가 컴파일 때 잡히는가\", \"왜 JSON 경계에서 깨지는가\", \"왜 GC가 latency를 흔드는가\", \"왜 async 코드가 병렬이 아닌가\"를 설명할 수 있습니다."},{"docId":"engineering-language-runtime","docLabel":"02 프로그래밍 언어·런타임","groupLabel":"개발 핸드북","sectionId":"types","code":"LR-02","title":"TYPE SYSTEM BOUNDARY","summary":"타입 시스템은 값의 모양과 연산 가능성을 제한합니다. 강한 타입은 런타임 오류를 줄이고, 약한 경계는 빠른 실험을 돕지만 계약을 테스트와 검증으로 보강해야 합니다."},{"docId":"engineering-language-runtime","docLabel":"02 프로그래밍 언어·런타임","groupLabel":"개발 핸드북","sectionId":"pipeline","code":"LR-03","title":"AST COMPILER PIPELINE","summary":"컴파일러와 인터프리터는 소스 텍스트를 의미 있는 구조로 바꿉니다. AST를 이해하면 lint, formatter, codemod, transpiler, query planner 같은 도구가 같은 계열 문제라는 것이 보입니다."},{"docId":"engineering-language-runtime","docLabel":"02 프로그래밍 언어·런타임","groupLabel":"개발 핸드북","sectionId":"modules","code":"LR-04","title":"모듈과 패키지","summary":"모듈 시스템은 이름 충돌을 막고 의존성 그래프를 관리합니다. 패키지 매니저는 버전, lockfile, transitive dependency, 공급망 위험을 관리합니다."},{"docId":"engineering-language-runtime","docLabel":"02 프로그래밍 언어·런타임","groupLabel":"개발 핸드북","sectionId":"memory","code":"LR-05","title":"GC JIT MEMORY MODEL","summary":"런타임은 객체를 할당하고 회수하며, 자주 실행되는 코드를 더 빠른 형태로 바꿉니다. 이 자동화는 생산성을 주지만 latency, warmup, pause, visibility 비용을 만듭니다."},{"docId":"engineering-language-runtime","docLabel":"02 프로그래밍 언어·런타임","groupLabel":"개발 핸드북","sectionId":"concurrency","code":"LR-06","title":"동시성 의미론","summary":"언어마다 동시성을 표현하는 단위가 다릅니다. OS thread, green thread, coroutine, event loop, actor는 같은 문제를 다르게 모델링합니다."},{"docId":"engineering-language-runtime","docLabel":"02 프로그래밍 언어·런타임","groupLabel":"개발 핸드북","sectionId":"serialization","code":"LR-07","title":"SERIALIZATION CONTRACT","summary":"객체가 프로세스 밖으로 나가는 순간 포인터, 메서드, 타입 정보, 시간대, 정밀도, null 의미가 일부 사라집니다. 직렬화는 단순 변환이 아니라 독립 시스템 사이의 계약입니다."},{"docId":"engineering-applied-math-measurement","docLabel":"03 응용 수학·측정·검증","groupLabel":"개발 핸드북","sectionId":"spine","code":"AM-01","title":"APPLIED MEASUREMENT SPINE","summary":"좋은 측정은 먼저 질문을 좁힙니다. \"빨라졌나\"보다 \"어떤 사용자군의 p95 latency가 얼마나 줄었고, 오차와 회귀 위험은 얼마인가\"가 더 나은 질문입니다."},{"docId":"engineering-applied-math-measurement","docLabel":"03 응용 수학·측정·검증","groupLabel":"개발 핸드북","sectionId":"sampling","code":"AM-02","title":"PROBABILITY SAMPLING DRILL","summary":"확률은 장기 빈도 또는 믿음의 정도를 다루는 언어입니다. 엔지니어링에서는 \"이 관찰이 우연인지\", \"이 표본이 전체를 대표하는지\", \"위험이 얼마나 자주 발생하는지\"를 묻는 데 쓰입니다."},{"docId":"engineering-applied-math-measurement","docLabel":"03 응용 수학·측정·검증","groupLabel":"개발 핸드북","sectionId":"confidence","code":"AM-03","title":"신뢰구간과 실험 설계","summary":"신뢰구간은 \"진짜 값이 있을 법한 범위\"를 표현합니다. 단일 숫자보다 더 정직한 이유는 표본 변동성을 함께 드러내기 때문입니다."},{"docId":"engineering-applied-math-measurement","docLabel":"03 응용 수학·측정·검증","groupLabel":"개발 핸드북","sectionId":"latency","code":"AM-04","title":"LATENCY PERCENTILE EVIDENCE","summary":"latency는 평균보다 percentile로 봐야 합니다. 사용자는 평균 요청이 아니라 자신이 겪은 한 요청을 경험하고, 시스템은 꼬리 지연에서 먼저 깨집니다."},{"docId":"engineering-applied-math-measurement","docLabel":"03 응용 수학·측정·검증","groupLabel":"개발 핸드북","sectionId":"vectors","code":"AM-05","title":"VECTOR SIMILARITY BASICS","summary":"벡터 유사도는 객체를 숫자 공간에 놓고 가까움을 계산합니다. 검색, 추천, 임베딩 기반 분류는 대부분 \"표현을 만들고 거리 함수를 고르는\" 문제입니다."},{"docId":"engineering-applied-math-measurement","docLabel":"03 응용 수학·측정·검증","groupLabel":"개발 핸드북","sectionId":"error","code":"AM-06","title":"측정 오차와 편향","summary":"측정값은 현실의 복사본이 아니라 관측 시스템이 만든 결과입니다. 계측 위치, 시간 동기화, 샘플링, 누락, 단위 변환이 모두 오차를 만듭니다."},{"docId":"engineering-applied-math-measurement","docLabel":"03 응용 수학·측정·검증","groupLabel":"개발 핸드북","sectionId":"verification","code":"AM-07","title":"VERIFICATION EVIDENCE PACKET","summary":"검증은 예제 몇 개가 통과했다는 보고가 아닙니다. 속성 기반 테스트, fuzzing, benchmark, 회귀 임계값을 조합해 코드가 넓은 입력과 시간 예산에서 성질을 지킨다는 증거를 만듭니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"FRONTEND ENGINEERING HANDBOOK, BROWSER RUNTIME HANDBOOK, WEB ACCESSIBILITY HANDBOOK 원천을 기반으로 역할 판단에서 시작해 브라우저 제약, UI 계약, 접근성 검증으로 이어 읽도록 구성했습니다. 각 파트는 원문을 그대로 나열하지 않고 통합 흐름에서 중복되는 문서 크롬을 제거해 이어 읽기 좋게 "},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"doc-fe","code":"SOURCE","title":"프론트엔드 개요","summary":""},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch1","code":"FE-01","title":"실무 프론트엔드의 역할","summary":"프론트엔드의 성공 기준은 \"화면이 보인다\"가 아닙니다. 사용자가 의도한 일을 끝낼 수 있고, 실패했을 때 이유를 이해할 수 있으며, 팀이 기능을 계속 바꿔도 UI가 무너지지 않는 것입니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch2","code":"FE-02","title":"브라우저를 알아야 하는 이유","summary":"React나 Vue 이전에 브라우저가 있습니다. 이 장은 상세 원리 설명이 아니라, 프론트엔드 의사결정이 브라우저 제약과 어떻게 연결되는지 보여주는 입구입니다. 이벤트 루프, 렌더링 파이프라인, 네트워크 waterfall의 상세 진단은 브라우저 동작 원리 파트에서 다룹니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch3","code":"FE-03","title":"HTML·CSS UI 계약","summary":"HTML과 CSS는 화면을 꾸미는 재료가 아니라 브라우저, 보조기술, 테스트가 읽는 UI 계약입니다. 이 장은 기본 요소 선택과 스타일 경계만 다루고, accessible name, ARIA, 키보드 패턴은 웹접근성 파트에서 상세히 다룹니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch4","code":"FE-04","title":"컴포넌트 설계와 합성","summary":"컴포넌트는 재사용 가능한 조각이기 전에 책임 경계입니다. 좋은 컴포넌트는 \"무엇을 하는지, 무엇을 몰라도 되는지, 어디까지 바꿔도 소비자가 깨지지 않는지\"가 명확합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch5","code":"FE-05","title":"상태 관리와 서버 상태","summary":"프론트엔드 상태 문제의 절반은 \"상태의 종류\"를 구분하지 않아서 생깁니다. 모든 것을 전역 store에 넣는 것은 단순화가 아니라 책임 회피일 때가 많습니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch6","code":"FE-06","title":"API 연동과 에러·로딩 UX","summary":"API 연동은 fetch 한 줄이 아니라 사용자 흐름 설계입니다. 느림, 실패, 권한 없음, 부분 데이터, 재시도, 중복 제출을 모두 다뤄야 합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch7","code":"FE-07","title":"폼·검증·사용자 입력","summary":"폼은 프론트엔드에서 가장 복잡한 상태 기계 중 하나입니다. 입력값, touched, dirty, validation, async validation, submit 상태가 함께 움직입니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch8","code":"FE-08","title":"성능: 번들·렌더링·메모이제이션","summary":"프론트엔드 성능은 초기 로드, 상호작용 반응성, 화면 안정성으로 나뉩니다. \"빠르다\"는 하나의 숫자가 아니라 사용자 여정의 여러 지점입니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch9","code":"FE-09","title":"디자인 시스템과 UI 품질","summary":"디자인 시스템은 버튼 모음이 아니라 제품 UI의 의사결정 체계입니다. 색, 간격, 타이포그래피, 상태, 접근성, 컴포넌트 API가 함께 맞아야 합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch10","code":"FE-10","title":"테스트 전략","summary":"프론트엔드 테스트는 DOM 구조를 얼리는 것이 아니라 사용자 행동을 검증해야 합니다. 좋은 테스트는 refactor를 방해하지 않으면서 회귀를 잡습니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch11","code":"FE-11","title":"배포와 관측가능성","summary":"프론트엔드는 배포 후에도 살아 있는 시스템입니다. 빌드 산출물, CDN 캐시, 환경변수, 오류 수집, 성능 지표가 운영 품질을 결정합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch12","code":"FE-12","title":"보안: XSS·CSRF·토큰 저장","summary":"프론트엔드 보안의 시작은 브라우저가 적대적 입력을 어떻게 실행 가능한 코드로 바꾸는지 이해하는 것입니다. DOM에 넣는 순간, URL로 이동하는 순간, storage에 저장하는 순간 위험이 달라집니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch13","code":"FE-13","title":"대규모 제품 운영","summary":"프론트엔드가 커질수록 어려운 문제는 컴포넌트 작성이 아니라 제품 전체의 변경 비용을 통제하는 일입니다. 성능, 접근성, 디자인 시스템, API 계약, 배포 전략이 하나의 운영 체계로 묶여야 합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch14","code":"FE-14","title":"실무 의사결정 게이트","summary":"좋은 프론트엔드 설계는 멋진 구조보다 결정의 흔적이 남아 있는 구조입니다. PR과 설계 문서는 아래 질문에 답할 수 있어야 합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"fe-ch15","code":"FE-15","title":"용어집","summary":"실무에서 자주 부딪히는 프론트엔드 용어를 의사결정 관점으로 정리합니다. 통합 문서에서는 브라우저·접근성 용어와 함께 마지막 참조 장으로 읽습니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"doc-browser","code":"SOURCE","title":"브라우저 동작 원리","summary":""},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"browser-ch1","code":"BR-01","title":"브라우저는 앱 런타임이다","summary":"브라우저는 HTML 뷰어가 아니라 네트워크, 파서, JS 엔진, 렌더링 엔진, 저장소, 보안 모델을 가진 애플리케이션 런타임입니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"browser-ch2","code":"BR-02","title":"이벤트 루프와 태스크 큐","summary":"이벤트 루프는 JS 실행, Promise callback, timer, 사용자 입력, 렌더링을 순서대로 조율합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"browser-ch3","code":"BR-03","title":"DOM·CSSOM·렌더 트리","summary":"화면은 DOM과 CSSOM이 합쳐진 렌더 트리에서 시작합니다. 이후 style, layout, paint, composite를 거쳐 픽셀이 됩니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"browser-ch4","code":"BR-04","title":"네트워크와 로딩 우선순위","summary":"초기 로드는 HTML, CSS, JS, font, image가 경쟁하는 과정입니다. 무엇을 먼저 받게 할지 결정하는 것이 성능 설계입니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"browser-ch5","code":"BR-05","title":"저장소와 worker","summary":"브라우저 저장소와 worker는 강력하지만 보안과 동기화 비용을 동반합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"browser-ch6","code":"BR-06","title":"브라우저 문제 진단 루틴","summary":"브라우저 문제는 추측으로 고치기 쉽지만, 원인 계층을 잘못 잡으면 해결이 늦어집니다. 증상에서 시작해 main thread, network, rendering, storage를 순서대로 좁힙니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"browser-ch7","code":"BR-07","title":"고빈도 브라우저 이슈","summary":"실무에서 자주 만나는 브라우저 문제는 대부분 같은 패턴으로 반복됩니다. 아래 표는 원인 후보를 빠르게 좁히기 위한 출발점입니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"browser-ch8","code":"BR-08","title":"치트시트","summary":"브라우저 파트의 마지막 참조 장입니다. 본문을 읽은 뒤 진단 중 자주 확인하는 용어만 모았습니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"doc-a11y","code":"SOURCE","title":"웹접근성","summary":""},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"a11y-ch1","code":"A11Y-01","title":"접근성은 UI의 계약","summary":"화면에 보이는 것과 DOM이 말하는 의미가 다르면 UI는 거짓말을 합니다. 접근성의 출발점은 시각 표현이 아니라 의미 구조입니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"a11y-ch2","code":"A11Y-02","title":"Semantic HTML","summary":"가장 좋은 ARIA는 필요 없는 ARIA입니다. 먼저 올바른 HTML 요소를 선택합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"a11y-ch3","code":"A11Y-03","title":"키보드와 focus","summary":"키보드 사용자는 focus를 통해 UI의 현재 위치를 파악합니다. focus가 사라지거나 예측 불가능하게 이동하면 UI 맥락이 끊깁니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"a11y-ch4","code":"A11Y-04","title":"ARIA 사용 기준","summary":"ARIA는 의미를 보강하는 도구이지 잘못된 HTML을 고치는 만능 패치가 아닙니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"a11y-ch5","code":"A11Y-05","title":"폼·오류·상태 전달","summary":"폼 접근성은 label, 설명, 오류, 필수 여부, 제출 상태를 사용자가 이해할 수 있게 연결하는 일입니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"a11y-ch6","code":"A11Y-06","title":"컴포넌트별 접근성 패턴","summary":"접근성 품질은 페이지 단위보다 컴포넌트 단위에서 반복적으로 무너집니다. 공통 컴포넌트는 의미, 키보드, focus, 상태 전달을 API 계약으로 가져야 합니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"a11y-ch7","code":"A11Y-07","title":"검증 루틴","summary":"접근성은 자동 검사만으로 충분하지 않습니다. 패턴을 설계한 뒤 자동화와 수동 키보드 검사를 함께 둡니다."},{"docId":"engineering-frontend-core","docLabel":"04 프론트엔드 핵심","groupLabel":"개발 핸드북","sectionId":"a11y-ch8","code":"A11Y-08","title":"접근성 회귀 방지","summary":"접근성은 한 번 감사해서 끝나는 품질이 아닙니다. 공통 컴포넌트와 핵심 플로우에 자동 검사, 수동 검사, 리뷰 질문을 반복 가능하게 넣어야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"목표는 화면을 보기 좋게 움직이는 개발자가 아니라 입력 모델, 상태 기계, 모션 파이프라인, Canvas/WebGL 렌더링, asset pipeline, 성능 진단, fallback까지 설명하고 구현할 수 있는 수준급 인터랙티브 개발자입니다. 이 문서는 인터랙션 계약 → 입력 이벤트와 상태 아키텍처 → 모션 시스템과 FLIP/spring → 그래픽·3D 구"},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"doc-interaction","code":"SOURCE","title":"인터랙션 설계","summary":"인터랙션은 화면에 움직임을 더하는 장식이 아니라 사용자 의도, 시스템 상태, 입력 장치, 성능 제약, 접근성 을 하나의 계약으로 묶는 엔지니어링입니다. 좋은 인터랙션은 사용자가 무엇을 할 수 있고, 무엇이 진행 중이며, 실패하면 어떻게 회복할 수 있는지 즉시 알게 만듭니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch1","code":"INT-01","title":"인터랙션 설계의 역할","summary":"프론트엔드 인터랙션의 목표는 “멋있게 움직인다”가 아닙니다. 사용자의 입력이 시스템에 도착했고, 시스템이 어떤 상태이며, 다음 행동이 무엇인지 사용자가 확신하게 만드는 것입니다. 애니메이션과 3D는 이 목적을 도울 때만 제품 품질이 됩니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch2","code":"INT-02","title":"상태와 입력 피드백","summary":"입력 피드백은 사용자가 같은 행동을 반복하지 않게 만드는 방어선입니다. 눌림, 포커스, 비활성, 진행 중, 성공, 실패가 구분되지 않으면 사용자는 중복 제출, 강제 새로고침, 이탈로 대응합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch3","code":"INT-03","title":"포인터·터치·키보드","summary":"하나의 UI는 여러 입력 장치에서 같은 의미를 가져야 합니다. hover, drag, pinch, keyboard shortcut, screen reader 동작은 서로 충돌하지 않게 설계해야 하며, 포인터 중심 기능에는 반드시 대체 경로가 있어야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch4","code":"INT-04","title":"모션 시스템과 안전성","summary":"모션 시스템은 duration 숫자 모음이 아니라 상태 전환의 언어입니다. 어떤 변화가 즉시 일어나고, 어떤 변화가 공간 이동으로 설명되며, 어떤 변화는 줄이거나 꺼야 하는지 팀 기준을 가져야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch5","code":"INT-05","title":"Scroll interaction","summary":"스크롤 인터랙션은 사용자의 기본 탐색 행위를 빌려 쓰는 기능입니다. 스크롤을 조종하거나 과하게 연출하면 정보 탐색, 접근성, 성능이 동시에 나빠질 수 있습니다. 스크롤 기반 효과는 콘텐츠 이해를 돕는 경우에만 사용합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch6","code":"INT-06","title":"3D 인터랙션 판단","summary":"3D는 제품 이해를 높일 수도 있지만, 비용이 큽니다. 로딩, GPU, 입력 장치, fallback, 접근성, QA 복잡도가 모두 증가합니다. 3D는 “있으면 멋있다”가 아니라 2D로는 해결하기 어려운 공간 이해나 조작 문제가 있을 때 선택합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch7","code":"INT-07","title":"실패 모드와 관측","summary":"인터랙션 결함은 “동작 안 함”보다 “사용자가 다음 행동을 오해함”으로 자주 나타납니다. 그래서 기능 테스트만으로 부족하고, 상태 로그, 사용자 행동, 성능 지표, 오류 수집을 함께 봐야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch8","code":"INT-08","title":"QA와 PR 게이트","summary":"인터랙션 품질은 리뷰어의 기억에 맡기면 빠집니다. 새 컴포넌트, 모션, scroll effect, 3D 장면, 위험 작업에는 PR 게이트를 두고 증거를 요구해야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch9","code":"INT-09","title":"인터랙션 아키텍처","summary":"수준급 인터랙티브 개발자는 “클릭하면 상태를 바꾼다”가 아니라 입력, 상태 전이, 비동기 작업, 취소, 실패 복구, 관측을 하나의 작은 시스템으로 봅니다. 복잡한 UI일수록 컴포넌트 내부 boolean 여러 개보다 명시적인 상태 기계와 이벤트 계약이 안전합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch10","code":"INT-10","title":"입력 이벤트 심화","summary":"고급 인터랙션은 입력 장치의 차이를 무시하지 않습니다. Pointer Events, keyboard event, wheel, scroll, focus event는 서로 다른 수명주기를 가지며, 드래그·줌·스크롤·텍스트 선택이 충돌하는 지점에서 품질 차이가 납니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch11","code":"INT-11","title":"실전 과제 로드맵","summary":"수준급 인터랙티브 개발자는 문서를 읽어서가 아니라 구현·측정·회귀 방지를 반복하면서 성장합니다. 아래 과제는 입력, 상태, 모션, 스크롤, Canvas/3D를 단계적으로 묶어 실전 감각을 만드는 로드맵입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch12","code":"INT-12","title":"구현 패턴과 좌표계","summary":"정교한 인터랙션은 좋은 문장만으로 구현되지 않습니다. 상태 전이를 코드에서 제한하고, pointer lifecycle을 명시적으로 닫고, 좌표계를 구분해야 드래그·줌·캔버스·3D 조작이 안정됩니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch13","code":"INT-13","title":"Hook 레시피와 접근성 구현","summary":"정교한 인터랙션 구현은 매번 이벤트 핸들러를 새로 쓰는 방식으로 유지하기 어렵습니다. 반복되는 입력 세션, roving tabindex, keyboard reorder, live announcement는 작은 hook 또는 primitive로 표준화해야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch14","code":"INT-14","title":"근거 기반 판단 기준","summary":"인터랙션 품질은 “부드러워 보인다”가 아니라 사용자가 입력한 뒤 어느 시점에 시스템 반응을 확인하고, 실패했을 때 어떤 부작용이 생기는지로 판단합니다. 아래 숫자는 절대 법칙이 아니라 리뷰와 계측을 시작하기 위한 기준선입니다. 실제 승인 기준은 제품의 핵심 행동별 p75, p95 현장 데이터로 보정해야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"interaction-ch15","code":"INT-15","title":"자주 봉착하는 문제와 해결","summary":"인터랙션 문제는 대부분 “이벤트가 안 먹는다”가 아니라 입력 세션, 비동기 상태, focus, scroll, 접근성 경로가 서로 다른 수명으로 움직일 때 생깁니다. 문제를 고칠 때는 시각 효과만 만지지 말고 상태 전이, cleanup, 관측 이벤트를 함께 고쳐야 재발하지 않습니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"doc-motion","code":"SOURCE","title":"애니메이션·모션 시스템","summary":"모션은 화면을 화려하게 만드는 장식이 아니라 상태 변화, 공간 관계, 사용자 행동의 결과 를 설명하는 피드백입니다. 좋은 애니메이션은 덜 보이고, 실패한 애니메이션은 사용자의 시간을 빼앗습니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch1","code":"MOTION-01","title":"모션의 역할과 원칙","summary":"모션의 1차 목적은 즐거움이 아니라 이해입니다. 사용자가 방금 누른 버튼이 어떤 상태를 만들었는지, 새 패널이 어디서 왔는지, 목록 항목이 왜 이동했는지 설명하지 못하는 모션은 대부분 제거하는 편이 낫습니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch2","code":"MOTION-02","title":"CSS transition/keyframes","summary":"CSS 애니메이션은 UI 상태 전환의 기본값입니다. hover, focus, open/close, skeleton, 간단한 reveal처럼 DOM 상태와 스타일 변화가 일대일로 연결되는 경우에는 CSS가 가장 단순하고 안정적입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch3","code":"MOTION-03","title":"WAAPI와 JS animation","summary":"JS 애니메이션은 “CSS보다 고급”이라서 쓰는 것이 아닙니다. 애니메이션의 시작, 중단, 재생 방향, 사용자 입력, Promise 흐름, 동적 측정값이 제품 상태와 연결될 때 사용합니다. 그렇지 않다면 CSS가 더 적은 코드와 낮은 위험을 줍니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch4","code":"MOTION-04","title":"Framer Motion/GSAP/Lottie 선택 기준","summary":"애니메이션 라이브러리 선택은 취향 문제가 아니라 제품 표면, 팀 역량, 번들 예산, 디자이너 산출물, 상호작용 복잡도의 문제입니다. 간단한 상태 전환에 대형 라이브러리를 넣는 것도 문제고, 복잡한 timeline을 CSS로 억지로 관리하는 것도 문제입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch5","code":"MOTION-05","title":"Motion system","summary":"모션 시스템은 개별 애니메이션 모음이 아니라 제품 전체의 시간, easing, 거리, 상태 언어를 표준화한 계약입니다. 토큰이 없으면 화면마다 다른 속도감이 생기고, 토큰만 있고 사용 기준이 없으면 장식 모음이 됩니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch6","code":"MOTION-06","title":"고급 모션과 전환","summary":"고급 모션의 어려움은 효과 자체가 아니라 상태 전환, unmount, 빠른 반복 입력, route 변경, focus 복귀가 동시에 일어나는 데 있습니다. 이 장은 3D 구현이 아니라 제품 UI의 복잡한 전환을 안정적으로 제어하는 기준을 다룹니다. WebGL·Three.js 구현은 그래픽·3D 파트에서 별도로 다룹니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch7","code":"MOTION-07","title":"Reduced motion","summary":"Reduced motion은 애니메이션을 전부 없애라는 뜻이 아닙니다. 어지러움, 집중 방해, 전정기관 민감성을 유발할 수 있는 큰 이동, 확대, 회전, 패럴랙스, 자동 재생을 줄이고 상태 의미는 유지하라는 요구입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch8","code":"MOTION-08","title":"모션 QA와 회귀 방지","summary":"모션 QA는 눈으로 예쁜지 보는 절차가 아닙니다. 빠른 클릭, 느린 기기, reduced motion, 키보드, 라우트 전환, 네트워크 지연, unmount 같은 실제 실패 조건에서 상태가 깨지지 않는지 확인하는 절차입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch9","code":"MOTION-09","title":"FLIP과 layout animation","summary":"수준급 모션 구현에서 FLIP은 필수 도구입니다. DOM layout 자체를 매 프레임 움직이는 대신, 변화 전후 위치를 측정하고 transform으로 차이를 보간하면 layout 비용을 줄이면서 사용자가 위치 변화를 이해할 수 있습니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch10","code":"MOTION-10","title":"Spring과 물리 모션","summary":"Spring 모션은 duration 기반 easing보다 자연스럽지만, 파라미터 의미를 모르면 화면마다 다른 감각과 긴 tail을 만들기 쉽습니다. Spring은 drag, snap, sheet, carousel처럼 사용자의 힘과 해제가 이어지는 인터랙션에 특히 유효합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch11","code":"MOTION-11","title":"Compositor 진단","summary":"모션 성능은 CSS 속성 이름만 보고 판단하면 안 됩니다. 브라우저는 style, layout, paint, composite 단계로 화면을 갱신하며, 같은 transform이라도 layer 수, texture 크기, filter, clip, backdrop 효과에 따라 비용이 달라집니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch12","code":"MOTION-12","title":"모션 실전 로드맵","summary":"모션 실력은 라이브러리 API보다 문제 유형별 구현 경험에서 생깁니다. 아래 과제는 CSS token에서 시작해 FLIP, spring, gesture, route transition, 진단 자동화로 이어지는 성장 경로입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch13","code":"MOTION-13","title":"구현 패턴 예시","summary":"모션 구현의 수준은 효과의 화려함보다 수명주기 관리에서 갈립니다. 측정, 적용, 중단, cleanup, reduced motion, 테스트 증거가 한 흐름에 있어야 운영 가능한 애니메이션입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch14","code":"MOTION-14","title":"Hook과 회귀 자동화","summary":"모션은 눈으로 보기 좋아도 회귀가 숨어 있기 쉽습니다. reduced motion, unmount cleanup, rapid toggle, visual state capture, trace budget을 자동화해야 팀 규모가 커져도 품질이 유지됩니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch15","code":"MOTION-15","title":"근거 기반 모션 예산","summary":"모션은 감각 품질이지만 운영 기준은 숫자로 관리해야 합니다. duration, frame budget, input delay, layer 수, reduced motion 경로를 함께 보지 않으면 “보기에는 부드러운” 효과가 실제로는 입력 지연, 배터리 소모, 접근성 저하를 만들 수 있습니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"motion-ch16","code":"MOTION-16","title":"자주 봉착하는 문제와 해결","summary":"모션 버그는 “애니메이션이 이상하다”로 보이지만 실제 원인은 layout 속성, animation 수명, focus trap, layer 비용, reduced motion 누락인 경우가 많습니다. 해결은 easing을 바꾸는 것이 아니라 어떤 속성을 언제 읽고 쓰며, 취소와 종료를 어떻게 처리하는지 명확히 하는 것입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"doc-graphics","code":"SOURCE","title":"그래픽·3D·WebGL","summary":"그래픽 기술 선택은 “멋있게 보이는가”가 아니라 상호작용 밀도, 픽셀 수, 접근성, 성능 예산, 실패 시 대체 경험 을 동시에 만족하는지로 판단합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch1","code":"GFX-01","title":"SVG·Canvas·WebGL 선택","summary":"SVG, Canvas, WebGL은 렌더링 단위와 책임이 다릅니다. SVG는 DOM 기반 벡터, Canvas는 명령형 2D bitmap, WebGL은 GPU 파이프라인입니다. 기술 선택은 나중에 바꾸기 어렵기 때문에 “현재 구현 편의”보다 데이터 크기, hit testing, 접근성, 애니메이션 빈도, 메모리 상한으로 결정합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch2","code":"GFX-02","title":"Canvas 실무 패턴","summary":"Canvas는 React 컴포넌트처럼 선언적으로 관리되지 않습니다. 한 번 그린 픽셀은 DOM 요소가 아니므로 상태, invalidation, 좌표계, hit testing, 접근성을 직접 설계해야 합니다. 좋은 Canvas 구현은 매 frame 전체를 무작정 다시 그리지 않고, 무엇이 dirty인지 알고 그립니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch3","code":"GFX-03","title":"WebGL 기초 모델","summary":"WebGL은 DOM에 도형을 추가하는 API가 아니라 GPU에게 버퍼, 텍스처, shader, state를 넘겨 draw call을 실행하는 모델입니다. 문제를 빨리 잡으려면 “무엇을 그리는가”보다 “얼마나 자주 state를 바꾸고, 얼마나 많은 데이터를 GPU에 올리고, 몇 번 draw하는가”를 봐야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch4","code":"GFX-04","title":"Three.js 구조","summary":"Three.js는 WebGL을 scene graph, camera, material, loader, renderer로 다루게 해줍니다. 추상화는 빠른 제품 개발에 유리하지만, 자원 생명주기와 frame loop 비용은 여전히 개발자가 책임져야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch5","code":"GFX-05","title":"3D 제품 경험 설계","summary":"3D 제품 경험은 모델을 화면에 띄우는 일이 아니라 사용자가 제품을 이해하고, 비교하고, 설정하고, 구매·승인 같은 다음 행동을 결정하게 만드는 흐름입니다. 카메라, 조명, 입력, 상태 표시, fallback은 같은 제품 경험의 일부입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch6","code":"GFX-06","title":"성능·메모리 예산","summary":"그래픽 성능은 FPS 하나로 관리하면 부족합니다. CPU frame, GPU frame, draw call, texture memory, geometry memory, shader compile, asset download, battery/thermal을 나눠야 원인과 owner가 선명해집니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch7","code":"GFX-07","title":"Fallback·접근성","summary":"Canvas와 WebGL은 보조기술이 내부 픽셀 구조를 이해하지 못합니다. 접근성은 나중에 aria를 붙이는 작업이 아니라, 어떤 정보와 작업을 DOM으로 병렬 제공할지 정하는 설계입니다. Fallback도 “안 보이면 이미지”가 아니라 사용자가 같은 결정을 내릴 수 있는 대체 경로입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch8","code":"GFX-08","title":"QA와 릴리스 게이트","summary":"그래픽 기능 QA는 화면이 예쁘게 보이는지 확인하는 단계가 아닙니다. 기기·브라우저·GPU·입력 방식·네트워크·메모리 반복 시나리오를 통과해야 운영에서 깨지지 않습니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch9","code":"GFX-09","title":"Asset pipeline","summary":"3D 품질은 코드만으로 결정되지 않습니다. 모델링 툴에서 export된 glTF, mesh 압축, texture 포맷, color management, variant 구조, CDN cache 전략이 모두 런타임 성능과 시각 품질을 좌우합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch10","code":"GFX-10","title":"R3F와 상호작용 구조","summary":"React Three Fiber는 React 컴포넌트 모델로 Three.js scene을 구성하게 해주지만, 3D scene은 여전히 imperative한 GPU 자원을 다룹니다. React state, scene mutation, frame loop, pointer event, asset lifecycle의 경계를 명확히 해야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch11","code":"GFX-11","title":"그래픽 진단 도구","summary":"그래픽 성능 문제는 “FPS가 낮다”로 끝나면 해결되지 않습니다. CPU submit, GPU fragment, texture upload, shader compile, memory leak, context loss 중 어디가 병목인지 나눠야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch12","code":"GFX-12","title":"3D 실전 로드맵","summary":"수준급 3D 프론트엔드 개발자는 모델을 띄우는 데서 멈추지 않습니다. asset budget, camera, interaction, fallback, performance trace, 운영 관측까지 한 세트로 제출할 수 있어야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch13","code":"GFX-13","title":"좌표·Shader·Lighting","summary":"정교한 3D 경험은 모델을 띄우는 수준을 넘어 좌표계, shader 비용, 색과 조명 파이프라인을 이해해야 안정됩니다. 클릭한 DOM 좌표가 어떤 3D object를 의미하는지, 왜 같은 색상이 기기마다 다르게 보이는지 설명할 수 있어야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch14","code":"GFX-14","title":"Configurator case study","summary":"아래 사례는 3D product configurator를 설계할 때 어떤 순서로 판단하고 증거를 남길지 보여줍니다. 목표는 멋진 데모가 아니라 사용자가 옵션을 이해하고, 잘못된 조합을 피하고, 느린 기기에서도 구매 결정을 이어가는 것입니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch15","code":"GFX-15","title":"추가 case studies","summary":"정교한 인터랙티브 개발자는 3D configurator만 만드는 사람이 아닙니다. 대량 데이터 편집, 스크롤 기반 설명, workflow 조작, 공간 dashboard처럼 서로 다른 입력·렌더링·접근성 문제를 풀 수 있어야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch16","code":"GFX-16","title":"Canvas·WebGL 자동화","summary":"Canvas와 WebGL은 DOM snapshot만으로 품질을 검증하기 어렵습니다. 최소한 canvas가 비어 있지 않은지, fallback이 동작하는지, renderer.info가 반복 후 증가하지 않는지, reduced motion과 low-end tier가 적용되는지 자동화해야 합니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch17","code":"GFX-17","title":"근거 기반 그래픽 예산과 부수효과","summary":"Canvas와 WebGL 품질은 “GPU를 썼다”로 보장되지 않습니다. 픽셀 수, DPR, texture 해상도, draw call, context loss 복구, fallback 비용을 숫자로 계산해야 저사양 기기와 긴 세션에서 품질이 유지됩니다."},{"docId":"engineering-frontend-interaction","docLabel":"05 프론트엔드 인터랙션·3D","groupLabel":"개발 핸드북","sectionId":"graphics-ch18","code":"GFX-18","title":"자주 봉착하는 문제와 해결","summary":"그래픽/3D 문제는 눈에 보이는 증상이 강해서 즉흥적으로 수정하기 쉽지만, 실제 원인은 GPU resource 수명, 좌표계 변환, asset pipeline, fallback 계약에 있는 경우가 많습니다. 해결은 shader나 camera 값을 찍어 맞추는 것이 아니라 재현 조건과 resource lifecycle을 고정하는 데서 시작합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"doc-rendering","code":"SOURCE","title":"번들링·렌더링·메모이제이션","summary":"성능 최적화는 덜 보내고, 덜 실행하고, 덜 다시 그리는 것 입니다. 하지만 무엇을 줄일지는 측정 후 결정해야 합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"rendering-ch1","code":"RO-01","title":"최적화의 순서","summary":"최적화는 기법 목록이 아니라 병목을 찾는 절차입니다. 먼저 사용자 증상을 한 문장으로 고정하고, 같은 조건에서 측정한 뒤, 네트워크·JS 실행·React render·DOM commit·layout·paint 중 어디에 시간이 쓰였는지 분리합니다. 번들이 큰데 memo를 넣거나, 렌더링이 병목인데 CDN을 바꾸면 효과가 없습니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"rendering-ch2","code":"RO-02","title":"번들링과 code splitting","summary":"번들러는 여러 모듈을 브라우저가 받을 수 있는 산출물로 묶습니다. 성능 관점의 핵심은 파일 개수가 아니라 초기 route에 필요한 byte, parse/compile 비용, chunk waterfall, 장기 캐시 안정성입니다. Vite는 개발 중 ESM 기반으로 빠르게 제공하고, 빌드 시 Rollup 계열 최적화를 수행합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"rendering-ch3","code":"RO-03","title":"React 렌더링 모델","summary":"React에서 렌더링은 컴포넌트 함수를 다시 실행해 다음 UI tree를 계산하는 과정입니다. DOM 업데이트와 같은 말이 아닙니다. 성능 진단은 render phase의 계산 비용, reconciliation의 remount 여부, commit phase의 DOM 변경, 그 뒤 브라우저 layout/paint 비용을 분리해야 정확해집니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"rendering-ch4","code":"RO-04","title":"메모이제이션 판단","summary":"memoization은 공짜가 아닙니다. 비교 비용, 메모리, stale closure 위험, dependency 관리 비용을 추가합니다. 좋은 memoization은 “렌더링이 많다”가 아니라 “같은 입력에서 비싼 계산이나 비싼 child render가 반복된다”는 증거가 있을 때 적용합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"rendering-ch5","code":"RO-05","title":"큰 목록과 무거운 UI","summary":"수천 행 테이블, 차트, 에디터는 일반 컴포넌트와 다른 전략이 필요합니다. 큰 UI의 병목은 “React가 느리다”가 아니라 DOM 수, 측정·layout 비용, 데이터 파생 계산, 편집 상태 소유권, 접근성 요구가 동시에 얽힌 문제인 경우가 많습니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"rendering-ch6","code":"RO-06","title":"증상별 빠른 판단표","summary":"치트시트는 용어장이 아니라 첫 가설을 고르는 도구여야 합니다. 아래 표는 증상에서 바로 확인 도구와 배제 순서로 이어지도록 정리한 빠른 판단표입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"rendering-ch7","code":"RO-07","title":"렌더링 병목 분해","summary":"렌더링 최적화는 “memo를 넣는다”가 아니라 업데이트가 어디서 시작되고, 어떤 컴포넌트 경계를 지나며, commit 이후 브라우저가 어떤 작업을 하는지 분해하는 일입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"rendering-ch8","code":"RO-08","title":"SSR·Hydration·Streaming","summary":"SSR은 HTML을 빨리 보여줄 수 있지만, 클라이언트 JS가 hydration을 끝내기 전까지 상호작용 비용이 남습니다. 서버 렌더링은 로드 성능 문제를 자동으로 해결하는 만능 해법이 아닙니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"doc-perf","code":"SOURCE","title":"성능과 지표","summary":"성능은 개발자의 느낌이 아니라 사용자가 체감하는 시간입니다. Lighthouse 점수는 출발점이고, 실제 판단은 사용자 환경의 field data 와 제품 목표를 함께 봐야 합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"perf-ch1","code":"PM-01","title":"성능은 사용자 경험이다","summary":"빠른 앱은 단순히 로드가 빠른 앱이 아닙니다. 빨리 보이고, 빨리 반응하고, 화면이 흔들리지 않아야 합니다. 성능 대화는 평균 점수보다 핵심 사용자 경로에서 몇 퍼센트의 사용자가 어떤 지연을 겪는지로 시작해야 합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"perf-ch2","code":"PM-02","title":"Core Web Vitals","summary":"Core Web Vitals는 사용자 체감 성능을 대표하는 세 지표입니다. 제품 성능 대화의 공통 언어로 삼기 좋지만, 지표 이름만 외우면 개선이 불가능합니다. 각 지표의 후보 요소, attribution, percentile, route segment를 같이 봐야 합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"perf-ch3","code":"PM-03","title":"Lighthouse 읽는 법","summary":"Lighthouse는 자동 진단 도구입니다. 점수 자체보다 어떤 병목을 지목하는지 읽어야 합니다. Lighthouse 결과는 재현 가능한 lab 신호이지 실제 사용자 전체의 판정이 아니므로, PR에서는 같은 조건의 delta를 보고 운영 판단은 field data와 합쳐야 합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"perf-ch4","code":"PM-04","title":"Lab vs Field","summary":"Lab data는 재현 가능한 테스트이고, field data는 실제 사용자 경험입니다. 둘 중 하나만 보면 판단이 왜곡됩니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"perf-ch5","code":"PM-05","title":"개선 우선순위","summary":"성능 개선은 가장 큰 사용자 영향과 가장 낮은 구현 위험을 함께 봅니다. 우선순위는 “점수에 많이 기여하는 항목”이 아니라 “핵심 사용자의 실패율·이탈·반복 작업 지연을 줄이는 항목”입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"perf-ch6","code":"PM-06","title":"운영 지표","summary":"운영 지표는 “우리 서비스가 빠른가”를 배포, route, 사용자 환경별로 답하기 위한 데이터입니다. 평균 하나로는 회귀를 찾을 수 없으므로 분포와 segment를 기본값으로 둡니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"perf-ch7","code":"PM-07","title":"성능 예산과 SLO","summary":"성능 예산은 “빠르게 만들자”를 PR에서 판단 가능한 기준으로 바꾸는 장치입니다. 기능 추가가 사용자 경험 비용을 얼마나 늘리는지 수치로 드러나야 합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"perf-ch8","code":"PM-08","title":"RUM 계측 설계","summary":"RUM은 실제 사용자의 성능을 수집하지만, 아무 이벤트나 많이 보내면 원인 분석도 어렵고 개인정보 위험도 커집니다. 계측은 질문에서 시작해야 합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"perf-ch9","code":"PM-09","title":"자주 봉착하는 성능 문제","summary":"프론트엔드 성능 문제는 매번 새롭지 않습니다. 대부분은 비슷한 증상으로 나타나고, 잘못된 첫 가설 때문에 시간이 낭비됩니다. 아래 표는 현장에서 자주 만나는 문제를 증상, 흔한 오진, 확인 증거, 해결 방향으로 정리한 것입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"doc-devtools","code":"SOURCE","title":"DevTools 사용법","summary":"DevTools는 문제를 추측에서 측정으로 바꾸는 도구입니다. 좋은 프론트엔드 디버깅은 증상을 재현하고, 레이어를 나누고, 가장 싼 가설부터 제거 하는 과정입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"devtools-ch1","code":"DT-01","title":"디버깅 루틴","summary":"DevTools를 열기 전에 문제를 한 문장으로 정의합니다. \"느리다\"가 아니라 \"검색어 입력 후 목록 갱신까지 600ms 걸린다\"처럼 관찰 가능한 증상이어야 합니다. 좋은 디버깅은 패널을 많이 여는 것이 아니라 가설을 하나씩 제거하는 일입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"devtools-ch2","code":"DT-02","title":"Elements·Styles","summary":"Elements 패널은 DOM과 CSS cascade를 확인하는 곳입니다. UI 깨짐은 대부분 여기서 원인을 찾지만, 성능 진단에서도 DOM 수, layout containment, 접근성 tree, focus 상태를 확인하는 출발점이 됩니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"devtools-ch3","code":"DT-03","title":"Network","summary":"Network는 API와 리소스 로딩 문제를 분리하는 첫 관문입니다. 느린 화면을 보면 먼저 서버가 늦은지, 리소스 우선순위가 틀렸는지, 캐시가 깨졌는지, 프론트엔드가 요청을 늦게 시작했는지 나눕니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"devtools-ch4","code":"DT-04","title":"Performance·Memory","summary":"Performance 패널은 main thread의 실제 비용을 보여줍니다. Memory 패널은 누수가 의심될 때 사용합니다. 핵심은 긴 막대를 발견하는 것이 아니라 사용자 action부터 다음 paint까지 어떤 단계가 시간을 썼는지 설명하는 것입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"devtools-ch5","code":"DT-05","title":"Application·Security","summary":"Application 패널은 storage, cookie, cache, service worker를 보는 곳입니다. Security 패널은 HTTPS와 인증서 문제를 확인합니다. 프론트엔드 장애 중에는 코드 문제가 아니라 오래된 cache, 잘못된 cookie scope, service worker update 정책 때문에 생기는 문제가 많습니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"devtools-ch6","code":"DT-06","title":"React DevTools","summary":"React DevTools는 컴포넌트 트리, props, state, render 비용을 확인하는 도구입니다. Performance 패널이 “main thread에서 오래 걸린 일”을 보여준다면 React Profiler는 “어떤 컴포넌트 commit이 그 비용에 기여했는지”를 좁히는 도구입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"devtools-ch7","code":"DT-07","title":"Performance trace 해석","summary":"Performance trace는 “느린 것 같다”를 시간축 위의 증거로 바꿉니다. 핵심은 긴 막대를 찾는 것이 아니라 사용자 상호작용부터 다음 paint까지 어떤 단계가 시간을 썼는지 연결하는 것입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"devtools-ch8","code":"DT-08","title":"회귀 재현 패킷","summary":"성능 이슈는 “느립니다”로 공유하면 해결이 늦어집니다. 누가 봐도 같은 조건에서 재현하고 비교할 수 있는 패킷으로 남겨야 합니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"devtools-ch9","code":"DT-09","title":"AI 성능 진단 방법론","summary":"AI는 성능 문제를 대신 측정하지 못합니다. 하지만 재현 조건, trace 요약, 코드 경로, 가설 목록, 검증 계획을 구조화하는 데 매우 유용합니다. AI를 잘 쓰는 방법은 “느린데 고쳐줘”가 아니라 “이 증거로 가능한 원인을 좁히고, 가장 작은 실험을 설계해줘”라고 요청하는 것입니다."},{"docId":"engineering-frontend-performance","docLabel":"06 프론트엔드 성능·진단","groupLabel":"개발 핸드북","sectionId":"performance-glossary","code":"GLOSSARY","title":"성능 용어 사전","summary":"성능 문서에서 자주 나오는 약어와 도구 이름을 한 줄로 다시 확인합니다. 정확한 진단은 각 지표가 측정하는 사용자 경험을 먼저 구분하는 데서 시작합니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"문서 개요","summary":"검색 최적화는 더 이상 title과 description을 채우는 작업만이 아닙니다. 사용자는 검색엔진 결과, AI 요약, 음성 답변, 소셜 미리보기, 앱 내부 검색, 추천 피드 등 여러 발견 경로를 통해 제품을 만납니다. 프론트엔드는 이 경로들이 읽을 수 있는 HTML, 의미 구조, 성능, 콘텐츠 신뢰 신호, 구조화 데이터, canonical 정책, 이벤"},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"discovery-model","code":"MODEL","title":"DISCOVERY AND MEASUREMENT MODEL","summary":"좋은 최적화는 노출만 늘리지 않습니다. 발견된 사용자가 기대한 정보를 얻고, 제품에서 의미 있는 행동을 완료하며, 그 결과가 지표로 검증되어야 합니다. 그래서 검색·AI 최적화는 콘텐츠, 프론트엔드 런타임, 데이터 계측, 개인정보 거버넌스를 한 흐름으로 봐야 합니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"seo-foundation","code":"SEO-01","title":"SEO의 기술 기반","summary":"SEO는 검색엔진을 속이는 기술이 아니라 페이지의 의미와 품질을 기계가 안정적으로 이해하게 만드는 작업입니다. 크롤링 가능성, 색인 가능성, 중복 URL 정리, 내부 링크, 메타 정보, 성능, 모바일 사용성을 기본으로 두고, 그 위에 콘텐츠 신뢰성과 사용자 행동 데이터를 해석합니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"content-architecture","code":"SEO-02","title":"콘텐츠 구조와 정보 설계","summary":"검색과 AI 답변에서 강한 콘텐츠는 키워드를 많이 반복하지 않습니다. 의도별로 정보를 분리하고, 제목 구조가 논리적이며, 사용자가 비교·판단·행동할 수 있는 근거를 제공합니다. 프론트엔드는 이 구조가 DOM, URL, heading, table, list, internal link로 정확히 표현되도록 구현해야 합니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"aeo-geo","code":"AEO-03","title":"AEO·GEO·LLM 최적화","summary":"AEO는 Answer Engine Optimization, GEO는 Generative Engine Optimization으로 부릅니다. 두 용어 모두 고정된 표준이라기보다 검색 경험이 답변형·생성형으로 바뀌면서 생긴 실무 프레임입니다. 핵심은 AI가 문서를 읽을 때 질문, 답, 근거, entity, 출처, 최신성을 잃지 않도록 구조를 제공하는 것입니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"technical-seo","code":"SEO-04","title":"기술 SEO와 렌더링","summary":"프론트엔드 렌더링 전략은 SEO의 핵심 의사결정입니다. CSR, SSR, SSG, ISR, edge rendering은 성능과 운영 비용뿐 아니라 색인 안정성, 콘텐츠 최신성, 개인화, 캐시 전략에 영향을 줍니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"structured-data","code":"SEO-05","title":"구조화 데이터와 메타","summary":"구조화 데이터는 검색엔진과 AI가 페이지의 대상과 관계를 이해하도록 돕는 명시적 힌트입니다. schema.org JSON-LD를 주로 사용하며, 실제 화면에 없는 거짓 정보를 넣으면 신뢰를 해칩니다. 메타 정보는 검색 결과, 공유 미리보기, 브라우저 탭, 접근성, 분석 지표까지 연결됩니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"international-local","code":"SEO-06","title":"국제화·로컬·도메인 전략","summary":"다국어 사이트의 SEO는 번역 파일을 바꾸는 일보다 URL, canonical, hreflang, 언어별 콘텐츠 품질, 지역별 법적 문구, analytics segment를 함께 맞추는 일입니다. 같은 내용을 여러 언어로 제공할 때 검색엔진이 어느 페이지를 어느 사용자에게 보여줘야 하는지 명확해야 합니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"analytics-measurement","code":"ANA-07","title":"애널리틱스 측정 설계","summary":"애널리틱스는 스크립트를 붙이는 작업이 아니라 제품 질문에 답하기 위한 측정 설계입니다. “방문자가 몇 명인가”보다 “어떤 의도의 사용자가 어떤 경로로 들어와 어떤 행동에서 이탈하고, 어떤 품질 문제가 전환을 막는가”를 설명해야 합니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"event-taxonomy","code":"ANA-08","title":"이벤트 택소노미","summary":"이벤트는 많이 찍을수록 좋은 것이 아닙니다. 이름과 파라미터가 일관되지 않으면 분석 비용이 폭증하고, 같은 행동이 여러 이벤트로 중복 집계됩니다. 좋은 이벤트 택소노미는 사용자의 의도, 객체, 결과, 맥락을 안정적인 스키마로 표현합니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"dashboards-experiments","code":"ANA-09","title":"대시보드와 실험","summary":"대시보드는 예쁜 차트가 아니라 반복 의사결정 도구입니다. 검색 최적화 대시보드는 impression, CTR, average position, landing page engagement, conversion, Web Vitals, index coverage를 함께 봐야 합니다. 실험은 전환율만 보지 않고 성능, 오류, 장기 유지 같은 보호 지표를 함께 둬야"},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"privacy-governance","code":"GOV-10","title":"개인정보와 거버넌스","summary":"애널리틱스와 광고 태그는 제품 코드만큼 강한 거버넌스가 필요합니다. third-party script는 성능, 보안, 개인정보, 동의 관리, 데이터 국외 이전, CSP에 영향을 줍니다. 프론트엔드는 스크립트 삽입 위치와 로딩 우선순위뿐 아니라 수집 항목과 동의 상태에 따른 동작을 확인해야 합니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"release-checklist","code":"CHECK","title":"릴리스 체크리스트","summary":"검색·AI 최적화와 애널리틱스 변경은 배포 후 바로 결과가 나오지 않을 수 있습니다. 그래서 배포 전에는 기술 무결성을, 배포 후에는 색인·지표·오답·전환 변화를 시간차로 추적해야 합니다."},{"docId":"engineering-frontend-seo-analytics","docLabel":"07 SEO·AEO·GEO·애널리틱스","groupLabel":"개발 핸드북","sectionId":"glossary","code":"TERM","title":"용어 사전","summary":""},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"프론트엔드 품질·릴리스는 보안, 테스트, 배포를 따로 점검하는 목록이 아니라 변경을 안전하게 사용자에게 내보내는 운영 루프입니다. 변경 위험을 분류하고, 그 위험에 맞는 테스트와 보안 리뷰를 선택하고, preview와 CI에서 확인한 뒤, release health window 동안 오류·Web Vitals·API 실패율을 관찰하고 rollback 또는 f"},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"frontend-release-quality-model","code":"MODEL","title":"FRONTEND RELEASE QUALITY OPERATING MODEL","summary":"프론트엔드 품질은 테스트 개수나 배포 성공 로그가 아니라 사용자의 브라우저에서 새 버전이 안전하게 작동한다는 증거입니다. 이 모델은 변경이 들어온 순간부터 release health window가 끝날 때까지의 판단 순서를 고정합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"frontend-quality-output","code":"OUTPUT","title":"FRONTEND QUALITY OUTPUTS","summary":"이 문서를 읽은 뒤 남겨야 하는 것은 지식 요약이 아니라 릴리스 때 재사용할 수 있는 증거 패킷입니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"doc-fesec","code":"SOURCE","title":"보안 대응","summary":"프론트엔드 보안은 브라우저가 신뢰 경계를 어떻게 다루는지 이해하는 일입니다. 입력, HTML, URL, storage, dependency가 모두 공격 표면입니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fesec-ch1","code":"FSEC-01","title":"브라우저 위협 모델","summary":"사용자 입력, URL parameter, 외부 API, CMS 콘텐츠, third-party script는 모두 신뢰할 수 없는 입력입니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fesec-ch2","code":"FSEC-02","title":"XSS와 HTML 주입","summary":"XSS는 공격자가 브라우저에서 스크립트를 실행하게 만드는 취약점입니다. React는 문자열 escape를 기본 제공하지만, 그 안전장치를 끄면 책임은 개발자에게 넘어갑니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fesec-ch3","code":"FSEC-03","title":"CSRF와 쿠키","summary":"CSRF는 브라우저가 쿠키를 자동 첨부한다는 성질을 악용합니다. 사용자가 공격자 사이트를 방문했을 뿐인데 우리 서비스에 mutation 요청이 갈 수 있습니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fesec-ch4","code":"FSEC-04","title":"토큰 저장","summary":"토큰 저장 위치에는 정답이 없습니다. XSS와 CSRF 중 어느 위험을 어떻게 줄일지의 선택입니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fesec-ch5","code":"FSEC-05","title":"CSP와 보안 헤더","summary":"CSP는 브라우저가 어떤 리소스를 실행할 수 있는지 제한하는 정책입니다. XSS 피해를 줄이는 강력한 방어층입니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fesec-ch6","code":"FSEC-06","title":"의존성과 공급망","summary":"프론트엔드는 npm 생태계 위에서 움직입니다. 작은 패키지 하나도 배포 산출물과 사용자 브라우저에 들어갈 수 있습니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"doc-fetest","code":"SOURCE","title":"테스트 전략","summary":"좋은 테스트는 코드를 얼리지 않고 사용자 계약을 보호 합니다. 구현 세부를 많이 알수록 refactor를 방해하고, 사용자 행동을 검증할수록 오래 갑니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fetest-ch1","code":"FTEST-01","title":"테스트의 목적","summary":"테스트는 QA 문서가 아니라 변경 안전장치입니다. 실패했을 때 무엇이 깨졌고 사용자에게 어떤 영향이 있는지 알려야 합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fetest-ch2","code":"FTEST-02","title":"테스트 피라미드","summary":"프론트엔드에서는 피라미드보다 \"테스트 트로피\" 사고가 더 실용적일 때가 많습니다. 순수 로직은 단위, UI 계약은 컴포넌트, 핵심 여정은 E2E로 보호합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fetest-ch3","code":"FTEST-03","title":"컴포넌트 테스트","summary":"Testing Library의 관점은 \"사용자가 찾는 방식으로 찾는다\"입니다. role, label, text를 우선합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fetest-ch4","code":"FTEST-04","title":"E2E 테스트","summary":"E2E는 비싸지만 실제 통합 문제를 잡습니다. 모든 것을 E2E로 덮지 말고, 실패하면 매출/업무 흐름이 깨지는 핵심 경로에 집중합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fetest-ch5","code":"FTEST-05","title":"Mock 전략","summary":"mock은 빠른 테스트를 만들지만 현실과 멀어질 수 있습니다. 어떤 경계를 mock할지 명확히 정해야 합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fetest-ch6","code":"FTEST-06","title":"시각 회귀","summary":"프론트엔드는 로직이 맞아도 UI가 깨질 수 있습니다. 시각 회귀는 디자인 시스템과 핵심 화면에 특히 유용합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"doc-fedeploy","code":"SOURCE","title":"배포","summary":"프론트엔드 배포는 파일을 올리는 일이 아니라 사용자의 브라우저와 CDN 캐시가 새 버전을 안전하게 만나게 하는 과정 입니다. 빌드 산출물, cache header, release id, 오류 수집이 함께 맞아야 합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fedeploy-ch1","code":"DEP-01","title":"프론트엔드 배포의 본질","summary":"백엔드는 서버 프로세스를 교체하지만, 프론트엔드는 이미 사용자 브라우저에 내려간 파일과도 공존해야 합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fedeploy-ch2","code":"DEP-02","title":"Vite build와 환경변수","summary":"Vite의 환경변수는 빌드 시점에 클라이언트 번들로 주입됩니다. 브라우저에 들어가는 값은 secret이 될 수 없습니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fedeploy-ch3","code":"DEP-03","title":"정적 호스팅·CDN·캐시","summary":"CDN은 빠르게 전달하지만 잘못된 cache header는 배포 사고를 키웁니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fedeploy-ch4","code":"DEP-04","title":"sourcemap과 오류 수집","summary":"운영 오류를 추적하려면 minified stack trace를 원본 코드로 복원할 수 있어야 합니다. sourcemap은 강력하지만 노출 정책을 신중히 정해야 합니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fedeploy-ch5","code":"DEP-05","title":"rollback과 release","summary":"좋은 배포는 실패하지 않는 배포가 아니라 실패해도 빠르게 되돌릴 수 있는 배포입니다."},{"docId":"engineering-frontend-quality","docLabel":"08 프론트엔드 품질·릴리스","groupLabel":"개발 핸드북","sectionId":"fedeploy-ch6","code":"DEP-06","title":"배포 체크리스트","summary":"배포 관련 변경은 cache header, sourcemap 공개 여부, release id 주입, 이전 assets 보존, rollback 절차, service worker 업데이트 정책을 체크합니다. 한 항목이라도 바뀌면 배포 리허설 또는 staging 검증을 거칩니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"백엔드 핵심은 로그인과 보안까지 한 문서에 밀어 넣는 목록이 아니라 요청이 계약, 상태, 실패, 증거를 남기며 통과하는 경로를 설명하는 능력입니다. 이 문서는 요청 생명주기, API 계약, validation, transaction boundary, JPA persistence boundary, concurrency, idempotency, cache, a"},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-roadmap-overview","code":"ROADMAP","title":"BACKEND ROADMAP OVERVIEW","summary":"백엔드 핵심은 기능 구현 목록이 아니라 요청이 계약, 상태, 실패, 증거를 남기며 통과하는 경로를 설명하는 능력입니다. 아래 순서로 읽으면 API, DB, 트랜잭션, 테스트, 운영, 아키텍처가 따로 놀지 않습니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-request-ops-map","code":"MAP","title":"REQUEST TO OPERATIONS MAP","summary":"좋은 백엔드 설명은 controller에서 끝나지 않습니다. 요청 하나가 저장소, 외부 의존성, 큐, 로그와 지표까지 어떻게 이어지는지 따라가야 합니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-study-outputs","code":"OUTPUT","title":"BACKEND STUDY OUTPUTS","summary":"학습 완료 기준은 읽은 분량이 아니라 제출 가능한 산출물입니다. 아래 묶음은 백엔드 코어에서 직접 검증할 수 있는 설계 판단과 동작 증거만 남깁니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"doc-backend","code":"SOURCE","title":"백엔드 개요","summary":"백엔드 학습은 기술명을 넓게 훑는 일이 아니라 요청 하나가 계약, 트랜잭션, 실패 처리, 테스트, 운영 증거를 남기며 통과하는 경로 를 구체적으로 설명할 수 있게 되는 과정입니다. 이 문서는 HTTP/API, Java·Spring, DB/JPA, 캐시·비동기, 테스트, 배포·관측성, 운영을 하나의 실무 판단 흐름으로 다시 묶습니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch1","code":"BE-00","title":"백엔드 학습 지도","summary":"실무형 백엔드 엔지니어는 더 많은 기능을 짜는 사람이 아니라, 모든 선택에 대해 \"이 결정의 비용은 무엇인가\" 와 \"어떤 증거로 맞게 동작한다고 말할 수 있는가\" 를 묻는 사람입니다. 코드가 도는 것은 시작점일 뿐입니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch1-5","code":"BE-01","title":"요청 생명주기와 서버 책임","summary":"백엔드 학습은 기술 이름을 나열하는 순서가 아니라 요청 하나가 시스템을 통과하며 어떤 계약, 상태, 실패, 증거를 남기는지 따라가는 순서여야 합니다. 이 모델을 먼저 잡으면 API, DB, 검증, 테스트, 운영이 따로 놀지 않습니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch2","code":"BE-02","title":"HTTP·REST·API 계약","summary":"API는 코드가 아니라 계약 입니다. 한 번 공개하면 수많은 클라이언트가 의존하고, 함부로 못 바꿉니다. 설계의 무게가 내부 함수와 다른 이유입니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch2-5","code":"BE-03","title":"Java·Spring 실행 모델","summary":"프레임워크를 잘 쓴다는 것은 annotation을 많이 아는 것이 아니라, 요청이 어떤 객체를 거쳐 어떤 proxy, transaction, validation, exception handler를 통과하는지 설명하는 것입니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch3","code":"BE-04","title":"관계형 DB·SQL·트랜잭션","summary":"백엔드 실무의 진짜 시험장. 성능 문제의 대부분과 정합성 버그의 거의 전부가 여기서 납니다. ORM 뒤에 숨지 말고 직접 봐야 하는 층입니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch4","code":"BE-05","title":"ORM·JPA와 영속성 경계","summary":"ORM은 객체와 테이블 사이의 임피던스 불일치를 가립니다 — 가리지만 없애지 않습니다. 생성되는 SQL을 모르면, ORM은 편의가 아니라 지뢰밭이 됩니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch5","code":"BE-06","title":"동시성·락·멱등성","summary":"단일 요청에선 멀쩡하던 코드가 동시 요청에서 무너집니다. \"재고 1개 남았는데 두 명이 동시에 주문\"은 백엔드의 통과의례입니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch10","code":"BE-07","title":"인증·보안 핸드북 포인터","summary":"이 백엔드 코어 문서는 인증·인가·보안을 깊게 설명하지 않습니다. 상세한 토큰 설계, OAuth/OIDC, 세션 탈취 대응, 취약점 검증, 감사 정책은 별도의 백엔드 인증·보안 핸드북 에서 다룹니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch6","code":"BE-08","title":"캐시·Redis·정합성","summary":"캐시는 가장 손쉬운 성능 개선이자 가장 흔한 정합성 버그의 원천입니다. \"캐시 무효화는 컴퓨터 과학의 두 어려운 문제 중 하나\"라는 농담은 진담입니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch7","code":"BE-09","title":"비동기·메시징·이벤트","summary":"동기 호출은 두 서비스를 시간으로 묶습니다 — 하나가 느리거나 죽으면 다른 하나도 같이 멈춥니다. 큐는 그 결합을 끊어, 시간과 장애를 분리합니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch11","code":"BE-10","title":"테스트 전략","summary":"테스트의 목적은 커버리지 숫자가 아니라 변경을 두렵지 않게 만드는 것 입니다. 리팩토링·배포의 자신감이 테스트에서 나옵니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch15","code":"BE-11","title":"배포·런타임·운영 준비","summary":"시스템이 커지면 “어떤 기술을 쓸까”보다 “어디까지 단순하게 버티고, 언제 복잡도를 받아들일까”가 중요해집니다. 이 장은 기존의 대규모 운영 판단 을 배포·런타임 준비와 합쳐, 규모, 위험, 팀 역량, 운영 비용을 함께 놓고 결정하는 기준으로 재정리합니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch9","code":"BE-12","title":"관측가능성·장애 대응","summary":"운영을 책임질 수 있느냐가 백엔드 품질의 분기점입니다. 관측가능성은 \"안 돼요\"를 \"여기가 이래서 안 됩니다\"로 바꾸는 능력입니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch12","code":"BE-13","title":"아키텍처와 시스템 설계","summary":"백엔드 설계의 최종 시험은 \"정답을 아는가\"가 아니라 \"트레이드오프를 설명하는가\" 입니다. 시스템 설계엔 정답이 없고, 제약에 맞는 선택과 그 비용의 명시가 있을 뿐입니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch19","code":"BE-14","title":"학습 산출물 포인터","summary":"백엔드 핵심 페이지에서 남겨야 할 산출물은 커리어 문장이 아니라 설계 판단과 동작 증거 입니다. 면접 답변, 포트폴리오 구성, 개인 경험 편집은 면접·커리어 문서로 넘기고, 이 장은 코어 학습이 실제로 쌓였는지 확인하는 최소 증거만 고정합니다."},{"docId":"engineering-backend-core","docLabel":"09 백엔드 핵심","groupLabel":"개발 핸드북","sectionId":"backend-ch13","code":"BE-15","title":"용어집","summary":""},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"백엔드 보안은 로그인 기능을 붙이는 일이 아니라 신뢰 경계, identity proof, session lifecycle, authorization decision, tenant isolation, audit evidence, incident response를 설계하는 일입니다. 이 문서는 세션/JWT/OAuth/OIDC와 RBAC/ABAC/ReBAC, C"},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"doc-auth","code":"SOURCE","title":"인증과 보안","summary":""},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch1","code":"SEC-01","title":"보안 지도와 신뢰 경계","summary":"보안 설계의 시작은 \"로그인 기능\"이 아니라 무엇을 누구에게서 보호하는가 를 그리는 일입니다. 좋은 백엔드 보안 문서는 자산, 행위자, 진입점, 신뢰 경계, 실패 시 영향, 탐지 증거를 한 장에서 설명할 수 있어야 합니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch2","code":"SEC-02","title":"인증 vs 인가","summary":"인증(authentication, authN)은 \"요청 주체가 누구인지\"를 세우는 절차이고, 인가(authorization, authZ)는 \"그 주체가 특정 자원에 특정 행동을 해도 되는지\"를 매 요청 판정하는 절차입니다. 로그인 성공은 권한 판정의 시작이지 끝이 아닙니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch3","code":"SEC-03","title":"세션·쿠키·CSRF·CORS","summary":"브라우저 기반 인증의 핵심은 쿠키가 자동 첨부된다는 사실입니다. 이 자동성은 사용자 경험에는 좋지만 CSRF 위험을 만들고, CORS 설정과 섞이면 \"어떤 origin이 credential 요청을 보낼 수 있는가\"라는 운영 정책이 됩니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch4","code":"SEC-04","title":"JWT와 토큰 생명주기","summary":"JWT는 서명된 claim 묶음입니다. payload는 Base64URL 인코딩이지 암호화가 아니며, stateless 검증은 확장성에는 유리하지만 만료 전 회수와 권한 변경 반영을 어렵게 만듭니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch5","code":"SEC-05","title":"OAuth2·OIDC","summary":"OAuth2는 인가 위임 프로토콜이고, OIDC는 OAuth2 위에 인증 계층을 얹은 표준입니다. \"소셜 로그인\"을 안전하게 설명하려면 access token과 ID token을 구분해야 합니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch6","code":"SEC-06","title":"비밀번호·MFA·계정 복구","summary":"비밀번호 보안은 저장 방식만의 문제가 아닙니다. 등록, 로그인, 실패 제한, MFA, 복구, 비밀번호 변경 이후 세션 폐기까지 계정 생명주기 전체가 공격 표면입니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch7","code":"SEC-07","title":"RBAC·ABAC·ReBAC","summary":"인가는 권한 문자열을 확인하는 작업이 아니라 정책 결정입니다. 실무에서는 RBAC로 큰 권한 묶음을 관리하고, ABAC와 ReBAC로 소유권, 조직, 관계, 환경 조건을 보완합니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch8","code":"SEC-08","title":"Tenant Isolation","summary":"멀티테넌트 보안의 목표는 단순합니다. 한 테넌트의 사용자가 다른 테넌트의 데이터를 읽거나, 바꾸거나, 존재 여부를 추론할 수 없어야 합니다. 이것은 필터 옵션이 아니라 시스템 불변식입니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch9","code":"SEC-09","title":"OWASP 서버 취약점","summary":"OWASP 항목은 외울 목록이 아니라 리뷰 질문 묶음입니다. 백엔드 인증·보안 문맥에서는 접근 제어, 입력 신뢰, 암호화 실패, 설정 오류, 관측 부재가 반복적으로 사고를 만듭니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch10","code":"SEC-10","title":"Secret·Key·Audit","summary":"secret과 key는 인증 시스템의 루트 신뢰입니다. 감사 로그는 사고 이후 \"무슨 일이 있었는지\"를 증명하는 자료입니다. 둘 다 코드 뒤에 붙이는 운영 잡무가 아니라 보안 설계의 핵심입니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch11","code":"SEC-11","title":"Security Review Rubric","summary":"보안 리뷰는 \"문제 없어 보임\"이 아니라 정해진 질문에 증거로 답하는 과정입니다. PR, 설계 문서, 면접 과제 리뷰에 아래 표를 그대로 붙여도 됩니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch12","code":"SEC-12","title":"Security Tabletop Drills","summary":"SECURITY TABLETOP DRILLS는 취약점 이름 암기가 아니라 사고 대응 근육을 만드는 연습입니다. 제한 시간 안에 재현, 영향 범위, 임시 통제, 영구 수정, 고객/법무/지원 handoff까지 말할 수 있어야 합니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"auth-auth-ch13","code":"SEC-13","title":"SECURITY INCIDENT PACKET","summary":"SECURITY INCIDENT PACKET은 사고가 의심될 때 흩어진 정보를 한곳에 모으는 최소 문서입니다. 목적은 멋진 보고서가 아니라, 대응자가 같은 사실 위에서 빠르게 판단하게 하는 것입니다."},{"docId":"engineering-backend-auth-security","docLabel":"10 백엔드 인증·보안","groupLabel":"개발 핸드북","sectionId":"backend-security-review-packet","code":"PACKET","title":"BACKEND SECURITY REVIEW PACKET","summary":"보안 문서를 읽은 뒤 실제 PR과 설계 리뷰에 붙일 증거 묶음입니다. 인증·권한·데이터 경계 변경은 단순 기능 변경처럼 리뷰하지 않습니다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아키텍처는 패턴명을 외우는 영역이 아니라 경계, 소유권, 실패 모드, 배포 단위, 데이터 일관성을 조정하는 의사결정입니다. 백엔드 핵심 문서에서 API·보안·운영 기본기를 잡은 뒤, 이 문서에서 모듈러 모놀리스, 헥사고날, DDD, MSA, CQRS, event-driven 설계를 별도 흐름으로 읽습니다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-decision-map","code":"MAP","title":"ARCHITECTURE DECISION MAP","summary":"좋은 아키텍처 문서는 다이어그램이 아니라 결정을 설명합니다. 무엇을 같은 모듈에 둘지, 어떤 데이터가 어느 경계에 속하는지, 실패를 어디서 끊을지, 나중에 어떤 지표가 나오면 분리할지까지 남겨야 합니다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"doc-architecture","code":"SOURCE","title":"아키텍처 패턴","summary":"아키텍처는 정답이 아니라 트레이드오프 다 — 변경 비용을 낮추는 구조를 제약에 맞게 고르고, 그 비용을 설명하는 능력. 이 핸드북은 패턴의 카탈로그가 아니라, 왜 이 구조이고 무엇을 포기했는가 를 읽는 훈련이다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch1","code":"ARCH-01","title":"좋은 아키텍처란","summary":"좋은 아키텍처의 정의는 \"빠르다\"도 \"확장된다\"도 아니다. 변경 비용이 낮은 구조 다 — 요구가 바뀌었을 때 고쳐야 할 코드의 범위가 작고, 그 영향이 예측 가능한 것. 거의 모든 설계 원칙은 이 한 문장의 따름정리다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch2","code":"ARCH-02","title":"계층형 아키텍처","summary":"가장 흔하고, 그래서 가장 잘못 쓰이는 구조. 코드를 역할별 층(layer) 으로 쌓고, 위층이 아래층에만 의존하게 한다. Spring 프로젝트의 controller / service / repository 가 바로 이 패턴의 축약형이다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch3","code":"ARCH-03","title":"헥사고날·클린 아키텍처","summary":"계층형의 누수 문제를 정면으로 푸는 구조. 핵심 발상 하나 — 도메인을 안쪽에 두고, DB·웹·메시지큐 같은 외부를 바깥에 두되, 의존성이 항상 바깥에서 안쪽으로만 향하게 한다. 헥사고날(포트 & 어댑터)과 클린 아키텍처는 같은 아이디어의 두 표현이다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch4","code":"ARCH-04","title":"DDD 기초","summary":"Domain-Driven Design은 \"복잡한 비즈니스를 코드로 옮길 때, 도메인 전문가의 언어를 그대로 코드의 언어로 삼자\"는 접근이다. 두 층위가 있다 — 객체를 어떻게 모델링하는가(전술적 패턴)와, 시스템을 어떻게 나누는가(전략적 설계)."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch5","code":"ARCH-05","title":"모놀리스 vs 마이크로서비스","summary":"MSA는 유행이 아니라 비용을 옮기는 결정 이다. 모놀리스의 코드 복잡도를 분산 시스템의 운영 복잡도로 바꾼다. 그 거래가 이득인 경우는 생각보다 드물다 — 기본값은 모듈러 모놀리스 다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch6","code":"ARCH-06","title":"서비스 경계와 통신","summary":"서비스를 어디서 쪼갤지는 기술이 아니라 비즈니스 능력(business capability) 으로 정한다. \"주문\" \"결제\" \"배송\"처럼 독립적으로 변하는 단위가 경계의 후보다 — 바운디드 컨텍스트(→ ARCH-04)가 그대로 서비스 경계로 이어지는 경우가 많다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch7","code":"ARCH-07","title":"CQRS와 이벤트 소싱","summary":"두 패턴은 자주 함께 언급되지만 별개다. CQRS 는 읽기 모델과 쓰기 모델을 분리하는 것, 이벤트 소싱 은 상태 대신 상태 변화(이벤트)를 저장하는 것. 둘 다 강력하지만, 둘 다 대부분의 경우 과하다 ."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch8","code":"ARCH-08","title":"회복탄력성 패턴","summary":"분산 시스템에서 실패는 예외가 아니라 상수 다. 네트워크는 끊기고, 의존 서비스는 느려지고, 인스턴스는 죽는다. 회복탄력성 패턴의 목표는 실패를 없애는 게 아니라, 한 곳의 실패가 전체로 번지지 않게 가두는 것이다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch9","code":"ARCH-09","title":"패턴 선택 기준","summary":"이 핸드북의 모든 패턴은 비용을 동반한 도구 다. 중요한 것은 패턴을 아는 것이 아니라, 지금 이 패턴이 필요한지 를 판단하고 그 판단을 설명할 수 있는 것이다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch10","code":"ARCH-10","title":"용어집","summary":"반복해서 등장하는 핵심 용어를 한자리에. 정의보다 \"왜 중요한가\" 에 무게를 둔다."},{"docId":"engineering-backend-architecture","docLabel":"11 백엔드 아키텍처","groupLabel":"개발 핸드북","sectionId":"architecture-ch11","code":"ARCH-11","title":"경계 설계와 점진적 전환","summary":"아키텍처의 핵심은 유행하는 구조를 고르는 것이 아니라 변경의 경계를 찾고, 기존 시스템을 끊지 않으면서 개선하는 것입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"doc-db","code":"SOURCE","title":"DB","summary":"백엔드 성능·정합성 문제의 대부분이 여기서 납니다 — ORM 뒤에 숨지 말고 직접 봐야 하는 층 입니다. JPA가 만들어주는 SQL이 무엇이고, 그게 어떤 트랜잭션·격리수준·인덱스 위에서 도는지 모르면, 느린 쿼리도 깨진 정합성도 손을 못 댑니다. 개념의 \"왜\"를 먼저 잡고, 트레이드오프와 흔한 실패 모드로 전개합니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch1","code":"DB-01","title":"관계형 모델과 정규화","summary":"관계형 DB는 1970년 Edgar Codd의 논문에서 나온 수학적 모델 입니다. 핵심 발상 하나 — 데이터를 관계(relation, 곧 테이블) 로 표현하고, 행 사이의 연결을 포인터가 아니라 값(key) 으로 맺는다. 이 \"값으로 잇는다\"가 무결성과 유연한 조회의 출발점입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch2","code":"DB-02","title":"트랜잭션과 ACID","summary":"트랜잭션은 \"전부 되거나, 전부 안 되거나\" 를 보장하는 작업 묶음입니다. 계좌 이체에서 출금은 됐는데 입금이 실패하면 돈이 증발합니다 — 트랜잭션은 이런 부분 실패를 원천 차단하기 위해 존재합니다. ACID는 그 보장의 네 가지 측면입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch3","code":"DB-03","title":"격리수준과 동시성 이상","summary":"완벽한 격리(모두가 한 줄로 줄 서서 차례로 실행)는 안전하지만 느립니다. 그래서 SQL 표준은 \"어디까지 동시성 이상을 허용하고 그 대가로 얼마나 빠를 것인가\" 를 고르는 격리수준 을 둡니다. 격리는 안전성과 성능 사이의 다이얼입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch4","code":"DB-04","title":"락과 데드락","summary":"MVCC가 읽기를 자유롭게 해줘도, 같은 행을 동시에 쓰는 충돌은 결국 누군가 기다려야 합니다. 락은 그 충돌을 직렬화하는 도구이고, 데드락은 그 도구를 잘못 써서 서로를 무한정 기다리는 상태입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch5","code":"DB-05","title":"인덱스 심화","summary":"인덱스가 없으면 DB는 원하는 행을 찾으려 테이블을 처음부터 끝까지 훑습니다( full table scan , O(n)). 인덱스는 특정 컬럼으로 정렬해둔 별도의 사본 이라, 이진 탐색처럼 O(log n)에 위치를 찾습니다. 책 뒤의 색인과 같은 원리입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch6","code":"DB-06","title":"실행계획과 쿼리 최적화","summary":"SQL은 \"무엇을 원하는지\" 만 적고 \"어떻게 가져올지\" 는 DB의 옵티마이저가 정합니다. 그 결정을 들여다보는 창이 EXPLAIN 입니다. 느린 쿼리를 추측으로 고치지 말고, 실행계획을 읽어 병목을 짚으세요."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch7","code":"DB-07","title":"커넥션 풀","summary":"DB 커넥션 하나를 새로 맺는 건 비쌉니다 — TCP 핸드셰이크, 인증, 세션 설정이 매번 일어납니다(→ 백엔드 개요의 네트워킹). 요청마다 새로 맺으면 그 비용이 쌓입니다. 커넥션 풀 은 미리 만들어둔 커넥션을 빌려주고 돌려받아 이 비용을 없앱니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch8","code":"DB-08","title":"스키마 설계와 마이그레이션","summary":"스키마는 코드보다 바꾸기 어렵습니다 — 이미 쌓인 데이터가 있고, 운영 중인 서비스가 그 위에서 돕니다. 그래서 설계 단계의 트레이드오프와, 변경을 안전하게 굴리는 절차가 둘 다 중요합니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch9","code":"DB-09","title":"확장 — 복제·파티셔닝·샤딩","summary":"한 대의 DB로 부하를 못 감당할 때 세 가지 길이 있습니다 — 복사본을 더 두거나(복제), 한 테이블을 쪼개 한 서버 안에서 나누거나(파티셔닝), 데이터를 여러 서버로 분산하거나(샤딩). 뒤로 갈수록 강력하지만 복잡하고, 잃는 것도 많습니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch10","code":"DB-10","title":"NoSQL은 언제","summary":"NoSQL은 \"RDBMS의 상위 호환\"이 아니라 다른 트레이드오프 입니다. 관계형이 정합성과 유연한 조회를 위해 포기한 것들(수평 확장성, 스키마 유연성)을 가져오는 대신, 관계형이 공짜로 주던 것(조인, 강한 일관성, 트랜잭션)을 일부 내려놓습니다. \"유행이라서\"가 아니라 워크로드가 맞을 때 씁니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch11","code":"DB-11","title":"용어집","summary":"핸드북 전체에서 반복되는 핵심 용어. 정의를 한 줄로 잡아두면 본문이 빠르게 읽힙니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch12","code":"DB-12","title":"실무 DB 운영 심화","summary":"데이터베이스 문제는 대부분 “쿼리가 느리다”로 보이지만 실제 원인은 MVCC, 락, 인덱스 선택, 마이그레이션 방식에 숨어 있습니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch13","code":"DB-13","title":"락과 MVCC를 실제로 읽기","summary":"MVCC와 락은 정의를 외우면 쉬워 보이지만, 운영에서는 “왜 이 UPDATE가 멈췄는가”, “왜 방금 쓴 값이 안 보이는가”, “왜 vacuum이 밀리는가”를 설명해야 합니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch14","code":"DB-14","title":"실행계획 해석 훈련","summary":"실행계획은 DB가 쿼리를 어떻게 풀기로 결정했는지 보여주는 지도입니다. 인덱스를 탔는지만 보는 것이 아니라 예상 행 수, 실제 행 수, join 방식, sort, buffer 사용을 같이 봐야 합니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch15","code":"DB-15","title":"무중단 스키마 변경","summary":"스키마 변경은 SQL 한 줄이 아니라 배포 프로토콜입니다. 운영 중인 앱 버전이 여러 개 섞여 있을 수 있고, 큰 테이블의 DDL은 lock과 rewrite를 만들 수 있습니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"db-ch16","code":"DB-16","title":"Performance & DB Lab","summary":"성능 튜닝은 “인덱스를 추가했다”가 아니라 가설 → 측정 → 변경 → 재측정 → 부작용 확인 으로 닫혀야 합니다. 이 섹션은 실무에서 그대로 복사해 쓸 수 있는 랩 노트입니다. 쿼리 하나의 실행계획부터 부하 테스트, 커넥션 풀, 락 대기, 마이그레이션까지 같은 형식으로 증거를 남기는 훈련을 목표로 합니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"doc-postgresql","code":"SOURCE","title":"PostgreSQL 예시","summary":"psql 기본부터 upsert·JSONB·윈도우 함수·실행계획까지 — 바로 쓰는 PostgreSQL 레시피. 개념(격리수준·인덱스 원리)은 DB 핸드북에."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch1","code":"PG-01","title":"psql 기본·접속","summary":"psql 은 PostgreSQL의 공식 CLI입니다. SQL을 치기 전에 접속하고, 무엇이 있는지 둘러보는 메타명령( \\ 로 시작)부터 손에 익히세요. GUI 없이도 디버깅의 90%가 여기서 끝납니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch2","code":"PG-02","title":"자주 쓰는 SQL","summary":"SQL 기본 문법은 표준이라 익숙할 겁니다. 여기선 PostgreSQL에서 실전에 매일 치는 형태 를 모았습니다 — 필터링, JOIN, 그룹 집계까지."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch3","code":"PG-03","title":"INSERT·UPDATE·upsert","summary":"데이터를 넣고 고치는 건 기본이지만, PostgreSQL의 진짜 무기는 ON CONFLICT 입니다 — \"있으면 업데이트, 없으면 삽입\"을 한 문장으로, 경쟁 조건 없이. 멱등한 동기화 작업의 핵심입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch4","code":"PG-04","title":"인덱스와 EXPLAIN ANALYZE","summary":"\"쿼리가 느려요\"의 답은 거의 항상 인덱스 와 실행계획 에 있습니다. 인덱스를 만들고, EXPLAIN ANALYZE 로 PostgreSQL이 실제로 어떻게 도는지 들여다보세요. 원리는 DB 핸드북(B-tree)에."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch5","code":"PG-05","title":"트랜잭션·격리","summary":"여러 변경을 전부 성공 또는 전부 취소 로 묶는 게 트랜잭션입니다. 동시에 같은 행을 건드릴 때의 충돌은 격리수준과 행 잠금으로 다룹니다. 격리수준의 개념·이상현상은 DB 핸드북에."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch6","code":"PG-06","title":"JSONB — 반정형 데이터","summary":"스키마가 유동적인 데이터(설정값, 외부 API 응답, 메타데이터)는 jsonb 컬럼에 담습니다. json 이 아니라 jsonb 를 쓰세요 — 이진 저장이라 빠르고 인덱싱이 됩니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch7","code":"PG-07","title":"윈도우 함수 — 순위·누적","summary":"\"유저별 최신 주문\", \"카테고리 내 매출 순위\", \"누적 합계\" — GROUP BY 는 행을 뭉치지만, 윈도우 함수는 행을 유지한 채 그 행 주변을 계산합니다. 한 번 익히면 복잡한 서브쿼리가 사라집니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch8","code":"PG-08","title":"페이지네이션 — OFFSET vs keyset","summary":"OFFSET 페이징은 쓰기 쉽지만 뒤로 갈수록 느려집니다 — DB가 건너뛸 행을 매번 다 세기 때문입니다. 무한 스크롤·대용량엔 keyset(cursor) 페이징이 정답입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch9","code":"PG-09","title":"유용한 기능","summary":"매일 쓰진 않지만 알면 코드가 짧아지는 PostgreSQL 기능들. RETURNING , COALESCE , generate_series , 날짜 함수."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"postgresql-ch10","code":"PG-10","title":"치트시트 — 바로 쓰는 한 줄","summary":"반복되는 PostgreSQL 패턴 모음. 외우기보다 \"이런 게 된다\"를 알아두고 필요할 때 찾으세요."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"doc-redis","code":"SOURCE","title":"Redis 예시","summary":"캐시·세션·분산 락·rate limit — Spring Boot에서 Redis를 쓰는 실전 레시피. 개념(캐싱 무효화 전략 등)은 백엔드 개요를 참조하고, 여기서는 바로 복붙해 동작하는 코드 에 집중합니다. Java/Spring 코드와 redis-cli 를 나란히 두어, 애플리케이션이 실제로 무슨 명령을 보내는지 눈으로 잇습니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"redis-ch1","code":"REDIS-01","title":"Redis란·자료구조 개요","summary":"Redis는 메모리에 사는 key-value 저장소 입니다. RDBMS가 디스크에 정규화된 행을 두는 것과 달리, Redis는 RAM 위에서 단순한 자료구조를 마이크로초 단위로 읽고 씁니다. \"빠르게 읽혀야 하고, 잠깐 살아 있어도 되는\" 데이터가 Redis 자리입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"redis-ch2","code":"REDIS-02","title":"연결 설정","summary":"Spring Boot에서 Redis 연결은 의존성 하나와 설정 몇 줄이면 끝납니다. spring-boot-starter-data-redis 가 커넥션 풀(기본 Lettuce 클라이언트)과 RedisTemplate 자동 설정을 가져옵니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"redis-ch3","code":"REDIS-03","title":"캐시 — Spring Cache 추상화","summary":"\"이 메서드 결과를 캐싱하고 싶다\"가 목적이라면, RedisTemplate 을 직접 만지기 전에 Spring Cache 추상화 부터 보세요. 어노테이션 몇 개로 메서드 결과를 Redis에 자동 캐싱하고, 비즈니스 코드는 캐시를 거의 의식하지 않습니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"redis-ch4","code":"REDIS-04","title":"cache-aside 직접 구현","summary":"어노테이션이 표현하기 어려운 캐시 로직(조건부 적재, 커스텀 키, 부분 갱신)이 필요하면 RedisTemplate 으로 직접 짭니다. 가장 흔한 패턴이 cache-aside(lazy loading) — 캐시를 먼저 보고, 없으면 DB에서 읽어 캐시에 채운 뒤 반환."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"redis-ch5","code":"REDIS-05","title":"세션 저장소","summary":"서버를 여러 대로 늘리는 순간 세션 문제가 터집니다. 로그인 세션이 서버 A의 메모리에만 있으면, 다음 요청이 서버 B로 가는 순간 \"로그인 안 됨\" 상태가 됩니다. 세션을 서버 바깥의 공유 저장소(Redis)에 두면 어느 서버로 가든 같은 세션을 봅니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"redis-ch6","code":"REDIS-06","title":"분산 락","summary":"여러 인스턴스가 동시에 같은 작업(예: 같은 주문의 중복 정산)을 하면 안 될 때, 서버 메모리의 synchronized 는 무력합니다 — 다른 JVM은 그 락을 모릅니다. Redis로 여러 프로세스가 공유하는 락 을 만들 수 있습니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"redis-ch7","code":"REDIS-07","title":"rate limiting","summary":"\"IP당 분당 100회\"처럼 호출 횟수를 제한할 때, Redis의 INCR 이 깔끔합니다. INCR 은 키 값을 원자적으로 1 증가시키므로(동시 요청에도 카운트가 안 꼬임), 카운터 + 만료만으로 고정 윈도우 제한기가 됩니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"redis-ch8","code":"REDIS-08","title":"TTL·만료·메모리","summary":"Redis를 캐시로 쓴다는 건 \"이 데이터는 언젠가 사라진다\"를 전제로 코드를 짠다 는 뜻입니다. TTL은 메모리를 지키는 안전장치이자, stale 데이터를 자동 청소하는 수단입니다."},{"docId":"engineering-data","docLabel":"12 데이터 계층·저장소","groupLabel":"개발 핸드북","sectionId":"redis-ch9","code":"REDIS-09","title":"치트시트","summary":"실전에서 반복되는 패턴과 명령 모음. 외우기보다 \"이럴 땐 이걸 쓴다\"의 대응표로 두고 필요할 때 찾으세요."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"doc-async","code":"SOURCE","title":"비동기·메시지 큐","summary":"동기 호출은 두 서비스를 시간으로 묶는다 — 큐는 그 결합을 끊어 시간과 장애를 분리한다. 이 핸드북은 명령어가 아니라 사고 모델 을 다룹니다: 왜 비동기로 가는가, 무엇을 포기하는 대가인가, 그리고 어디서 깨지는가."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch1","code":"MSG-01","title":"동기 vs 비동기","summary":"핵심 질문은 \"빠르냐 느리냐\"가 아니라 \"호출자가 결과를 기다리느냐\" 입니다. 동기 호출은 두 서비스를 같은 시간선에 묶습니다 — 한쪽이 느리거나 죽으면 다른 쪽도 그만큼 멈춥니다. 비동기는 그 시간 결합(temporal coupling)을 끊는 도구입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch2","code":"MSG-02","title":"비동기 실행 모델","summary":"메시지 큐로 가기 전에, 한 프로세스 안의 비동기부터 짚습니다. \"비동기\"는 한 단어지만 구현 모델이 다릅니다 — 스레드를 늘리는 방식 (Java 전통)과 스레드를 안 막는 방식 (이벤트 루프)은 출발점이 정반대입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch3","code":"MSG-03","title":"메시지 큐 vs 이벤트 스트림","summary":"\"카프카랑 래빗엠큐 뭐 써요?\"의 진짜 질문은 \"메시지가 소비되면 사라지길 원하나, 로그로 남아 여러 번 읽히길 원하나\" 입니다. 둘은 비슷해 보이지만 데이터 수명 모델이 근본적으로 다릅니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch4","code":"MSG-04","title":"전달 보장 — delivery semantics","summary":"분산 메시징의 가장 중요한 진실: 네트워크는 신뢰할 수 없고, ack는 유실될 수 있습니다. 그래서 \"정확히 한 번\"은 대부분 환상이고, 현실의 표준은 at-least-once + 멱등 소비자 입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch5","code":"MSG-05","title":"멱등 소비와 중복 처리","summary":"멱등성(idempotency)은 \"같은 메시지를 몇 번 처리해도 결과가 한 번 처리한 것과 같다\" 입니다. at-least-once 세계에서 중복은 버그가 아니라 일상이라, 소비자는 중복을 견디도록 설계되어야 합니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch6","code":"MSG-06","title":"순서와 파티셔닝","summary":"\"메시지가 보낸 순서대로 처리되나?\" — 분산 큐에서 전역 순서(total order) 는 비싸고, 대부분의 시스템은 \"관련된 것끼리만\" 순서 를 보장하는 타협을 택합니다. Kafka의 파티션이 그 도구입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch7","code":"MSG-07","title":"이중 쓰기 문제와 Outbox 패턴","summary":"비동기 설계의 핵심 함정 하나: \"DB에 저장하고, 그다음 메시지를 발행한다\" 는 두 줄의 코드는 원자적이지 않습니다. 둘 사이에서 프로세스가 죽으면 DB는 바뀌었는데 메시지는 안 나갔거나, 그 반대가 됩니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch8","code":"MSG-08","title":"실패 처리 — 재시도·백오프·DLQ","summary":"소비자는 실패합니다 — 일시적 실패(DB 잠깐 끊김)와 영구적 실패(메시지 자체가 깨짐)는 대응이 달라야 합니다. 무한 재시도는 시스템을 마비시키고, 재시도 없는 포기는 데이터를 잃습니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch9","code":"MSG-09","title":"백프레셔와 흐름 제어","summary":"생산자가 소비자보다 빠르면 어딘가 메시지가 쌓입니다. 백프레셔(backpressure) 는 \"느리니까 천천히 보내\"라는 역방향 신호 입니다 — 이게 없으면 큐 적체나 메모리 폭발로 시스템이 무너집니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch10","code":"MSG-10","title":"사가 패턴 — 분산 트랜잭션의 대체","summary":"여러 서비스에 걸친 작업을 하나의 ACID 트랜잭션으로 묶을 수는 없습니다(서비스마다 DB가 다름). 사가(Saga) 는 이를 \"로컬 트랜잭션의 연쇄 + 실패 시 보상\" 으로 풀어, 최종 일관성(eventual consistency)을 달성합니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch11","code":"MSG-11","title":"용어집","summary":"한 번 더 압축한 정의. 면접·설계 리뷰에서 이 단어들을 정확히 구분해 쓰면 설계 논의가 훨씬 명확해집니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"async-ch12","code":"MSG-12","title":"운영 가능한 메시징 설계","summary":"메시징은 큐를 붙이는 순간 끝나는 것이 아니라 중복, 지연, 독성 메시지, 재처리, 관측성을 설계해야 운영 가능합니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"doc-testing","code":"SOURCE","title":"테스트","summary":"테스트의 목적은 커버리지 숫자가 아니라 변경을 두렵지 않게 만드는 것 — 리팩토링·배포의 자신감이 여기서 나온다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch1","code":"TEST-01","title":"테스트의 목적","summary":"테스트를 쓰는 이유를 잘못 잡으면 방향이 통째로 틀어집니다. 테스트는 \"맞다는 증명\"이 아니라 변경 앞에서의 안전망 입니다 — 코드를 고칠 때 무엇이 깨졌는지 즉시 알려주는 장치죠."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch2","code":"TEST-02","title":"테스트 피라미드","summary":"모든 테스트가 같은 비용·속도·신뢰도를 갖지 않습니다. 피라미드는 어떤 종류를 얼마나 쓸지 의 비율 가이드입니다 — 빠르고 싼 단위 테스트를 많이, 느리고 비싼 E2E를 적게."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch3","code":"TEST-03","title":"단위 테스트","summary":"단위 테스트의 본령은 순수 로직 입니다 — 입력을 받아 출력을 내는, 외부 의존(DB·네트워크·시간·랜덤)이 없는 코드. 이 영역을 두껍게 덮으면 피라미드의 바닥이 단단해집니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch4","code":"TEST-04","title":"테스트 더블","summary":"\"테스트 더블(test double)\"은 진짜 협력 객체 대신 끼워 넣는 대역의 총칭입니다 — 영화의 스턴트 더블에서 온 말이죠. 다섯 종류를 뭉뚱그려 \"mock\"이라 부르는 경우가 많은데, 구분이 의도를 분명하게 합니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch5","code":"TEST-05","title":"통합 테스트","summary":"단위 테스트는 \"내 로직이 맞다\"를 보장하지만 경계 는 못 봅니다 — SQL이 진짜 도는지, JPA 매핑이 맞는지, 트랜잭션이 의도대로 커밋·롤백되는지는 진짜 DB 앞에서만 드러납니다. 통합 테스트는 이 경계를 검증합니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch6","code":"TEST-06","title":"TDD","summary":"TDD(Test-Driven Development)는 \"테스트를 많이 쓰자\"가 아니라 테스트를 먼저 쓰는 개발 리듬 입니다. 핵심은 검증이 아니라 설계 압력 — 쓰기 전에 \"이걸 어떻게 호출할까\"를 강제로 먼저 정하게 만듭니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch7","code":"TEST-07","title":"행동 vs 구현 테스트","summary":"테스트가 깨지는 데는 두 종류가 있습니다 — 동작이 진짜 망가져서 깨지는 좋은 실패, 그리고 동작은 멀쩡한데 내부 구조를 바꿨다고 깨지는 나쁜 실패. 후자를 만드는 게 구현 테스트입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch8","code":"TEST-08","title":"커버리지의 함정","summary":"커버리지는 \"테스트가 실행한 코드 줄의 비율\"입니다 — 실행했다 는 사실만 말할 뿐, 검증했다 는 보장이 아닙니다. 이 차이를 놓치면 숫자는 높은데 안전망은 없는 상태가 됩니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch9","code":"TEST-09","title":"flaky test","summary":"flaky test는 코드 변경 없이 어떤 때는 통과하고 어떤 때는 실패하는 테스트입니다. 가장 해로운 종류인데, 신뢰를 갉아먹기 때문입니다 — 빨간불을 보고도 \"또 그거겠지\" 하며 재실행을 누르는 순간, 테스트 전체가 무의미해집니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch10","code":"TEST-10","title":"Spring 테스트","summary":"Spring Boot에서 가장 비싼 비용은 애플리케이션 컨텍스트 기동 입니다. 테스트가 느려지는 주범이 보통 여기죠. 그래서 \"전체 컨텍스트를 띄울지, 필요한 슬라이스만 띄울지\"의 선택이 테스트 속도를 좌우합니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch11","code":"TEST-11","title":"용어집","summary":"핸드북 전체에서 쓴 핵심 용어를 한자리에. 정의는 \"무엇이며 왜 중요한가\" 중심으로."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"testing-ch12","code":"TEST-12","title":"실무 테스트 전략 심화","summary":"백엔드 테스트는 단위 테스트 개수보다 변경 위험을 어느 경계에서 막는지가 중요합니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"doc-observability","code":"SOURCE","title":"로깅·모니터링·장애대응","summary":"운영을 책임진다는 것은 \"안 돼요\"를 \"여기가 이래서 안 됩니다\"로 바꾸는 능력 입니다. 코드를 짜는 것과, 그 코드가 새벽 3시에 죽었을 때 무슨 일이 일어났는지 5분 안에 말하는 것은 다른 기술입니다. 이 핸드북은 후자를 다룹니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch1","code":"OBS-01","title":"관측가능성이란","summary":"관측가능성(observability)은 \"대시보드를 많이 띄우는 것\"이 아닙니다. 시스템 외부로 나오는 신호만 보고 내부에서 무슨 일이 벌어지는지 추론할 수 있는 정도 를 말합니다. 핵심은 \"사후에, 미리 예상 못 한 질문에 답할 수 있는가\"입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch2","code":"OBS-02","title":"로깅","summary":"로그는 가장 익숙하면서 가장 자주 잘못 쓰이는 도구입니다. System.out.println(\"여기까지 옴\") 은 로그가 아닙니다. 좋은 로그는 사람이 읽기 전에 기계가 먼저 검색·집계할 수 있는 구조 를 가집니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch3","code":"OBS-03","title":"상관관계 ID·분산 추적","summary":"단일 서버라면 로그를 시간순으로 읽으면 됩니다. 하지만 요청 하나가 게이트웨이 → 인증 → 결제 → 알림 서비스를 거치면, 각 서비스의 로그가 따로 흩어집니다. 이 흩어진 조각을 다시 꿰는 실 하나가 상관관계 ID(correlation/trace id) 입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch4","code":"OBS-04","title":"메트릭","summary":"메트릭은 시간에 따라 변하는 숫자입니다 — 싸고, 집계가 빠르고, 추세를 봅니다. 문제는 \"무슨 숫자를 재느냐\"입니다. 무작정 다 재면 노이즈가 되고 비용만 듭니다. 검증된 두 프레임워크가 길을 줄여줍니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch5","code":"OBS-05","title":"백분위 지연","summary":"\"평균 응답시간 120ms\"는 안심되는 숫자처럼 보이지만, 종종 거짓말입니다. 평균은 소수의 느린 요청을 다수의 빠른 요청에 희석시켜 숨깁니다. 사용자 경험을 결정하는 건 평균이 아니라 꼬리(tail) 입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch6","code":"OBS-06","title":"대시보드·시각화","summary":"대시보드의 목적은 \"예뻐 보이는 것\"이 아니라 장애 중에 5초 안에 무엇이 비정상인지 가리키는 것 입니다. 그래프가 30개면 아무것도 안 보이는 것과 같습니다. 좋은 대시보드는 적게, 의도적으로 고릅니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch7","code":"OBS-07","title":"헬스체크","summary":"오케스트레이터(Kubernetes 등)나 로드밸런서는 앱에게 \"너 괜찮아?\"를 주기적으로 묻습니다. 이 질문이 사실 두 개의 다른 질문 이라는 걸 모르면, 헬스체크가 오히려 장애를 만듭니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch8","code":"OBS-08","title":"SLI·SLO·에러버짓","summary":"\"우리 서비스는 안정적이어야 한다\"는 측정할 수 없습니다. \"99.9%의 요청이 300ms 안에 성공한다\"는 측정할 수 있습니다. SLI/SLO는 신뢰성을 구호에서 숫자로 바꾸고, 에러버짓은 그 숫자를 의사결정 도구 로 만듭니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch9","code":"OBS-09","title":"알림","summary":"알림(alert)의 유일한 목적은 사람의 행동을 유발하는 것 입니다. 행동할 게 없는 알림은 알림이 아니라 노이즈이고, 노이즈는 진짜 신호를 죽입니다. 좋은 알림 설계는 \"더 거는 것\"이 아니라 \"덜 거는 것\"에서 나옵니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch10","code":"OBS-10","title":"장애 대응","summary":"장애가 터지면 본능은 \"왜 이렇게 됐지?\"를 파고드는 것입니다. 그건 나중 일입니다. 인시던트 대응의 첫 계명은 원인 분석보다 복구가 먼저 입니다 — 피를 멈추는 게 먼저, 부검은 나중에."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch11","code":"OBS-11","title":"포스트모템","summary":"장애가 끝났다고 일이 끝난 게 아닙니다. 같은 장애가 다시 안 나게 하는 게 진짜 마무리입니다. 포스트모템(postmortem)은 처벌 문서가 아니라 학습 문서입니다 — 그래서 비난 없이(blameless) 가 전제입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch12","code":"OBS-12","title":"용어집","summary":"앞 장들의 핵심 용어를 한자리에. 면접·온콜·포스트모템에서 정확한 단어로 말하는 것이 운영 커뮤니케이션의 기본기입니다."},{"docId":"engineering-runtime-quality","docLabel":"13 런타임 품질·장애대응","groupLabel":"개발 핸드북","sectionId":"observability-ch13","code":"OBS-13","title":"관측성 운영 심화","summary":"좋은 관측성은 로그를 많이 남기는 것이 아니라 장애 판단에 필요한 신호를 빠르게 찾게 만드는 것입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"플랫폼 도구는 명령어 모음이 아니라 변경을 안전하게 만들고, 장애가 났을 때 증거를 찾고, 되돌릴 수 있게 하는 운영 루프입니다. 로컬 재현 → 빌드 → 이미지 → 설정 주입 → 배포 → 헬스체크 → 로그·메트릭 → 롤백 순서로 읽습니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"platform-operating-model","code":"MODEL","title":"플랫폼 운영 모델","summary":"Docker, Linux, nginx, CI/CD는 서로 다른 도구처럼 보이지만 실무에서는 하나의 변경 경로를 이룹니다. 좋은 플랫폼 작업은 \"명령을 실행했다\"가 아니라 어떤 artifact가 어느 환경에 올라갔고, 어떤 지표로 정상임을 확인했으며, 실패하면 어떻게 되돌릴지까지 설명합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"doc-deploy","code":"SOURCE","title":"Docker와 배포","summary":"컨테이너는 \"제 PC에선 됩니다\" 를 끝냅니다 — 코드·런타임·의존성을 한 이미지로 봉인해 어디서나 같게 돕니다. 이 핸드북은 명령어 나열이 아니라 왜 이렇게 도는가 를 먼저 잡습니다 — 레이어 캐시가 왜 그 순서를 강요하는지, 배포 전략 사이의 트레이드오프가 무엇인지, 어디서 깨지는지."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch1","code":"OPS-01","title":"컨테이너란","summary":"컨테이너의 핵심은 가상화가 아니라 격리 입니다 — 하나의 OS 커널을 공유하면서, 프로세스가 자기만의 파일시스템·네트워크·프로세스 공간을 가진 것처럼 속이는 기술입니다. VM과 헷갈리면 무게도 한계도 잘못 잡게 됩니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch2","code":"OPS-02","title":"이미지와 레이어","summary":"세 단어를 정확히 구분하세요 — 이미지 는 불변 스냅샷(설계도), 레이어 는 그 이미지를 쌓아 올린 캐시 단위, 컨테이너 는 이미지를 실행한 인스턴스입니다. 클래스와 인스턴스의 관계를 떠올리면 정확합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch3","code":"OPS-03","title":"Dockerfile 기초·베스트 프랙티스","summary":"Dockerfile은 이미지를 만드는 레시피입니다. 명령 몇 개만 알면 동작은 하지만, 순서와 선택 이 빌드 속도·이미지 크기·보안을 가릅니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch4","code":"OPS-04","title":"멀티스테이지 빌드와 이미지 최적화","summary":"빌드에 필요한 것과 실행에 필요한 것은 다릅니다. 컴파일러·devDependencies·빌드 캐시는 실행 시점엔 쓰레기 입니다. 멀티스테이지 빌드는 이 둘을 분리해 최종 이미지에서 빌드 도구를 통째로 들어냅니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch5","code":"OPS-05","title":"컨테이너 실행과 구성","summary":"이미지를 만들었으면 이제 돌립니다 . 실행 시점의 4대 구성 축 — 포트·볼륨·환경변수·네트워크 — 만 잡으면 로컬에서 운영까지 같은 그림으로 다룹니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch6","code":"OPS-06","title":"레지스트리와 태깅","summary":"레지스트리는 이미지의 원격 저장소 입니다 — git의 GitHub에 해당합니다. 로컬에서 빌드한 이미지를 push 하고, 서버·CI가 pull 해 실행합니다. 그 사이를 잇는 건 태그 이고, 태그 전략이 배포 추적성을 좌우합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch7","code":"OPS-07","title":"12-factor 앱","summary":"12-factor는 \"컨테이너·클라우드에서 잘 도는 앱\"의 설계 원칙 모음입니다. 전부 외울 필요는 없고, 컨테이너 배포에 직결되는 네 가지만 몸에 익히면 대부분의 사고를 피합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch8","code":"OPS-08","title":"CI/CD 파이프라인","summary":"CI(지속적 통합)는 코드가 합쳐질 때마다 자동으로 빌드·테스트하는 것, CD(지속적 배포)는 그 결과물을 자동으로 환경에 올리는 것입니다. 컨테이너가 CI/CD와 잘 맞는 이유는 빌드 산출물이 이미지 하나 로 떨어져 그대로 배포되기 때문입니다 — 빌드와 배포 사이에 변형이 없습니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch9","code":"OPS-09","title":"배포 전략","summary":"\"새 버전으로 어떻게 갈아끼우는가\"의 문제입니다. 핵심 목표는 셋 — 무중단 (사용자가 끊김을 못 느낌), 빠른 롤백 (문제 시 즉시 되돌림), 위험 통제 (나쁜 버전의 폭발 반경 최소화). 전략마다 이 셋의 균형이 다릅니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch10","code":"OPS-10","title":"오케스트레이션 개요","summary":"컨테이너 하나를 돌리는 건 docker run 으로 끝입니다. 그러나 수십~수백 개를 여러 서버에 걸쳐 띄우고·살피고·죽으면 되살리고·확장하고·배포 하는 건 손으로 못 합니다. 이걸 자동화하는 게 오케스트레이션이고, 사실상 표준이 Kubernetes(K8s) 입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch11","code":"OPS-11","title":"용어집","summary":"이 핸드북에서 반복된 핵심 용어. 정의를 한 줄로 못 줄이면 아직 이해 못 한 것입니다 — 막힐 때 여기로."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"deploy-ch12","code":"OPS-12","title":"운영 가능한 배포 심화","summary":"배포는 이미지를 올리는 일이 아니라 트래픽 전환, 종료 처리, 설정 일관성, 롤백 가능성을 관리하는 일입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"doc-linux","code":"SOURCE","title":"리눅스","summary":"명령어 암기가 아니라 사고 모델 을 먼저 잡습니다 — 모든 명령은 텍스트 스트림을 입력받아 텍스트 스트림을 내보내고, 작은 도구들을 파이프로 조립해 큰 일을 합니다. 이 한 가지 철학을 이해하면 나머지는 조합입니다. 네 환경(macOS·zsh·mise·chezmoi)과 모던 CLI(rg·fd·bat) 기준."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch1","code":"LX-01","title":"셸의 사고 모델","summary":"Unix 철학 한 줄: \"한 가지를 잘하는 작은 프로그램을, 텍스트 스트림으로 잇는다.\" 명령어를 외우기 전에 이 구조를 잡으면, 처음 보는 명령도 같은 문법으로 읽힙니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch2","code":"LX-02","title":"탐색·이동","summary":"디렉터리 트리 안에서 \"지금 어디고, 뭐가 있고, 어디로 갈까\". 가장 자주 치는 명령들이라 손에 붙여둘 가치가 큽니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch3","code":"LX-03","title":"파일 보기·편집","summary":"\"내용만 잠깐 볼 것\"과 \"고칠 것\"은 도구가 다릅니다. 큰 로그를 cat 으로 통째로 쏟지 마세요."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch4","code":"LX-04","title":"검색 — 텍스트와 파일","summary":"두 종류의 검색을 구분하세요 — 파일 안의 내용 을 찾는가(grep/rg), 파일 자체 를 찾는가(find/fd). 개발 일상에서 가장 자주 쓰는 무기입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch5","code":"LX-05","title":"파일 조작","summary":"복사·이동·삭제·생성. 단순하지만 rm 은 되돌릴 수 없으니, 파괴적 명령엔 손이 한 번 멈춰야 합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch6","code":"LX-06","title":"권한·소유권","summary":"Unix 권한은 외울 게 아니라 모델 입니다 — 누구(소유자/그룹/기타)가 무엇(읽기/쓰기/실행)을 할 수 있는가. ls -l 의 맨 앞 10글자가 그 지도입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch7","code":"LX-07","title":"프로세스·잡","summary":"\"포트가 이미 쓰이고 있어요\", \"멈춘 프로세스를 죽여야 해요\" — 백엔드 일상의 단골입니다. 프로세스를 보고, 신호를 보내고, 백그라운드로 다루는 법."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch8","code":"LX-08","title":"파이프·텍스트 가공","summary":"셸의 진짜 힘이 여기 있습니다. 작은 도구를 | 로 이어 데이터를 흐르게 하면, 한 줄로 로그 분석·집계가 됩니다. \"조립\"의 영역입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch9","code":"LX-09","title":"네트워크·HTTP","summary":"API를 때려보고, 포트 연결을 확인하고, DNS를 추적하는 일상 도구들. 백엔드라면 curl 은 거의 반사신경이 돼야 합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch10","code":"LX-10","title":"디스크·시스템","summary":"\"디스크가 꽉 찼어요\", \"메모리가 부족해요\"의 진단 도구들. 평소엔 안 쓰다가 사고 날 때 찾게 됩니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch11","code":"LX-11","title":"압축·아카이브","summary":"tar 의 플래그는 한 번 외우면 평생 씁니다 — \"create / extract\" 의 두 패턴만 손에 넣으세요."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch12","code":"LX-12","title":"원격·동기화","summary":"서버에 접속하고, 파일을 옮기고, 디렉터리를 동기화. 배포·운영의 기본 동선입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch13","code":"LX-13","title":"셸 환경·생산성","summary":"같은 명령을 매번 길게 치지 마세요. 환경변수·alias·히스토리·키바인딩이 손의 속도를 바꿉니다. 네 도구 체인(zsh·mise·chezmoi) 기준으로."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"linux-ch14","code":"LX-14","title":"치트시트 — 자주 쓰는 한 줄","summary":"실전에서 반복되는 조합들. 외우기보다 \"이런 게 가능하다\"를 알아두고 필요할 때 찾으세요."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"doc-vi","code":"SOURCE","title":"vi","summary":"vi는 단축키 목록 이 아니라 언어 다 — 모드 위에서 \"연산자 × 모션\"을 조합한다. 이 문법 하나를 잡으면 외울 게 덧셈이 아니라 곱셈으로 줄어든다. d (삭제)와 w (단어)· i\" (따옴표 안)를 알면 dw · di\" 가 공짜로 나온다. macOS 기본 vim 기준."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"vi-ch1","code":"VI-01","title":"사고 모델 — 모드와 문법","summary":"vi를 어렵게 만드는 건 단축키 개수가 아니라 두 가지 개념이다 — (1) 모드 , (2) \"동사(연산자) + 명사(모션/객체)\" 문법 . 이 둘을 잡으면 나머지는 조합이다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"vi-ch2","code":"VI-02","title":"모드와 전환","summary":"vi가 다른 에디터와 다른 단 하나의 이유 — 키가 모드마다 다른 뜻을 갖는다. Normal에서 d 는 \"삭제 명령\"이고, Insert에서 d 는 글자 'd'다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"vi-ch3","code":"VI-03","title":"이동 (모션)","summary":"모션은 그 자체로 \"이동\"이면서, 연산자 뒤에 붙으면 \"어디까지 적용할지\"가 된다 — w 는 \"다음 단어로 이동\"이자 dw 의 \"단어만큼\"이다. 그래서 모션을 익히면 편집까지 같이 빨라진다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"vi-ch4","code":"VI-04","title":"편집 — 연산자","summary":"연산자는 \"무엇을 할지\"(동사)다. 뒤에 모션(VI-03)이나 텍스트 객체(VI-05)를 붙여 범위를 정한다. 연산자를 두 번 치면( dd cc yy ) \"현재 줄 전체\"가 된다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"vi-ch5","code":"VI-05","title":"텍스트 객체 — vi의 진짜 힘","summary":"모션이 \"어디까지\"라면, 텍스트 객체는 \"무엇을\"이다 — 커서가 그 안 어디에 있든 단어·따옴표·괄호 단위를 통째로 잡는다. 위치를 정렬할 필요가 없어서 압도적으로 빠르다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"vi-ch6","code":"VI-06","title":"검색·치환","summary":"검색은 가장 빠른 이동 수단이기도 하다(원하는 단어로 점프). 치환은 ex 명령( : )의 영역으로, 범위 지정이 핵심이다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"vi-ch7","code":"VI-07","title":"비주얼 모드","summary":"\"먼저 선택하고, 그다음 무엇을 할지 정한다\" — 연산자+모션의 순서를 뒤집은 모드. 범위가 눈에 보여서 직관적이고, 한 영역에 여러 작업을 시도할 때 좋다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"vi-ch8","code":"VI-08","title":"파일·창·저장·종료","summary":"\"vi에서 못 빠져나온다\"는 농담의 답이 여기 있다 — 전부 : (command-line)에서 한다. Esc 로 Normal에 온 뒤 : 를 쳐라."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"vi-ch9","code":"VI-09","title":"생산성 + 치트시트","summary":"vi가 \"빠른 에디터\"를 넘어 \"증폭기\"가 되는 지점 — 반복( . )과 매크로다. 한 번 잘 만든 변경을 공짜로 N번 재생한다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"doc-docker","code":"SOURCE","title":"Docker 예시","summary":"이 스택을 한 번에 띄우는 실전 Dockerfile·compose 레시피. 개념은 Docker·배포 핸드북에. 여기서는 바로 복사해 쓰는 설정 만 — 멀티스테이지 빌드, compose 한 파일, 볼륨·네트워크·헬스체크까지 실재 문법으로."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"docker-ch1","code":"DOCKER-01","title":"Spring Boot Dockerfile","summary":"언제·왜: jar 하나를 이미지로 굽는 가장 표준적인 방법. 멀티스테이지 로 빌드 도구(Gradle·JDK)는 빌드 스테이지에만 두고, 런타임 이미지엔 JRE와 jar만 남깁니다. 이미지가 수백 MB 작아지고 공격 표면도 줄어듭니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"docker-ch2","code":"DOCKER-02","title":".dockerignore와 이미지 최적화","summary":"언제·왜: docker build 는 먼저 빌드 컨텍스트(현재 디렉터리 전체)를 데몬으로 전송합니다. .gradle · build · node_modules 가 딸려가면 느리고, 캐시도 무의미하게 깨집니다. 컨텍스트를 줄이고, 잘 안 바뀌는 것부터 COPY 가 캐시의 핵심."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"docker-ch3","code":"DOCKER-03","title":"compose — 이 스택 한 파일","summary":"언제·왜: app(Spring Boot) + postgres + redis + nginx를 한 명령으로 띄우고 내립니다. 아래가 네 서비스를 다 담은 compose.yaml 골격 — 이후 챕터(환경변수·볼륨·네트워크·헬스체크)가 이 파일을 한 조각씩 채웁니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"docker-ch4","code":"DOCKER-04","title":"환경변수·설정 주입","summary":"언제·왜: 같은 이미지를 환경(local·staging·prod)별로 다르게 띄우려면 설정을 코드가 아니라 환경변수 로 주입해야 합니다. Spring Boot는 SPRING_ 접두 환경변수를 properties로 자동 매핑합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"docker-ch5","code":"DOCKER-05","title":"데이터 영속 — 볼륨","summary":"언제·왜: 컨테이너는 지워지면 안의 데이터도 사라집니다. DB 데이터가 컨테이너 수명과 함께 증발하면 안 되니, named volume 에 데이터를 두어 컨테이너를 재생성해도 살아남게 합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"docker-ch6","code":"DOCKER-06","title":"서비스 간 네트워크","summary":"언제·왜: compose는 프로젝트마다 기본 네트워크를 만들고, 모든 서비스를 거기에 붙입니다. 같은 네트워크 안에서는 서비스명이 곧 호스트명 (내부 DNS)이라, localhost 가 아니라 서비스명으로 서로를 찾습니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"docker-ch7","code":"DOCKER-07","title":"헬스체크·기동 순서","summary":"언제·왜: depends_on 만으로는 \"postgres 컨테이너가 시작 됐다\"까지만 보장하지, \"DB가 접속 받을 준비 가 됐다\"는 보장하지 않습니다. app이 DB보다 먼저 붙어 죽는 경쟁을 막으려면 healthcheck + condition: service_healthy 가 필요합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"docker-ch8","code":"DOCKER-08","title":"자주 쓰는 명령","summary":"언제·왜: 일상의 띄우기·내리기·로그·디버깅·정리. compose 명령과 단일 컨테이너 명령을 나눠 손에 붙입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"docker-ch9","code":"DOCKER-09","title":"치트시트","summary":"Dockerfile 키워드·compose 구조·자주 쓰는 명령을 한 곳에. 외우기보다 \"이런 게 있다\"를 알고 필요할 때 찾으세요."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"doc-nginx","code":"SOURCE","title":"nginx 예시","summary":"Spring Boot 앞단의 리버스 프록시부터 TLS·로드밸런싱까지 — 바로 쓰는 nginx 설정 레시피. 프론트엔드 빌드를 서빙하고, API 요청을 백엔드로 넘기고, 인증서를 붙이는 일상 동선을 설정 블록째로 모았습니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"nginx-ch1","code":"NGINX-01","title":"리버스 프록시","summary":"가장 기본 동선부터. 브라우저가 nginx(80/443)에 들어오면, nginx가 그 요청을 뒤에 있는 Spring Boot(8080)로 대신 넘겨주고 응답을 받아 전달합니다. 클라이언트는 백엔드 포트를 직접 알 필요가 없습니다 — 이게 reverse proxy입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"nginx-ch2","code":"NGINX-02","title":"정적 파일·SPA","summary":"프론트 빌드 산출물(React/Next export, Vite dist/ )을 서빙하는 패턴. nginx가 정적 파일을 직접 내보내는 건 백엔드를 거치는 것보다 압도적으로 빠릅니다 — 디스크에서 바로 읽어 보냅니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"nginx-ch3","code":"NGINX-03","title":"TLS / HTTPS","summary":"인증서를 붙여 443에서 https를 받고, 80으로 들어온 평문 요청은 https로 영구 리다이렉트(301)합니다. TLS 종료(termination)를 nginx가 맡으면, 뒤의 Spring Boot는 평문 http만 다루면 돼서 단순해집니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"nginx-ch4","code":"NGINX-04","title":"로드 밸런싱","summary":"백엔드 인스턴스가 여럿일 때, nginx가 요청을 나눠 보냅니다. upstream 블록에 서버들을 묶어 이름을 주고, proxy_pass 가 그 이름을 가리키게 합니다. 기본 분배 방식은 round-robin(순서대로 돌려가며)입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"nginx-ch5","code":"NGINX-05","title":"gzip·캐싱","summary":"전송량을 줄이고, 안 바뀌는 자원은 브라우저가 다시 안 받게 합니다. 프론트 번들·CSS·JSON 응답을 gzip으로 압축하면 전송 크기가 크게 줄고, 해시가 박힌 정적 자원엔 긴 expires 를 걸어 캐시합니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"nginx-ch6","code":"NGINX-06","title":"보안 헤더·rate limit","summary":"기본 보안 헤더 몇 개를 nginx 레벨에서 일괄로 붙이고, 무차별 요청(brute-force·스크래핑)을 속도 제한으로 막습니다. 애플리케이션 코드를 건드리지 않고 엣지에서 처리하는 게 장점입니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"nginx-ch7","code":"NGINX-07","title":"운영 — 검증·리로드","summary":"설정을 바꿨으면 적용 전에 문법을 검사 하고, 무중단으로 반영합니다. nginx는 설정 오류가 있으면 리로드를 거부하므로, nginx -t 를 먼저 거는 습관이 서비스 다운을 막습니다."},{"docId":"engineering-platform-tools","docLabel":"14 플랫폼 도구·운영 기본기","groupLabel":"개발 핸드북","sectionId":"nginx-ch8","code":"NGINX-08","title":"치트시트 — 디렉티브 한눈에","summary":"앞에서 다룬 핵심 디렉티브를 한 곳에. 외우기보다 \"이걸 쓰면 된다\"를 떠올리고 본문 섹션에서 전체 블록을 찾으세요."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"doc-java","code":"SOURCE","title":"Java 예시","summary":"개념이 아니라 바로 쓰는 코드 — JS/TS 하던 손에 Java 문법을 붙이는 레시피. 각 섹션은 \"언제·왜\" 한두 줄과 복붙해서 고쳐 쓸 코드 카드로 구성됩니다. Java 17+ 기준."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch1","code":"JAVA-01","title":"변수·타입·var","summary":"Java는 정적 타입 언어 — 변수마다 타입이 박힙니다. 핵심 구분 하나: 기본형(primitive) 은 값 자체를, 참조형(reference) 은 객체 주소를 담습니다. JS의 let / const 와 대비하면 감이 빨리 잡힙니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch2","code":"JAVA-02","title":"컬렉션","summary":"JS의 배열·Map·Set이 Java에선 List · Map · Set 인터페이스로 나뉩니다. 인터페이스( List )로 선언하고 구현체( ArrayList )로 생성하는 게 관례입니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch3","code":"JAVA-03","title":"스트림 API","summary":"JS의 .filter().map().reduce() 체이닝이 Java에선 Stream입니다. 차이 하나: 컬렉션에 .stream() 으로 진입하고, .collect() 로 빠져나와야 결과가 나옵니다(lazy)."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch4","code":"JAVA-04","title":"Optional","summary":"\"값이 있을 수도, 없을 수도\" 를 타입으로 표현 — JS의 ?. / ?? 가 메서드로 들어온 형태입니다. null 체크를 강제해 NPE를 줄입니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch5","code":"JAVA-05","title":"record와 불변 객체","summary":"데이터만 담는 클래스(DTO, value object)는 record 한 줄이면 끝 — 생성자·getter· equals · hashCode · toString 이 자동 생성됩니다. TS의 readonly 객체 타입에 가깝습니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch6","code":"JAVA-06","title":"예외 처리","summary":"Java 예외는 두 갈래 — checked (컴파일러가 처리를 강제)와 unchecked (런타임, 강제 안 함). JS에는 이 구분이 없어서 처음엔 낯섭니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch7","code":"JAVA-07","title":"제네릭","summary":"TS의 <T> 와 같은 개념 — 타입을 파라미터로 받아 재사용 가능한 코드를 만듭니다. 차이: Java 제네릭은 컴파일 후 타입 정보가 지워집니다(type erasure)."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch8","code":"JAVA-08","title":"동시성 기초","summary":"JS는 단일 스레드 + 이벤트 루프지만, Java는 진짜 멀티스레드입니다. 스레드를 직접 만들기보다 ExecutorService (스레드 풀)와 CompletableFuture (JS Promise에 해당)를 씁니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch9","code":"JAVA-09","title":"날짜·시간","summary":"옛날 Date / Calendar 는 잊으세요 — Java 8+의 java.time 이 표준입니다. 모두 불변 이라 JS의 가변 Date 보다 안전합니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch10","code":"JAVA-10","title":"자주 쓰는 이디엄","summary":"매일 마주치는 작은 패턴들. equals/hashCode, enum, switch 표현식, 문자열 처리 — 여기서 JS 습관과 가장 자주 충돌합니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"java-ch11","code":"JAVA-11","title":"치트시트 — 복붙용 패턴","summary":"반복해서 찾게 되는 한 줄들. 외우기보다 \"이렇게 쓴다\"를 눈에 익혀두고 필요할 때 가져다 고치세요."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"doc-jpa","code":"SOURCE","title":"JPA 예시","summary":"엔티티 매핑부터 N+1 회피까지 — 바로 복붙해 쓰는 JPA 레시피. 개념의 왜 는 JPA 핸드북에 넘기고, 여기선 실제로 어떻게 쓰는지 만 코드로 봅니다. 각 섹션은 \"언제·왜\" 한두 줄 + 복붙 가능한 코드 + 발 걸리는 곳 경고."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch1","code":"JPA-01","title":"엔티티 기본","summary":"테이블 하나를 객체 하나에 매핑하는 출발점. 엔티티 = DB 테이블에 대응하는 영속 객체 이고, JPA가 추적할 수 있는 형태로 만드는 게 1번 작업입니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch2","code":"JPA-02","title":"연관관계 매핑","summary":"테이블의 외래키(FK)를 객체 참조로 바꾸는 작업. 핵심 두 가지 — FK를 가진 쪽이 연관관계의 주인(owner) 이고, fetch는 거의 항상 LAZY 로 시작합니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch3","code":"JPA-03","title":"Repository","summary":"Spring Data JPA의 핵심 편의 — 인터페이스만 선언하면 구현체는 런타임에 자동 생성 됩니다. 메서드 이름 규칙만 지키면 쿼리가 만들어집니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch4","code":"JPA-04","title":"JPQL과 @Query","summary":"메서드 이름으로 표현이 안 되는 쿼리는 직접 씁니다. JPQL은 테이블이 아니라 엔티티·필드를 대상으로 하는 쿼리 입니다 — FROM Member m 처럼 클래스명을 씁니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch5","code":"JPA-05","title":"N+1 해결","summary":"JPA에서 가장 자주 만나는 성능 함정. 목록 1번 조회 후, 각 행의 연관 엔티티를 N번 추가 조회 하는 현상입니다. LAZY 연관을 루프에서 건드릴 때 터집니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch6","code":"JPA-06","title":"페이징·정렬","summary":"목록을 통째로 읽지 말고 페이지 단위로. Spring Data가 Pageable 하나로 LIMIT·OFFSET·정렬·전체 개수 를 한 번에 처리합니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch7","code":"JPA-07","title":"트랜잭션·영속성 컨텍스트","summary":"JPA의 마법이자 함정. 트랜잭션 안에서 조회한 엔티티는 영속 상태이고, 값을 바꾸면 커밋 시점에 자동으로 UPDATE가 나갑니다 — 이게 dirty checking입니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch8","code":"JPA-08","title":"낙관적 락","summary":"두 트랜잭션이 같은 행을 동시에 수정할 때, 마지막 저장이 앞 저장을 덮어쓰는(lost update) 문제를 막습니다. 락을 미리 걸지 않고 \"충돌하면 그때 실패\"시키는 방식."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch9","code":"JPA-09","title":"Auditing","summary":"생성·수정 시각을 매번 수동으로 세팅하지 마세요. JPA Auditing이 INSERT·UPDATE 시점에 자동으로 채워줍니다 . 거의 모든 엔티티에 공통으로 들어가는 패턴."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch10","code":"JPA-10","title":"치트시트 — 자주 쓰는 한 줄","summary":"현장에서 반복되는 어노테이션·API. 외우기보다 \"이게 있다\"를 알아두고 필요할 때 찾으세요."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"jpa-ch11","code":"JPA-11","title":"프록시·flush·연관관계 심화","summary":"JPA 면접에서 깊이를 가르는 지점은 어노테이션 이름이 아니라 “언제 SQL이 나가고, 언제 프록시가 초기화되고, 왜 트랜잭션 밖에서 터지는가”를 설명하는 능력입니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"doc-spring","code":"SOURCE","title":"Spring Boot 예시","summary":"컨트롤러부터 예외 처리·검증·테스트까지 — 한 기능을 끝까지 짜는 레시피. 개념 설명보다 실제로 동작하는 코드를 먼저 보고, 계층(Controller / Service / Repository)이 각자 무슨 책임을 지는지 손에 익히는 게 목표입니다. 프론트엔드에서 넘어온 감각으로 읽히게 썼습니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch1","code":"SPRING-01","title":"프로젝트 구조와 시작","summary":"Spring Boot 앱의 출발점은 main 메서드 하나입니다 — 거기서 컨테이너가 뜨고, 패키지를 스캔해 객체들을 알아서 엮습니다. 프론트의 index.tsx 처럼 \"여기가 시작\"인 파일을 먼저 잡으세요."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch2","code":"SPRING-02","title":"REST 컨트롤러","summary":"컨트롤러는 HTTP의 경계입니다 — URL과 메서드를 받아 service에 넘기고, 결과를 상태코드와 함께 돌려줍니다. Express의 라우터 핸들러와 같은 자리지만, 어노테이션으로 선언합니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch3","code":"SPRING-03","title":"DI와 빈","summary":"JS에서는 new UserService() 로 직접 객체를 만들지만, Spring에서는 컨테이너가 객체를 만들어 들고 있다가 필요한 곳에 넣어줍니다 . 이게 의존성 주입(DI)입니다. 당신은 \"이게 필요해\"라고 선언만 합니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch4","code":"SPRING-04","title":"설정","summary":"환경마다 다른 값(DB URL, 외부 키, 포트)을 코드에서 분리합니다. .env 의 Spring 버전이 application.yml 이고, 환경 분리는 profile로 합니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch5","code":"SPRING-05","title":"서비스·트랜잭션","summary":"service 계층이 비즈니스 로직의 집입니다. 그리고 여기서 트랜잭션 경계 를 긋습니다 — \"이 메서드 안의 DB 작업은 전부 성공하거나, 전부 롤백된다\"."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch6","code":"SPRING-06","title":"예외 처리","summary":"각 컨트롤러에서 try-catch 를 반복하지 마세요. service는 도메인 예외를 던지고, 한 곳에서 잡아 일관된 에러 응답으로 변환합니다. 프론트의 전역 에러 바운더리에 가깝습니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch7","code":"SPRING-07","title":"요청 검증","summary":"잘못된 입력은 service에 닿기 전에 막습니다. DTO에 제약을 어노테이션으로 선언하고, 컨트롤러에서 @Valid 로 발동시키면 Spring이 자동으로 검사합니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch8","code":"SPRING-08","title":"데이터 접근 연동","summary":"service는 DB를 직접 만지지 않고 repository에 위임합니다. repository는 인터페이스만 선언하면 Spring Data JPA가 구현체를 자동으로 만들어줍니다 — 여기서는 연동 흐름 만 보고, 쿼리 작성은 (→ JPA 예시)."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch9","code":"SPRING-09","title":"테스트","summary":"전부 띄울지( @SpringBootTest ), 웹 계층만 잘라 빠르게 볼지( @WebMvcTest )를 먼저 고릅니다. 컨트롤러 검증·매핑 테스트는 슬라이스가 빠르고 충분합니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch10","code":"SPRING-10","title":"운영 — Actuator","summary":"배포한 앱이 살아있는지, 어떤 상태인지를 들여다보는 창입니다. spring-boot-starter-actuator 를 추가하면 운영용 엔드포인트가 열립니다 — 로드밸런서·쿠버네티스 헬스체크의 표적이 됩니다."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch11","code":"SPRING-11","title":"치트시트","summary":"한 기능을 짤 때 반복되는 핵심들. 외우기보다 \"이 자리엔 이게 온다\"는 감각으로 필요할 때 찾으세요."},{"docId":"engineering-java-spring","docLabel":"15 Java·Spring·JPA 사례","groupLabel":"개발 핸드북","sectionId":"spring-ch12","code":"SPRING-12","title":"프록시·트랜잭션·테스트 심화","summary":"Spring을 깊게 이해한다는 것은 어노테이션을 많이 아는 것이 아니라, 컨테이너가 만든 프록시 객체를 통해 부가기능이 적용된다는 사실을 이해하는 것입니다. @Transactional , 보안, 캐시, 로깅 AOP가 모두 이 사고 위에 있습니다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"index","code":"INDEX","title":"이 문서의 위치","summary":"이 문서는 경험담을 흉내 내기 위한 글이 아니라, 고급 엔지니어링 사례가 자연스럽게 읽히도록 만드는 기반 개념서입니다. 기술명보다 규모, 소유권, 품질, 지표, 호환성, 운영 책임의 언어를 먼저 익힙니다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"scale-01","code":"SCALE-01","title":"규모는 숫자가 아니라 실패 방식이다","summary":"사용자 수가 늘면 코드가 갑자기 어려워지는 것이 아니라 실패가 드러나는 방식이 바뀐다. 로컬에서는 한 번 누락된 상태가 production에서는 수천 명의 재시도, 캐시 오염, 큐 적체, 고객센터 문의로 증폭된다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"scale-02","code":"SCALE-02","title":"트래픽 감각","summary":"트래픽은 평균 요청 수가 아니라 피크, burst, fan-out, retry까지 포함한 압력이다. 요청 하나가 내부 API 5개와 DB query 8개를 부르면 외부 QPS보다 내부 부하가 훨씬 커질 수 있다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"scale-03","code":"SCALE-03","title":"릴리즈 규모","summary":"큰 조직에서 배포는 코드를 서버에 올리는 행위가 아니라 변경을 사용자에게 노출하는 리스크 관리다. 한 릴리즈에 수백 개 변경이 들어가면 어떤 변경이 어떤 기능을 깨뜨릴지 영향 범위를 자동화와 소유권으로 줄여야 한다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"scale-04","code":"SCALE-04","title":"상태와 데이터 규모","summary":"데이터가 많아지면 페이지네이션, 인덱스, 캐시, 배치, export가 모두 제품 기능이 된다. 화면에서 50개를 보여주는 일도 실제로는 권한, 필터, 정렬, 총 개수, 최신성, 다운로드 정책을 포함한다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"scale-05","code":"SCALE-05","title":"조직 규모와 소유권","summary":"시스템이 커지면 모든 사람이 모든 것을 알 수 없다. 그래서 owner, boundary, interface, runbook, review rule이 필요하다. 좋은 엔지니어링 글은 기술 설명보다 누가 무엇을 책임졌는지의 경계를 자주 보여준다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"scale-06","code":"SCALE-06","title":"읽히는 신호","summary":"규모 있는 글을 읽을 때는 숫자보다 압력의 종류를 본다. 사용자가 많아서 어려운가, 변경이 많아서 어려운가, 팀이 많아서 어려운가, 호환성을 지켜야 해서 어려운가를 구분하면 맥락이 읽힌다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"metric-anchor","code":"METRIC","title":"Metric anchor packet","summary":"이 주제는 개념 설명만으로 끝내지 않는다. 읽은 내용을 실제 판단으로 옮기려면 기준선, 임계값, 변경 전후 증거가 한 묶음으로 남아야 한다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"case","code":"CASE","title":"실무 상황 예시","summary":"아래 수치는 이해를 위한 가상 운영 수치입니다. 목적은 특정 회사 사례를 베끼는 것이 아니라, 기술 글에 자주 등장하는 상황·숫자·판단 기준을 읽는 감각을 만드는 것입니다."},{"docId":"context-scale-systems","docLabel":"00 엔지니어링 규모 감각","groupLabel":"엔지니어링 맥락","sectionId":"review","code":"REVIEW","title":"학습 확인 질문","summary":"아래 질문에 막힘없이 답하면 이 주제의 글을 읽을 때 핵심 맥락을 놓칠 가능성이 줄어듭니다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"index","code":"INDEX","title":"이 문서의 위치","summary":"이 문서는 경험담을 흉내 내기 위한 글이 아니라, 고급 엔지니어링 사례가 자연스럽게 읽히도록 만드는 기반 개념서입니다. 기술명보다 규모, 소유권, 품질, 지표, 호환성, 운영 책임의 언어를 먼저 익힙니다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"plat-01","code":"PLAT-01","title":"플랫폼은 공통 책임을 제품화한 것이다","summary":"플랫폼 엔지니어링은 팀마다 반복하던 배포, 권한, 관측, 템플릿, 테스트 환경을 공통 제품으로 만드는 일이다. 핵심 고객은 내부 개발자이고, 성공 기준은 사용 팀의 속도와 안전성이다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"plat-02","code":"PLAT-02","title":"Golden path","summary":"Golden path는 조직이 권장하는 안전한 기본 경로다. 모든 선택지를 금지하는 것이 아니라, 대부분의 팀이 빠르게 시작하고 안전하게 운영할 수 있는 기본 조합을 제공한다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"plat-03","code":"PLAT-03","title":"개발자 생산성 지표","summary":"생산성은 커밋 수가 아니라 대기 시간, 반복 작업, 실패 후 복구 시간, 변경 리드타임으로 본다. 좋은 플랫폼 글은 도구 기능보다 개발자가 덜 기다리고 덜 실수하게 된 구조를 설명한다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"plat-04","code":"PLAT-04","title":"사내 도구의 함정","summary":"사내 도구는 만들기보다 유지가 어렵다. 문서, 권한, 장애 대응, 호환성, 지원 채널이 없으면 도구가 생산성을 높이는 대신 또 다른 병목이 된다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"plat-05","code":"PLAT-05","title":"플랫폼과 제품팀의 계약","summary":"플랫폼은 제품팀의 책임을 없애지 않는다. 공통 기반은 안전한 기본값을 제공하고, 제품팀은 도메인 요구, 사용자 영향, 출시 판단을 책임진다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"plat-06","code":"PLAT-06","title":"읽히는 신호","summary":"플랫폼 글을 읽을 때는 ‘무엇을 만들었나’보다 ‘누구의 반복 문제를 줄였나’를 본다. 내부 고객, adoption, migration, support cost, guardrail이 함께 나오면 플랫폼 맥락이 있는 글이다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"metric-anchor","code":"METRIC","title":"Metric anchor packet","summary":"이 주제는 개념 설명만으로 끝내지 않는다. 읽은 내용을 실제 판단으로 옮기려면 기준선, 임계값, 변경 전후 증거가 한 묶음으로 남아야 한다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"case","code":"CASE","title":"실무 상황 예시","summary":"아래 수치는 이해를 위한 가상 운영 수치입니다. 목적은 특정 회사 사례를 베끼는 것이 아니라, 기술 글에 자주 등장하는 상황·숫자·판단 기준을 읽는 감각을 만드는 것입니다."},{"docId":"context-platform-productivity","docLabel":"01 플랫폼 엔지니어링·개발자 생산성","groupLabel":"엔지니어링 맥락","sectionId":"review","code":"REVIEW","title":"학습 확인 질문","summary":"아래 질문에 막힘없이 답하면 이 주제의 글을 읽을 때 핵심 맥락을 놓칠 가능성이 줄어듭니다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"index","code":"INDEX","title":"이 문서의 위치","summary":"이 문서는 경험담을 흉내 내기 위한 글이 아니라, 고급 엔지니어링 사례가 자연스럽게 읽히도록 만드는 기반 개념서입니다. 기술명보다 규모, 소유권, 품질, 지표, 호환성, 운영 책임의 언어를 먼저 익힙니다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"qual-01","code":"QUAL-01","title":"품질은 출시 가능성의 언어다","summary":"품질 엔지니어링은 버그를 찾는 활동만이 아니라 어떤 변경을 언제 내보내도 되는지 판단하는 기준을 만드는 일이다. 테스트는 그 기준을 실행 가능한 형태로 만든 도구다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"qual-02","code":"QUAL-02","title":"테스트 피라미드보다 테스트 목적","summary":"unit, integration, e2e는 계층 이름보다 목적이 중요하다. 빠르게 원인을 좁히는 테스트, 계약을 지키는 테스트, 실제 사용자 흐름을 지키는 테스트가 서로 다른 역할을 한다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"qual-03","code":"QUAL-03","title":"Flaky test","summary":"가끔 실패하는 테스트는 테스트가 아니라 신뢰 비용이다. randomness, time, network, async wait, shared state, test order 의존성을 제거하지 않으면 CI가 경고음이 아니라 소음이 된다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"qual-04","code":"QUAL-04","title":"릴리즈 후보와 회귀","summary":"Release candidate는 새 기능을 더 넣는 시점이 아니라 현재 변경 묶음을 검증하는 단위다. 회귀 테스트는 모든 것을 다시 누르는 것이 아니라 변경 영향 범위와 핵심 경로를 조합해 위험을 줄인다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"qual-05","code":"QUAL-05","title":"핫픽스 판단","summary":"핫픽스는 빠른 해결처럼 보이지만 사용자에게 또 다른 변경을 강제한다. 즉시 수정, 다음 릴리즈 반영, feature flag off, rollback 중 무엇이 안전한지 사용자 영향과 재발 가능성으로 판단한다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"qual-06","code":"QUAL-06","title":"읽히는 신호","summary":"품질 글을 읽을 때는 테스트 도구 이름보다 기준을 본다. 무엇을 blocker로 보고, 어떤 변경을 위험하다고 보고, 출시 후 어떤 지표로 확인하는지가 있으면 품질 엔지니어링 맥락이 살아 있다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"metric-anchor","code":"METRIC","title":"Metric anchor packet","summary":"이 주제는 개념 설명만으로 끝내지 않는다. 읽은 내용을 실제 판단으로 옮기려면 기준선, 임계값, 변경 전후 증거가 한 묶음으로 남아야 한다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"case","code":"CASE","title":"실무 상황 예시","summary":"아래 수치는 이해를 위한 가상 운영 수치입니다. 목적은 특정 회사 사례를 베끼는 것이 아니라, 기술 글에 자주 등장하는 상황·숫자·판단 기준을 읽는 감각을 만드는 것입니다."},{"docId":"context-quality-release","docLabel":"02 품질 엔지니어링·릴리즈 시스템","groupLabel":"엔지니어링 맥락","sectionId":"review","code":"REVIEW","title":"학습 확인 질문","summary":"아래 질문에 막힘없이 답하면 이 주제의 글을 읽을 때 핵심 맥락을 놓칠 가능성이 줄어듭니다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"index","code":"INDEX","title":"이 문서의 위치","summary":"이 문서는 경험담을 흉내 내기 위한 글이 아니라, 고급 엔지니어링 사례가 자연스럽게 읽히도록 만드는 기반 개념서입니다. 기술명보다 규모, 소유권, 품질, 지표, 호환성, 운영 책임의 언어를 먼저 익힙니다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"met-01","code":"MET-01","title":"성능 주장은 비교 조건이 전부다","summary":"성능 개선 글에서 가장 중요한 것은 숫자 자체가 아니라 측정 조건이다. 입력 크기, 데이터 분포, warm/cold 상태, 네트워크, 디바이스, 캐시 상태가 없으면 개선 수치를 해석할 수 없다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"met-02","code":"MET-02","title":"평균보다 percentiles","summary":"평균 latency는 tail을 숨긴다. p95, p99는 느린 사용자 경험과 큐잉, GC, DB lock, 네트워크 지연 같은 문제를 드러낸다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"met-03","code":"MET-03","title":"프론트엔드 성능 지표","summary":"프론트엔드 성능은 번들 크기만이 아니다. LCP, INP, CLS, hydration, JavaScript parse/execute, image loading, network waterfall을 함께 본다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"met-04","code":"MET-04","title":"신뢰성과 제품 지표","summary":"서비스 품질은 error rate, crash-free rate, availability, success funnel 같은 제품 지표와 연결된다. 기술 지표가 좋아도 사용자가 실패하면 품질은 나쁜 것이다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"met-05","code":"MET-05","title":"비용과 효율","summary":"성능은 비용과 분리되지 않는다. 캐시를 늘리면 latency는 줄 수 있지만 freshness와 invalidation 비용이 생기고, 더 큰 인스턴스는 빠르지만 단위 요청 비용이 커진다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"met-06","code":"MET-06","title":"읽히는 신호","summary":"좋은 성능 글은 숫자, 조건, trade-off, 회귀 방지 방법이 함께 있다. 개선 수치만 있고 측정 조건과 재현 방법이 없으면 홍보 문장에 가깝다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"metric-anchor","code":"METRIC","title":"Metric anchor packet","summary":"이 주제는 개념 설명만으로 끝내지 않는다. 읽은 내용을 실제 판단으로 옮기려면 기준선, 임계값, 변경 전후 증거가 한 묶음으로 남아야 한다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"case","code":"CASE","title":"실무 상황 예시","summary":"아래 수치는 이해를 위한 가상 운영 수치입니다. 목적은 특정 회사 사례를 베끼는 것이 아니라, 기술 글에 자주 등장하는 상황·숫자·판단 기준을 읽는 감각을 만드는 것입니다."},{"docId":"context-performance-metrics","docLabel":"03 성능 측정·지표 해석","groupLabel":"엔지니어링 맥락","sectionId":"review","code":"REVIEW","title":"학습 확인 질문","summary":"아래 질문에 막힘없이 답하면 이 주제의 글을 읽을 때 핵심 맥락을 놓칠 가능성이 줄어듭니다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"index","code":"INDEX","title":"이 문서의 위치","summary":"이 문서는 경험담을 흉내 내기 위한 글이 아니라, 고급 엔지니어링 사례가 자연스럽게 읽히도록 만드는 기반 개념서입니다. 기술명보다 규모, 소유권, 품질, 지표, 호환성, 운영 책임의 언어를 먼저 익힙니다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"lib-01","code":"LIB-01","title":"라이브러리는 API 약속이다","summary":"앱 내부 함수는 호출자를 바꿀 수 있지만 라이브러리는 알 수 없는 사용자의 코드와 호환성을 지켜야 한다. 그래서 API surface, edge case, semver, documentation이 구현만큼 중요하다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"lib-02","code":"LIB-02","title":"Edge case의 비용","summary":"라이브러리는 단순한 80% 사용 사례와 오래된 호환성 사이에서 선택해야 한다. 모든 edge case를 지원하면 무거워지고, 너무 적게 지원하면 adoption이 어렵다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"lib-03","code":"LIB-03","title":"패키지 형식과 번들링","summary":"ESM, CJS, tree-shaking, sideEffects, type declaration은 라이브러리 사용자의 빌드 결과를 좌우한다. 라이브러리 설계는 런타임 코드뿐 아니라 배포 형태의 설계다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"lib-04","code":"LIB-04","title":"Adoption cost","summary":"좋은 라이브러리는 기능이 좋아도 옮겨오기 어려우면 쓰이지 않는다. drop-in replacement, codemod, migration guide, compatibility test가 adoption을 좌우한다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"lib-05","code":"LIB-05","title":"오픈소스 운영","summary":"오픈소스는 공개 저장소가 아니라 이슈, PR, 릴리즈, 문서, 보안 신고, 커뮤니티 기대치를 운영하는 일이다. maintainer time이 가장 희소한 자원이다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"lib-06","code":"LIB-06","title":"읽히는 신호","summary":"라이브러리 글을 읽을 때는 성능 수치와 함께 API 호환성, migration path, edge case 정책을 본다. 빠르지만 기존 사용자가 옮기기 어렵다면 생태계 영향은 제한된다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"metric-anchor","code":"METRIC","title":"Metric anchor packet","summary":"이 주제는 개념 설명만으로 끝내지 않는다. 읽은 내용을 실제 판단으로 옮기려면 기준선, 임계값, 변경 전후 증거가 한 묶음으로 남아야 한다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"case","code":"CASE","title":"실무 상황 예시","summary":"아래 수치는 이해를 위한 가상 운영 수치입니다. 목적은 특정 회사 사례를 베끼는 것이 아니라, 기술 글에 자주 등장하는 상황·숫자·판단 기준을 읽는 감각을 만드는 것입니다."},{"docId":"context-library-oss","docLabel":"04 라이브러리·패키지·오픈소스 설계","groupLabel":"엔지니어링 맥락","sectionId":"review","code":"REVIEW","title":"학습 확인 질문","summary":"아래 질문에 막힘없이 답하면 이 주제의 글을 읽을 때 핵심 맥락을 놓칠 가능성이 줄어듭니다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"index","code":"INDEX","title":"이 문서의 위치","summary":"이 문서는 경험담을 흉내 내기 위한 글이 아니라, 고급 엔지니어링 사례가 자연스럽게 읽히도록 만드는 기반 개념서입니다. 기술명보다 규모, 소유권, 품질, 지표, 호환성, 운영 책임의 언어를 먼저 익힙니다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"mig-01","code":"MIG-01","title":"마이그레이션은 변경 관리다","summary":"마이그레이션은 새 기술 적용이 아니라 기존 사용자를 깨뜨리지 않고 상태를 옮기는 과정이다. 코드, 데이터, API, 문서, 팀 습관까지 함께 이동해야 한다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"mig-02","code":"MIG-02","title":"호환성의 종류","summary":"Backward compatibility는 새 코드가 옛 입력을 받아들이는 능력이고, forward compatibility는 옛 코드가 새 데이터를 만나도 크게 깨지지 않는 능력이다. 배포 순서가 나뉘면 둘 다 중요해진다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"mig-03","code":"MIG-03","title":"Expand-contract","summary":"DB와 API 변경은 보통 expand-contract로 간다. 먼저 새 필드/경로를 추가하고, 양쪽을 모두 지원하고, 트래픽을 옮긴 뒤, 마지막에 옛 것을 제거한다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"mig-04","code":"MIG-04","title":"점진적 롤아웃","summary":"한 번에 전환하면 실패 반경이 전체가 된다. feature flag, canary, shadow traffic, dual write, read fallback은 실패 반경을 줄이는 기술이다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"mig-05","code":"MIG-05","title":"Deprecation","summary":"사용 중단은 공지문이 아니라 계약 변경 절차다. 대체 경로, 사용량 측정, 경고, deadline, owner, 제거 PR이 함께 있어야 한다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"mig-06","code":"MIG-06","title":"읽히는 신호","summary":"마이그레이션 글은 새 기술의 장점보다 전환 전략이 중요하다. 호환성, 롤백, 사용량 측정, 단계별 제거가 있으면 큰 시스템에서 나온 글이다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"metric-anchor","code":"METRIC","title":"Metric anchor packet","summary":"이 주제는 개념 설명만으로 끝내지 않는다. 읽은 내용을 실제 판단으로 옮기려면 기준선, 임계값, 변경 전후 증거가 한 묶음으로 남아야 한다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"case","code":"CASE","title":"실무 상황 예시","summary":"아래 수치는 이해를 위한 가상 운영 수치입니다. 목적은 특정 회사 사례를 베끼는 것이 아니라, 기술 글에 자주 등장하는 상황·숫자·판단 기준을 읽는 감각을 만드는 것입니다."},{"docId":"context-migration-compatibility","docLabel":"05 마이그레이션·호환성","groupLabel":"엔지니어링 맥락","sectionId":"review","code":"REVIEW","title":"학습 확인 질문","summary":"아래 질문에 막힘없이 답하면 이 주제의 글을 읽을 때 핵심 맥락을 놓칠 가능성이 줄어듭니다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"index","code":"INDEX","title":"이 문서의 위치","summary":"이 문서는 경험담을 흉내 내기 위한 글이 아니라, 고급 엔지니어링 사례가 자연스럽게 읽히도록 만드는 기반 개념서입니다. 기술명보다 규모, 소유권, 품질, 지표, 호환성, 운영 책임의 언어를 먼저 익힙니다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"fer-01","code":"FER-01","title":"프론트엔드는 빌드 결과가 제품이다","summary":"개발자가 쓴 소스가 아니라 브라우저가 받은 HTML, CSS, JS, asset, cache header가 실제 제품이다. 빌드 시스템은 이 산출물을 만드는 compiler pipeline이다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"fer-02","code":"FER-02","title":"번들러의 역할","summary":"번들러는 모듈 그래프를 읽고, 변환하고, 쪼개고, 최적화한다. tree-shaking, code splitting, minification, asset hashing은 런타임 성능과 배포 안정성을 만든다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"fer-03","code":"FER-03","title":"ESM/CJS와 패키지 경계","summary":"프론트엔드 생태계의 많은 문제는 패키지 형식과 module resolution에서 나온다. ESM-only 패키지, dual package hazard, default export 차이, browser field를 이해해야 빌드 오류를 읽을 수 있다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"fer-04","code":"FER-04","title":"Hydration과 클라이언트 런타임","summary":"SSR/SSG 앱은 HTML이 먼저 보이고 JavaScript가 나중에 붙는다. hydration mismatch, client-only state, browser API 접근, streaming은 렌더링 전략의 핵심 제약이다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"fer-05","code":"FER-05","title":"브라우저 호환성과 Polyfill","summary":"브라우저 기능은 사용 가능성과 비용을 함께 본다. polyfill은 호환성을 주지만 번들 비용과 전역 오염을 만들 수 있다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"fer-06","code":"FER-06","title":"읽히는 신호","summary":"프론트엔드 생태계 글은 사용자 코드보다 빌드 산출물과 브라우저 비용을 자주 다룬다. chunk, ESM, tree-shaking, hydration, cache가 함께 보이면 이 층의 이야기다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"metric-anchor","code":"METRIC","title":"Metric anchor packet","summary":"이 주제는 개념 설명만으로 끝내지 않는다. 읽은 내용을 실제 판단으로 옮기려면 기준선, 임계값, 변경 전후 증거가 한 묶음으로 남아야 한다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"case","code":"CASE","title":"실무 상황 예시","summary":"아래 수치는 이해를 위한 가상 운영 수치입니다. 목적은 특정 회사 사례를 베끼는 것이 아니라, 기술 글에 자주 등장하는 상황·숫자·판단 기준을 읽는 감각을 만드는 것입니다."},{"docId":"context-frontend-runtime-ecosystem","docLabel":"06 프론트엔드 빌드·런타임·생태계","groupLabel":"엔지니어링 맥락","sectionId":"review","code":"REVIEW","title":"학습 확인 질문","summary":"아래 질문에 막힘없이 답하면 이 주제의 글을 읽을 때 핵심 맥락을 놓칠 가능성이 줄어듭니다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"index","code":"INDEX","title":"이 문서의 위치","summary":"이 문서는 경험담을 흉내 내기 위한 글이 아니라, 고급 엔지니어링 사례가 자연스럽게 읽히도록 만드는 기반 개념서입니다. 기술명보다 규모, 소유권, 품질, 지표, 호환성, 운영 책임의 언어를 먼저 익힙니다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"own-01","code":"OWN-01","title":"Ownership은 코드 소유가 아니라 결과 책임이다","summary":"운영 책임은 누가 파일을 수정했는가보다 사용자가 실패했을 때 누가 판단하고 복구하고 재발을 막는가에 가깝다. owner는 변경, 알림, runbook, 지표, 의사결정의 접점이다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"own-02","code":"OWN-02","title":"On-call","summary":"온콜은 밤에 깨는 사람이 아니라 시스템의 긴급 의사결정 경로다. alert가 울리면 영향 범위, 완화책, escalation, communication을 빠르게 정해야 한다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"own-03","code":"OWN-03","title":"Incident language","summary":"장애 대응의 언어는 원인 추측보다 사용자 영향, 현재 상태, 완화책, 다음 업데이트 시간이다. 원인은 나중에 찾더라도 사용자 영향과 복구 방향은 먼저 공유해야 한다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"own-04","code":"OWN-04","title":"SLO와 error budget","summary":"SLO는 완벽한 서비스가 아니라 약속 가능한 신뢰성 수준이다. error budget은 실패를 0으로 만들지 않고 기능 개발과 안정성의 균형을 잡기 위한 언어다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"own-05","code":"OWN-05","title":"Postmortem","summary":"사후분석은 범인 찾기가 아니라 시스템이 왜 그 실패를 허용했는지 찾는 일이다. timeline, contributing factors, detection gap, action items가 핵심이다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"own-06","code":"OWN-06","title":"읽히는 신호","summary":"운영 책임 글은 기술 해결책보다 책임 구조가 중요하다. 누가 알림을 받고, 누가 결정하고, 어떤 기준으로 배포를 멈추고, 사후 액션을 추적하는지 보면 조직의 운영 성숙도가 보인다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"metric-anchor","code":"METRIC","title":"Metric anchor packet","summary":"이 주제는 개념 설명만으로 끝내지 않는다. 읽은 내용을 실제 판단으로 옮기려면 기준선, 임계값, 변경 전후 증거가 한 묶음으로 남아야 한다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"case","code":"CASE","title":"실무 상황 예시","summary":"아래 수치는 이해를 위한 가상 운영 수치입니다. 목적은 특정 회사 사례를 베끼는 것이 아니라, 기술 글에 자주 등장하는 상황·숫자·판단 기준을 읽는 감각을 만드는 것입니다."},{"docId":"context-operational-ownership","docLabel":"07 운영 책임·장애 대응 언어","groupLabel":"엔지니어링 맥락","sectionId":"review","code":"REVIEW","title":"학습 확인 질문","summary":"아래 질문에 막힘없이 답하면 이 주제의 글을 읽을 때 핵심 맥락을 놓칠 가능성이 줄어듭니다."},{"docId":"llm-roadmap","docLabel":"00 LLM 로드맵·AI Native 개발자 모델","groupLabel":"LLM","sectionId":"ch1","code":"LLM-00","title":"AI NATIVE ROLE BOUNDARY","summary":"AI Native 개발자의 기준은 “프롬프트를 잘 쓴다”가 아닙니다. LLM을 권한, 데이터, 평가, 비용, 장애 대응이 필요한 소프트웨어 컴포넌트로 다루는 능력입니다."},{"docId":"llm-roadmap","docLabel":"00 LLM 로드맵·AI Native 개발자 모델","groupLabel":"LLM","sectionId":"ch2","code":"MAP","title":"LLM CAPABILITY STACK","summary":"LLM 앱은 모델 API 위에 얇은 UI를 붙인 구조가 아닙니다. 입력 계약, 검색, 도구, 평가, 감사 로그, 비용 통제가 같이 움직이는 시스템입니다."},{"docId":"llm-roadmap","docLabel":"00 LLM 로드맵·AI Native 개발자 모델","groupLabel":"LLM","sectionId":"ch3","code":"FAIL","title":"LLM FAILURE MODE MATRIX","summary":"LLM 시스템의 실패는 500 에러로만 드러나지 않습니다. 틀린 근거, 권한 누락, 비용 폭주, 스키마 깨짐처럼 정상 응답처럼 보이는 실패가 많습니다."},{"docId":"llm-roadmap","docLabel":"00 LLM 로드맵·AI Native 개발자 모델","groupLabel":"LLM","sectionId":"ch4","code":"PATH","title":"학습 순서와 완료 기준","summary":"순서는 모델 원리 → 프롬프트 계약 → RAG → 평가 → agent/tool use → 보안 → 운영 → 포트폴리오입니다. 평가를 뒤로 미루면 데모는 빠르지만 품질을 설명하지 못합니다."},{"docId":"llm-roadmap","docLabel":"00 LLM 로드맵·AI Native 개발자 모델","groupLabel":"LLM","sectionId":"build-roadmap","code":"BUILD","title":"4-WEEK BUILD ROADMAP","summary":"이 로드맵은 읽는 순서가 아니라 매주 남길 산출물 순서입니다. 각 주차는 다음 주차의 실패를 줄이는 증거를 만들고, 마지막에는 출시 가능한 Document Intelligence RAG capstone으로 합쳐야 합니다."},{"docId":"llm-roadmap","docLabel":"00 LLM 로드맵·AI Native 개발자 모델","groupLabel":"LLM","sectionId":"api-control-surface","code":"API","title":"Messages API, Tool Use, Eval Control Surface","summary":"실무 LLM 앱의 중심 코드는 프롬프트 한 줄이 아니라 입력 계약, 도구 schema, tool_use 처리, tool_result 재전송, structured output schema 검증, eval gate 기록을 묶는 제어면입니다."},{"docId":"llm-roadmap","docLabel":"00 LLM 로드맵·AI Native 개발자 모델","groupLabel":"LLM","sectionId":"ch5","code":"PORT","title":"AI NATIVE PORTFOLIO RUBRIC","summary":"포트폴리오는 “LLM을 붙였다”가 아니라 “불확실한 시스템을 어떤 계약과 평가로 통제했는가”를 보여줘야 합니다."},{"docId":"llm-roadmap","docLabel":"00 LLM 로드맵·AI Native 개발자 모델","groupLabel":"LLM","sectionId":"ai-native-dod","code":"DONE","title":"AI Native Definition of Done","summary":"로드맵의 최종 산출물은 기능 데모가 아니라 AI Native 작업 표준을 통과한 capstone입니다. 포트폴리오 evidence pack은 새 표준 문서의 완료 기준과 연결해 제출합니다."},{"docId":"llm-roadmap","docLabel":"00 LLM 로드맵·AI Native 개발자 모델","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"AI Native 실무 전환 기준","summary":"AI Native 개발자로 넘어간다는 것은 모델 API를 호출할 줄 안다는 뜻이 아닙니다. 같은 입력이어도 모델·프롬프트·검색 결과·도구 응답·샘플링 조건에 따라 출력이 달라질 수 있다는 사실을 제품 설계의 출발점으로 삼는다는 뜻입니다. 일반 API는 보통 명시된 입력과 코드 경로가 결과를 결정하지만, LLM 기능은 확률적 출력, 외부 문서, 권한 정책, "},{"docId":"llm-ai-native-work-standards","docLabel":"01 AI Native 작업 표준·Definition of Done","groupLabel":"LLM","sectionId":"ch1","code":"DONE","title":"AI NATIVE DEFINITION OF DONE","summary":"AI Native 작업은 코드, 문서, 분석 결과 중 무엇이든 동일한 완료 기준을 가집니다. 생성 결과는 초안이고, 완료는 검증 가능한 증거 패키지가 붙은 상태입니다."},{"docId":"llm-ai-native-work-standards","docLabel":"01 AI Native 작업 표준·Definition of Done","groupLabel":"LLM","sectionId":"ch2","code":"CTX","title":"CONTEXT PACKAGE","summary":"컨텍스트 패키지는 모델에게 많이 넣는 자료가 아니라, 작업 판단에 필요한 경계와 증거를 압축한 입력 계약입니다."},{"docId":"llm-ai-native-work-standards","docLabel":"01 AI Native 작업 표준·Definition of Done","groupLabel":"LLM","sectionId":"ch3","code":"MODEL","title":"PROMPT MODEL VERSION RECORD","summary":"프롬프트와 모델은 코드처럼 변경 이력을 가져야 합니다. 버전 기록이 없으면 품질 회귀, 비용 증가, 보안 우회가 언제 들어왔는지 찾을 수 없습니다."},{"docId":"llm-ai-native-work-standards","docLabel":"01 AI Native 작업 표준·Definition of Done","groupLabel":"LLM","sectionId":"ch4","code":"EVAL","title":"EVAL DATASET","summary":"평가 데이터셋은 성공 예시 모음이 아니라, 정상·애매함·근거 없음·권한 없음·공격 입력을 반복 측정하는 회귀 장치입니다."},{"docId":"llm-ai-native-work-standards","docLabel":"01 AI Native 작업 표준·Definition of Done","groupLabel":"LLM","sectionId":"ch5","code":"SEC","title":"SECURITY FIXTURE","summary":"보안 fixture는 보안 문서의 주장보다 강합니다. 악성 입력과 기대 차단 지점이 함께 있어야 릴리스 때마다 같은 경계를 검증할 수 있습니다."},{"docId":"llm-ai-native-work-standards","docLabel":"01 AI Native 작업 표준·Definition of Done","groupLabel":"LLM","sectionId":"ch6","code":"OPS","title":"COST LATENCY TRACE · HUMAN APPROVAL RISK TIER · RESIDUAL RISK REGISTER","summary":"AI Native 운영 표준은 품질 점수만 보지 않습니다. 같은 품질이라도 비용, 지연, 승인 부담, 남은 위험이 제품 기준을 넘으면 출시할 수 없습니다."},{"docId":"llm-ai-native-work-standards","docLabel":"01 AI Native 작업 표준·Definition of Done","groupLabel":"LLM","sectionId":"ch7","code":"VERIFY","title":"AI OUTPUT VERIFICATION PACKET","summary":"최종 제출물은 “AI가 만든 결과”가 아니라 “AI 출력이 독립적으로 검증된 패킷”이어야 합니다. 이 패킷이 포트폴리오, 리뷰, 운영 인수인계의 공통 단위가 됩니다."},{"docId":"llm-fundamentals","docLabel":"02 LLM 기초·모델 동작 원리","groupLabel":"LLM","sectionId":"ch1","code":"FND-00","title":"LLM Mental Model","summary":"LLM은 “알고 있는 사실을 조회”하는 시스템이 아니라, 주어진 context에서 가장 그럴듯한 다음 token을 생성하는 시스템입니다. 그래서 정답성은 모델 내부가 아니라 입력 근거, 출력 계약, 평가 체계로 만들어야 합니다."},{"docId":"llm-fundamentals","docLabel":"02 LLM 기초·모델 동작 원리","groupLabel":"LLM","sectionId":"ch2","code":"FND-01","title":"FND-TOKEN-01 Tokenization","summary":"Token은 비용, 지연, context budget의 기본 단위입니다. 단어 수와 token 수는 같지 않으며, 한국어·코드·JSON·URL·로그는 예상보다 token이 늘어날 수 있습니다."},{"docId":"llm-fundamentals","docLabel":"02 LLM 기초·모델 동작 원리","groupLabel":"LLM","sectionId":"ch3","code":"FND-02","title":"FND-CONTEXT-01 TOKEN CONTEXT ATTENTION","summary":"Context window는 system prompt, developer instruction, user input, 대화 기록, 검색 chunk, tool result, 출력 token이 함께 쓰는 공유 예산입니다."},{"docId":"llm-fundamentals","docLabel":"02 LLM 기초·모델 동작 원리","groupLabel":"LLM","sectionId":"ch4","code":"FND-03","title":"FND-SAMPLE-01 SAMPLING CONTROL","summary":"temperature, top_p, seed, max output은 창의성 버튼이 아니라 품질·재현성·비용을 조정하는 운영 파라미터입니다."},{"docId":"llm-fundamentals","docLabel":"02 LLM 기초·모델 동작 원리","groupLabel":"LLM","sectionId":"ch5","code":"FND-04","title":"FND-HALL-01 Hallucination Taxonomy","summary":"환각은 모델이 악의적으로 거짓말하는 것이 아니라, 근거 확인 없이 그럴듯한 token을 생성하는 구조적 현상입니다."},{"docId":"llm-fundamentals","docLabel":"02 LLM 기초·모델 동작 원리","groupLabel":"LLM","sectionId":"ch6","code":"FND-05","title":"FND-MODEL-01 모델 선택 기준","summary":"모델 선택은 최신 모델 이름 맞히기가 아니라 업무 요구와 실패 비용을 맞추는 결정입니다. 같은 제품에서도 경로별로 모델이 달라질 수 있습니다."},{"docId":"llm-fundamentals","docLabel":"02 LLM 기초·모델 동작 원리","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"기초 개념을 설계로 옮기는 법","summary":"LLM을 DB처럼 다루면 설계가 계속 어긋납니다. DB는 저장된 값을 조회하지만, LLM은 context 안의 token 관계를 바탕으로 그럴듯한 다음 출력을 생성합니다. 따라서 모델 내부 지식, 입력 context, 검색된 근거, 외부 tool, validator는 서로 다른 책임을 가져야 합니다. 최신 사내 정책은 모델이 “알고 있길” 기대하는 것이 아"},{"docId":"llm-prompting","docLabel":"03 프로덕션 프롬프팅·구조화 출력","groupLabel":"LLM","sectionId":"ch1","code":"PRM-01","title":"PROMPT CONTRACT","summary":"프롬프트는 문자열이 아니라 버전 관리되는 API contract입니다. 변경 시 품질, 비용, 지연, 보안 회귀가 생길 수 있으므로 코드처럼 소유자와 검증 기준이 있어야 합니다."},{"docId":"llm-prompting","docLabel":"03 프로덕션 프롬프팅·구조화 출력","groupLabel":"LLM","sectionId":"ch2","code":"PRM-02","title":"STRUCTURED OUTPUT CONTRACT","summary":"JSON을 “잘 써줘”라고 요청하는 것과 schema로 강제하는 것은 다릅니다. 제품 코드는 파싱 가능한 계약에 의존해야 하며, schema evolution 규칙도 필요합니다."},{"docId":"llm-prompting","docLabel":"03 프로덕션 프롬프팅·구조화 출력","groupLabel":"LLM","sectionId":"ch3","code":"PRM-03","title":"Validation And Repair Loop","summary":"schema validation 실패는 예외 상황이 아니라 정상 운영 경로입니다. 실패할 때마다 같은 요청을 무한 재시도하면 비용만 증가합니다."},{"docId":"llm-prompting","docLabel":"03 프로덕션 프롬프팅·구조화 출력","groupLabel":"LLM","sectionId":"ch4","code":"PRM-04","title":"TOOL USE BOUNDARY","summary":"Function calling은 모델이 코드를 실행한다는 뜻이 아니라, 모델이 호출 의도를 구조화하고 애플리케이션이 검증 후 실행한다는 뜻입니다."},{"docId":"llm-prompting","docLabel":"03 프로덕션 프롬프팅·구조화 출력","groupLabel":"LLM","sectionId":"ch5","code":"PRM-05","title":"streaming event contract","summary":"스트리밍은 UX 개선이지만, 저장과 후속 처리는 검증된 최종 structured output만 사용해야 합니다. 부분 토큰을 곧바로 DB 상태로 믿으면 중간 실패가 제품 데이터가 됩니다."},{"docId":"llm-prompting","docLabel":"03 프로덕션 프롬프팅·구조화 출력","groupLabel":"LLM","sectionId":"ch6","code":"PRM-06","title":"TOKEN COST LATENCY ECONOMICS","summary":"컨설팅과 실무 리뷰에서 반드시 묻는 질문은 “한 요청에 얼마가 들고, p95는 얼마이며, 실패 재시도까지 포함했는가”입니다."},{"docId":"llm-prompting","docLabel":"03 프로덕션 프롬프팅·구조화 출력","groupLabel":"LLM","sectionId":"ch7","code":"PRM-07","title":"OUTPUT SINK SECURITY","summary":"모델 출력은 사용자에게 보이는 텍스트에서 끝나지 않습니다. HTML/Markdown, SQL, shell command, browser action, email, ticket, DB write 같은 sink로 흘러갈 때는 다시 비신뢰 데이터로 검증해야 합니다."},{"docId":"llm-prompting","docLabel":"03 프로덕션 프롬프팅·구조화 출력","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"프롬프트를 제품 계약으로 운영하기","summary":"나쁜 프롬프트는 “이 문서를 요약하고 위험을 찾아줘”처럼 모델에게 의도를 맡깁니다. 프로덕션 프롬프트는 API contract처럼 동작해야 합니다. 어떤 입력을 신뢰할 수 있는지, 어떤 근거만 사용할 수 있는지, 어떤 경우에 no-answer로 멈춰야 하는지, 출력 schema가 무엇인지, 실패 시 repair를 몇 번 허용하는지까지 명시해야 합니다. 프롬"},{"docId":"llm-rag","docLabel":"04 RAG·임베딩·벡터DB","groupLabel":"LLM","sectionId":"ch1","code":"RAG-01","title":"EMBEDDING MODEL CONTRACT","summary":"임베딩은 텍스트 의미를 벡터로 바꾼 표현입니다. 운영에서는 “어떤 모델로, 어떤 차원으로, 어떤 거리 함수로, 언제 재색인할지”가 계약이어야 합니다."},{"docId":"llm-rag","docLabel":"04 RAG·임베딩·벡터DB","groupLabel":"LLM","sectionId":"ch2","code":"RAG-02","title":"CHUNKING STRATEGY와 CHUNK METADATA SCHEMA","summary":"RAG 품질의 절반은 문서를 어떻게 쪼개느냐에서 결정됩니다. chunk는 검색 단위이면서 답변 근거 단위이므로, 원문 위치와 권한을 잃으면 안 됩니다."},{"docId":"llm-rag","docLabel":"04 RAG·임베딩·벡터DB","groupLabel":"LLM","sectionId":"ch3","code":"RAG-03","title":"PGVECTOR CHROMA DECISION","summary":"벡터DB 선택은 성능만의 문제가 아닙니다. 권한, 백업, 운영자 경험, migration, index tuning, 비용까지 같이 봐야 합니다."},{"docId":"llm-rag","docLabel":"04 RAG·임베딩·벡터DB","groupLabel":"LLM","sectionId":"ch4","code":"RAG-04","title":"RAG PIPELINE과 Retrieval 설계","summary":""},{"docId":"llm-rag","docLabel":"04 RAG·임베딩·벡터DB","groupLabel":"LLM","sectionId":"ch5","code":"RAG-05","title":"Permission Filter와 Context Policy","summary":"RAG 보안의 기본은 “문서가 존재하는가”가 아니라 “현재 actor가 이 chunk를 볼 권한이 있는가”입니다. 권한 없는 chunk는 prompt에 들어가기 전에 제거되어야 합니다."},{"docId":"llm-rag","docLabel":"04 RAG·임베딩·벡터DB","groupLabel":"LLM","sectionId":"ch6","code":"RAG-06","title":"Retrieval Evaluation","summary":"RAG 품질은 생성 답변만 보면 원인을 알 수 없습니다. 검색 평가와 답변 평가를 분리해야 chunking, embedding, reranking, prompt 중 무엇을 고칠지 결정할 수 있습니다."},{"docId":"llm-rag","docLabel":"04 RAG·임베딩·벡터DB","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"RAG를 검색·근거·권한 시스템으로 다루기","summary":"RAG의 핵심은 “비슷한 문서를 찾는다”가 아니라 “현재 질문에 답할 수 있는 근거를, 현재 사용자가 볼 수 있는 범위 안에서, 답변에 인용 가능한 형태로 공급한다”입니다. 같은 모델과 같은 프롬프트를 써도 정답 chunk가 context에 없으면 답변은 우연이 됩니다. 그래서 RAG 디버깅은 생성 답변을 먼저 고치는 것이 아니라, 정답 근거가 검색 후보에"},{"docId":"llm-evaluation","docLabel":"05 LLM 평가·품질 관리","groupLabel":"LLM","sectionId":"ch1","code":"EVAL-01","title":"Evaluation Architecture","summary":"LLM 평가는 모델 점수 놀이가 아니라 제품 위험을 줄이는 장치입니다. 프롬프트, 모델, chunking, reranking 변경이 품질을 떨어뜨리지 않는지 감시합니다."},{"docId":"llm-evaluation","docLabel":"05 LLM 평가·품질 관리","groupLabel":"LLM","sectionId":"ch2","code":"EVAL-02","title":"GOLDEN DATASET · golden-dataset-fields","summary":"골든 데이터셋은 “정답셋”입니다. 실제 고객 질문, 어려운 edge case, 권한/보안 케이스, 근거 문서 id를 함께 저장합니다."},{"docId":"llm-evaluation","docLabel":"05 LLM 평가·품질 관리","groupLabel":"LLM","sectionId":"ch3","code":"EVAL-03","title":"retrieval-metrics","summary":"RAG에서는 검색 실패와 생성 실패를 분리해야 합니다. 검색이 틀렸다면 프롬프트를 고쳐도 답변 품질이 안정되지 않습니다."},{"docId":"llm-evaluation","docLabel":"05 LLM 평가·품질 관리","groupLabel":"LLM","sectionId":"ch4","code":"EVAL-04","title":"groundedness-taxonomy","summary":"환각 평가는 “맞다/틀리다”만으로 부족합니다. 어떤 주장이 어떤 근거와 연결되지 않았는지 분해해야 디버깅이 가능합니다."},{"docId":"llm-evaluation","docLabel":"05 LLM 평가·품질 관리","groupLabel":"LLM","sectionId":"ch5","code":"EVAL-05","title":"LLM-AS-JUDGE · llm-judge-calibration","summary":"LLM-as-judge는 모델이 모델 답변을 채점하게 하는 방법입니다. 빠르지만 편향과 불안정성이 있으므로 rubric, pairwise 비교, 사람 검수가 필요합니다."},{"docId":"llm-evaluation","docLabel":"05 LLM 평가·품질 관리","groupLabel":"LLM","sectionId":"ch6","code":"EVAL-06","title":"PROMPT REGRESSION · prompt-regression-gate","summary":"프롬프트 변경은 코드 변경입니다. 변경 전후 점수, 실패 케이스, 비용, 지연을 비교하고 임계값을 넘으면 eval gate가 릴리스를 막아야 합니다."},{"docId":"llm-evaluation","docLabel":"05 LLM 평가·품질 관리","groupLabel":"LLM","sectionId":"ch7","code":"EVAL-07","title":"QUALITY REPORT · quality-report-template","summary":"품질 리포트는 고객사와 팀이 PoC를 판단하는 한 장짜리 증거입니다. 좋은 리포트는 성공률뿐 아니라 실패 유형과 다음 개선 우선순위를 보여줍니다."},{"docId":"llm-evaluation","docLabel":"05 LLM 평가·품질 관리","groupLabel":"LLM","sectionId":"ch8","code":"EVAL-08","title":"ONLINE FEEDBACK LOOP와 production drift","summary":"오프라인 golden set은 출시 전 회귀를 막지만, 운영 분포 변화는 온라인 피드백과 drift 모니터링으로 봐야 합니다. thumbs feedback은 신호일 뿐 정답 라벨이 아니며, human-labeled holdout으로 보정해야 합니다."},{"docId":"llm-evaluation","docLabel":"05 LLM 평가·품질 관리","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"평가를 릴리스 의사결정으로 연결하기","summary":"LLM 평가를 모델 순위표처럼 다루면 제품 품질을 지키기 어렵습니다. 실제 시스템에서 품질을 흔드는 변경은 모델 교체뿐 아니라 prompt 수정, chunk size 변경, parser 업데이트, reranker 추가, 권한 필터 변경까지 다양합니다. 평가는 이 변경들이 사용자에게 나가기 전에 어떤 위험을 만들었는지 확인하는 release gate입니다. "},{"docId":"llm-agents-tool-use","docLabel":"06 Agent·Tool Use·Workflow","groupLabel":"LLM","sectionId":"ch1","code":"AGT-01","title":"agent-workflow-rule","summary":"기본값은 workflow입니다. 모델이 다음 행동을 선택해야 할 만큼 불확실성이 높고, 실패를 검증할 수 있으며, 위험 행동을 승인 게이트로 막을 수 있을 때만 agent를 사용합니다."},{"docId":"llm-agents-tool-use","docLabel":"06 Agent·Tool Use·Workflow","groupLabel":"LLM","sectionId":"ch2","code":"AGT-02","title":"PLANNER EXECUTOR · planner-output-contract와 role-contracts","summary":"Planner와 Executor를 분리하면 모델이 세운 계획과 실제 도구 실행을 다르게 통제할 수 있습니다. Verifier는 결과가 목표를 충족했는지 증거 기반으로 판단합니다."},{"docId":"llm-agents-tool-use","docLabel":"06 Agent·Tool Use·Workflow","groupLabel":"LLM","sectionId":"ch3","code":"AGT-03","title":"tool-schema-hardening","summary":"도구 실행은 모델 출력이 아니라 애플리케이션 권한입니다. 모델이 제안한 함수명과 인자는 모두 비신뢰 입력으로 검증해야 합니다."},{"docId":"llm-agents-tool-use","docLabel":"06 Agent·Tool Use·Workflow","groupLabel":"LLM","sectionId":"ch4","code":"AGT-04","title":"HUMAN APPROVAL GATE · approval-gate-payload","summary":"Human approval은 “확인하시겠습니까?” 팝업이 아닙니다. 사용자가 무엇이 실행되고 어떤 위험이 있는지 판단할 수 있는 payload가 필요합니다."},{"docId":"llm-agents-tool-use","docLabel":"06 Agent·Tool Use·Workflow","groupLabel":"LLM","sectionId":"ch5","code":"AGT-05","title":"memory-lifecycle","summary":"Agent memory는 모든 대화를 저장하는 것이 아니라 다음 행동에 필요한 상태를 구조화해 보존하는 것입니다. memory도 prompt injection과 privacy의 공격면이 됩니다."},{"docId":"llm-agents-tool-use","docLabel":"06 Agent·Tool Use·Workflow","groupLabel":"LLM","sectionId":"ch6","code":"AGT-06","title":"retry-taxonomy와 budget-accounting","summary":"Agent는 실패할 수 있으므로 retry와 stop condition이 제품 안전장치입니다. 같은 실패를 반복하는 것은 지능이 아니라 비용 폭주입니다."},{"docId":"llm-agents-tool-use","docLabel":"06 Agent·Tool Use·Workflow","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"Agent를 안전한 실행 시스템으로 만들기","summary":"Agent는 자동화의 상위 단계가 아니라 불확실성을 모델에게 일부 위임하는 설계입니다. 그래서 agent를 쓰면 비용, 지연, 권한 검증, 감사 로그, 중단 조건이 모두 어려워집니다. 단계가 고정되어 있고 입력과 출력이 예측 가능하다면 deterministic workflow가 기본값입니다. agent는 도구 선택이 동적이고, 중간 결과에 따라 다음 행동이"},{"docId":"llm-security-governance","docLabel":"07 LLM 보안·거버넌스","groupLabel":"LLM","sectionId":"ch1","code":"SEC-01","title":"LLM 보안의 기본 전제","summary":"LLM은 권한을 가진 사용자가 아니라 권한을 가진 애플리케이션의 입력 처리기입니다. 모델이 “허용된다”고 말해도 서버 권한 검증, tool allowlist, 데이터 접근 정책을 우회할 수 없어야 합니다."},{"docId":"llm-security-governance","docLabel":"07 LLM 보안·거버넌스","groupLabel":"LLM","sectionId":"ch2","code":"SEC-02","title":"Threat Model: actor · asset · trust boundary · source · sink","summary":"LLM 보안은 “사용자 prompt가 위험하다”에서 끝나지 않습니다. 비신뢰 source가 모델을 통해 sink로 흘러가는 경로를 찾아야 합니다."},{"docId":"llm-security-governance","docLabel":"07 LLM 보안·거버넌스","groupLabel":"LLM","sectionId":"ch3","code":"SEC-03","title":"PROMPT INJECTION · indirect prompt injection과 exfiltration","summary":"Prompt injection은 비신뢰 텍스트가 모델에게 “이전 지시를 무시하라” 같은 행동 지시를 주는 공격입니다. RAG, tool result, memory가 모두 공격 경로가 될 수 있습니다."},{"docId":"llm-security-governance","docLabel":"07 LLM 보안·거버넌스","groupLabel":"LLM","sectionId":"ch4","code":"SEC-04","title":"RAG와 Tool Calling 보안","summary":""},{"docId":"llm-security-governance","docLabel":"07 LLM 보안·거버넌스","groupLabel":"LLM","sectionId":"ch5","code":"SEC-05","title":"DATA LEAKAGE와 Privacy","summary":"데이터 등급은 입력 가능 여부만이 아니라 저장, 로그, 벤더 전송, 학습 사용, retention, deletion request를 함께 정의해야 합니다."},{"docId":"llm-security-governance","docLabel":"07 LLM 보안·거버넌스","groupLabel":"LLM","sectionId":"ch6","code":"SEC-06","title":"risk tier와 Governance","summary":""},{"docId":"llm-security-governance","docLabel":"07 LLM 보안·거버넌스","groupLabel":"LLM","sectionId":"ch7","code":"SEC-07","title":"audit log와 incident response","summary":""},{"docId":"llm-security-governance","docLabel":"07 LLM 보안·거버넌스","groupLabel":"LLM","sectionId":"ch8","code":"SEC-08","title":"OWASP LLM TOP 10 COVERAGE","summary":"보안 문서는 자체 원칙만으로 끝내지 말고 OWASP LLM Top 10과 매핑해야 합니다. 아래는 2025 개정판 기준입니다(2023 v1.0에서 Insecure Output Handling→Improper Output Handling, Model Denial of Service→Unbounded Consumption으로 개명되고 System Prompt "},{"docId":"llm-security-governance","docLabel":"07 LLM 보안·거버넌스","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"LLM 보안을 공격 경로로 이해하기","summary":"LLM 보안은 “사용자가 이상한 prompt를 입력했다” 수준에서 끝나지 않습니다. user input, retrieved document, tool output, memory, admin config는 모두 source가 될 수 있고, model prompt, logs, DB write, email, external API, UI output은 sink가"},{"docId":"llm-app-architecture-operations","docLabel":"08 LLM 앱 아키텍처·운영","groupLabel":"LLM","sectionId":"ch1","code":"OPS-01","title":"운영 가능한 LLM 앱의 정의","summary":"LLM 앱의 성공 기준은 응답 성공 여부가 아니라 latency, cost, quality, safety, reliability를 동시에 만족하는 것입니다. “실패는 500만이 아니다”가 운영의 출발점입니다."},{"docId":"llm-app-architecture-operations","docLabel":"08 LLM 앱 아키텍처·운영","groupLabel":"LLM","sectionId":"ch2","code":"OPS-02","title":"Request Lifecycle Envelope","summary":"LLM 요청은 추적 가능해야 합니다. 답변이 틀렸을 때 어떤 prompt, model, retrieval index, tool result가 사용됐는지 재구성할 수 있어야 합니다."},{"docId":"llm-app-architecture-operations","docLabel":"08 LLM 앱 아키텍처·운영","groupLabel":"LLM","sectionId":"ch3","code":"OPS-03","title":"model_gateway와 Resilience","summary":"모델 제공자 장애, 지연, rate limit은 정상적으로 발생합니다. gateway는 timeout, retry_budget, circuit_breaker, fallback_routing을 한곳에서 관리해야 합니다."},{"docId":"llm-app-architecture-operations","docLabel":"08 LLM 앱 아키텍처·운영","groupLabel":"LLM","sectionId":"ch4","code":"OPS-04","title":"Queue·Cache·RATE LIMIT·quota","summary":""},{"docId":"llm-app-architecture-operations","docLabel":"08 LLM 앱 아키텍처·운영","groupLabel":"LLM","sectionId":"ch5","code":"OPS-05","title":"LLM OBSERVABILITY","summary":"LLM 운영은 logs, metrics, traces, evals를 구분해서 봐야 합니다. 단순 API 성공률로는 품질 실패를 볼 수 없습니다."},{"docId":"llm-app-architecture-operations","docLabel":"08 LLM 앱 아키텍처·운영","groupLabel":"LLM","sectionId":"ch6","code":"OPS-06","title":"Release, Runbook, production_readiness_checklist","summary":"prompt, model, retrieval index, schema 변경은 코드 배포처럼 다뤄야 합니다. eval_gate를 통과하고 canary_rollout 후 문제가 있으면 prompt_rollback이 가능해야 합니다."},{"docId":"llm-app-architecture-operations","docLabel":"08 LLM 앱 아키텍처·운영","groupLabel":"LLM","sectionId":"ch7","code":"OPS-07","title":"Vendor governance · DATA RESIDENCY · routing policy","summary":"프로덕션 LLM 운영은 모델 gateway 내부 문제만이 아닙니다. provider due diligence, 데이터 국외 이전, 보존 기간, 학습 사용 여부, SLA, 장애 공지, 비용 계약까지 운영 설계에 포함해야 합니다."},{"docId":"llm-app-architecture-operations","docLabel":"08 LLM 앱 아키텍처·운영","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"운영 가능한 LLM 앱의 증거 설계","summary":"request envelope는 로그 장식이 아닙니다. 답변이 틀렸을 때 같은 입력, 같은 prompt_version, 같은 model_version, 같은 retrieval index로 사고를 재현하기 위한 최소 증거입니다. 비용이 급증했을 때 어떤 feature와 tenant에서 token이 늘었는지 추적하고, 권한 사고가 났을 때 어떤 document"},{"docId":"llm-multimodal-realtime","docLabel":"09 멀티모달·파일·음성·Realtime","groupLabel":"LLM","sectionId":"ch1","code":"MM-01","title":"MULTIMODAL REQUEST ENVELOPE","summary":"멀티모달 요청은 actor, media, extraction goal, risk tier, consent, retention을 함께 기록해야 합니다. 같은 이미지라도 OCR, 시각 질의응답, 품질 검사, 안전 판정은 서로 다른 평가와 보안 기준을 갖습니다."},{"docId":"llm-multimodal-realtime","docLabel":"09 멀티모달·파일·음성·Realtime","groupLabel":"LLM","sectionId":"ch2","code":"MM-02","title":"vision extraction과 visual grounding","summary":"이미지 이해 기능은 “이미지를 설명한다”와 “증거 위치를 가진 값을 추출한다”를 구분해야 합니다. 업무 자동화에서는 자연어 설명보다 bbox, page, crop, confidence, reviewer override가 더 중요합니다."},{"docId":"llm-multimodal-realtime","docLabel":"09 멀티모달·파일·음성·Realtime","groupLabel":"LLM","sectionId":"ch3","code":"MM-03","title":"file ingestion과 document intelligence","summary":"파일 입력은 업로드가 아니라 ingestion pipeline입니다. parser, page segmentation, table extraction, image OCR, metadata, ACL, virus scan, content hash가 검색과 평가의 기초가 됩니다."},{"docId":"llm-multimodal-realtime","docLabel":"09 멀티모달·파일·음성·Realtime","groupLabel":"LLM","sectionId":"ch4","code":"MM-04","title":"audio turn-taking과 voice UX","summary":"음성 앱은 STT, VAD, partial transcript, interruption, TTS, latency budget이 함께 움직입니다. 텍스트 챗봇보다 오류 수정과 사용자 중단 처리가 훨씬 중요합니다."},{"docId":"llm-multimodal-realtime","docLabel":"09 멀티모달·파일·음성·Realtime","groupLabel":"LLM","sectionId":"ch5","code":"MM-05","title":"realtime session state machine","summary":"Realtime은 websocket을 여는 기능이 아니라 세션 상태 머신입니다. 입력 스트림, 모델 응답, 도구 제안, 사용자 중단, 재연결, 비용 예산을 같은 trace 안에서 관리해야 합니다."},{"docId":"llm-multimodal-realtime","docLabel":"09 멀티모달·파일·음성·Realtime","groupLabel":"LLM","sectionId":"ch6","code":"MM-06","title":"multimodal eval","summary":"멀티모달 평가는 텍스트 정답만 비교하면 부족합니다. 위치, 시간, 시각 근거, transcript 품질, 사용자 중단 처리까지 케이스로 고정해야 합니다."},{"docId":"llm-multimodal-realtime","docLabel":"09 멀티모달·파일·음성·Realtime","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"멀티모달을 운영 가능한 제품으로 만들기","summary":"텍스트 RAG에서는 citation이 핵심 증거지만, 이미지와 음성에서는 citation만으로 부족합니다. 이미지 추출은 bbox와 crop, PDF는 page와 table cell, 음성은 timestamp와 final transcript, realtime은 session event trace가 있어야 리뷰어가 결과를 검증할 수 있습니다. 증거 단위가 없"},{"docId":"llm-model-customization","docLabel":"10 Fine-tuning·Customization·Model Routing","groupLabel":"LLM","sectionId":"ch1","code":"CUS-01","title":"CUSTOMIZATION DECISION MATRIX","summary":"prompt vs RAG vs fine-tuning 선택은 유행이 아니라 실패 원인에 따라 결정합니다. 최신 사내 지식이 없으면 RAG, 출력 형식이 흔들리면 schema와 validator, 반복 스타일이 문제면 fine-tuning 후보입니다."},{"docId":"llm-model-customization","docLabel":"10 Fine-tuning·Customization·Model Routing","groupLabel":"LLM","sectionId":"ch2","code":"CUS-02","title":"fine-tuning readiness","summary":"Fine-tuning은 모델에게 새 정책 문서를 외우게 하는 도구가 아니라, 반복되는 입력-출력 행동을 더 안정적으로 만드는 도구입니다. 데이터 품질과 평가 체계가 없으면 prompt보다 더 고치기 어려운 회귀를 만듭니다."},{"docId":"llm-model-customization","docLabel":"10 Fine-tuning·Customization·Model Routing","groupLabel":"LLM","sectionId":"ch3","code":"CUS-03","title":"distillation과 small model strategy","summary":"Distillation은 큰 모델의 판단을 작은 모델이나 더 싼 경로로 이전해 비용·지연을 줄이는 전략입니다. 단, teacher output을 정답처럼 믿지 말고 사람 라벨과 hard negative를 섞어야 합니다."},{"docId":"llm-model-customization","docLabel":"10 Fine-tuning·Customization·Model Routing","groupLabel":"LLM","sectionId":"ch4","code":"CUS-04","title":"routing policy와 reasoning effort","summary":"모든 요청을 가장 강한 모델에 보내는 것은 품질 전략이 아니라 비용 전략 실패입니다. routing policy는 risk, difficulty, latency SLO, context size, tool requirement, reasoning_budget을 기준으로 결정해야 합니다."},{"docId":"llm-model-customization","docLabel":"10 Fine-tuning·Customization·Model Routing","groupLabel":"LLM","sectionId":"ch5","code":"CUS-05","title":"training dataset governance","summary":"커스터마이징 데이터셋은 운영 로그의 복사본이 아닙니다. 개인정보, 비밀, 저작권, 사용자 동의, 라벨 기준, 삭제 요청 대응을 갖춘 제품 자산입니다."},{"docId":"llm-model-customization","docLabel":"10 Fine-tuning·Customization·Model Routing","groupLabel":"LLM","sectionId":"ch6","code":"CUS-06","title":"custom model release gate","summary":"커스텀 모델 배포는 prompt 변경보다 되돌리기 어려울 수 있습니다. offline eval, safety fixture, shadow traffic, canary, rollback을 갖춘 변경 관리로 다뤄야 합니다."},{"docId":"llm-model-customization","docLabel":"10 Fine-tuning·Customization·Model Routing","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"커스터마이징 의사결정 방어하기","summary":"사내 정책, 가격, 계약 조항처럼 바뀌고 삭제되어야 하는 지식은 RAG나 tool로 공급해야 합니다. fine-tuning에 넣으면 업데이트, 권한 분리, 삭제 요청, 출처 추적이 어려워집니다. fine-tuning이 강한 영역은 반복되는 형식, 분류 기준, 문체, 특정 출력 행동입니다. 그래서 커스터마이징 리뷰의 첫 질문은 “모델이 모르는가”가 아니라 “"},{"docId":"llm-portfolio-projects","docLabel":"11 포트폴리오 프로젝트","groupLabel":"LLM","sectionId":"ch1","code":"PORT-00","title":"weak portfolio vs strong portfolio","summary":"LLM 포트폴리오의 목표는 “모델 호출 경험”이 아니라 “불확실한 모델을 제품 시스템으로 통제한 증거”를 보여주는 것입니다."},{"docId":"llm-portfolio-projects","docLabel":"11 포트폴리오 프로젝트","groupLabel":"LLM","sectionId":"ch2","code":"PORT-01","title":"problem statement와 user scenario","summary":"프로젝트는 기술 목록이 아니라 문제 정의에서 출발해야 합니다. 어떤 문서 업무를, 어떤 사용자를 위해, 어떤 품질 기준으로 해결하는지 적어야 합니다."},{"docId":"llm-portfolio-projects","docLabel":"11 포트폴리오 프로젝트","groupLabel":"LLM","sectionId":"ch3","code":"PORT-02","title":"문서 분석 API: input/output schema","summary":"Phase 1 산출물은 “문서 요약 + 자동 분석 API”입니다. 긴 텍스트 입력을 받아 구조화된 요약, 핵심 추출, 엔티티, 위험 신호, 후속 질문을 반환합니다."},{"docId":"llm-portfolio-projects","docLabel":"11 포트폴리오 프로젝트","groupLabel":"LLM","sectionId":"ch4","code":"PORT-03","title":"RAG 지식 검색 챗봇","summary":"Phase 1에 RAG를 붙여 문서 지식 검색 챗봇을 완성합니다. 메인 포트폴리오는 이 프로젝트가 됩니다."},{"docId":"llm-portfolio-projects","docLabel":"11 포트폴리오 프로젝트","groupLabel":"LLM","sectionId":"ch5","code":"PORT-04","title":"평가 하니스와 QUALITY REPORT · LLM-as-judge rubric","summary":"챗봇에 평가 하니스를 붙이고 한 장짜리 품질 리포트를 만듭니다. 이 산출물이 컨설턴트 차별점입니다."},{"docId":"llm-portfolio-projects","docLabel":"11 포트폴리오 프로젝트","groupLabel":"LLM","sectionId":"ch6","code":"PORT-05","title":"README evidence pack과 interview questions","summary":"“LLM 챗봇을 만들었습니다”보다 “문서 분석 API에서 시작해 RAG 검색 챗봇으로 확장했고, golden dataset과 LLM-as-judge로 정확도·근거성·검색 적중률을 리포트했습니다. pgvector는 기존 Postgres 권한·백업·트랜잭션과 묶기 쉬워 선택했고, hallucination은 no-answer 정책과 citation precisi"},{"docId":"llm-portfolio-projects","docLabel":"11 포트폴리오 프로젝트","groupLabel":"LLM","sectionId":"ax-evidence","code":"AX","title":"AX EXECUTION EVIDENCE PACK","summary":"LLM 포트폴리오는 결과물만 보여주면 약합니다. AI와 함께 작업한 실행 과정, 거절한 출력, 독립 검증, 비용·지연까지 남겨야 AX 역량을 증명할 수 있습니다."},{"docId":"llm-portfolio-projects","docLabel":"11 포트폴리오 프로젝트","groupLabel":"LLM","sectionId":"ch8","code":"UX","title":"AI UX EVIDENCE","summary":"강한 LLM 포트폴리오는 백엔드 trace만 보여주지 않습니다. 사용자가 AI 출력을 어떻게 검토하고, 의심하고, 수정하고, 거절하고, 사람에게 넘기는지까지 보여줘야 합니다."},{"docId":"llm-portfolio-projects","docLabel":"11 포트폴리오 프로젝트","groupLabel":"LLM","sectionId":"depth","code":"DEPTH","title":"제출 가능한 포트폴리오 증거 패키지","summary":"LLM 포트폴리오에서 챗 화면은 가장 약한 증거입니다. 화면은 잘 된 한 번의 결과만 보여주지만, 채용자나 리뷰어가 알고 싶은 것은 실패를 어떻게 발견하고 줄였는지입니다. 강한 포트폴리오는 API contract, prompt contract, retrieval trace, golden dataset, regression report, cost/latenc"},{"docId":"ai-native-competency-map","docLabel":"00 역량 매트릭스·진단","groupLabel":"AI Native 훈련","sectionId":"roadmap","code":"MAP-00","title":"큰그림 로드맵","summary":"중급 개발자가 AI Native로 전환할 때의 목표는 “모델을 잘 쓰는 사람”이 아니라 불확실한 AI 출력을 제품 변경, 평가, 보안, 운영 증거로 통제하는 사람 이 되는 것입니다. 시작 단계에서는 아래 6단계를 순서대로 밟습니다."},{"docId":"ai-native-competency-map","docLabel":"00 역량 매트릭스·진단","groupLabel":"AI Native 훈련","sectionId":"ch1","code":"MAP-01","title":"판정 기준","summary":"역량 진단은 감상이나 자신감이 아니라 제출 가능한 산출물로 판정합니다. 설명할 수 있어도 재현 가능한 증거가 없으면 아직 실무 역량으로 보지 않습니다. 점수는 평균이 아니라 최저 축으로 제한합니다. 평가·보안·운영이 비어 있으면 L3 이상으로 판정하지 않습니다."},{"docId":"ai-native-competency-map","docLabel":"00 역량 매트릭스·진단","groupLabel":"AI Native 훈련","sectionId":"ch2","code":"MAP-02","title":"AI Native 역량 축","summary":""},{"docId":"ai-native-competency-map","docLabel":"00 역량 매트릭스·진단","groupLabel":"AI Native 훈련","sectionId":"ch3","code":"MAP-03","title":"빠른 수준 진단","summary":"각 질문에 대해 현재 남길 수 있는 증거가 없다면 해당 수준은 아직 통과하지 않은 것으로 봅니다."},{"docId":"ai-native-competency-map","docLabel":"00 역량 매트릭스·진단","groupLabel":"AI Native 훈련","sectionId":"ch4","code":"MAP-04","title":"Evidence Ledger","summary":"학습 결과는 하나의 ledger에 누적합니다. 같은 프로젝트라도 평가, 보안, 운영, UX 증거를 분리해야 면접과 리뷰에서 방어할 수 있습니다."},{"docId":"ai-native-competency-map","docLabel":"00 역량 매트릭스·진단","groupLabel":"AI Native 훈련","sectionId":"ch5","code":"MAP-05","title":"보강 루프","summary":"이 문서를 끝냈다는 뜻은 표를 읽었다는 뜻이 아니라, 현재 자신의 L1-L4 위치, 총점, 다음 실습 랩, 제출할 산출물을 정했다는 뜻입니다. 중급 개발자 기준으로는 4주 안에 최소 28점과 L3 증거 2개를 목표로 둡니다."},{"docId":"ai-native-competency-map","docLabel":"00 역량 매트릭스·진단","groupLabel":"AI Native 훈련","sectionId":"sample","code":"SAMPLE","title":"진단 제출 예시와 리뷰 기준","summary":"아래처럼 현재 수준, 증거 공백, 다음 랩을 한 장으로 제출해야 진단이 실제 훈련 계획으로 바뀝니다. 점수만 적으면 자기평가이고, 증거와 다음 실험이 붙으면 코칭 가능한 산출물입니다."},{"docId":"ai-native-labs","docLabel":"01 실습 랩","groupLabel":"AI Native 훈련","sectionId":"ch1","code":"LAB-00","title":"랩 공통 규격","summary":"랩은 “해봤다”가 아니라 “실패 fixture를 통과했다”로 판정합니다. 각 랩은 입력, 작업, 측정, 리뷰 산출물을 가져야 하며 결과는 역량 매트릭스 점수에 반영합니다."},{"docId":"ai-native-labs","docLabel":"01 실습 랩","groupLabel":"AI Native 훈련","sectionId":"path","code":"PATH","title":"훈련 순서","summary":"중급 개발자는 모델 원리를 오래 읽기보다 한 요청이 제품에서 실패하는 경로를 따라 훈련해야 합니다. 아래 순서를 지키면 출력 계약, 근거, 평가, 보안, 운영이 끊기지 않습니다."},{"docId":"ai-native-labs","docLabel":"01 실습 랩","groupLabel":"AI Native 훈련","sectionId":"lab1","code":"LAB-01","title":"Prompt/schema contract regression","summary":"모델 출력이 UI와 API가 기대하는 구조를 안정적으로 만족하는지 검증합니다."},{"docId":"ai-native-labs","docLabel":"01 실습 랩","groupLabel":"AI Native 훈련","sectionId":"lab2","code":"LAB-02","title":"RAG retrieval evaluation","summary":"검색 실패와 생성 실패를 분리합니다. 정답 근거가 context에 없으면 프롬프트를 고쳐도 안정적인 품질이 나오지 않습니다."},{"docId":"ai-native-labs","docLabel":"01 실습 랩","groupLabel":"AI Native 훈련","sectionId":"lab3","code":"LAB-03","title":"LLM security red-team","summary":"공격을 문서로 읽지 않고 fixture로 실행합니다. 직접/간접 injection, tool injection, tenant 경계, PII 누출을 분리합니다."},{"docId":"ai-native-labs","docLabel":"01 실습 랩","groupLabel":"AI Native 훈련","sectionId":"lab4","code":"LAB-04","title":"Agent tool approval and idempotency","summary":"에이전트 도구 호출을 승인, 재시도, 감사 가능한 형태로 만듭니다."},{"docId":"ai-native-labs","docLabel":"01 실습 랩","groupLabel":"AI Native 훈련","sectionId":"lab5","code":"LAB-05","title":"LLM observability and incident drill","summary":"AI 기능의 장애를 프롬프트 수정으로만 다루지 않고 지표, 완화, 롤백, 회고로 닫습니다."},{"docId":"ai-native-labs","docLabel":"01 실습 랩","groupLabel":"AI Native 훈련","sectionId":"lab6","code":"LAB-06","title":"AX episode package","summary":"AI와 협업한 작업을 재현 가능한 에피소드로 남깁니다. AI의 판단과 사람의 검증을 분리해야 합니다."},{"docId":"ai-native-labs","docLabel":"01 실습 랩","groupLabel":"AI Native 훈련","sectionId":"sample","code":"SAMPLE","title":"랩 완료 보고서 예시","summary":"랩 결과는 “완료”라고 쓰는 대신 fixture 실행 결과, 실패 원인, 개선 diff, 재실행 결과를 함께 제출합니다. 강의 과제로 쓰려면 아래 형식이 최소 기준입니다."},{"docId":"ai-native-toolkit","docLabel":"02 템플릿 키트","groupLabel":"AI Native 훈련","sectionId":"ch1","code":"KIT-01","title":"템플릿 사용 원칙","summary":""},{"docId":"ai-native-toolkit","docLabel":"02 템플릿 키트","groupLabel":"AI Native 훈련","sectionId":"context","code":"KIT-02","title":"context-package.yaml","summary":""},{"docId":"ai-native-toolkit","docLabel":"02 템플릿 키트","groupLabel":"AI Native 훈련","sectionId":"eval","code":"KIT-03","title":"eval-dataset.jsonl","summary":""},{"docId":"ai-native-toolkit","docLabel":"02 템플릿 키트","groupLabel":"AI Native 훈련","sectionId":"security","code":"KIT-04","title":"security-fixtures.jsonl","summary":""},{"docId":"ai-native-toolkit","docLabel":"02 템플릿 키트","groupLabel":"AI Native 훈련","sectionId":"episode","code":"KIT-05","title":"agent-episode-log.md","summary":""},{"docId":"ai-native-toolkit","docLabel":"02 템플릿 키트","groupLabel":"AI Native 훈련","sectionId":"release","code":"KIT-06","title":"prompt release와 LLM incident","summary":""},{"docId":"ai-native-toolkit","docLabel":"02 템플릿 키트","groupLabel":"AI Native 훈련","sectionId":"portfolio","code":"KIT-07","title":"portfolio-evidence-pack.md","summary":"# Portfolio Evidence Pack Problem: Architecture: Data/RAG: Evaluation: Security: Operations: Tradeoffs: Measured result: Failure handled: Interview story: 나쁜 예 \"AI를 활용해 생산성을 높였습니다\"는 증거가 아닙니다. 어떤 fixtu"},{"docId":"ai-native-toolkit","docLabel":"02 템플릿 키트","groupLabel":"AI Native 훈련","sectionId":"sample","code":"SAMPLE","title":"템플릿 작성 예시","summary":"빈 템플릿은 출발점일 뿐입니다. 실제 제출물은 결정, 근거, 검증, 남은 위험이 채워져야 합니다."},{"docId":"ai-native-evaluation-harness","docLabel":"03 평가 하네스","groupLabel":"AI Native 훈련","sectionId":"ch1","code":"EVAL-LAB-01","title":"하네스 구조","summary":""},{"docId":"ai-native-evaluation-harness","docLabel":"03 평가 하네스","groupLabel":"AI Native 훈련","sectionId":"ch2","code":"EVAL-LAB-02","title":"Dataset schema","summary":""},{"docId":"ai-native-evaluation-harness","docLabel":"03 평가 하네스","groupLabel":"AI Native 훈련","sectionId":"ch3","code":"EVAL-LAB-03","title":"Baseline/Candidate Runner","summary":"항상 기준선과 후보를 같은 데이터셋, 같은 parser, 같은 judge rubric으로 비교합니다."},{"docId":"ai-native-evaluation-harness","docLabel":"03 평가 하네스","groupLabel":"AI Native 훈련","sectionId":"ch4","code":"EVAL-LAB-04","title":"Judge calibration","summary":"LLM-as-Judge는 빠르지만 최종 권위가 아닙니다. 사람 라벨 holdout과의 agreement를 추적해야 합니다."},{"docId":"ai-native-evaluation-harness","docLabel":"03 평가 하네스","groupLabel":"AI Native 훈련","sectionId":"ch5","code":"EVAL-LAB-05","title":"CI Gate","summary":""},{"docId":"ai-native-evaluation-harness","docLabel":"03 평가 하네스","groupLabel":"AI Native 훈련","sectionId":"ch6","code":"EVAL-LAB-06","title":"Eval report","summary":""},{"docId":"ai-native-evaluation-harness","docLabel":"03 평가 하네스","groupLabel":"AI Native 훈련","sectionId":"sample","code":"SAMPLE","title":"평가 리포트 제출 예시","summary":"좋은 평가 리포트는 점수 상승만 보여주지 않습니다. 어떤 품질은 좋아졌고 어떤 위험은 새로 생겼는지, 그래서 릴리스를 통과할지 막을지 결정합니다."},{"docId":"ai-native-security-red-team","docLabel":"04 보안 레드팀 Fixture","groupLabel":"AI Native 훈련","sectionId":"ch1","code":"SEC-LAB-01","title":"Threat model","summary":""},{"docId":"ai-native-security-red-team","docLabel":"04 보안 레드팀 Fixture","groupLabel":"AI Native 훈련","sectionId":"ch2","code":"SEC-LAB-02","title":"Prompt injection fixtures","summary":""},{"docId":"ai-native-security-red-team","docLabel":"04 보안 레드팀 Fixture","groupLabel":"AI Native 훈련","sectionId":"ch3","code":"SEC-LAB-03","title":"Tool, memory, connector 공격","summary":""},{"docId":"ai-native-security-red-team","docLabel":"04 보안 레드팀 Fixture","groupLabel":"AI Native 훈련","sectionId":"ch4","code":"SEC-LAB-04","title":"Tenant와 데이터 경계","summary":""},{"docId":"ai-native-security-red-team","docLabel":"04 보안 레드팀 Fixture","groupLabel":"AI Native 훈련","sectionId":"ch5","code":"SEC-LAB-05","title":"Regression으로 고정하기","summary":"보안 문서를 읽은 것이 아니라, 공격 payload가 저장소에 있고 릴리스 때 다시 실행되는 상태가 완료입니다."},{"docId":"ai-native-security-red-team","docLabel":"04 보안 레드팀 Fixture","groupLabel":"AI Native 훈련","sectionId":"sample","code":"SAMPLE","title":"레드팀 리포트 예시","summary":"보안 레드팀 결과는 공격 문장을 모아둔 목록이 아니라, 방어가 어떤 경계에서 작동했는지 증명하는 리포트입니다."},{"docId":"ai-native-agent-runtime","docLabel":"05 Agent Runtime 구현","groupLabel":"AI Native 훈련","sectionId":"ch1","code":"AGENT-01","title":"Runtime의 책임","summary":""},{"docId":"ai-native-agent-runtime","docLabel":"05 Agent Runtime 구현","groupLabel":"AI Native 훈련","sectionId":"ch2","code":"AGENT-02","title":"Tool adapter interface","summary":""},{"docId":"ai-native-agent-runtime","docLabel":"05 Agent Runtime 구현","groupLabel":"AI Native 훈련","sectionId":"ch3","code":"AGENT-03","title":"Approval policy","summary":""},{"docId":"ai-native-agent-runtime","docLabel":"05 Agent Runtime 구현","groupLabel":"AI Native 훈련","sectionId":"ch4","code":"AGENT-04","title":"Idempotency와 retry","summary":"모든 실패를 재시도하면 사고가 납니다. 네트워크 타임아웃과 외부 쓰기 성공 여부 불명확 상태를 구분해야 합니다."},{"docId":"ai-native-agent-runtime","docLabel":"05 Agent Runtime 구현","groupLabel":"AI Native 훈련","sectionId":"ch5","code":"AGENT-05","title":"Audit와 Replay","summary":""},{"docId":"ai-native-agent-runtime","docLabel":"05 Agent Runtime 구현","groupLabel":"AI Native 훈련","sectionId":"ch6","code":"AGENT-06","title":"MCP/plugin trust boundary","summary":""},{"docId":"ai-native-agent-runtime","docLabel":"05 Agent Runtime 구현","groupLabel":"AI Native 훈련","sectionId":"sample","code":"SAMPLE","title":"Agent runtime 리뷰 예시","summary":"Agent runtime 산출물은 “도구를 호출했다”가 아니라, 위험한 호출을 승인·재시도·감사·재생할 수 있음을 보여줘야 합니다."},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch1","code":"OP-00","title":"운영 전체 지도","summary":"인프라·운영은 네트워크, 배포, 모니터링을 따로 외우는 영역이 아니다. 운영자는 request path, change path, control plane, data plane, recovery path를 한 장으로 연결해야 한다. 사용자의 요청은 DNS → CDN/WAF → Load Balancer → Runtime → Data store를 지나고, 변경은"},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch2","code":"OP-01","title":"4주 학습 순서","summary":"학습 순서는 서비스 장애를 좁히는 순서와 같아야 한다. 1주차에는 브라우저에서 DB까지 요청 경로를 그리고, 2주차에는 VPC, subnet, route table, NAT, ingress, egress, private endpoint를 붙인다. 3주차에는 CI/CD, artifact, runtime, health check, IaC 변경을 배포 경로로 묶"},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch3","code":"OP-02","title":"계층별 실패 모드","summary":"운영 실력은 장애 때 어떤 계층을 먼저 의심하고 어떤 증거로 배제하는지에서 드러난다. DNS/TLS, CDN/WAF, Load Balancer, runtime, DB, network policy, deploy pipeline, observability, incident process마다 대표 실패 모드와 첫 확인 증거가 다르다."},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch4","code":"OP-03","title":"운영 산출물과 답변 구조","summary":"운영 문서는 아키텍처 다이어그램만으로 끝나지 않는다. owner, escalation, SLO, dashboard, alert, runbook, rollback plan, RPO/RTO, 변경 이력, 비용 owner, access owner, 마지막 drill 날짜가 있어야 다음 사람이 같은 판단을 반복할 수 있다. 면접에서도 도구 이름보다 경로, 경계, "},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"인프라·운영 로드맵은 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"인프라·운영 로드맵 체크리스트는 운영 전체 지도, 4주 학습 순서, 계층별 실패 모드, 운영 산출물과 답변 구조의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"인프라·운영 로드맵 플레이북은 OPERATIONS READINESS PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"인프라·운영 로드맵은 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"인프라·운영 로드맵에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"신규 서비스를 런칭하기 전 운영 준비도 리뷰를 진행한다. 요청 경로는 DNS, CDN/WAF, Load Balancer, Runtime, DB로 그리고, 변경 경로는 CI/CD, artifact, config, environment, metric gate로 확인한다. 복구 경로는 rollback, feature flag off, traffic shift, "},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"인프라·운영 로드맵에서 자주 틀리는 판단은 운영 전체 지도와 운영 산출물과 답변 구조의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-roadmap","docLabel":"00 인프라·운영 로드맵","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"인프라·운영은 요청 경로, 변경 경로, 복구 경로를 함께 보는 영역이라고 답합니다. 사용자의 요청은 DNS부터 DB까지 계층별로 흐르고, 코드 변경은 artifact와 환경 설정, 런타임, 관측, 장애 대응 절차를 거쳐 안전해집니다. 저는 각 단계의 실패 모드와 검증 증거를 연결하고, 원인 확정 전에도 사용자 영향 완화책을 선택하는 방식으로 운영 준비도를 "},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch1","code":"REQ-00","title":"기준 경로","summary":"대표 경로는 DNS → CDN/WAF → Load Balancer → App → DB다. 장애가 나면 사용자의 증상, DNS 해석, TLS handshake, CDN cache, WAF 차단, Load Balancer target health, 애플리케이션 로그, DB connection pool을 같은 시간축에 올린다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch2","code":"REQ-01","title":"DNS와 TLS","summary":"DNS가 잘못되면 애플리케이션 로그가 비어 있을 수 있다. TLS 인증서 만료, SNI 불일치, intermediate chain 누락은 네트워크 연결은 되지만 HTTPS에서 실패하는 전형적인 원인이다. curl -v, openssl s_client, dig 결과를 함께 남긴다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch3","code":"REQ-02","title":"Load Balancer와 health check","summary":"Load Balancer는 단순 분산 장치가 아니라 장애 격리 장치다. health check path가 실제 의존성을 너무 깊게 보거나 너무 얕게 보면 정상 pod가 빠지거나 죽은 앱이 살아 있는 것처럼 보인다. 502는 upstream 연결 실패, 504는 timeout으로 우선 분리한다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch4","code":"REQ-03","title":"앱과 DB 경계","summary":"App → DB 구간은 connection pool, timeout, transaction lock, migration, secret rotation이 얽힌다. 프론트 증상만 보고 API 문제로 단정하지 말고, traceId로 request log, slow query, DB wait event를 이어 본다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"서비스 요청 경로는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"서비스 요청 경로 체크리스트는 기준 경로, DNS와 TLS, Load Balancer와 health check, 앱과 DB 경계의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"서비스 요청 경로 플레이북은 REQUEST PATH TRIAGE PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"서비스 요청 경로는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"서비스 요청 경로에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"특정 시간대에 로그인 API가 간헐적으로 504를 반환한다. 먼저 DNS와 TLS가 정상인지 배제하고, CDN/WAF 차단 로그와 Load Balancer target health를 본다. 그 다음 App의 request latency와 DB connection pool 대기를 확인해 timeout이 어디에서 시작됐는지 좁힌다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"서비스 요청 경로에서 자주 틀리는 판단은 기준 경로와 앱과 DB 경계의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-request-path","docLabel":"01 서비스 요청 경로","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"요청 장애는 DNS → CDN/WAF → Load Balancer → App → DB 순서로 좁힌다고 답합니다. 각 hop마다 볼 증거가 다르기 때문에 dig, curl -v, LB target health, 애플리케이션 로그, DB slow query를 같은 시간축에 놓고 판단합니다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch1","code":"NET-00","title":"CIDR과 subnet","summary":"VPC CIDR은 RFC 1918 대역을 쓰더라도 사내망, 고객사망, peering, VPN, Private Endpoint와 겹치면 나중에 막힌다. subnet은 public, private, data 계층으로 나누고 AZ 확장과 reserved IP를 고려한다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch2","code":"NET-01","title":"route table","summary":"route table은 패킷의 다음 hop을 정한다. 0.0.0.0/0이 Internet Gateway인지 NAT Gateway인지, 고객사 CIDR이 VPN Gateway로 가는지, 더 구체적인 prefix가 Longest Prefix Match로 우선되는지 확인한다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch3","code":"NET-02","title":"ingress와 egress","summary":"ingress는 외부에서 들어오는 경로이고 egress는 내부에서 나가는 경로다. private subnet의 서버가 외부 API를 호출하려면 NAT, DNS, outbound security group, NACL, return path가 모두 맞아야 한다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch4","code":"NET-03","title":"Private Endpoint","summary":"DB, object storage, managed API를 인터넷으로 나가지 않고 호출해야 할 때 Private Endpoint 또는 PrivateLink 계열을 검토한다. 이때 DNS override와 endpoint policy까지 함께 봐야 트래픽이 의도한 사설 경로로 흐른다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"VPC·Subnet·Routing·NAT는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"VPC·Subnet·Routing·NAT 체크리스트는 CIDR과 subnet, route table, ingress와 egress, Private Endpoint의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"VPC·Subnet·Routing·NAT 플레이북은 VPC ROUTING EVIDENCE PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"VPC·Subnet·Routing·NAT는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"VPC·Subnet·Routing·NAT에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"private subnet의 배치 작업이 외부 결제 API를 호출하지 못한다. route table의 0.0.0.0/0이 NAT로 향하는지, security group outbound와 NACL 응답 포트가 열려 있는지, DNS가 public endpoint를 해석하는지, return path가 가능한지 순서대로 확인한다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"VPC·Subnet·Routing·NAT에서 자주 틀리는 판단은 CIDR과 subnet와 Private Endpoint의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-vpc-routing","docLabel":"02 VPC·Subnet·Routing·NAT","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"VPC 문제는 CIDR, subnet, route table, security policy, DNS, return path 순서로 설명합니다. 특히 private subnet의 egress는 NAT나 Private Endpoint가 있어야 하며, ingress와 egress를 분리해서 검증해야 합니다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch1","code":"SEC-00","title":"공개면 줄이기","summary":"인터넷에 공개되는 것은 DNS record, CDN, WAF, Load Balancer 정도로 제한한다. App, DB, cache, queue는 private subnet에 두고 관리 접근은 VPN, bastion, SSO, short-lived credential로 제한한다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch2","code":"SEC-01","title":"WAF와 방화벽","summary":"WAF는 L7의 악성 요청 패턴을 줄이고, security group은 stateful L4 허용 목록을 만든다. NACL은 stateless subnet 경계라 응답 포트까지 고려해야 한다. 차단 로그가 남지 않는 규칙은 운영 중 원인 분석을 어렵게 만든다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch3","code":"SEC-02","title":"IAM과 secret","summary":"IAM은 사람, 서비스, pipeline, workload identity를 분리한다. secret은 repo, image, log, frontend bundle에 들어가면 안 된다. rotation 절차에는 revoke, 재발급, 배포, 영향 범위 확인이 포함된다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch4","code":"SEC-03","title":"검증 질문","summary":"위협 모델링은 public ingress, 인증 우회, 권한 상승, secret 노출, egress 악용, 로그 공백을 먼저 본다. 이 서비스의 public ingress는 어디인가? egress는 어떤 도메인과 포트까지 허용되는가? 관리자 권한은 누가 승인하고 얼마나 유지되는가? 침해 시 어떤 로그로 행위를 추적할 수 있는가?"},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"보안 경계는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"보안 경계 체크리스트는 공개면 줄이기, WAF와 방화벽, IAM과 secret, 검증 질문의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"보안 경계 플레이북은 SECURITY BOUNDARY OPERATIONS PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"보안 경계는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"보안 경계에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"외부 공개 API를 신규 오픈한다. WAF rule과 rate limit을 먼저 적용하고, Load Balancer 뒤의 App은 private subnet에 둔다. IAM은 배포 권한과 운영 조회 권한을 분리하고, 인증 실패·차단·권한 거부 로그가 관측 시스템으로 들어오는지 확인한다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"보안 경계에서 자주 틀리는 판단은 공개면 줄이기와 검증 질문의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-security-boundary","docLabel":"03 보안 경계","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"보안 경계는 공개면 최소화, 네트워크 통제, IAM 최소 권한, secret 관리, 감사 로그로 나눠 답합니다. WAF와 방화벽은 역할이 다르고, 침해를 완전히 막는 것보다 탐지와 피해 제한까지 설계하는 것이 중요합니다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch1","code":"DNS-00","title":"DNS record와 TTL","summary":"A, AAAA, CNAME, ALIAS, TXT, CAA record의 목적을 구분한다. TTL은 장애 대응 속도와 resolver 부하 사이의 선택이다. 이전 작업 전 TTL을 낮추고, 작업 후 안정화되면 다시 올린다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch2","code":"DNS-01","title":"split-horizon DNS","summary":"같은 이름이 내부와 외부에서 다른 IP로 해석되는 split-horizon DNS는 VPN, 사내망, Private Endpoint에서 자주 필요하다. 장애 분석 시 사용자가 어느 resolver를 쓰는지 먼저 확인한다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch3","code":"DNS-02","title":"TLS 인증서","summary":"TLS 운영은 인증서 발급만이 아니다. SAN, wildcard 범위, SNI, intermediate chain, OCSP, 자동 갱신, 만료 알림, CAA 정책을 함께 본다. 인증서 교체는 rollback 가능한 변경으로 관리한다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch4","code":"DNS-03","title":"도메인 변경 절차","summary":"도메인 변경에는 사전 TTL 조정, record diff, 인증서 준비, CDN/WAF 연결, smoke test, 전파 모니터링, rollback record가 필요하다. dig, curl -v, openssl s_client 결과를 변경 티켓에 남긴다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"DNS·TLS·도메인 운영은 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"DNS·TLS·도메인 운영 체크리스트는 DNS record와 TTL, split-horizon DNS, TLS 인증서, 도메인 변경 절차의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"DNS·TLS·도메인 운영 플레이북은 DNS TLS CHANGE PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"DNS·TLS·도메인 운영은 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"DNS·TLS·도메인 운영에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"도메인을 새 CDN으로 이전한다. 24~48시간 전에 TTL을 낮추고, 새 CDN에 인증서를 미리 붙인다. CAA와 DNS record diff를 리뷰하고, 일부 트래픽으로 smoke test를 수행한 뒤 문제가 생기면 이전 record로 rollback한다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"DNS·TLS·도메인 운영에서 자주 틀리는 판단은 DNS record와 TTL와 도메인 변경 절차의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-dns-tls","docLabel":"04 DNS·TLS·도메인 운영","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"DNS와 TLS 운영은 record 변경, 전파, 인증서, 갱신, rollback을 함께 다루는 변경 관리라고 답합니다. dig와 openssl로 실제 사용자가 보는 이름 해석과 인증서 체인을 검증해야 합니다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch1","code":"VPN-00","title":"연결 방식","summary":"Site-to-Site VPN은 빠르게 구축할 수 있지만 인터넷 품질과 IPsec 협상에 의존한다. 전용선, Direct Connect, Interconnect, ExpressRoute, Private Endpoint는 비용과 리드타임이 크지만 예측 가능성과 격리가 좋다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch2","code":"VPN-01","title":"IPsec 협상","summary":"IPsec은 Phase 1에서 IKE SA를 만들고 Phase 2에서 데이터 트래픽용 SA를 만든다. encryption, integrity, DH group, PFS, lifetime, PSK, NAT-T, traffic selector가 양쪽에서 일치해야 한다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch3","code":"VPN-02","title":"라우팅과 방화벽","summary":"터널 UP은 충분하지 않다. local CIDR, peer CIDR, route table, security group, 고객사 방화벽, return path가 맞아야 앱 통신이 된다. CIDR overlap은 설계 단계에서 제거해야 한다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch4","code":"VPN-03","title":"운영 증거","summary":"장애 시 터널 상태, rekey 로그, packet counter, tcpdump, nc, curl 결과를 분리해 본다. 고객사에 요청할 때는 source IP, destination IP, port, timestamp, packet evidence를 제공한다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"VPN·Private Connectivity는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"VPN·Private Connectivity 체크리스트는 연결 방식, IPsec 협상, 라우팅과 방화벽, 운영 증거의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"VPN·Private Connectivity 플레이북은 PRIVATE CONNECTIVITY DEBUG PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"VPN·Private Connectivity는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"VPN·Private Connectivity에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"고객사 ERP와 Site-to-Site VPN을 연결한다. CIDR overlap을 먼저 확인하고, IPsec proposal을 양쪽 문서로 맞춘다. 터널이 올라온 뒤에는 ICMP가 아니라 실제 API port와 DB port를 nc, tcpdump, 애플리케이션 health check로 검증한다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"VPN·Private Connectivity에서 자주 틀리는 판단은 연결 방식와 운영 증거의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-private-connectivity","docLabel":"05 VPN·Private Connectivity","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"VPN은 암호화 터널, 라우팅, 방화벽, DNS, 애플리케이션 포트 검증이 모두 맞아야 한다고 답합니다. Phase 1/2 협상과 서비스 통신 성공을 구분하는 것이 핵심입니다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch1","code":"CD-00","title":"pipeline stage","summary":"좋은 pipeline은 install, lint, typecheck, test, build, artifact publish, deploy, smoke test, metric gate가 분리되어 있다. 실패한 stage가 명확해야 재시도와 rollback 판단이 빨라진다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch2","code":"CD-01","title":"artifact","summary":"운영에 배포되는 단위는 branch가 아니라 artifact다. image digest, commit SHA, migration version, config version, build provenance를 묶어야 어떤 코드가 어디에 배포됐는지 추적된다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch3","code":"CD-02","title":"environment","summary":"development, staging, production은 같은 artifact에 다른 environment config를 주입하는 구조가 안정적이다. secret, public config, runtime config를 분리하고 권한 있는 approval 없이 production 변경이 나가지 않게 한다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch4","code":"CD-03","title":"rollback과 release strategy","summary":"rolling, blue-green, canary, feature flag는 모두 rollback 비용을 줄이기 위한 선택지다. DB 변경은 expand-contract로 나누고, rollback이 불가능한 변경은 forward fix와 feature off 절차를 먼저 준비한다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"CI/CD·Artifact·Environment는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"CI/CD·Artifact·Environment 체크리스트는 pipeline stage, artifact, environment, rollback과 release strategy의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"CI/CD·Artifact·Environment 플레이북은 RELEASE SAFETY PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"CI/CD·Artifact·Environment는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"CI/CD·Artifact·Environment에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"staging에서는 정상인데 production 배포 후 오류율이 증가한다. 배포된 artifact digest와 config version을 먼저 확인하고, feature flag를 끄거나 이전 artifact로 rollback한다. 이후 pipeline에 production smoke test와 error rate gate를 추가한다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"CI/CD·Artifact·Environment에서 자주 틀리는 판단은 pipeline stage와 rollback과 release strategy의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-delivery-pipeline","docLabel":"06 CI/CD·Artifact·Environment","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"CI/CD는 자동화가 아니라 변경 통제 시스템이라고 답합니다. 같은 artifact를 환경별 설정으로 승격하고, 배포 후 smoke test와 metric gate를 통과해야 하며, 실패 시 rollback 또는 feature off 절차가 있어야 합니다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch1","code":"RUN-00","title":"컨테이너 런타임","summary":"컨테이너는 프로세스, filesystem, network namespace, cgroup 제한을 묶은 실행 단위다. CPU, memory, file descriptor, ephemeral storage 제한을 모르고 운영하면 OOM, throttling, log 폭증을 놓친다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch2","code":"RUN-01","title":"오케스트레이션 객체","summary":"Kubernetes 기준으로 Deployment는 desired state, ReplicaSet은 replica 유지, Pod는 실행 단위, Service는 안정된 discovery, Ingress는 외부 HTTP 진입점이다. label과 selector가 어긋나면 정상 pod도 traffic을 받지 못한다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch3","code":"RUN-02","title":"health check","summary":"readiness는 트래픽을 받아도 되는지, liveness는 재시작이 필요한지, startup probe는 느린 부팅을 보호하는지 판단한다. health check가 DB까지 강하게 묶이면 DB 지연 때 전체 pod가 빠질 수 있다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch4","code":"RUN-03","title":"배포 안정성","summary":"rolling update는 maxUnavailable, maxSurge, pod disruption budget, connection draining, graceful shutdown이 함께 맞아야 무중단에 가까워진다. HPA는 CPU만이 아니라 queue lag, request rate 같은 업무 지표도 후보가 된다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"컨테이너·오케스트레이션·Health Check는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"컨테이너·오케스트레이션·Health Check 체크리스트는 컨테이너 런타임, 오케스트레이션 객체, health check, 배포 안정성의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"컨테이너·오케스트레이션·Health Check 플레이북은 RUNTIME ORCHESTRATION PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"컨테이너·오케스트레이션·Health Check는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"컨테이너·오케스트레이션·Health Check에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"배포 중 일부 요청이 502로 실패한다. 새 pod가 readiness 통과 전에 트래픽을 받는지, 종료 pod가 connection draining 없이 내려가는지, graceful shutdown 시간보다 terminationGracePeriod가 짧은지 확인한다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"컨테이너·오케스트레이션·Health Check에서 자주 틀리는 판단은 컨테이너 런타임와 배포 안정성의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-runtime-orchestration","docLabel":"07 컨테이너·오케스트레이션·Health Check","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"컨테이너 운영은 image 실행이 아니라 desired state, health check, resource isolation, traffic routing, graceful shutdown을 맞추는 일이라고 답합니다. readiness와 liveness를 구분하는 것이 무중단 배포의 기본입니다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch1","code":"IAC-00","title":"IaC의 목적","summary":"IaC는 콘솔 클릭을 코드로 바꾸는 것이 아니라 변경 이력, 리뷰, 재현성, 감사 가능성을 얻는 방식이다. Terraform, Pulumi, CloudFormation 모두 state와 실제 리소스의 관계를 이해해야 한다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch2","code":"IAC-01","title":"plan과 apply","summary":"plan은 생성, 수정, 교체, 삭제, 권한 변경을 분류해 리뷰한다. apply 전에는 state lock, workspace, provider version, target environment, destructive change를 확인한다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch3","code":"IAC-02","title":"drift","summary":"drift는 코드와 실제 인프라가 달라진 상태다. 콘솔 hotfix, 자동 확장, 외부 시스템 변경이 원인이 된다. drift를 무조건 되돌리지 말고 왜 발생했는지, 코드에 흡수할지, 수동 변경을 금지할지 결정한다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch4","code":"IAC-03","title":"변경 티켓","summary":"운영 인프라 변경에는 목적, 영향 범위, plan 요약, 적용 시간, 검증 명령, rollback 또는 forward fix가 필요하다. DB, DNS, network 변경은 전파와 lock 때문에 더 보수적으로 쪼갠다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"IaC·변경관리·Drift는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"IaC·변경관리·Drift 체크리스트는 IaC의 목적, plan과 apply, drift, 변경 티켓의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"IaC·변경관리·Drift 플레이북은 IAC CHANGE REVIEW PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"IaC·변경관리·Drift는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"IaC·변경관리·Drift에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"Terraform plan에서 Load Balancer가 replace로 표시된다. 단순 apply가 아니라 왜 교체가 필요한지, downtime이 발생하는지, create-before-destroy가 가능한지, DNS와 target group 영향이 무엇인지 리뷰한 뒤 적용 여부를 결정한다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"IaC·변경관리·Drift에서 자주 틀리는 판단은 IaC의 목적와 변경 티켓의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-iac-change","docLabel":"08 IaC·변경관리·Drift","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"IaC는 인프라를 코드로 적는 것이 아니라 변경 리뷰와 재현성을 얻는 방식이라고 답합니다. plan, state, drift, apply 후 검증, rollback 또는 forward fix가 모두 절차에 포함되어야 합니다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch1","code":"OBS-00","title":"세 신호","summary":"로그는 사건의 세부 맥락, 메트릭은 시간에 따른 수치, 트레이스는 요청 경로를 보여준다. 세 신호가 traceId, service, environment, version으로 연결되어야 장애 시 요청 단위로 원인을 좁힐 수 있다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch2","code":"OBS-01","title":"RED와 USE","summary":"HTTP 서비스는 RED(rate, error, duration)를 먼저 본다. 인프라 리소스는 USE(utilization, saturation, errors)를 본다. p95/p99 latency, error rate, saturation은 평균보다 사용자 영향을 잘 드러낸다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch3","code":"OBS-02","title":"SLO","summary":"SLO는 사용자 경험을 기준으로 잡는 내부 신뢰성 목표다. SLA처럼 외부 보상 약속 자체는 아니지만, 제품 약속과 운영 우선순위의 근거가 된다. SLI를 정의하고 error budget을 계산하면 모든 경고를 paging하지 않고 사용자 영향이 큰 실패에 집중할 수 있다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch4","code":"OBS-03","title":"SLO burn rate","summary":"SLO burn rate는 error budget이 얼마나 빠르게 소진되는지 보는 방식이다. 짧은 창과 긴 창을 함께 사용하면 급격한 장애와 느린 품질 저하를 모두 잡을 수 있다. 알림에는 owner, dashboard, runbook 링크가 있어야 한다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"Observability·SLO는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"Observability·SLO 체크리스트는 세 신호, RED와 USE, SLO, SLO burn rate의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"Observability·SLO 플레이북은 SLO OBSERVABILITY DESIGN PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"Observability·SLO는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"Observability·SLO에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"새 릴리스 후 p99 latency만 증가하고 error rate는 안정적이다. 평균 latency가 아니라 tail latency를 보고, trace에서 특정 downstream 호출이 느려졌는지 확인한다. SLO burn rate가 빠르게 증가하면 paging하고, 느린 소진이면 ticket으로 관리한다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"Observability·SLO에서 자주 틀리는 판단은 세 신호와 SLO burn rate의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-observability-slo","docLabel":"09 Observability·SLO","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"관측 가능성은 로그, 메트릭, 트레이스를 모으는 것이 아니라 장애 판단 시간을 줄이는 설계라고 답합니다. SLO와 error budget을 기준으로 알림을 나누고, burn rate로 빠른 장애와 느린 품질 저하를 구분합니다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch1","code":"INC-00","title":"역할","summary":"장애가 커지면 Incident Commander, scribe, communications owner, subject matter expert를 나눈다. 한 사람이 원인 분석, 의사결정, 공지를 모두 맡으면 시간이 갈수록 판단 품질이 떨어진다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch2","code":"INC-01","title":"초기 대응","summary":"처음 15분에는 사용자 영향, 최근 변경, error budget 소진, 핵심 지표, 우회 가능성을 확인한다. 원인 확정 전에는 rollback, traffic shift, feature flag off 같은 사용자 영향 완화책을 우선 고려한다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch3","code":"INC-02","title":"rollback과 restore","summary":"rollback은 이전 artifact로 돌아가는 것이고 restore는 데이터나 상태를 복구하는 것이다. migration이 포함된 변경은 rollback이 어려울 수 있으므로 expand-contract, backup, restore drill이 필요하다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch4","code":"INC-03","title":"DR과 사후 분석","summary":"DR은 disaster recovery이며 RPO/RTO로 목표를 말한다. RPO는 허용 가능한 데이터 손실, RTO는 복구 시간 목표다. 운영 리허설은 Rollback drill, Restore drill, traffic shift drill로 나누어 실행한다. postmortem은 비난이 아니라 timeline, contributing factors, "},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"Incident Response·Rollback·DR는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"Incident Response·Rollback·DR 체크리스트는 역할, 초기 대응, rollback과 restore, DR과 사후 분석의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"Incident Response·Rollback·DR 플레이북은 INCIDENT RESPONSE DRILL PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"Incident Response·Rollback·DR는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"Incident Response·Rollback·DR에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"배포 직후 결제 성공률이 급락한다. Incident Commander가 역할을 나누고, 배포 artifact와 feature flag를 확인한다. 원인 분석과 별개로 rollback 또는 flag off로 사용자 영향을 줄인 뒤, 결제 누락 데이터가 있는지 restore와 reconciliation 절차를 실행한다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"Incident Response·Rollback·DR에서 자주 틀리는 판단은 역할와 DR과 사후 분석의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-incident-dr","docLabel":"10 Incident Response·Rollback·DR","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"장애 대응은 역할 분리, 영향 완화, 원인 분석, 복구 검증, 사후 개선의 순서로 답합니다. DR은 RPO/RTO로 목표를 정의하고 Rollback drill과 Restore drill로 실제 복구 가능성을 검증해야 합니다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch1","code":"CHK-00","title":"운영 인수","summary":"운영 인수에는 owner, escalation, architecture diagram, DNS, TLS 인증서, secret 위치, deployment pipeline, dashboard, alert, runbook, rollback, backup, RPO/RTO, 비용 owner가 포함되어야 한다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch2","code":"CHK-01","title":"배포 전 체크","summary":"변경 범위, artifact, migration, config, secret, feature flag, smoke test, metric gate, rollback 조건을 확인한다. 하나라도 말로만 존재하면 운영 준비가 끝난 것이 아니다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch3","code":"CHK-02","title":"장애 대응 체크","summary":"증상, 영향 범위, 시작 시각, 최근 변경, 주요 metric, log, trace, 의사결정, 사용자 공지, 복구 시각을 기록한다. 장애가 끝난 뒤에는 runbook과 alert를 반드시 업데이트한다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch4","code":"CHK-03","title":"면접 답변","summary":"인프라·운영 질문에는 '요청 경로를 먼저 그리고, 실패 지점을 계층별로 좁혔고, 배포와 rollback은 artifact와 metric gate로 통제했으며, 장애 후에는 SLO와 runbook을 개선했다'는 구조로 답한다. 직접 해본 일과 설계 지식의 경계도 함께 말한다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"운영 체크리스트·면접 답변은 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"운영 체크리스트·면접 답변 체크리스트는 운영 인수, 배포 전 체크, 장애 대응 체크, 면접 답변의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"운영 체크리스트·면접 답변 플레이북은 OPERATIONS HANDOFF REVIEW PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"운영 체크리스트·면접 답변은 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"운영 체크리스트·면접 답변에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"서비스를 다른 팀에서 인수받는다. 아키텍처 다이어그램만 받지 않고 DNS, TLS, 배포 pipeline, secret 위치, SLO, dashboard, alert, backup, RPO/RTO, 비용 owner까지 확인한다. 빠진 항목은 인수 후 리스크로 남기지 않고 인수 조건으로 되돌린다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"운영 체크리스트·면접 답변에서 자주 틀리는 판단은 운영 인수와 면접 답변의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-checklist-interview","docLabel":"11 운영 체크리스트·면접 답변","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"운영 경험을 말할 때는 요청 경로, 배포 경로, 관측 지표, 장애 대응, 인수 산출물을 순서대로 설명합니다. 직접 한 일은 구체적 증거로 말하고, 설계 지식은 어떤 기준으로 검증하겠다고 구분합니다."},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"chindex","code":"INDEX","title":"문서 구조","summary":"이 문서는 개념 요약이 아니라 운영 판단 연습용 플레이북입니다. 각 항목은 “무엇을 아는가”보다 “장애 때 어떤 증거를 보고 어떤 가설을 버리는가”를 기준으로 읽습니다."},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch1","code":"CLD-00","title":"웹 서비스 기본 구성","summary":"AWS와 Azure 서비스는 이름을 1:1로 외우면 안 된다. CloudFront와 Azure Front Door는 edge 계층에서 캐시, WAF, 전역 라우팅을 담당하고, Application Load Balancer와 Application Gateway는 regional L7 진입점 역할을 한다. 런타임, 데이터, identity, observabil"},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch2","code":"CLD-01","title":"사설 네트워크와 데이터 경계","summary":"AWS는 VPC, public/private subnet, NAT Gateway, Security Group, VPC Endpoint, AWS PrivateLink로 경계를 만든다. Azure는 VNet, subnet, NAT Gateway, Network Security Group, Private Endpoint, Private Link, Private "},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch3","code":"CLD-02","title":"Secret과 배포","summary":"AWS에서는 IAM role, Secrets Manager, Parameter Store, ECR, CodePipeline 또는 GitHub Actions를 사용한다. Azure에서는 Microsoft Entra ID, Managed Identity, Key Vault, Azure Container Registry, Azure DevOps 또는 GitHub"},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch4","code":"CLD-03","title":"장애와 비용 사례","summary":"CloudFront나 Azure Front Door 캐시 설정 오류는 stale content를 만들고, NAT Gateway 비용 폭증은 private subnet egress 설계가 잘못됐다는 신호일 수 있다. RDS/Azure SQL connection pool 고갈, ALB/Application Gateway health probe 실패, AKS/E"},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch5","code":"MODEL","title":"개념 모델","summary":"AWS·Azure 실전 시나리오는 단일 지식 항목이 아니라 운영 판단의 일부다. 아래 표처럼 개념을 책임, 확인 지표, 실패 신호로 나누면 면접 답변과 실제 장애 대응이 모두 선명해진다."},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch6","code":"CHECK","title":"실무 체크리스트","summary":"AWS·Azure 실전 시나리오 체크리스트는 웹 서비스 기본 구성, 사설 네트워크와 데이터 경계, Secret과 배포, 장애와 비용 사례의 변경 위험을 사전에 드러내기 위한 검토표다. 각 항목은 리뷰, 배포 승인, 운영 인수에서 같은 증거로 다시 확인되어야 한다."},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch7","code":"PLAYBOOK","title":"실무 플레이북","summary":"AWS·Azure 실전 시나리오 플레이북은 AWS AZURE OPERATIONS PLAYBOOK 기준으로 증상, 범위, 최근 변경, 계층별 증거를 연결한다. 목표는 명령어 암기가 아니라 어떤 가설을 버리고 어떤 완화책을 실행할지 결정하는 것이다."},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch8","code":"PRACTICE","title":"출력 판독 훈련","summary":"AWS·Azure 실전 시나리오는 개념을 아는 것보다 실제 출력에서 정상과 비정상을 구분하는 훈련이 중요하다. 아래 lab은 명령, 출력, 판단, 완화, 영구 수정을 한 번에 연결한다."},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch9","code":"TERM","title":"용어사전","summary":"AWS·Azure 실전 시나리오에서 반복적으로 등장하는 운영 용어를 정의, 증거, 오해, 관련 항목 기준으로 정리한다. 장애 중에는 용어 자체보다 해당 용어가 어떤 로그, 지표, 설정, 책임 경계와 연결되는지를 확인한다."},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch10","code":"CASE","title":"장애/운영 시나리오","summary":"B2B SaaS 관리자 서비스를 클라우드에 배포한다. AWS안은 Route 53 → CloudFront/WAF → Application Load Balancer → ECS Fargate → RDS Multi-AZ와 ElastiCache로 구성하고, secret은 Secrets Manager, 이미지는 ECR, 로그와 알림은 CloudWatch로 둔다. Az"},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch11","code":"RISK","title":"자주 틀리는 판단","summary":"AWS·Azure 실전 시나리오에서 자주 틀리는 판단은 웹 서비스 기본 구성와 장애와 비용 사례의 책임 경계를 흐리는 데서 시작된다. 아래 신호가 보이면 설계, runbook, 답변 구조를 다시 점검한다."},{"docId":"operations-cloud-scenarios","docLabel":"12 AWS·Azure 실전 시나리오","groupLabel":"인프라·운영","sectionId":"ch12","code":"Q&A","title":"면접 답변 템플릿","summary":"실제 클라우드 구성 질문에는 먼저 역할을 나눠 답합니다. DNS는 Route 53 또는 Azure DNS, edge는 CloudFront 또는 Azure Front Door, L7 진입점은 Application Load Balancer 또는 Application Gateway, 런타임은 ECS Fargate/EKS 또는 AKS/App Service, 데이터"},{"docId":"operations-ai-llm-operations","docLabel":"13 AI·LLM 운영 Addendum","groupLabel":"인프라·운영","sectionId":"ch1","code":"AI-OPS-01","title":"AI/LLM SLI","summary":"개념 모델은 일반 웹 서비스의 availability, latency, error rate 위에 AI 품질 신호를 얹는 것입니다. 모델 호출이 성공해도 근거 없는 답변, 잘못된 citation, schema 실패, 과도한 비용은 운영 장애입니다."},{"docId":"operations-ai-llm-operations","docLabel":"13 AI·LLM 운영 Addendum","groupLabel":"인프라·운영","sectionId":"ch2","code":"AI-OPS-02","title":"Dashboard 구성","summary":""},{"docId":"operations-ai-llm-operations","docLabel":"13 AI·LLM 운영 Addendum","groupLabel":"인프라·운영","sectionId":"ch3","code":"AI-OPS-03","title":"Prompt/model release","summary":""},{"docId":"operations-ai-llm-operations","docLabel":"13 AI·LLM 운영 Addendum","groupLabel":"인프라·운영","sectionId":"ch4","code":"AI-OPS-04","title":"Incident drill","summary":""},{"docId":"operations-ai-llm-operations","docLabel":"13 AI·LLM 운영 Addendum","groupLabel":"인프라·운영","sectionId":"ch5","code":"AI-OPS-05","title":"LLM Runbook","summary":"실무 체크리스트는 장애 때 바로 실행할 수 있어야 합니다. 아래 항목이 비어 있으면 아직 운영 준비가 끝난 것이 아닙니다."},{"docId":"operations-ai-llm-operations","docLabel":"13 AI·LLM 운영 Addendum","groupLabel":"인프라·운영","sectionId":"term","code":"TERM","title":"AI 운영 TERM 용어 사전","summary":""},{"docId":"operations-ai-llm-operations","docLabel":"13 AI·LLM 운영 Addendum","groupLabel":"인프라·운영","sectionId":"lab","code":"LAB","title":"AI 운영 Practice Lab","summary":""},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"doc-ax","code":"SOURCE","title":"AX 개요","summary":"AX는 AI를 잘 쓰는 기술이 아니라, 업무를 AI가 수행해도 사람이 검증하고 책임질 수 있는 구조로 바꾸는 방식 입니다. 핵심은 긴 프롬프트가 아니라 명세, 컨텍스트, 권한, 검증, 기록입니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"ax-ch1","code":"AX-01","title":"한 문장 정의","summary":"AX는 사람이 책임지는 업무 체계 안에서 AI가 작업하고, 검증받고, 기록되도록 만드는 운영 방식입니다. AI Experience, Agent Experience, AI-augmented eXecution이라는 표현보다 실무에서는 이 한 문장이 더 중요합니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"ax-ch2","code":"AX-02","title":"실행 모델","summary":"AX의 기본 흐름은 Spec → Context → Permission → Execution → Verification → Audit 입니다. 기존의 Model·Harness·Environment 관점을 실제 운영에서는 아래 여섯 산출물로 내려야 합니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"ax-ch3","code":"AX-03","title":"적용 판단 기준","summary":"AX는 모든 업무에 적용하는 구호가 아닙니다. 먼저 Workflow Mining으로 반복 episode를 모으고, 검증 가능성과 실패 비용을 기준으로 적용 후보를 고릅니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"ax-ch4","code":"AX-04","title":"최소 산출물","summary":"AX는 말로 전파되지 않고 표준 산출물로 전파됩니다. 처음부터 큰 플랫폼을 만들 필요는 없지만, 최소한 task spec, context package, verification report는 남겨야 합니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"ax-ch5","code":"AX-05","title":"책임 경계","summary":"AI는 작업자가 될 수 있지만 책임자는 될 수 없습니다. AX 전문가의 핵심 역할은 AI에게 더 많은 문장을 쓰는 것이 아니라 실행 권한과 중단 조건을 정하는 것입니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"ax-ch6","code":"AX-06","title":"첫 도입 순서","summary":"AX 도입은 도구 설치에서 시작하지 않습니다. 조직 진단으로 후보 업무를 고르고, 작은 파일럿에서 실패 비용을 제한한 뒤, 검증된 표준 산출물만 확산합니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"doc-axcap","code":"SOURCE","title":"AX 엔지니어 역량 모델","summary":"AX 엔지니어는 AI를 잘 쓰는 사람이 아니라 업무를 AI가 안전하게 수행할 수 있는 실행 시스템으로 바꾸는 사람 입니다. 핵심 역량은 프롬프트 작성보다 업무 분해, 컨텍스트 설계, 검증, 권한 통제, 효과 측정에 있습니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axcap-ch1","code":"CAP-01","title":"역할 정의","summary":"AX 역량은 개인 사용자, 업무 책임자, 플랫폼 리더가 서로 다른 책임을 나누어 가질 때 조직 역량이 됩니다. 한 사람이 모든 것을 해내는 구조가 아니라 역할별 산출물과 승인 경계를 명확히 하는 구조가 필요합니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axcap-ch2","code":"CAP-02","title":"역량 지도","summary":"역량 지도는 프롬프트 기술 목록이 아니라 업무 분해 관점에서 반복 업무를 실행 가능한 단위로 바꾸는 능력 목록입니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axcap-ch3","code":"CAP-03","title":"성장 레벨","summary":"AX 성장 레벨은 더 복잡한 모델을 쓰는 순서가 아니라 더 넓은 책임 경계를 다루는 순서입니다. 개인 episode에서 팀 workflow, 조직 governance로 이동할수록 산출물의 품질과 추적 가능성이 중요해집니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axcap-ch4","code":"CAP-04","title":"훈련 루브릭","summary":"훈련은 도구 기능 소개보다 실제 업무 episode를 기준으로 평가해야 합니다. 교육 과정은 실습자가 자신의 업무를 가져와 명세, 컨텍스트, 검증, 기록으로 바꾸는 방식이 가장 효과적입니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axcap-ch5","code":"CAP-05","title":"포트폴리오 산출물","summary":"AX 포트폴리오는 데모 영상보다 운영 증거가 중요합니다. 어떤 업무를 선택했고, 어떻게 권한을 제한했으며, 어떤 검증으로 승인했는지 보여주는 산출물이 역량을 증명합니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"doc-axorg","code":"SOURCE","title":"AX 조직 적용 패턴","summary":"AX 도입은 도구 배포가 아니라 소프트웨어 전달 시스템에 AI 실행 계층을 추가하는 조직 변화 입니다. 규모가 커질수록 하네스보다 더 중요한 것은 정책, 지식, 측정, 교육, 책임 경계입니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axorg-ch1","code":"ORG-01","title":"조직 진단","summary":"조직 진단은 “어떤 도구를 살 것인가”가 아니라 어떤 업무가 반복되고, 어떤 검증이 가능하며, 어떤 위험 때문에 자동화를 멈춰야 하는지 확인하는 단계입니다. baseline이 없으면 파일럿 성과도 비용도 판단할 수 없습니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axorg-ch2","code":"ORG-02","title":"파일럿 설계","summary":"파일럿은 성공 사례를 과시하는 행사가 아니라 위험을 제한한 상태에서 조직 학습을 얻는 실험입니다. 처음부터 전사 확산을 목표로 하지 말고 guarded workflow를 한두 개 만들고 실패 조건을 먼저 정합니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axorg-ch3","code":"ORG-03","title":"이해관계자 지도","summary":"AX 도입은 개발팀만의 변화가 아닙니다. 데이터, 보안, 법무, 플랫폼, 운영, 현업 책임자가 각기 다른 위험과 승인 기준을 가집니다. stakeholder map은 확산 전에 반드시 작성해야 합니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axorg-ch4","code":"ORG-04","title":"교육 경로","summary":"교육 경로는 도구 기능 나열이 아니라 역할별 책임을 학습시키는 구조여야 합니다. Practitioner는 episode를 남기고, Workflow Owner는 평가 기준을 만들며, Platform/Adoption Lead는 governance와 지원 체계를 연결해야 합니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axorg-ch5","code":"ORG-05","title":"확산 게이트","summary":"AX 확산은 사용량이 아니라 안정성 기준을 통과할 때 진행합니다. team standard가 생기고 platform support가 준비되며 scaled governance가 감당 가능한 속도일 때만 다음 단계로 넘어갑니다."},{"docId":"practice-ax-foundation","docLabel":"00 AX 기반·조직 적용","groupLabel":"AX 실무","sectionId":"axorg-ch6","code":"ORG-06","title":"운영 지표","summary":"조직 단위 AX 지표는 개인 생산성보다 흐름과 품질을 봐야 합니다. 사용량이 늘어도 review burden, rework, risk event가 함께 늘면 성공이 아닙니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"doc-axauto","code":"SOURCE","title":"AX 업무 자동화 설계","summary":"업무 자동화의 핵심은 AI에게 일을 맡기는 것이 아니라, 업무를 검증 가능한 단위로 쪼개고 위험도에 맞는 자동화 수준을 정하는 것 입니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axauto-ch1","code":"AUTO-01","title":"Workflow Mining","summary":"AX 자동화는 전체 직무를 대체하는 방식보다 반복되는 workflow를 찾아 안정화하는 방식이 실무적입니다. Workflow Mining은 실제 episode를 모아 입력, 판단, 행동, 검증, 예외 처리를 분해하는 훈련입니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axauto-ch2","code":"AUTO-02","title":"후보 선정 매트릭스","summary":"자동화 후보는 감으로 고르지 않습니다. repeatability, verifiability, context stability, permission risk, failure cost, expert bottleneck을 함께 평가해야 합니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axauto-ch3","code":"AUTO-03","title":"Autonomy Ladder","summary":"Autonomy Ladder는 AI에게 맡기는 범위를 단계적으로 넓히는 운영 모델입니다. 팀은 각 workflow가 어느 단계까지 허용되는지 명시하고, merge 금지와 deploy 금지를 기본 정책으로 둡니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axauto-ch4","code":"AUTO-04","title":"Task Spec","summary":"Task Spec은 자동화 episode의 계약서입니다. 좋은 spec은 목표, 비목표, 허용 권한, 필요한 컨텍스트, 검증, 중단 조건을 같은 형식으로 남깁니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axauto-ch5","code":"AUTO-05","title":"교육 실습","summary":"교육 실습은 프롬프트 작성보다 업무를 자동화 가능한 단위로 바꾸는 연습에 집중합니다. 참가자는 실제 업무 사례를 가져와 matrix, ladder, task spec으로 변환합니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axauto-ch6","code":"AUTO-06","title":"도입 체크포인트","summary":""},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"doc-axcontext","code":"SOURCE","title":"Context Engineering","summary":"Context Engineering은 정보를 많이 넣는 기술이 아니라 지금 작업에 필요한 정보를 충분하지만 오염되지 않게, 출처와 함께 제공하는 기술 입니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axcontext-ch1","code":"CTX-01","title":"Context source inventory","summary":"컨텍스트 품질은 어떤 자료를 넣을지보다 먼저 어떤 자료원이 존재하는지 파악하는 데서 시작합니다. 팀은 반복 업무마다 source inventory를 만들고, 각 source의 소유자와 갱신 주기를 적어야 합니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axcontext-ch2","code":"CTX-02","title":"품질 기준","summary":"좋은 컨텍스트는 길지 않습니다. 현재 결정에 필요한 정보가 관련성 순서로 들어 있고, 신뢰 수준과 출처가 분리되어 있습니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axcontext-ch3","code":"CTX-03","title":"신뢰 경계","summary":"모델은 주어진 텍스트 안에서 지시와 자료를 혼동할 수 있습니다. untrusted content는 내부 정책이나 시스템 지시와 격리하고, prompt injection 가능성을 항상 검토합니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axcontext-ch4","code":"CTX-04","title":"Package Template","summary":""},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axcontext-ch5","code":"CTX-05","title":"실패 모드","summary":""},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"doc-axharness","code":"SOURCE","title":"AI Harness Engineering","summary":"AI Harness Engineering은 모델을 더 똑똑하게 만드는 일이 아니라, 모델이 실무 작업을 안정적으로 수행하도록 작업 환경을 설계하는 일 입니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axharness-ch1","code":"HAR-01","title":"하네스의 역할","summary":"하네스는 모델과 실제 개발 환경 사이의 런타임 계층입니다. 이 계층은 무엇을 보게 할지, 어떤 도구를 쓰게 할지, 어디까지 수정하게 할지, 무엇을 완료 증거로 인정할지를 통제합니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axharness-ch2","code":"HAR-02","title":"Architecture","summary":"AUTOMATION HARNESS ARCHITECTURE는 agent 하나를 뜻하지 않습니다. 모델 호출, 도구 연결, 권한 판단, 컨텍스트 구성, 검증, 감사, 사람 인계가 분리된 실행 시스템입니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axharness-ch3","code":"HAR-03","title":"Policy","summary":"harness policy는 agent의 행동 범위를 실행 전에 고정합니다. 기본값은 dry-run과 read-only이며, 쓰기나 외부 영향이 있는 행동은 approval gate를 통과해야 합니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axharness-ch4","code":"HAR-04","title":"Design Worksheet","summary":""},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axharness-ch5","code":"HAR-05","title":"실패 모드","summary":""},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axharness-ch6","code":"HAR-06","title":"도입 성숙도","summary":""},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"doc-axloop","code":"SOURCE","title":"Loop Engineering","summary":"Loop Engineering은 에이전트 작업을 단발성 명령이 아니라 입력, 실행, 검증, 반성, 중단 조건을 가진 반복 가능한 시스템 으로 설계하는 기술입니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axloop-ch1","code":"LOOP-01","title":"루프의 정의","summary":"AI 코딩은 생성보다 루프 운영이 중요합니다. 좋은 루프는 매 반복마다 불확실성을 줄이고, 나쁜 루프는 더 많은 파일을 읽고 더 많은 코드를 바꾸며 더 많은 가정을 만듭니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axloop-ch2","code":"LOOP-02","title":"Plan Act Verify Reflect","summary":""},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axloop-ch3","code":"LOOP-03","title":"State Transition","summary":"루프는 상태 기계처럼 운영합니다. 각 iteration은 state transition을 만들고, 상태 전이가 없으면 반복을 멈추고 spec이나 context를 보강해야 합니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axloop-ch4","code":"LOOP-04","title":"Stop Condition","summary":"stop condition은 실패 인정이 아니라 품질 통제입니다. 루프가 불확실성을 줄이지 못하면 더 돌리는 것이 아니라 범위를 다시 잡아야 합니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axloop-ch5","code":"LOOP-05","title":"Failure Attribution","summary":"Failure Attribution은 “모델이 틀렸다”로 끝내지 않습니다. 실패 원인을 spec, context, tool, permission, verification, model reasoning 중 어디에 둘지 나누어야 다음 루프가 나아집니다."},{"docId":"practice-ax-workflow","docLabel":"01 AX 실행 루프·자동화","groupLabel":"AX 실무","sectionId":"axloop-ch6","code":"LOOP-06","title":"Loop Log","summary":"주간 workflow improvement review에서는 성공 사례보다 반복 실패를 먼저 봅니다. unclear spec, missing tests, unsafe permission, context gap이 반복되면 프롬프트가 아니라 업무 정의와 하네스를 고칩니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"doc-axmulti","code":"SOURCE","title":"Multi-Agent Workflow","summary":"멀티 에이전트 워크플로우는 많은 에이전트를 돌리는 기술이 아니라 서로 다른 책임과 관점을 분리해 자기검열의 약점을 줄이는 운영 방식 입니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axmulti-ch1","code":"MA-01","title":"역할 분리","summary":"코드를 작성한 에이전트에게 최종 평가까지 맡기지 않습니다. 작성자는 구현 의도에 끌리고, 리뷰어는 실제 동작과 위험에 집중해야 합니다. independent roles reduce risk: 독립 역할은 같은 착각을 반복하는 자기검열 위험을 낮춥니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axmulti-ch2","code":"MA-02","title":"언제 쓰는가","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axmulti-ch3","code":"MA-03","title":"워크트리 전략","summary":"여러 에이전트가 같은 브랜치에서 동시에 수정하면 충돌과 책임 혼란이 생깁니다. 독립 워크트리는 실험, 구현, 리뷰, 회귀 확인을 분리합니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axmulti-ch4","code":"MA-04","title":"도구 조합","summary":"반복 절차가 중요하면 skill, 외부 도구 실행이 필요하면 plugin, 외부 데이터가 필요하면 connector, 독립 판단이 필요하면 subagent를 씁니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axmulti-ch5","code":"MA-05","title":"통합과 리뷰","summary":"병렬 작업의 성패는 에이전트 수가 아니라 integration checklist와 conflict-handling 기준에 달려 있습니다. 각 결과에 검증 증거가 없으면 통합하지 않습니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"doc-axverify","code":"SOURCE","title":"검증과 평가","summary":"AI 결과의 신뢰는 그럴듯함에서 나오지 않습니다. 어떤 입력으로, 어떤 도구를 써서, 어떤 검증을 통과했는지 가 남아야 합니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axverify-ch1","code":"EVAL-01","title":"검증의 목적","summary":"AI output은 초안입니다. 신뢰는 독립 검증, 재현 가능한 trace, 실패 원인 분류에서 나옵니다. “테스트 통과”와 “충분히 검증됨”은 다릅니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axverify-ch2","code":"EVAL-02","title":"Episode Package","summary":"Episode package는 하나의 AI 작업을 재현 가능한 평가 단위로 저장한 것입니다. 최종 diff만 저장하면 왜 그런 변경이 나왔는지, 무엇을 검증했는지 알 수 없습니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axverify-ch3","code":"EVAL-03","title":"Failure Classification","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axverify-ch4","code":"EVAL-04","title":"Adversarial Verification","summary":"검증자는 결과를 통과시키려 하지 말고 깨뜨리려 해야 합니다. 특히 인증, 결제, 권한, 마이그레이션, 캐싱, 보안 변경은 adversarial case가 필요합니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axverify-ch5","code":"EVAL-05","title":"평가 체크리스트","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axverify-ch6","code":"EVAL-06","title":"자동화 성과 평가","summary":"AX 자동화는 “AI가 만든 양”이 아니라 업무 흐름이 실제로 좋아졌는지로 평가합니다. 특히 리뷰 부담과 재작업은 생성 속도 뒤에 숨어 있는 비용입니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"doc-axgov","code":"SOURCE","title":"AI Governance & Security","summary":"AI agent는 강력한 자동화 사용자입니다. 그래서 권한, 데이터 경계, 도구 실행, 감사 로그, 사람 승인 이 설계되어야 합니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axgov-ch1","code":"GOV-01","title":"AI threat model","summary":"AI agent는 사용자, 코드, 외부 입력, 도구 사이의 권한 중개자입니다. 거버넌스 위협 모델은 “모델이 실수할 수 있다”가 아니라 “모델이 untrusted content를 지시로 오해하거나 위험한 도구를 실행할 수 있다”에서 출발합니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axgov-ch2","code":"GOV-02","title":"Injection","summary":"README, 이슈 본문, 웹페이지, 이메일, CSV, 로그는 모두 untrusted content입니다. 그 안의 문장은 데이터일 뿐 지시가 아닙니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axgov-ch3","code":"GOV-03","title":"Data leakage","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axgov-ch4","code":"GOV-04","title":"Permission boundary","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axgov-ch5","code":"GOV-05","title":"Audit log","summary":"사고 후 누가 무엇을 왜 바꿨는지 재구성할 수 없으면 거버넌스가 아닙니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"doc-axcase","code":"SOURCE","title":"AX 실전 적용 사례","summary":"실무 AX는 멋진 프롬프트보다 문제, 하네스, 검증, 지표, 실패 모드가 함께 정의된 사례 에서 배워야 합니다. 아래 사례는 특정 회사 내부 자료가 아니라 공개 연구와 현업 패턴을 바탕으로 재구성한 적용 모델입니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axcase-ch1","code":"CASE-01","title":"사례 읽는 법","summary":"AX 사례는 “무엇을 AI로 했는가”보다 “어떤 업무를 어떤 위험 경계 안에서 자동화했는가”로 읽습니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axcase-ch2","code":"CASE-02","title":"대규모 조직","summary":"Problem : PR 수가 늘며 reviewer가 핵심 위험보다 스타일 noise에 시간을 씁니다. Workflow : diff 수집, risk map 생성, reviewer triage, owner 승인 순서로 운영합니다. Harness : PR diff, ownership, 테스트 결과, 최근 장애를 묶습니다. Context : 보안, migratio"},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axcase-ch3","code":"CASE-03","title":"소규모 셀","summary":"Problem : 작은 제품 셀에서 접근성, 성능, 핵심 사용자 흐름 점검이 PR마다 흔들립니다. Workflow : 변경 화면 식별, screenshot 비교, axe/Lighthouse 실행, 수정 후보 triage로 운영합니다. Harness : changed components, route, screenshots, axe result, Lightho"},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axcase-ch4","code":"CASE-04","title":"업무별 사례","summary":"Problem : DB migration이 lock, backward compatibility, rollback 위험을 충분히 드러내지 못합니다. Workflow : schema diff 분석, expand-contract 확인, dry-run, 승인으로 진행합니다. Harness : migration SQL, table size, query plan, a"},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axcase-ch5","code":"CASE-05","title":"실패 사례","summary":"Problem : AI 리뷰와 생성 코드가 도입됐지만 delivery 품질은 좋아지지 않았습니다. Workflow : 도구 배포 후 각 팀이 자유롭게 사용했고 공통 gate가 없었습니다. Harness : episode 저장소, eval set, 실패 taxonomy가 없었습니다. Context : 업무별 위험도와 승인 경계가 빠졌습니다. Permissio"},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"doc-axplay","code":"SOURCE","title":"AX 실무 플레이북","summary":"이 문서는 AI를 매일 개발 업무에 넣을 때 쓰는 실행 절차와 교육 과정입니다. 목표는 빠른 생성이 아니라 제한된 시간과 비용 안에서 검증 가능한 변경을 만드는 것 입니다."},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axplay-ch1","code":"PLAY-01","title":"AI Coding Workflow","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axplay-ch2","code":"PLAY-02","title":"리뷰 루프","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axplay-ch3","code":"PLAY-03","title":"테스트·마이그레이션 루프","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axplay-ch4","code":"PLAY-04","title":"프롬프트 템플릿","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axplay-ch5","code":"PLAY-05","title":"Capstone","summary":""},{"docId":"practice-ax-scale-governance","docLabel":"02 AX 확장·거버넌스","groupLabel":"AX 실무","sectionId":"axplay-ch6","code":"PLAY-06","title":"업무 자동화 운영","summary":"실무에서 AX 자동화는 한 번에 완성하지 않습니다. 반복 업무를 수집하고, 작은 하네스로 실험하고, 검증 지표를 보고, 팀 표준으로 남길 것만 확장합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"이 문서는 원문을 단순히 이어 읽는 자료가 아니라, 새 기능이나 화면 개선을 시작할 때 문제 정의, 정보구조, 사용자 흐름, 상태·예외, 검증 기준을 하나의 산출물로 닫기 위한 실무 워크북입니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-foundation-routes","code":"ROUTES","title":"상황별 실행 루트","summary":"디자인 기반 문서는 처음부터 끝까지 읽는 것보다 현재 작업의 위험에 맞춰 들어가는 편이 실용적입니다. 아래 루트는 문제 정의, IA, flow, 검증 중 어디에서 멈춰야 하는지 정하는 기준입니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-foundation-canvas","code":"CANVAS","title":"Problem-to-Flow Canvas","summary":"이 캔버스는 이 문서의 최종 산출물입니다. 한 기능을 설계할 때 아래 항목을 채우면 문제 정의, IA, 사용자 흐름, 상태·예외, 검증 기준이 한 장으로 닫힙니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-foundation-case","code":"CASE","title":"관통 사례: 대량 권한 변경","summary":"아래 사례는 이 문서의 개념을 하나의 기능에 끝까지 적용한 예시입니다. 포인트는 버튼 배치가 아니라 문제, 객체, 권한, 상태, 실패 복구, 검증 기준을 한 흐름으로 닫는 것입니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-foundation-handoff","code":"HANDOFF","title":"개발 핸드오프 패킷","summary":"디자인 산출물이 개발로 넘어갈 때 화면만 전달되면 상태와 예외가 누락됩니다. 아래 패킷은 프론트엔드, 백엔드, QA가 같은 계약을 보게 만드는 최소 단위입니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-foundation-decision-gate","code":"GATE","title":"검증·결정 기준","summary":"리서치와 지표는 보기 좋은 첨부물이 아니라 의사결정을 바꾸는 기준이어야 합니다. 아래 기준 중 하나라도 비어 있으면 “검증 예정”이 아니라 “결정 기준 미정”으로 표시합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"doc-design","code":"SOURCE","title":"디자인 개요","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-ch1","code":"DES-01","title":"디자인의 목적","summary":"좋은 디자인은 사용자의 인지 비용을 낮추고, 제품이 원하는 행동을 무리 없이 수행하게 만듭니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-ch2","code":"DES-02","title":"UI와 UX","summary":"UI가 깔끔해도 UX가 나쁠 수 있습니다. 예를 들어 버튼은 예쁘지만 사용자가 왜 눌러야 하는지 모르거나, 오류가 난 뒤 복구 방법이 없으면 제품 경험은 실패합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-ch3","code":"DES-03","title":"좋은 디자인의 기준","summary":"시각적 완성도는 중요하지만 충분조건이 아닙니다. 실무 디자인 리뷰에서는 “예쁜가”보다 “사용자가 더 적은 판단으로 더 안전하게 목표를 달성하는가”를 먼저 봅니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-ch4","code":"DES-04","title":"제품 팀 협업","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-ch5","code":"DES-05","title":"제품 디자인 의사결정 프레임","summary":"심도 있는 디자인은 화면 취향이 아니라 제품 목표, 사용자 행동, 운영 제약을 함께 판단합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-ch6","code":"DES-06","title":"경험 전략과 품질 모델","summary":"전문적인 제품 디자인은 화면 단위 산출물이 아니라 제품 전략, 사용자 행동, 운영 비용, 시스템 제약을 하나의 경험 모델로 연결합니다. “좋아 보이는가”보다 “어떤 행동 변화를 만들고 어떤 위험을 줄이는가”를 먼저 정의합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-ch7","code":"DES-07","title":"디자인 크리틱 루브릭","summary":"고급 디자인 리뷰는 취향 토론을 피하고 근거의 품질을 봅니다. 리뷰어는 “더 예쁘게”가 아니라 어떤 가정이 약하고 어떤 리스크가 검증되지 않았는지를 지적해야 합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"design-ch8","code":"DES-08","title":"학습 순서","summary":"디자인 학습은 개별 화면 꾸미기보다 문제 정의에서 운영 검증까지 이어지는 순서로 익혀야 실무 판단으로 전환됩니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"doc-designux","code":"SOURCE","title":"UX 사고와 문제 정의","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designux-ch1","code":"UX-01","title":"문제와 솔루션","summary":"“검색 필터를 추가하자”는 솔루션이고, “사용자가 원하는 항목을 찾지 못한다”가 문제입니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designux-ch2","code":"UX-02","title":"사용자 이해","summary":"업무 시스템에서는 “사용자”가 구매자, 승인자, 실무자, 관리자, 감사자처럼 여러 역할로 나뉩니다. 같은 화면도 역할별 목표와 권한이 다르면 완전히 다른 UX가 됩니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designux-ch3","code":"UX-03","title":"가설과 지표","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designux-ch4","code":"UX-04","title":"리서치 신호","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designux-ch5","code":"UX-05","title":"의사결정 프레임","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designux-ch6","code":"UX-06","title":"문제 정의 심화","summary":"좋은 문제 정의는 사용자의 말, 행동 데이터, 비즈니스 손실, 기술 제약을 분리해서 봅니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designux-ch7","code":"UX-07","title":"Discovery 시스템","summary":"Discovery는 인터뷰 몇 번 하고 결론 내는 단계가 아닙니다. 제품이 풀 문제를 계속 갱신하기 위한 운영 시스템입니다. 정성 신호, 정량 신호, 지원 티켓, 세일즈 피드백, 사용 로그를 같은 문제 저장소로 모아야 합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designux-ch8","code":"UX-08","title":"가정·리스크 매핑","summary":"제품 디자인의 위험은 대부분 “사용자가 원할 것이다”, “이해할 것이다”, “운영 가능할 것이다”, “기술적으로 쉽게 될 것이다” 같은 검증되지 않은 가정에서 생깁니다. 가정은 명시하고, 위험도에 따라 검증 비용을 다르게 써야 합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"doc-designia","code":"SOURCE","title":"정보구조와 내비게이션","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designia-ch1","code":"IA-01","title":"정보구조의 목적","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designia-ch2","code":"IA-02","title":"분류와 위계","summary":"메뉴는 조직도가 아니라 사용자 작업 모델을 따라야 합니다. 내부 팀 구조를 그대로 노출하면 사용자는 기능을 찾기 어렵습니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designia-ch3","code":"IA-03","title":"내비게이션 패턴","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designia-ch4","code":"IA-04","title":"검색·필터·정렬","summary":"검색과 필터가 많아질수록 “현재 결과가 왜 이렇게 나왔는가”를 설명해야 합니다. 활성 조건, 결과 수, empty state, reset action을 함께 설계합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designia-ch5","code":"IA-05","title":"업무형 IA","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designia-ch6","code":"IA-06","title":"정보구조 검증","summary":"정보구조는 회의실에서 정한 메뉴명이 아니라 사용자가 실제로 찾을 수 있는 구조여야 합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designia-ch7","code":"IA-07","title":"Taxonomy와 객체 모델","summary":"고급 IA는 메뉴 배치가 아니라 제품의 객체 모델을 사용자가 이해할 수 있는 언어로 번역하는 일입니다. 고객, 주문, 캠페인, 승인 요청 같은 핵심 객체와 그 관계가 흐리면 검색, 권한, 상세 화면, 감사 로그가 모두 흔들립니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designia-ch8","code":"IA-08","title":"권한·상태 기반 IA","summary":"실무 제품의 IA는 모든 사용자에게 같은 메뉴를 보여주는 문제가 아닙니다. 역할, 권한, 데이터 소유권, 객체 상태에 따라 보이는 정보와 가능한 액션이 달라집니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"doc-designflow","code":"SOURCE","title":"사용자 흐름과 태스크 설계","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designflow-ch1","code":"FLOW-01","title":"Flow의 종류","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designflow-ch2","code":"FLOW-02","title":"Happy path와 예외","summary":"흐름 설계는 정상 경로만 그리면 부족합니다. 실제 제품은 예외와 중단, 재개가 더 중요할 때가 많습니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designflow-ch3","code":"FLOW-03","title":"상태 설계","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designflow-ch4","code":"FLOW-04","title":"마찰과 안전장치","summary":"모든 마찰이 나쁜 것은 아닙니다. 위험한 행동에는 의도적인 마찰이 필요하고, 반복 업무에는 마찰을 줄여야 합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designflow-ch5","code":"FLOW-05","title":"체크리스트","summary":""},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designflow-ch6","code":"FLOW-06","title":"실패와 중복을 포함한 흐름","summary":"실무 플로우는 happy path보다 재시도, 중복 제출, 권한 변경, 장시간 작업의 복구가 더 중요합니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designflow-ch7","code":"FLOW-07","title":"상태 머신과 전이","summary":"복잡한 사용자 흐름은 화면 순서가 아니라 상태 전이로 설계해야 합니다. 특히 승인, 결제, 권한, 자동화, 배포처럼 되돌리기 어렵거나 비동기 처리가 있는 흐름은 상태 머신 없이 설계하면 예외가 누락됩니다."},{"docId":"practice-design-foundation","docLabel":"00 디자인 기반·사용자 흐름","groupLabel":"디자인 실무","sectionId":"designflow-ch8","code":"FLOW-08","title":"서비스 블루프린트","summary":"사용자 흐름이 화면 안에서만 끝난다고 보면 실무 품질이 낮아집니다. 실제 경험은 고객 행동, 프론트 스테이지 UI, 백오피스 작업, 시스템 처리, 지원팀 대응이 함께 만들어냅니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"디자인 실행 문서는 세부 항목이 많으므로 왼쪽 목차는 문서 단위로 압축했습니다. 레이아웃과 인터랙션에서 시작해 폼, 컴포넌트, 시스템, AX, 접근성, 검증, 핸드오프 순서로 읽습니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"doc-designlayout","code":"SOURCE","title":"UI 레이아웃과 시각 위계","summary":"레이아웃은 요소를 배치하는 일이 아니라 사용자의 시선을 설계하는 일입니다. 좋은 화면은 어떤 정보가 중요하고, 어떤 행동을 먼저 해야 하며, 어떤 것은 나중에 봐도 되는지 구조적으로 알려줍니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designlayout-ch1","code":"LAY-01","title":"레이아웃의 역할","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designlayout-ch2","code":"LAY-02","title":"그리드와 간격","summary":"간격은 장식이 아니라 정보의 관계를 표현합니다. 가까운 것은 관련 있고, 멀리 떨어진 것은 다른 그룹으로 인식됩니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designlayout-ch3","code":"LAY-03","title":"시각 위계","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designlayout-ch4","code":"LAY-04","title":"반응형 구조","summary":"반응형은 화면을 줄였을 때 요소가 그냥 접히는 것이 아니라 우선순위가 재배치되는 것입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designlayout-ch5","code":"LAY-05","title":"리뷰 기준","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designlayout-ch6","code":"LAY-06","title":"인지 법칙과 업무 UI","summary":"레이아웃 판단은 감각만으로 하지 않습니다. 사용자의 시선, 선택지 수, 조작 거리, 반복 업무의 피로를 기준으로 봅니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designlayout-ch7","code":"LAY-07","title":"정보 밀도와 스캔 전략","summary":"업무형 제품에서 좋은 레이아웃은 여백이 많은 화면이 아니라 사용자가 반복 판단을 빠르게 할 수 있는 화면입니다. 정보 밀도는 낮출수록 좋은 값이 아니라 업무 빈도, 위험도, 비교 필요성에 맞춰 조절해야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designlayout-ch8","code":"LAY-08","title":"레이아웃 성능·운영 제약","summary":"레이아웃은 시각 구조인 동시에 프론트엔드 성능과 운영 데이터의 영향을 받습니다. 대량 목록, 동적 컬럼, 권한별 버튼, 긴 다국어 텍스트를 고려하지 않은 레이아웃은 실제 데이터에서 쉽게 깨집니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"doc-designinteraction","code":"SOURCE","title":"인터랙션 디자인 패턴","summary":"인터랙션은 사용자의 행동과 시스템의 반응 사이에 신뢰를 만드는 설계입니다. 버튼을 눌렀을 때 무엇이 일어났는지, 기다려야 하는지, 취소할 수 있는지, 실패하면 어떻게 복구하는지가 명확해야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designinteraction-ch1","code":"INT-01","title":"피드백","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designinteraction-ch2","code":"INT-02","title":"선택과 실행","summary":"선택 UI는 사용자가 무엇을 고르는지, 실행 UI는 선택 후 어떤 결과가 생기는지 분리해서 설계합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designinteraction-ch3","code":"INT-03","title":"확인과 되돌리기","summary":"모든 행동에 확인 모달을 붙이면 사용자는 내용을 읽지 않고 확인을 누릅니다. 위험도, 복구 가능성, 빈도에 따라 undo, confirmation, permission gate를 구분해야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designinteraction-ch4","code":"INT-04","title":"비동기 상태","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designinteraction-ch5","code":"INT-05","title":"패턴 선택","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designinteraction-ch6","code":"INT-06","title":"고급 인터랙션 판단","summary":"인터랙션 패턴은 멋진 효과가 아니라 지연, 실패, 위험, 반복 사용을 다루는 운영 전략입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designinteraction-ch7","code":"INT-07","title":"분산 상태와 낙관적 UI","summary":"현대 제품의 인터랙션은 브라우저 상태, 서버 상태, 캐시, 큐, 다른 사용자의 변경이 동시에 얽힙니다. 낙관적 UI는 단순히 빠르게 보이게 하는 기술이 아니라 실패와 충돌을 설계할 때만 안전합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designinteraction-ch8","code":"INT-08","title":"위험 행동 인터랙션","summary":"삭제, 권한 변경, 대량 적용, 배포, 결제처럼 손실이 큰 행동은 마찰을 줄이는 것보다 실수 방지와 책임 추적이 먼저입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"doc-designforms","code":"SOURCE","title":"폼과 입력 경험","summary":"폼은 사용자에게 일을 시키는 인터페이스입니다. 좋은 폼은 필요한 데이터만 묻고, 입력 형식을 예측 가능하게 만들며, 오류가 생겼을 때 사용자가 빠르게 고칠 수 있게 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designforms-ch1","code":"FORM-01","title":"폼의 목적","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designforms-ch2","code":"FORM-02","title":"입력 설계","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designforms-ch3","code":"FORM-03","title":"검증과 오류","summary":"오류 메시지는 사용자를 탓하는 문구가 아니라 복구 안내입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designforms-ch4","code":"FORM-04","title":"복잡한 폼","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designforms-ch5","code":"FORM-05","title":"체크리스트","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designforms-ch6","code":"FORM-06","title":"실무 폼 설계 심화","summary":"폼 UX는 프론트 입력 컴포넌트만으로 끝나지 않습니다. 검증 위치, 저장 전략, API 오류 계약이 함께 맞아야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designforms-ch7","code":"FORM-07","title":"데이터 계약과 오류 모델","summary":"고급 폼 설계는 필드 배치가 아니라 데이터 계약 설계입니다. 프론트 validation, 서버 validation, 비즈니스 rule, 권한 오류, 동시 수정 충돌이 사용자에게 어떻게 드러나는지 정의해야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designforms-ch8","code":"FORM-08","title":"고위험 입력과 감사","summary":"권한, 결제, 배포, 개인정보, 보안 설정 폼은 일반 입력과 다르게 설계합니다. 사용자가 값을 입력할 수 있는가보다 변경 영향과 책임을 이해하고 승인했는지가 중요합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"doc-designcomponents","code":"SOURCE","title":"컴포넌트 패턴","summary":"컴포넌트는 반복되는 UI 조각이 아니라 제품 의사결정을 재사용 가능한 단위로 만든 것입니다. 좋은 컴포넌트는 역할, 상태, 접근성, 사용 제한이 명확합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designcomponents-ch1","code":"CMP-01","title":"컴포넌트의 역할","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designcomponents-ch2","code":"CMP-02","title":"기본 컴포넌트","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designcomponents-ch3","code":"CMP-03","title":"상태와 변형","summary":"variant는 색상 조합이 아니라 의미의 이름이어야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designcomponents-ch4","code":"CMP-04","title":"복합 패턴","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designcomponents-ch5","code":"CMP-05","title":"API 관점","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designcomponents-ch6","code":"CMP-06","title":"컴포넌트 품질과 채택","summary":"컴포넌트는 만들어지는 것보다 제품팀이 일관되게 채택하는 것이 더 어렵습니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designcomponents-ch7","code":"CMP-07","title":"Headless·Compound 패턴","summary":"컴포넌트가 커질수록 prop을 계속 늘리는 방식은 한계가 옵니다. 복잡한 제품 UI는 behavior, accessibility, state는 재사용하되 layout composition은 열어두는 패턴이 필요합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designcomponents-ch8","code":"CMP-08","title":"제품 컴포넌트 거버넌스","summary":"전문적인 컴포넌트 시스템은 “만들어두면 쓰겠지”로 운영되지 않습니다. 채택, 예외, deprecation, migration을 관리해야 제품 전체의 UI 부채를 줄일 수 있습니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"doc-designtokens","code":"SOURCE","title":"디자인 시스템과 토큰","summary":"디자인 시스템은 UI 키트가 아니라 제품 경험을 일관되게 만드는 운영 체계입니다. 토큰, 컴포넌트, 문서, 코드, 변경 절차가 함께 있어야 실제 제품 속도와 품질을 높입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designtokens-ch1","code":"SYS-01","title":"시스템의 목적","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designtokens-ch2","code":"SYS-02","title":"토큰 구조","summary":"토큰은 값의 별칭이 아니라 디자인 결정의 이름입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designtokens-ch3","code":"SYS-03","title":"컴포넌트 가이드","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designtokens-ch4","code":"SYS-04","title":"운영 모델","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designtokens-ch5","code":"SYS-05","title":"성숙도","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designtokens-ch6","code":"SYS-06","title":"토큰 파이프라인과 거버넌스","summary":"디자인 시스템이 커질수록 Figma, 코드, 문서, 릴리스가 어긋나는 문제가 생깁니다. 이를 줄이려면 design token pipeline과 변경 관리가 필요합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designtokens-ch7","code":"SYS-07","title":"멀티 브랜드·테마 전략","summary":"토큰 시스템의 전문성은 다크 모드나 브랜드 색상 변경에서 드러납니다. primitive 값을 직접 화면에 쓰면 테마 확장이 불가능하고, semantic token을 통해 의미를 유지해야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designtokens-ch8","code":"SYS-08","title":"시스템 지표와 ROI","summary":"디자인 시스템은 미학 프로젝트가 아니라 제품 인프라입니다. 따라서 채택률, 리드타임, 회귀 감소, 접근성 품질처럼 운영 지표로 가치를 증명해야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"doc-designaxmotion","code":"SOURCE","title":"AX 인터랙션·마이크로인터랙션","summary":"AX 디자인에서 인터랙션은 “AI가 뭔가 하는 느낌”을 꾸미는 장식이 아닙니다. 사용자가 시스템의 상태를 이해하고, AI 결과를 검토하고, 위험한 자동화를 멈추거나 되돌릴 수 있게 만드는 신뢰 설계입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch1","code":"AXI-01","title":"인터랙션 설계 개요","summary":"AX 제품의 인터랙션은 사용자 의도, AI 처리 상태, 결과 검토, 승인과 복구를 하나의 흐름으로 연결합니다. 일반 UI보다 “시스템이 지금 무엇을 알고 무엇을 모르는가”를 더 명확히 드러내야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch2","code":"AXI-02","title":"AX 인터랙션 원칙","summary":"AX 인터랙션의 목표는 사용자를 놀라게 하는 것이 아니라 사용자가 시스템을 믿고 통제할 수 있게 만드는 것입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch3","code":"AXI-03","title":"입력과 응답 패턴","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch4","code":"AXI-04","title":"AI 처리 상태 디자인","summary":"AI 작업은 즉시 끝나지 않거나 부분적으로 진행될 수 있습니다. 상태 디자인은 기다림을 예쁘게 포장하는 것이 아니라 현재 작업이 살아 있는지, 멈췄는지, 사용자가 뭘 할 수 있는지 알려주는 장치입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch5","code":"AXI-05","title":"마이크로인터랙션","summary":"마이크로인터랙션은 작은 피드백이지만 AX에서는 신뢰의 단서가 됩니다. 복사됨, 저장됨, 적용 대기, 자동화 중단 같은 짧은 상태가 누락되면 사용자는 AI 작업이 실제로 반영됐는지 알 수 없습니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch6","code":"AXI-06","title":"애니메이션 원칙","summary":"AX에서 애니메이션은 “AI가 똑똑해 보이게” 만드는 장식이 아닙니다. 시스템 상태, 변경 위치, 사용자 다음 행동을 더 잘 이해하게 만들 때만 사용합니다. 기본 duration은 짧게 유지하고, 장시간 작업은 progress와 단계 설명으로 보완합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch7","code":"AXI-07","title":"결과 검토 인터랙션","summary":"AX 결과물은 생성보다 검토가 중요합니다. 사용자가 결과를 믿을 수 있으려면 변경 전후, 근거, 위험, 승인 상태가 같은 화면에서 연결되어야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch8","code":"AXI-08","title":"오류와 불확실성","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch9","code":"AXI-09","title":"접근성과 모션 안전성","summary":"AX 인터랙션이 복잡해질수록 접근성은 더 중요합니다. 처리 상태, 스트리밍 결과, 승인 대기, 오류는 시각적 애니메이션만으로 전달하면 안 됩니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch10","code":"AXI-10","title":"실무 패턴 라이브러리","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch11","code":"AXI-11","title":"리뷰 체크리스트","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designaxmotion-ch12","code":"AXI-12","title":"실전 사례","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"doc-designa11y","code":"SOURCE","title":"접근성과 인클루시브 디자인","summary":"접근성은 별도 사용자를 위한 추가 작업이 아니라 다양한 환경에서 제품을 사용할 수 있게 하는 기본 품질입니다. 키보드, 스크린리더, 저시력, 일시적 장애, 느린 네트워크까지 제품 조건으로 다룹니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designa11y-ch1","code":"A11Y-01","title":"접근성 관점","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designa11y-ch2","code":"A11Y-02","title":"키보드와 포커스","summary":"포커스 링은 장식이 아니라 현재 위치를 알려주는 내비게이션입니다. 브랜드 스타일에 맞출 수는 있지만 사라지면 안 됩니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designa11y-ch3","code":"A11Y-03","title":"시각 정보","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designa11y-ch4","code":"A11Y-04","title":"문구와 오류","summary":"인클루시브 디자인은 누구를 배제하는 언어와 흐름이 있는지 점검합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designa11y-ch5","code":"A11Y-05","title":"검증 방법","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designa11y-ch6","code":"A11Y-06","title":"접근성 심화 운영","summary":"접근성은 WCAG 체크리스트를 한 번 통과하는 일이 아니라 컴포넌트, 콘텐츠, QA, 릴리스에 계속 포함되어야 하는 운영 품질입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"doc-designprototype","code":"SOURCE","title":"프로토타입과 사용성 테스트","summary":"프로토타입은 완성도를 보여주기 위한 산출물이 아니라 위험한 가정을 싸게 검증하는 도구입니다. 사용성 테스트는 사용자를 평가하는 일이 아니라 설계가 사용자의 목표 달성을 돕는지 확인하는 과정입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designprototype-ch1","code":"TEST-01","title":"프로토타입 목적","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designprototype-ch2","code":"TEST-02","title":"충실도 선택","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designprototype-ch3","code":"TEST-03","title":"테스트 설계","summary":"좋은 사용성 테스트는 “마음에 드세요?”가 아니라 사용자가 실제 과업을 수행하게 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designprototype-ch4","code":"TEST-04","title":"관찰과 분석","summary":"사용자가 말한 선호보다 실제 행동을 더 신뢰합니다. “괜찮다”고 말해도 과업 중 헤매거나 되묻는다면 설계 문제로 기록해야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designprototype-ch5","code":"TEST-05","title":"의사결정","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designprototype-ch6","code":"TEST-06","title":"사용성 테스트 심화","summary":"테스트 결과는 “좋다/나쁘다”가 아니라 어떤 가정이 깨졌고 어떤 의사결정을 해야 하는지로 정리해야 합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"doc-designhandoff","code":"SOURCE","title":"디자인 핸드오프와 QA","summary":"핸드오프는 디자인 파일을 넘기는 이벤트가 아니라 제품 의도를 구현 가능한 계약으로 바꾸는 과정입니다. 좋은 QA는 픽셀 차이만 보는 것이 아니라 상태, 접근성, 반응형, 오류 흐름까지 확인합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designhandoff-ch1","code":"QA-01","title":"핸드오프의 목적","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designhandoff-ch2","code":"QA-02","title":"스펙 구성","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designhandoff-ch3","code":"QA-03","title":"개발 협업","summary":"디자인과 개발의 간극은 “완성 후 검수”가 아니라 “구현 전 계약”에서 줄어듭니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designhandoff-ch4","code":"QA-04","title":"디자인 QA","summary":""},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designhandoff-ch5","code":"QA-05","title":"출시 전 점검","summary":"핵심 흐름 happy path와 실패 경로 확인 loading/empty/error/permission 상태 확인 모바일과 긴 데이터에서 레이아웃 깨짐 확인 키보드만으로 주요 액션 수행 확인 시스템 컴포넌트와 토큰 이탈 여부 확인 분석 이벤트와 성공 지표 확인 릴리스 후 출시 후에는 디자인이 끝난 것이 아닙니다. 사용 로그, 문의, 오류율, 전환율, 세션 "},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designhandoff-ch6","code":"QA-06","title":"실무 QA와 회귀 관리","summary":"디자인 QA는 시안과 픽셀을 맞추는 일을 넘어 제품 계약이 구현됐는지 확인하는 과정입니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designhandoff-ch7","code":"QA-07","title":"릴리스 품질 게이트","summary":"디자인 QA는 출시 직전 감상평이 아니라 release gate여야 합니다. gate는 차단 기준, 예외 승인자, 출시 후 관측 기준이 함께 있어야 작동합니다."},{"docId":"practice-design-systems","docLabel":"01 디자인 실행·시스템 품질","groupLabel":"디자인 실무","sectionId":"designhandoff-ch8","code":"QA-08","title":"디자인 부채 운영","summary":"디자인 부채는 “나중에 예쁘게”가 아닙니다. 상태 누락, 용어 불일치, 컴포넌트 이탈, 접근성 결함, 추적 불가능한 예외가 쌓이면 제품 변경 속도와 신뢰성이 떨어집니다."},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"visual-foundation-map","code":"MAP","title":"시각디자인 지도","summary":"시각디자인은 예쁜 화면을 만드는 감각이 아니라, 요소를 고르고 그 사이의 관계를 조직해 사용자의 시선·이해·감정·행동을 통제하는 기술이다. 조형 원리를 알면 \"이게 더 나아 보인다\"가 아니라 \"왜 이게 목적에 맞는가\"로 시안을 방어할 수 있다. 이 문서는 재료(요소)에서 시작해 재료를 조직하는 규칙(원리), 사람이 그것을 묶어 보는 방식(Gestalt), "},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"visual-elements","code":"ELEM","title":"점·선·면·형태·공간·질감","summary":"모든 화면은 여섯 가지 기본 재료로 환원된다. 점은 위치와 초점을, 선은 방향과 분리를, 면은 정보의 덩어리와 배경을 만든다. 형태는 실루엣으로 의미를 실어 나르고, 공간은 요소 사이의 관계를 정의하며, 질감은 표면의 감촉과 위계를 만든다. 시안을 비평할 때는 \"이 요소가 어떤 재료로 작동하는가, 그 재료의 시각 기능이 목적과 맞는가\"를 묻는다."},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"visual-principles","code":"PRIN","title":"균형·대비·반복·리듬·정렬·통일·긴장","summary":"원리는 요소들을 조직하는 규칙이다. 요소가 명사라면 원리는 문법이다. 각 원리는 \"잘 됐을 때 만드는 효과\"와 \"깨졌을 때 나오는 실패 신호\"를 짝으로 외워두면 비평이 빨라진다. 시안을 볼 때 원리 이름을 하나씩 대입해 \"이건 어떤 원리를 쓰고 있고, 그게 목적에 맞나\"를 점검한다."},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"scale-proportion","code":"SCALE","title":"스케일·비율·비례","summary":"크기를 임의로 정하면 화면은 눈에 띄지 않게 계속 어긋난다. scale은 크기 값들을 하나의 수열로 묶어 \"이 크기와 저 크기가 같은 체계에서 나왔다\"는 일관성을 만든다. 목표는 값을 줄여 예측 가능성을 높이는 것이지 황금비 같은 마법 숫자를 찾는 것이 아니다."},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"gestalt-principles","code":"GESTALT","title":"게슈탈트 원리","summary":"Gestalt principles는 사람이 낱개 요소를 어떻게 묶고 해석하는지 설명하는 인지 법칙이다. 원리(PRIN)가 \"어떻게 조직할까\"라면 Gestalt는 \"사용자 뇌가 실제로 어떻게 묶어 보는가\"다. 이 둘이 어긋나면 아무리 정렬을 맞춰도 사용자는 다른 관계를 읽는다. UI 비평에서 가장 자주 쓰는 렌즈다."},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"whitespace","code":"SPACE","title":"여백·네거티브 스페이스","summary":"여백(whitespace, negative space)은 채우지 못한 빈 곳이 아니라 의도적으로 배치한 정보다. 여백은 두 가지를 말한다. 요소 사이의 관계(무엇이 무엇에 속하는가)와 중요도(무엇에 숨 쉴 공간을 줬는가). 여백을 아끼는 화면은 정보를 더 담는 게 아니라 관계를 지운다."},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"grid-systems","code":"GRID","title":"그리드·레이아웃 조형","summary":"grid는 요소를 앉힐 보이지 않는 좌표계다. 그리드가 있으면 배치 결정이 \"어디에 둘까(무한한 선택)\"에서 \"어느 칸에 둘까(유한한 선택)\"로 바뀐다. 선택지가 줄면 일관성이 올라가고 협업이 쉬워진다. 그리드는 창의성을 제한하는 게 아니라 매번 재발명하지 않게 해주는 것이다."},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"visual-hierarchy-audit","code":"AUDIT","title":"Visual hierarchy audit","summary":"visual hierarchy는 사용자가 무엇을 먼저, 다음에 무엇을 읽는지의 순서다. 좋은 위계는 눈이 노력 없이 중요한 것부터 훑게 한다. 아래 체크리스트로 시안의 실제 읽기 순서가 의도한 우선순위와 일치하는지 검증한다."},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"composition-critique","code":"CRIT","title":"Composition critique","summary":"composition critique는 시안 전체를 무게·흐름·밀도·초점의 언어로 진단하는 절차다. \"느낌이 이상하다\"를 \"무게가 좌측에 쏠렸고 초점이 분산됐다\"로 번역하면, 고칠 곳과 근거가 함께 나온다. 아래 표로 진단하고, 이어지는 사례로 before/after를 본다."},{"docId":"practice-visual-design-foundations","docLabel":"02 시각디자인 기초·조형 원리","groupLabel":"디자인 실무","sectionId":"glossary","code":"GLOSSARY","title":"조형 용어집","summary":"비평과 handoff에서 자주 쓰는 조형 용어. 정확한 단어를 쓰면 \"이상하다\" 대신 \"무엇이 왜 이상한지\"를 한 문장으로 전달할 수 있다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"color-typography-map","code":"MAP","title":"시각 언어 지도","summary":"시각 언어는 네 층이 겹쳐 작동한다. 색이 의미를 나르고, 대비가 그 의미를 읽을 수 있게 하고, 타이포그래피가 위계와 읽기 리듬을 만들고, 브랜드가 이 셋을 하나의 태도로 묶는다. 어느 한 층만 잘해도 제품은 흔들린다. 이 표는 각 층에서 물어야 할 질문과 그 층이 남겨야 할 산출물을 한눈에 정리한다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"color-fundamentals","code":"COLOR","title":"색채 기본","summary":"색을 말로 다루려면 축이 필요하다. Hue는 색상 계열, saturation은 선명도, value는 밝기다. 여기에 chroma(지각되는 색의 순도), temperature(색온도 인상), harmony(색 사이의 관계)를 더하면 색을 취향이 아니라 좌표로 논의할 수 있다. 좌표로 논의해야 팀이 재현할 수 있다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"color-models","code":"MODEL","title":"색 공간과 모델","summary":"같은 색도 어떤 좌표계로 표현하느냐에 따라 다루기 쉬움이 완전히 달라진다. RGB는 기계가 빛을 섞는 방식이고, HSL/HSB는 사람이 조절하기 편한 방식이며, LCH/OKLCH는 사람의 눈이 실제로 느끼는 차이에 맞춘 방식이다. 디자인 토큰을 만들 때는 이 차이가 곧 유지보수 비용이 된다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"color-harmony","code":"HARMONY","title":"배색 이론","summary":"배색 규칙은 색상환 위의 위치 관계다. 규칙 자체가 아름다움을 보장하지는 않지만, 색을 왜 이렇게 골랐는지 설명 가능하게 만들고 팔레트를 재현 가능하게 만든다. 아래는 자주 쓰는 다섯 관계와, 그 위에 얹는 60-30-10 분배 규칙이다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"palette-decision","code":"PAL","title":"팔레트 결정표","summary":"팔레트는 색 목록이 아니라 역할의 집합이다. 각 색이 \"무엇을 위한 색인가\"로 정의되어야 재사용되고, 화면이 늘어도 무너지지 않는다. 아래 표는 역할별로 무엇을 결정하고 무엇으로 검증하는지 정리한다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"color-accessibility","code":"A11Y","title":"색 접근성","summary":"접근성은 선택이 아니다. 공공·규제 산업 B2B 제품은 특히 대비·색맹 기준을 문서로 요구받는다. 핵심 원리는 셋이다. 텍스트는 배경과 충분히 대비되어야 하고, 의미는 색 하나에만 실리면 안 되고, 색맹 사용자에게도 구분이 살아야 한다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"typography-fundamentals","code":"TYPE","title":"타이포그래피 기본","summary":"타이포그래피는 글꼴을 고르는 취미가 아니라 읽기 조건을 설계하는 일이다. classification, pairing, hierarchy, leading, line length, optical alignment를 함께 판단해야 한다. 하나만 어긋나도 \"왠지 아마추어 같다\"는 인상이 만들어진다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"typography-advanced","code":"DEEP","title":"타이포그래피 심화","summary":"기본을 넘어 글자를 세밀하게 다루려면 용어부터 정확해야 한다. kerning·tracking·leading은 자주 혼용되지만 다른 것을 가리키고, 한글은 라틴 폰트의 상식이 그대로 통하지 않는다. 여기에 OpenType 기능과 variable font까지 알면 UI에서 숫자·표·다국어를 훨씬 깔끔하게 짤 수 있다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"typography-scale","code":"SCALE","title":"타입 스케일","summary":"타입 스케일은 크기를 임의로 정하지 않고 하나의 비율로 묶은 계단이다. 비율이 있으면 새 크기가 필요할 때 계산으로 나오고, 화면 사이 위계가 일관된다. 아래 체크리스트로 스케일을 정의하고, 표에서 흔한 비율을 고른다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"typesetting","code":"SET","title":"본문 조판","summary":"스케일이 크기의 문제라면, 조판은 텍스트 덩어리를 읽기 좋게 앉히는 문제다. 줄 길이, 정렬, 문단 끝 처리, 줄바꿈 — 눈에 잘 안 띄지만 읽기 속도와 피로를 실제로 좌우한다. 리포트·약관·공공 문서처럼 긴 텍스트가 많은 제품일수록 여기서 품질이 갈린다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"brand-language","code":"BRAND","title":"브랜드 시각 언어","summary":"브랜드 시각 언어는 로고 파일보다 훨씬 넓다. 색·타이포·이미지 방향·아이콘 스타일·레이아웃 리듬·모션 태도가 같은 성격을 공유할 때 사용자는 \"같은 제품\"으로 느낀다. 아래 표로 요소를 점검하고, 카드로 정기 audit을 돌린다."},{"docId":"practice-color-typography-brand","docLabel":"03 색채·타이포그래피·브랜드 시각 언어","groupLabel":"디자인 실무","sectionId":"glossary","code":"GLOSSARY","title":"용어집","summary":"색과 타이포에서 자주 쓰지만 혼용되기 쉬운 핵심 용어를 정리한다. 팀 안에서 같은 단어를 같은 뜻으로 쓰는 것이 시각 시스템 유지의 시작이다."},{"docId":"practice-iconography-illustration","docLabel":"04 아이콘·일러스트레이션 시스템","groupLabel":"디자인 실무","sectionId":"icon-illust-map","code":"MAP","title":"아이콘·일러스트 지도","summary":"아이콘과 일러스트는 목적이 다릅니다. 아이콘은 좁은 공간에서 개념을 빠르게 지시하는 기능 부품이고, 일러스트는 분위기와 맥락을 설명하는 서사 요소입니다. 둘을 같은 잣대로 다루면 아이콘은 장식이 되고 일러스트는 파편이 됩니다. 먼저 영역별 책임을 나눕니다."},{"docId":"practice-iconography-illustration","docLabel":"04 아이콘·일러스트레이션 시스템","groupLabel":"디자인 실무","sectionId":"icon-grid","code":"GRID","title":"아이콘 조형 원칙","summary":"아이콘이 한 세트처럼 보이는 이유는 그림 실력이 아니라 공유된 조형 규칙 때문입니다. keyline grid, 일정한 stroke weight, 통일된 corner radius와 terminal, 그리고 눈에 맞춘 optical balance가 그 규칙입니다. 규칙을 문서로 고정해야 여러 사람이 그려도 한 손에서 나온 것처럼 맞습니다."},{"docId":"practice-iconography-illustration","docLabel":"04 아이콘·일러스트레이션 시스템","groupLabel":"디자인 실무","sectionId":"icon-meaning","code":"SEM","title":"의미·메타포·일관성","summary":"아이콘의 가치는 조형이 아니라 의미 전달 속도입니다. 좋은 메타포는 설명 없이 읽히고, 나쁜 메타포는 라벨을 읽어야만 이해됩니다. 문제는 대부분의 개념에 보편적 메타포가 없다는 점입니다. 무엇이 학습 없이 통하고 무엇이 학습을 요구하는지 구분해야 합니다."},{"docId":"practice-iconography-illustration","docLabel":"04 아이콘·일러스트레이션 시스템","groupLabel":"디자인 실무","sectionId":"icon-delivery","code":"SVG","title":"제작·전달(구현)","summary":"아이콘은 디자인 파일에서 끝나지 않고 코드로 전달되어야 의미가 있습니다. 프론트엔드 관점에서 아이콘은 SVG라는 텍스트 자산이고, 색 상속·접근성·번들 방식이 실제 사용성을 좌우합니다. 여기서 결정을 잘못하면 테마 전환에서 색이 안 따라오거나, 스크린리더가 장식을 읽거나, 번들이 불필요하게 커집니다."},{"docId":"practice-iconography-illustration","docLabel":"04 아이콘·일러스트레이션 시스템","groupLabel":"디자인 실무","sectionId":"illust-style","code":"STYLE","title":"일러스트 스타일 시스템","summary":"일러스트가 브랜드처럼 보이려면 개별 그림의 완성도보다 스타일 속성의 일관성이 중요합니다. 선 굵기, 컬러 팔레트, 원근, 디테일 밀도, 질감이라는 몇 개의 축을 고정하면 서로 다른 장면도 한 세계관으로 묶입니다. 먼저 속성을 정의하고, 그다음 용도별 유형을 나눕니다."},{"docId":"practice-iconography-illustration","docLabel":"04 아이콘·일러스트레이션 시스템","groupLabel":"디자인 실무","sectionId":"illust-ops","code":"OPS","title":"일러스트 운영","summary":"일러스트는 한 번 그리고 끝이 아니라 계속 늘어나는 자산입니다. 요청 방식, 재사용 구조, 외주·AI 생성 관리, 파일·export 규칙이 없으면 매번 처음부터 그리게 되고 품질이 흔들립니다. 운영은 \"다음 사람이 최소 비용으로 일관되게 이어갈 수 있는가\"의 문제입니다."},{"docId":"practice-iconography-illustration","docLabel":"04 아이콘·일러스트레이션 시스템","groupLabel":"디자인 실무","sectionId":"pictogram-public","code":"PUB","title":"픽토그램·공공 맥락","summary":"공공·규제 산업 UI에서 아이콘은 취향의 영역이 아니라 명료성과 신뢰의 문제입니다. ISO 계열 공공 픽토그램의 원칙은 단순함이 곧 안전이라는 것입니다. 결제·정산·승인처럼 상태가 곧 돈·규제와 연결되는 화면에서는, 오독 가능한 그림 하나가 실무 사고로 이어질 수 있습니다."},{"docId":"practice-iconography-illustration","docLabel":"04 아이콘·일러스트레이션 시스템","groupLabel":"디자인 실무","sectionId":"review-checklist","code":"CRIT","title":"리뷰 체크리스트","summary":"아이콘·일러스트 리뷰는 \"예쁜가\"가 아니라 조형 일관성, 의미 명료성, 접근성, 전달 품질 네 축으로 봅니다. 아래를 통과하지 못하면 완성도와 무관하게 시스템에 반영하지 않습니다."},{"docId":"practice-iconography-illustration","docLabel":"04 아이콘·일러스트레이션 시스템","groupLabel":"디자인 실무","sectionId":"glossary","code":"GLOSSARY","title":"용어집","summary":""},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"dataviz-map","code":"MAP","title":"데이터 시각화 지도","summary":"시각화는 하나의 스킬이 아니라 몇 개의 독립된 판단이 순서대로 쌓이는 과정입니다. 데이터의 의도를 정하고, 차트 유형을 고르고, 값을 어떤 시각 채널에 실을지 정하고, 축·색으로 왜곡을 제거하고, 마지막에 접근성으로 검증합니다. 아래 표는 이 문서가 다루는 영역과 각 영역이 답하는 질문입니다."},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"chart-selection","code":"PICK","title":"의도별 차트 선택","summary":"차트를 고르는 첫 질문은 \"무슨 차트가 예쁜가\"가 아니라 \"데이터로 무슨 말을 하려는가\"입니다. 의도는 대개 여섯 가지 중 하나입니다. 비교, 시간 추이, 부분과 전체, 분포, 관계, 지리. 의도가 정해지면 후보 차트는 거의 자동으로 좁혀집니다. 취향은 그다음 미세 조정일 뿐입니다."},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"encoding-principles","code":"ENC","title":"시각 인코딩 원리","summary":"차트의 정확도는 데이터를 어떤 시각 채널(visual channel)로 인코딩하느냐로 결정됩니다. 위치, 길이, 각도, 넓이, 색은 모두 값을 담을 수 있지만, 인간이 이 채널들을 읽는 정확도는 같지 않습니다. 이건 취향이 아니라 실험으로 확인된 지각 위계입니다."},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"axes-scales","code":"AXIS","title":"축·스케일·기준선","summary":"축은 차트에서 가장 조용하지만 가장 정직성에 직결되는 부분입니다. 같은 데이터라도 y축 기준선을 어디에 두느냐로 \"안정적\"과 \"급락\"이 갈립니다. 축 설정은 미학이 아니라 데이터가 말하는 크기를 왜곡 없이 전달하는 계약입니다."},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"color-in-dataviz","code":"COLOR","title":"색 사용","summary":"데이터 시각화에서 색은 장식이 아니라 인코딩 채널입니다. 그리고 색은 데이터의 성격에 맞는 팔레트 유형이 정해져 있습니다. 유형을 틀리면 없는 순서를 암시하거나 있는 순서를 지웁니다. 색채의 기본 개념(hue, saturation, value)과 대비 기준은 03 색채·타이포그래피 문서에서 다루고, 여기서는 데이터에 특화된 색 사용을 봅니다."},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"dashboard-hierarchy","code":"DASH","title":"대시보드 정보 위계","summary":"대시보드는 차트의 모음이 아니라 질문에 답하는 순서입니다. 사용자가 화면을 열자마자 던지는 질문(\"지금 상태가 괜찮은가?\")에 가장 크고 위쪽에 있는 요소가 답해야 합니다. 정보 위계가 없으면 차트가 아무리 정확해도 대시보드는 데이터 벽이 됩니다."},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"misleading","code":"WARN","title":"오해 유발 안티패턴","summary":"시각화의 핵심 가치는 아름다움이 아니라 정직성 입니다. 특히 매출·SLA 목표 대비 진행처럼 재무·계약 판단이 걸린 데이터에서는, 차트가 데이터가 말하지 않는 것을 말하게 만드는 순간 그건 오류가 아니라 왜곡입니다. 아래는 의도했든 안 했든 독자를 오도하는 흔한 패턴입니다."},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"dataviz-a11y","code":"A11Y","title":"접근성","summary":"차트는 시각 매체이지만, 값에 도달하는 경로가 시각 하나뿐이면 그 차트는 일부 사용자에게 존재하지 않는 것과 같습니다. 색각 이상, 저시력, 스크린리더 사용자, 키보드 사용자 모두가 값에 도달할 수 있어야 합니다. 접근성은 마지막에 붙이는 게 아니라 인코딩 단계에서 함께 정합니다."},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"ops-report","code":"CASE","title":"운영 분석 리포트 사례","summary":"지금까지의 원리를 실제 화면 하나에 적용해 봅니다. 배경: SaaS 운영 대시보드의 \"월간 운영 현황\" 리포트. 네 가지를 보여줘야 합니다. (1) 월간 사용량 추이, (2) 잔여 예산/할당량, (3) 목표치 대비 진행, (4) 카테고리별 구성. 각각을 어떻게 고르고 오해 없이 보이는지 봅니다."},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"review-checklist","code":"CRIT","title":"리뷰 체크리스트","summary":""},{"docId":"practice-data-visualization","docLabel":"05 데이터 시각화","groupLabel":"디자인 실무","sectionId":"glossary","code":"GLOSSARY","title":"용어집","summary":""},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"motion-map","code":"MAP","title":"모션 지도","summary":"모션은 화면에 생기를 넣는 장식이 아니라, 시간을 쓰는 정보 채널입니다. 사용자의 주의(attention)를 잠깐 빌리는 대가로 무언가를 설명해야 합니다. 이 문서가 다루는 네 영역을 먼저 지도로 봅니다."},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"motion-purpose","code":"WHY","title":"모션의 목적","summary":"모든 모션은 하나 이상의 목적을 가져야 합니다. 목적이 없는 모션은 그냥 소음입니다. 사용자의 시선을 붙잡고, 처리 속도를 늦추고, 배터리를 쓰는데 아무것도 설명하지 않는다면 빼는 게 낫습니다. 모션의 목적은 대략 다섯 가지로 나뉩니다."},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"easing-duration","code":"CURVE","title":"easing · duration","summary":"easing은 시간에 따라 속도가 어떻게 변하는지를 정하는 곡선입니다. 현실의 물체는 즉시 최고 속도에 도달하지 않고 가속하며, 멈출 때 감속합니다. 선형(linear) 모션이 기계적으로 느껴지는 이유입니다. 핵심 직관 하나: 화면에 들어오는 것은 감속(ease-out)하고, 나가는 것은 가속(ease-in)한다."},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"choreography","code":"CHOR","title":"안무","summary":"여러 요소가 동시에 움직이면 눈은 어디를 봐야 할지 모릅니다. 안무(choreography)는 요소들의 등장·이동 순서와 타이밍을 조율해 하나의 이야기로 읽히게 하는 일입니다. 원칙은 하나입니다. 동시에 다 움직이지 않는다."},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"transitions","code":"TRANS","title":"의미 있는 전환","summary":"전환(transition)은 두 상태를 잇는 다리입니다. 상태가 갑자기 바뀌면 사용자는 \"무엇이 어떻게 달라졌는지\"를 스스로 재구성해야 합니다. 좋은 전환은 그 재구성을 대신 해줍니다. 방향성, 상태 변화, 레이아웃 이동 세 가지를 부드럽게 잇는 것이 핵심입니다."},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"microinteractions","code":"MICRO","title":"마이크로인터랙션","summary":"마이크로인터랙션은 단일 목적의 작은 순간입니다. 토글 하나, 좋아요 하나, 입력 검증 하나. Dan Saffer의 구조를 빌리면 trigger → rules → feedback → loops/modes 로 나뉩니다. 무엇이 시작시키고(trigger), 어떤 규칙으로 동작하며(rules), 무엇을 되돌려주고(feedback), 시간·반복에 따라 어떻게 달라지"},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"performance","code":"PERF","title":"구현 · 성능","summary":"부드러워 보이려면 프레임을 놓치지 않아야 합니다. 60fps는 프레임당 약 16.7ms의 예산을 뜻합니다. 이 예산 안에서 브라우저가 스타일 계산·레이아웃·페인트·합성을 끝내야 합니다. 원리는 단순합니다. 애니메이션은 transform과 opacity만 건드린다. 이 둘은 layout과 paint를 건너뛰고 compositor에서 처리되기 때문입니다."},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"motion-accessibility","code":"A11Y","title":"접근성 · 모션 안전","summary":"모션은 일부 사용자에게 불편이 아니라 신체 증상을 유발합니다. 전정기관(vestibular) 장애가 있는 사람은 큰 화면 이동·parallax·zoom·autoplay에서 어지럼증, 메스꺼움, 방향 상실을 겪을 수 있습니다. 그래서 원칙은 하나입니다. 안전이 기본값이다. 화려함은 옵트인, 절제는 디폴트입니다."},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"review-checklist","code":"CRIT","title":"리뷰 체크리스트","summary":"모션은 코드 리뷰에서 자주 빠집니다. 눈으로는 \"괜찮아 보인다\"로 넘어가기 쉽기 때문입니다. 아래 네 축으로 점검하면 감각이 아니라 원리로 판단할 수 있습니다."},{"docId":"practice-motion-animation","docLabel":"06 모션·애니메이션 원리","groupLabel":"디자인 실무","sectionId":"glossary","code":"GLOSSARY","title":"용어집","summary":""},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"photo-literacy-map","code":"MAP","title":"사진학 지도","summary":"이미지를 잘 쓴다는 것은 예쁜 사진을 고르는 감각이 아니라, 촬영 조건과 편집 의도를 읽고 목적에 맞는지 판단하는 능력이다. 제품 사진, 프로필, 리포트 그래픽, 랜딩 hero는 각각 다른 정보를 전달해야 하고, 잘못된 노출·왜곡·과보정은 곧 신뢰의 손상이다. 아래 표는 이 문서가 다루는 영역과 각 영역에서 물어야 할 핵심 질문을 요약한다."},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"exposure-triangle","code":"EXP","title":"Exposure triangle","summary":"Exposure triangle은 aperture(조리개), shutter speed(셔터 속도), ISO(감도)의 상호관계다. 세 값은 어떤 조합으로든 같은 밝기(exposure value)를 만들 수 있지만, 밝기만 같을 뿐 심도·움직임 표현·노이즈는 전혀 달라진다. 그래서 \"적정 노출\"은 하나가 아니라, 무엇을 살릴지에 따라 선택하는 것이다. 개발자에"},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"lens-perspective","code":"LENS","title":"렌즈·원근·심도","summary":"focal length(초점거리)는 단순한 확대 배율이 아니다. 초점거리가 바뀌면 원근감, 배경 압축, 얼굴·제품 형태의 인상이 함께 바뀐다. 흔히 \"광각은 왜곡, 망원은 압축\"이라고 하지만, 실제 왜곡의 원인은 렌즈보다 촬영 거리(카메라와 대상의 거리)다. 가까이서 광각으로 찍으면 가까운 부분이 과장되고, 멀리서 망원으로 찍으면 원근이 눌린다."},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"light-composition","code":"LIGHT","title":"빛과 조명","summary":"사진은 결국 빛을 기록하는 것이다. 같은 대상도 빛의 방향·질·색온도가 바뀌면 형태와 감정 톤이 완전히 달라진다. 방향은 입체감을, 질(hard/soft)은 그림자의 성격을, 색온도는 분위기와 색 정확성을 결정한다. 인공광을 다룰 때는 three-point lighting이 기본 문법이다."},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"color-processing","code":"PROC","title":"색·현상 처리","summary":"촬영 후 색과 톤을 다루는 단계다. 개발자에게 이 단계는 \"raw 데이터를 렌더링 가능한 표현으로 encode하는 파이프라인\"에 가깝다. white balance로 색 기준을 잡고, RAW/JPEG 중 어디서 작업할지 정하고, tone curve와 color grading으로 톤을 설계한다. 여기서 넘지 말아야 할 선이 retouching ethics — "},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"composition-photo","code":"COMP","title":"구도 심화","summary":"구도는 프레임 안에서 시선을 배치하는 문법이다. 규칙 자체가 목적이 아니라, 사람의 시지각(어디를 먼저 보고 어떻게 이동하는가)을 이용해 정보 우선순위를 만드는 도구다. 규칙은 안정감을 주지만 기계적으로 적용하면 밋밋해진다. 언제 따르고 언제 깰지가 실력이다."},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"image-quality-review","code":"RUBRIC","title":"이미지 품질 리뷰","summary":"이미지를 승인·반려할 때 감이 아니라 항목으로 본다. 아래 rubric은 리뷰의 최소 체크 축이다. 각 항목은 \"좋은 상태\"와 \"탈락 신호\"를 함께 두어, 무엇을 보면 반려해야 하는지 명확히 한다."},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"image-pipeline","code":"PIPE","title":"이미지 파이프라인","summary":"촬영·보정이 끝난 이미지를 웹으로 전달하는 단계는 프론트엔드 개발자의 직접 책임 영역이다. 화질과 용량, 성능(LCP)과 접근성(alt) 사이에서 판단해야 하고, 잘못하면 아무리 좋은 사진도 느리고 흐릿하게 나간다. 큰 흐름은 아래와 같다."},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"ai-stock-risk","code":"RISK","title":"AI·스톡 이미지 점검","summary":"스톡 이미지와 AI 생성 이미지는 빠르게 시각 분위기를 만들지만, 진정성·권리·정확성·bias·브랜드 적합성 리스크를 동시에 가져온다. 특히 공공·규제 산업 맥락에서는 \"실재하지 않는 것을 실재처럼\" 보이게 하는 것이 규제·신뢰 문제로 직결된다."},{"docId":"practice-photography-image-literacy","docLabel":"07 사진학·이미지 리터러시","groupLabel":"디자인 실무","sectionId":"glossary","code":"GLOSSARY","title":"용어집","summary":""},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"ai-ux-map","code":"MAP","title":"AI 제품 UX의 핵심 문제","summary":"일반 소프트웨어 UX는 \"버튼을 누르면 정해진 결과가 나온다\"는 결정론 위에 서 있다. AI 제품은 그 전제가 깨진다. 같은 질문에 다른 답이 나오고, 그럴듯하지만 틀린 답이 나오고, 근거 없이 확신한다. 그래서 AI UX의 일은 결과를 예쁘게 보여주는 게 아니라, 결과를 얼마나 믿어야 하는지 를 사용자가 판단하도록 돕는 것이다. 아래 다섯 문제가 이 문서"},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"uncertainty","code":"UNCERT","title":"불확실성 표시","summary":"가장 흔한 실수는 모델의 confidence 점수(예: 0.87)를 그대로 화면에 노출하는 것이다. 이 숫자는 두 가지 이유로 위험하다. 첫째, 대부분의 LLM confidence는 보정(calibration)되어 있지 않다 — 0.9라고 해서 실제로 90% 맞는 게 아니다. 둘째, 사용자는 숫자를 보고도 \"그래서 내가 뭘 해야 하지?\"를 모른다. 불확실성"},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"citation","code":"CITE","title":"출처·근거 UI","summary":"RAG 제품의 신뢰는 출처에서 만들어지고 출처에서 무너진다. 핵심은 \"링크가 있다\"가 아니라 \"그 링크가 실제로 이 주장을 뒷받침하는가 \"다. 출처 UI의 계약은 아래와 같다. 주장 → 출처 chip → 근거 미리보기 → 문서 내 위치 → 최종 수정일 → 접근 권한 상태 → 잘못된 출처 신고. 이 사슬 중 하나라도 끊기면 사용자는 검증을 포기하고, 검증을 "},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"review-approval","code":"REVIEW","title":"생성 결과 검토·승인","summary":"모델 출력을 사용자·시스템에 곧바로 반영할지, 사람 승인을 거칠지는 결과의 영향 범위와 되돌릴 수 있는 정도 로 정한다. 읽고 마는 요약과 외부로 나가는 공문, 시스템을 바꾸는 실행은 같은 정책일 수 없다. 위험이 커질수록 확인 단계를 늘리고, 감사 로그를 남긴다."},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"generation-ux","code":"GEN","title":"생성 UX 패턴","summary":"생성은 시간이 걸리고, 중간 상태가 있고, 결과가 완성형이 아니다. 이 세 성질을 인터페이스가 정직하게 드러내야 한다. 스트리밍으로 진행을 보여주고, 복잡한 결과는 점진적으로 펼치고, 결과는 고칠 수 있게 하고, 사용자가 무엇을 물어봐도 되는지 를 알려 준다."},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"errors-refusal","code":"FAIL","title":"에러·거절·복구","summary":"AI 제품의 에러는 두 종류를 반드시 구분한다. expected failure (예상된 실패 — 근거 없음, 정책상 거절, rate limit, timeout)와 bug (진짜 오류 — null, 파싱 실패, 서버 500)다. 전자는 정상 흐름의 일부로 설계하고, 후자는 신고·복구 경로를 준다. 둘을 같은 \"오류가 발생했습니다\" 화면으로 뭉개면 사용자는 자"},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"human-handoff","code":"HANDOFF","title":"Human handoff","summary":"좋은 AI UX는 사람이 개입해야 하는 순간을 숨기지 않는다. 오히려 그 순간을 먼저 감지해 넘긴다 . 핸드오프는 실패가 아니라 설계된 안전장치다. 넘겨야 할 신호는 대체로 네 가지 — 근거가 약할 때, 위험이 높을 때, 정책이 모호할 때, 사용자가 같은 지적을 반복할 때. 넘길 때는 담당자가 맥락을 다시 캐지 않도록 handoff packet 을 함께 넘"},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"trust-mental-model","code":"TRUST","title":"신뢰·기대 설정","summary":"사용자는 AI 제품을 쓰면서 머릿속에 \"이건 뭘 할 수 있고 뭘 못 하는가\"라는 mental model을 만든다. 이 모델이 틀리면 두 방향으로 사고가 난다. over-trust (automation bias — 틀린 답도 검증 없이 믿음)와 under-trust (맞는 답도 못 믿어 안 씀). 둘 다 위험하고, 해법은 하나다 — 능력과 한계를 정직하게 노"},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"accessibility","code":"A11Y","title":"접근성","summary":"AI UX의 동적 특성 — 스트리밍, 상태 변화, 실시간 근거 표시 — 은 접근성을 특히 어렵게 만든다. 시각적으로 나타나는 변화가 스크린리더 사용자에게 전달되지 않으면, 그 사용자에게는 화면이 조용히 멈춰 있는 것과 같다. 대비·명도 같은 정적 접근성은 별도 문서의 원칙(WCAG 대비 기준 등)을 따르고, 여기서는 AI 특유의 동적 접근성 에 집중한다."},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"qa-matrix","code":"QA","title":"AI UX QA Matrix","summary":"일반 QA는 \"기능이 동작하는가\"를 본다. AI UX QA는 거기에 더해 불확실성·근거·거절·피드백·접근성이 제대로 노출되는가 를 검증한다. happy path만 통과하고 실패 경로를 안 보면, 정작 사고가 나는 경로가 검증 안 된 채 나간다. 아래를 출시 전 체크리스트로 쓴다."},{"docId":"design-ai-product-ux","docLabel":"08 AI 제품 UX·신뢰 설계","groupLabel":"디자인 실무","sectionId":"glossary","code":"GLOSSARY","title":"용어집","summary":"이 문서에서 쓴 핵심 용어를 정리한다. 팀 안에서 이 단어들의 뜻을 맞춰 두면, \"신뢰 설계\"를 감각이 아니라 공통 어휘로 논의할 수 있다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"암기용 요약이 아니라 작업 중 5초 안에 찾아 복사할 참조입니다. 도메인마다 핵심 명령·스니펫, 판단 한 줄, 자주 터지는 것, 장애 증거 카드 네 블록으로 정리했습니다. 개념 설명은 개발 핸드북, 면접 답변은 커리어 핸드북이 담당합니다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheat-routes","code":"ROUTES","title":"상황별 사용 루트","summary":"전체를 처음부터 읽지 않습니다. 지금 겪는 상황에 맞는 문서 2~3개만 연결해 빠르게 증거를 모읍니다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"doc-cheatfe","code":"SOURCE","title":"Frontend","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatfe-ch1","code":"FE-CS-01","title":"핵심 명령·스니펫","summary":"화면을 고치기 전에 증거부터 고정한다. DevTools로 병목을 나누고, CLI로 번들·성능·리소스 크기를 측정한다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatfe-ch2","code":"FE-CS-02","title":"판단 한 줄","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatfe-ch3","code":"FE-CS-03","title":"자주 터지는 것 · 즉시 확인","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatfe-ch4","code":"FE-CS-04","title":"장애 증거 1카드","summary":"영향 범위와 데이터 변경 여부부터 확인. 데이터를 바꾸지 않는 flag off를 우선, 배포 회귀면 rollback, 정적 자산 stale이면 CDN purge. 원인 미확정 상태로 hotfix 배포 금지."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"doc-cheatbe","code":"SOURCE","title":"Backend","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatbe-ch1","code":"BE-CS-01","title":"핵심 명령·스니펫","summary":"# 헤더까지 보기 — status, 응답 헤더 확인 (가장 많이 씀) curl -i https://api.example.com/orders/42 # 상태코드만 뽑기 curl -s -o /dev/null -w '%{http_code}\\n' https://api.example.com/health # POST + JSON + 멱등키 (재시도 안전) curl -X"},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatbe-ch2","code":"BE-CS-02","title":"판단 한 줄","summary":"인증 쿠키는 HttpOnly (JS 접근 차단) + Secure (HTTPS 전용) + SameSite (CSRF 완화) 세 개 세트로. SameSite=Lax 가 기본 권장, 크로스사이트 전송이 꼭 필요하면 SameSite=None; Secure ."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatbe-ch3","code":"BE-CS-03","title":"자주 터지는 것 · 즉시 확인","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatbe-ch4","code":"BE-CS-04","title":"장애 증거 1카드","summary":"중복 생성·결제가 진행 중이면 쓰기 경로를 먼저 중단 (flag off)하고 affected row를 식별한다. 단일 release 회귀면 rollback, 상류 장애면 traffic shedding·retry 축소로 격리. data migration이 얽힌 변경은 rollback 전에 정합성부터 확인."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"doc-cheatdb","code":"SOURCE","title":"Database","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdb-ch1","code":"DB-CS-01","title":"핵심 명령·스니펫","summary":"실행계획 → 인덱스 → 락 → 통계 순으로 본다. 아래 스니펫은 대부분 복붙 후 테이블/컬럼명만 바꾸면 된다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdb-ch2","code":"DB-CS-02","title":"판단 한 줄","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdb-ch3","code":"DB-CS-03","title":"자주 터지는 것 · 즉시 확인","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdb-ch4","code":"DB-CS-04","title":"장애 증거 1카드","summary":"인덱스 추가는 CONCURRENTLY 로 무중단. 원인이 특정 세션의 blocking이면 pg_cancel_backend 로 완화. DDL이 락으로 서비스를 막고 있으면 즉시 취소하고 배치·CONCURRENTLY로 재설계 — 운영 중 대형 테이블 락은 롤백이 최우선 ."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"doc-cheatnet","code":"SOURCE","title":"Network","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatnet-ch1","code":"NW-CS-01","title":"핵심 명령·스니펫","summary":"dig +short example.com # A record만 간결하게 dig example.com A # A record + TTL + 권위 응답 dig example.com CNAME # CNAME chain 확인 dig +short example.com @1.1.1.1 # 특정 resolver로 질의 (내부/외부 비교) dig +trace exampl"},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatnet-ch2","code":"NW-CS-02","title":"판단 한 줄","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatnet-ch3","code":"NW-CS-03","title":"자주 터지는 것 · 즉시 확인","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatnet-ch4","code":"NW-CS-04","title":"장애 증거 1카드","summary":"출발지·목적지·포트·방향을 특정하기 전엔 \"네트워크 정상\"으로 판단 금지. 한 계층에서 증거가 확정되면 다음 계층으로 내려가고, 상위 계층 수정 전 하위 계층 증거를 먼저 확보한다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"doc-cheatdevops","code":"SOURCE","title":"DevOps","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdevops-ch1","code":"DO-CS-01","title":"핵심 명령·스니펫","summary":"kubectl get pods -o wide # 노드/IP까지 한눈에 kubectl get pods -w # 상태 변화 실시간 watch kubectl logs -f <pod> # 로그 follow kubectl logs <pod> --previous # 크래시 직전 컨테이너 로그 kubectl describe pod <pod> # 이벤트/스케줄링 실패 원"},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdevops-ch2","code":"DO-CS-02","title":"판단 한 줄","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdevops-ch3","code":"DO-CS-03","title":"자주 터지는 것 · 즉시 확인","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdevops-ch4","code":"DO-CS-04","title":"장애 증거 1카드","summary":"데이터 변경(DB migration·schema)이 동반된 배포는 rollback 보류 — 구 버전이 새 schema를 못 읽으면 롤백이 2차 장애가 된다. 이 경우 roll-forward(수정 배포) 또는 kubectl rollout pause 로 확산부터 멈추고 호환성을 확인한 뒤 결정한다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"doc-cheatlinux","code":"SOURCE","title":"Linux","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatlinux-ch1","code":"LX-CS-01","title":"핵심 명령·스니펫","summary":"# 메모리 많이 먹는 순으로 상위 프로세스 ps aux --sort=-%mem | head # CPU 많이 먹는 순 ps aux --sort=-%cpu | head # 실시간 모니터 (htop 있으면 더 편함) top htop # 특정 프로세스 찾기 pgrep -a node ps aux | grep '[n]ode' # 정상 종료 요청 (SIGTERM) → "},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatlinux-ch2","code":"LX-CS-02","title":"판단 한 줄","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatlinux-ch3","code":"LX-CS-03","title":"자주 터지는 것 · 즉시 확인","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatlinux-ch4","code":"LX-CS-04","title":"장애 증거 1카드","summary":"3번에서 열린 삭제 파일이 잡히면 파일을 더 지우지 말고 해당 프로세스를 restart해 fd를 놓게 한다. 대상 경로를 눈으로 확인하지 못하면 삭제를 중단한다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"doc-cheatdocker","code":"SOURCE","title":"Docker","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdocker-ch1","code":"DK-CS-01","title":"핵심 명령·스니펫","summary":"docker ps # 실행 중인 컨테이너 docker ps -a # 종료된 것 포함 전체 + EXIT CODE docker ps --format 'table {{.Names}}\\t{{.Status}}\\t{{.Ports}}' docker logs -f <c> # 로그 실시간 추적 (가장 자주 씀) docker logs --tail 100 <c> # 마지막 1"},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdocker-ch2","code":"DK-CS-02","title":"판단 한 줄","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdocker-ch3","code":"DK-CS-03","title":"자주 터지는 것 · 즉시 확인","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatdocker-ch4","code":"DK-CS-04","title":"장애 증거 1카드","summary":"EXIT 137이면 메모리 한계( --memory )나 외부 OOM kill부터 본다. logs·inspect로 원인을 짚기 전엔 재빌드 반복 금지 — 이미지가 아니라 env·mount·network 설정 문제인 경우가 많다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"doc-cheatinterview","code":"SOURCE","title":"Interview","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatinterview-ch1","code":"IV-CS-01","title":"즉답 구조 템플릿","summary":"질문을 받으면 키워드부터 쏟지 말고 아래 구조를 머릿속에 세운다. 결론 먼저, 근거는 조건과 함께."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatinterview-ch2","code":"IV-CS-02","title":"질문 유형별 접근","summary":"질문 유형을 먼저 분류하면 무엇을 첫 문장으로 말할지 정해진다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatinterview-ch3","code":"IV-CS-03","title":"감점 신호 · 즉시 확인","summary":"전문성은 말의 양이 아니라 경계·기준·증거에서 드러난다. 아래는 면접관이 즉시 감점하는 신호."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheatinterview-ch4","code":"IV-CS-04","title":"모르는 질문 1카드","summary":"추측을 사실처럼 이어 붙이는 순간 멈춘다. 모르면 \"여기까지는 알고, 그다음은 확인이 필요합니다\"로 경계를 긋는 게 지어내는 답보다 항상 낫다."},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"doc-cheattools","code":"SOURCE","title":"Tools·Shortcuts·Commands","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheattools-ch1","code":"TL-CS-01","title":"핵심 명령·스니펫","summary":"# 변경 파일 짧게 (가장 많이 씀) git status --short # 그래프로 전체 브랜치 흐름 git log --oneline --graph --all # 특정 파일 변경 이력 (이름 변경 추적 포함) git log --follow -- path/to/file # 스테이지된 것 vs 작업 중인 것 분리 확인 git diff # 아직 add 안 한 변"},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheattools-ch2","code":"TL-CS-02","title":"판단 한 줄","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheattools-ch3","code":"TL-CS-03","title":"자주 터지는 것 · 즉시 확인","summary":""},{"docId":"practice-cheat-sheets","docLabel":"00 실무 치트시트 모음","groupLabel":"실무 도구","sectionId":"cheattools-ch4","code":"TL-CS-04","title":"장애 증거 1카드","summary":"작업 유실이 의심되면 다른 명령을 치기 전에 git reflog 부터 — HEAD 이동 기록이 남아 있는 동안이 복구 골든타임이다. secret이 커밋·push됐다면 history 정리보다 토큰 재발급이 먼저 다. 히스토리 재작성(rebase/force)은 공유 브랜치에서 중단하고 merge로 우회한다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"doc-roadmap","code":"SOURCE","title":"풀스택 성장 로드맵","summary":"풀스택 역량은 프론트엔드와 백엔드 문법을 모두 아는 것이 아니라 사용자 행동, API 계약, 데이터 정합성, 배포, 운영 신호를 하나의 변경 흐름으로 연결해 설명하고 실행하는 능력 입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"roadmap-ch1","code":"FS-01","title":"목적과 기준","summary":"이 핸드북의 목적은 지식 목록을 넓히는 것이 아니라, 하나의 기능을 제품 경험에서 운영까지 끝까지 책임지는 판단 체계를 만드는 것입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"roadmap-ch2","code":"FS-02","title":"역량 지도","summary":"풀스택 역량은 여섯 축으로 나눠 익히면 누락이 줄어듭니다. 각 축은 독립 과목이 아니라 하나의 변경 안에서 동시에 만납니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"roadmap-ch3","code":"FS-03","title":"학습 순서","summary":"순서는 관심사가 아니라 의존 관계를 따릅니다. 먼저 한 기능을 끝까지 만들고, 그 다음 신뢰성과 운영성을 얹습니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"roadmap-ch4","code":"FS-04","title":"경계면 체크리스트","summary":"풀스택 실무의 대부분의 문제는 기술 내부보다 경계면에서 납니다. 화면과 서버, 서버와 DB, 앱과 인프라 사이의 계약을 먼저 봅니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"roadmap-ch5","code":"FS-05","title":"캡스톤 과제","summary":"읽은 내용을 몸에 붙이려면 작은 기능 하나를 끝까지 책임지는 과제가 필요합니다. 아래 과제를 반복하면 전체 연결이 보입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"roadmap-ch6","code":"FS-06","title":"품질 기준","summary":"풀스택 기능은 “동작한다”에서 끝나지 않습니다. 아래 기준을 PR 체크리스트처럼 사용합니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"roadmap-ch7","code":"FS-07","title":"고급 개발자 루브릭","summary":"고급 개발자는 더 많은 기술명을 아는 사람이 아니라, 불확실한 조건에서 시스템을 안전하게 바꾸고 그 결정을 설명할 수 있는 사람입니다. 아래 기준은 각 장을 읽은 뒤 스스로 점검할 최소 루브릭입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"roadmap-ch8","code":"FS-08","title":"실전 훈련 루프","summary":"핸드북은 읽는 것만으로 완성되지 않습니다. 하나의 capstone을 선택해 설계, 구현, 운영, 회고까지 반복해야 지식이 판단으로 바뀝니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"roadmap-ch9","code":"FS-09","title":"실전 경험 시뮬레이터","summary":"회사 경험을 완전히 대체할 수는 없지만, 불완전한 요구사항, 시간 압박, 장애, 리뷰 반박, 운영 증거 를 강제로 넣으면 실제 경험과 가까운 압력을 만들 수 있습니다. 아래 프로그램은 혼자 또는 스터디에서 하나의 캡스톤을 실제 서비스처럼 운영해 보는 훈련입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"doc-faq","code":"SOURCE","title":"개발자 FAQ·트러블슈팅","summary":"개발자가 가장 자주 묻는 질문은 대개 기술명이 아니라 증상 으로 시작합니다. 이 문서는 \"왜 로컬은 되는데 배포하면 안 되지?\", \"어떤 로그를 봐야 하지?\", \"AI가 만든 코드를 믿어도 되나?\" 같은 질문을 증상 → 가설 → 증거 → 수정 → 예방 의 실행 순서로 바꾸는 triage hub입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch15","code":"FAQ-15","title":"증상 기반 빠른 진입","summary":"실무에서 질문은 \"어느 장을 읽어야 하나요?\"가 아니라 \"지금 이 증상이 무엇을 뜻하나요?\"로 들어옵니다. 아래 표는 증상에서 바로 확인 순서로 들어가기 위한 routing table입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch1","code":"FAQ-01","title":"질문을 문제 정의로 바꾸기","summary":"초보자와 숙련자의 차이는 답을 아는 양보다 질문을 재현 가능한 문제로 바꾸는 속도 에서 크게 납니다. 질문이 \"안 돼요\"에 머물면 도와주는 사람도 추측만 하게 됩니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch2","code":"FAQ-02","title":"로컬은 되는데 CI·운영은 실패","summary":"가장 흔한 질문 중 하나입니다. 이 문제는 거의 항상 환경 차이 , 숨은 상태 , 외부 의존성 , 권한 중 하나입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch3","code":"FAQ-03","title":"빌드·의존성·버전 충돌","summary":"의존성 문제는 \"패키지 하나가 안 깔림\"처럼 보이지만 실제로는 lockfile, transitive dependency, peer dependency, native package, repository 권한 문제가 섞여 있습니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch4","code":"FAQ-04","title":"환경변수·쿠키·CORS·시크릿","summary":"배포 후 로그인, API 호출, redirect가 깨지는 문제는 대부분 설정 경계에서 발생합니다. 특히 build-time env와 runtime env, 브라우저 쿠키 정책, CORS credential 설정이 자주 섞입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch5","code":"FAQ-05","title":"DB 마이그레이션·락·시딩","summary":"DB 문제는 로컬에서 쉽게 고치려고 drop/reset을 반복하다가 운영 사고로 이어질 수 있습니다. 로컬 재생성과 운영 변경은 완전히 다른 절차입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch6","code":"FAQ-06","title":"\"느려요\" 성능 triage","summary":"성능 질문은 먼저 병목 위치를 찾아야 합니다. 프론트, 네트워크, API, DB, 외부 서비스, 런타임 자원 중 어디인지 모르면 최적화가 추측이 됩니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch7","code":"FAQ-07","title":"테스트가 로컬/CI에서 다르게 실패","summary":"flaky test는 팀의 신뢰를 빠르게 깎습니다. 실패한 테스트를 \"다시 돌리니 됨\"으로 넘기면 배포 판단이 무너집니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch8","code":"FAQ-08","title":"git·PR·리뷰 사고 복구","summary":"git 사고는 대부분 복구 가능합니다. 중요한 것은 panic 상태에서 destructive 명령을 치지 않는 것입니다. 먼저 현재 상태를 기록하고, 되돌릴 기준점을 찾습니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch9","code":"FAQ-09","title":"AI 생성 코드 검증 부채","summary":"AI 도구는 빠르게 초안을 만들지만, 많은 개발자가 정확도와 보안에 대한 낮은 신뢰를 보고합니다. 그래서 AI 코드의 핵심 문제는 \"생성\"이 아니라 검증 부채 입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch10","code":"FAQ-10","title":"장애 보고·에스컬레이션","summary":"장애 상황에서 좋은 개발자는 모든 것을 혼자 해결하려 하지 않습니다. 영향 범위와 증거를 빠르게 정리해 올바른 사람에게 올립니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch11","code":"FAQ-11","title":"동시성·멱등성·중복 처리","summary":"개발자가 자주 놓치는 운영 버그는 \"한 번만 일어난다\"는 가정에서 나옵니다. 실제 환경에서는 사용자가 두 번 누르고, 네트워크가 재시도하고, 메시지가 중복 소비되고, 같은 요청이 동시에 들어옵니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch12","code":"FAQ-12","title":"로그·메트릭·트레이스","summary":"\"로그를 봤는데 모르겠다\"는 말은 대부분 로그가 사건을 재구성할 수 없게 찍혔다는 뜻입니다. 관측 가능성은 장애 후에 붙이는 장식이 아니라 기능 설계의 일부입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch13","code":"FAQ-13","title":"보안·권한·데이터 삭제","summary":"보안 질문은 \"막았나요?\"가 아니라 \"어느 신뢰 경계에서 무엇을 검증하나요?\"로 바꿔야 합니다. 프론트 가드, API 인가, DB 제약, 감사 로그는 서로 대체재가 아닙니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch14","code":"FAQ-14","title":"문서화·온보딩·지식 이전","summary":"문서화는 시간이 남을 때 하는 일이 아니라 질문 비용을 줄이는 개발 생산성 장치입니다. 같은 질문이 세 번 나오면 문서가 없거나, 찾기 어렵거나, 최신성이 깨졌다는 신호입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch16","code":"FAQ-16","title":"60문항 문제 해결 매트릭스","summary":"아래 문항은 팀 FAQ, 온보딩, PR 리뷰, 장애 회고에서 반복적으로 꺼내야 할 질문입니다. 모두 외우는 표가 아니라, 문제를 받았을 때 빠뜨린 축이 없는지 확인하는 checklist입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch17","code":"FAQ-17","title":"운영 준비도 루브릭","summary":"이 문서가 실제로 충분한지 보려면 \"내용이 많다\"가 아니라 기능·문서·자동화가 아래 루브릭을 통과하는지 봐야 합니다. 각 기능이나 PR을 이 표로 점검하면 실무 가이드가 행동 기준으로 바뀝니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"faq-ch18","code":"FAQ-18","title":"참고 기준과 한계","summary":"이 문서는 특정 회사의 단일 표준이 아니라, 개발자 Q&A에서 반복되는 문제 유형과 운영 실무 패턴을 합쳐 만든 triage guide입니다. 조직, 스택, 규제, 배포 모델에 따라 차단 기준은 조정해야 합니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"doc-machine","code":"SOURCE","title":"새 PC 환경 설정","summary":"새 맥/윈도우를 받았을 때 0부터 개발 환경을 세우는 순서 — 패키지 매니저 → 런타임 → 도구 → 에이전트 → dotfiles . cmux 기반 멀티 에이전트 워크플로우까지."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch1","code":"SETUP-01","title":"시작 전 — 큰 그림","summary":"새 PC 셋업의 목표는 \"어찌어찌 돌아가는 환경\"이 아니라 다음 PC에서 한 줄로 재현되는 환경 입니다. 손으로 하나씩 깔면 그 노동은 매번 반복되고, 무엇을 왜 깔았는지도 잊힙니다. 그러니 처음부터 코드로 적습니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch2","code":"SETUP-02","title":"1단계 — 시스템 기반","summary":"맥을 켜고 가장 먼저 깔 두 가지 — Xcode Command Line Tools(컴파일러·git 등 기본기)와 Homebrew(패키지 매니저). 이 둘이 나머지 전부의 토대입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch3","code":"SETUP-03","title":"2단계 — Claude Code 진입점","summary":"Claude Code는 Brewfile에서 이미 깔렸습니다( cask \"claude-code\" ). 이제 인증하고, 모든 프로젝트에서 공유될 글로벌 메모리 를 만듭니다 — 매 대화마다 자기소개를 반복하지 않기 위해서입니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch4","code":"SETUP-04","title":"3단계 — MCP 서버 연결","summary":"MCP(Model Context Protocol) 서버는 Claude에게 파일시스템·GitHub·브라우저·DB·Obsidian 같은 외부 능력을 붙여줍니다. Claude Code에서는 claude mcp add 로 등록합니다. 서버 정의는 스코프에 따라 ~/.claude.json (user·local) 또는 프로젝트 루트 .mcp.json (project)"},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch5","code":"SETUP-05","title":"4단계 — zsh + cmux","summary":"셋업에서 가장 손이 많이 가는 단계입니다 — 셸 프롬프트(starship), 디렉터리 점프(zoxide), 퍼지 검색(fzf), alias, 그리고 멀티 에이전트 워크플로우의 중심인 cmux. 하나씩 쌓습니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch6","code":"SETUP-06","title":"5단계 — Obsidian 컨텍스트 시스템","summary":"Obsidian은 장기 컨텍스트 저장소입니다. Zettelkasten 구조로 vault를 만들어두면, MCP( SETUP-04 에서 연결됨)를 통해 Claude가 노트를 읽고 쓸 수 있습니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch7","code":"SETUP-07","title":"6단계 — 언어 런타임 mise","summary":"node·python·java를 각각 따로 깔지 않습니다. mise 하나가 여러 언어의 버전을 통합 관리합니다 — 프로젝트별로 다른 버전을 자동 전환하고, 글로벌 기본값도 잡아줍니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch8","code":"SETUP-08","title":"7단계 — Git·GitHub·dotfiles","summary":"마지막 단계이자 셋업 전체를 재현 가능하게 만드는 단계입니다. git 글로벌 설정, SSH 키, 그리고 chezmoi로 dotfiles를 코드화해 다음 맥에서 한 줄로 복원합니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch9","code":"SETUP-09","title":"Windows PC 셋업","summary":"Windows도 같은 철학으로 셋업합니다 — 패키지 매니저로 코드화하고, 유닉스 개발환경은 WSL2 안에서 위 Mac/Linux 절차를 재사용합니다. macOS 전용 도구(Ghostty·cmux)만 Windows 네이티브로 대체합니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch10","code":"SETUP-10","title":"검증 + cmux 운용 주의","summary":"전부 깔았으면 버전 출력으로 한 번에 점검합니다. 그리고 cmux 멀티 에이전트는 강력한 만큼 절제가 필요합니다 — 화면을 화려하게 채우는 게 목적이 아닙니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"machine-ch11","code":"SETUP-11","title":"치트시트 — 자주 쓰는 한 줄","summary":"셋업·재현·운용에서 반복되는 핵심 명령들. 새 PC를 받았을 때 이 표만 펴두면 됩니다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"doc-playbook","code":"SOURCE","title":"실무 플레이북","summary":"실무 감각은 재능이 아니라 압축된 사고 경험 이다 — 가속할 수 있다. 핵심 습관 하나: 막힐 때마다 \"이럴 때 → 이렇게\"를 runbook으로 박제 하라. 한 번 삽질한 게 다음엔 5분이 된다. 이 핸드북은 자주 만나는 시나리오의 모음이자, 계속 확장해 나갈 운영 지식의 틀이다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch1","code":"PLAY-01","title":"실무 감각은 어떻게 기르는가","summary":"\"실무 아이디어가 약하다\"는 건 지식이 부족한 게 아니라 시나리오를 미리 정리해둔 양 이 적다는 뜻이다. 이건 재능이 아니라 축적이고, 축적은 가속할 수 있다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch2","code":"PLAY-02","title":"로컬 DB 리셋·시더","summary":"가장 자주 만나는 루틴. 로컬 DB 리셋 워크플로우를 기준으로, 각 단계가 왜 옳은지를 풀어둔다 — 명령보다 원리가 남아야 응용된다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch3","code":"PLAY-03","title":"포트·프로세스 꼬임","summary":"\"Address already in use\" — 앱을 띄우려는데 이미 뭔가 그 포트를 쥐고 있다. 보통 강제 종료했던 이전 프로세스나 좀비 데몬이 범인이다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch4","code":"PLAY-04","title":"마이그레이션·스키마 드리프트","summary":"팀원이 스키마를 바꾼 걸 pull 했더니 엔티티와 DB가 안 맞아 앱이 안 뜬다. 로컬 비상 루틴(PLAY-02)이 바로 이 상황의 해법이다 — 하지만 로컬과 운영의 처방이 정반대 라는 게 핵심이다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch5","code":"PLAY-05","title":"빌드·의존성·런타임","summary":"\"어제는 됐는데 오늘 안 됨\", \"내 PC만 안 됨\" — 범인은 거의 항상 셋 중 하나다: 캐시 · 버전 · 환경변수."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch6","code":"PLAY-06","title":"\"느려요\"를 추적하는 순서","summary":"\"느리다\"는 신고에 바로 코드를 뜯어고치지 마라. 어디가 느린지부터 좁히는 게 9할이다 — 측정 없는 최적화는 추측이다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch7","code":"PLAY-07","title":"운영 장애 미니 런북","summary":"운영이 터졌을 때 가장 흔한 실수 — 원인을 찾으려 든다. 순서가 틀렸다. 먼저 출혈을 멈추고(완화), 그다음 원인을 찾는다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch8","code":"PLAY-08","title":"git 사고 복구","summary":"git은 거의 모든 걸 되돌릴 수 있다 — 커밋된 것은 reflog 에 남는다. 당황하지 말고 멈춰라. 커밋한 사고는 거의 다 복구되고, 무서운 건 커밋 안 한 변경 이다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch9","code":"PLAY-09","title":"환경설정·시크릿","summary":"\"로컬은 되는데 배포하면 안 됨\"의 절반은 설정·환경변수다. 환경별로 무엇이 다른지를 명확히 분리해두는 게 예방이다."},{"docId":"practice-workflow-setup","docLabel":"01 실무 준비·작업 루프","groupLabel":"실무 도구","sectionId":"playbook-ch10","code":"PLAY-10","title":"체크리스트 모음","summary":"실무 감각의 마지막 형태는 체크리스트다 — 기억력에 의존하지 않고 \"빠뜨리지 않는\" 장치. 아래는 시작점이고, 팀·프로젝트에 맞게 줄이고 늘려라."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"bundle-index","code":"INDEX","title":"통합 문서","summary":"아래 문서들을 한 페이지에서 이어 읽을 수 있도록 구성했습니다. 각 문서의 내부 목차는 왼쪽 목차에서 바로 이동할 수 있습니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"doc-gradle","code":"SOURCE","title":"Gradle 의존성·빌드","summary":"라이브러리를 어떻게 추가·고정·갱신하는가 — npm/package.json 하던 감각을 Gradle로 옮기는 실무 가이드. 개념 설명보다 \"이걸 실제로 어떻게 치나\"에 답합니다. Gradle 8.x · Spring Boot 3.x · Java 기준."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"gradle-ch1","code":"GRADLE-01","title":"Gradle이 하는 일·구조","summary":"Gradle은 JVM 세계의 빌드 도구입니다 — npm이 의존성 설치·스크립트 실행을 맡듯, Gradle은 의존성 해석 + 컴파일 + 테스트 + 패키징 을 한 번에 책임집니다. 프론트엔드 감각으로 매핑부터 잡으면 빠릅니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"gradle-ch2","code":"GRADLE-02","title":"의존성 추가","summary":"라이브러리 추가는 dependencies { } 블록에 한 줄을 적는 일입니다. npm처럼 CLI로 추가하는 게 아니라 파일을 직접 편집 한다는 게 가장 큰 차이입니다. 적고 나면 IDE가 새로고침하거나 빌드 시 자동으로 받습니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"gradle-ch3","code":"GRADLE-03","title":"의존성 스코프","summary":"npm의 dependencies vs devDependencies 가 둘로 갈리는 데 비해, Gradle은 더 세밀합니다 — 이 라이브러리를 언제(컴파일/런타임/테스트) 쓰고, 다른 모듈에 노출할지 까지 구분합니다. 이 구분이 빌드 속도와 모듈 캡슐화를 좌우합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"gradle-ch4","code":"GRADLE-04","title":"버전 관리","summary":"버전을 어디에 어떻게 적느냐가 유지보수의 질을 가릅니다. Spring Boot는 버전을 대신 정해주고 , version catalog는 버전을 한 곳에 모읍니다 . 둘 다 \"버전 숫자가 코드 여기저기 흩어지는\" 문제를 푸는 도구입니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"gradle-ch5","code":"GRADLE-05","title":"플러그인","summary":"플러그인은 Gradle에 능력 을 더합니다 — Java 컴파일, Spring Boot 패키징, 의존성 버전 관리 같은 기능이 플러그인으로 들어옵니다. plugins { } 블록에 선언하며, 보통 파일 맨 위에 둡니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"gradle-ch6","code":"GRADLE-06","title":"의존성 확인·트러블슈팅","summary":"\"이 라이브러리가 왜 들어왔지\", \"버전이 왜 이게 됐지\"를 추적하는 도구들. transitive dependency(간접 의존성)가 얽히면 눈으로는 못 풉니다 — Gradle이 답을 알려줍니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"gradle-ch7","code":"GRADLE-07","title":"자주 쓰는 task","summary":"Gradle은 \"task\" 단위로 동작합니다 — npm run 의 스크립트에 해당. 핵심 몇 개만 손에 붙이면 일상은 충분합니다. 항상 ./gradlew 로 호출하세요."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"gradle-ch8","code":"GRADLE-08","title":"멀티모듈 기초","summary":"앱이 커지면 하나의 빌드를 여러 모듈로 쪼갭니다 — core (도메인), api (웹), batch (배치) 식으로. npm의 monorepo/workspaces와 같은 동기. settings.gradle 이 모듈 구성을, 각 모듈의 build.gradle 이 자기 의존성을 책임집니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"gradle-ch9","code":"GRADLE-09","title":"치트시트 — 자주 쓰는 한 줄","summary":"실전에서 반복되는 조합들. 외우기보다 \"이런 게 가능하다\"를 알아두고 필요할 때 찾으세요."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"doc-packages","code":"SOURCE","title":"패키지·버전 매니저","summary":"자주 혼동되는 두 범주를 가른다 — 패키지 매니저 (npm·pnpm)와 런타임 버전 매니저 (nvm·mise). 전자는 라이브러리를 설치하고, 후자는 Node 자체의 버전을 바꿉니다. Gradle 가이드의 Node/JS 짝."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"packages-ch1","code":"PKG-01","title":"두 범주를 구분하라","summary":"제일 먼저 잡을 것: \"라이브러리를 설치하는 도구\" 와 \"Node 자체의 버전을 바꾸는 도구\" 는 다른 범주입니다. 둘 다 \"매니저\"라 불려서 섞이지만, 푸는 문제가 완전히 다릅니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"packages-ch2","code":"PKG-02","title":"npm 기본","summary":"npm은 Node에 기본 내장된 패키지 매니저입니다. 새 도구를 배우기 전에, 모든 매니저가 공유하는 기반인 package.json ·semver·lockfile부터 정확히 잡으세요."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"packages-ch3","code":"PKG-03","title":"pnpm","summary":"pnpm은 npm과 같은 일을 하되 디스크와 속도 에서 다른 설계를 택했습니다. 명령어는 거의 호환돼서 갈아타는 비용이 작습니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"packages-ch4","code":"PKG-04","title":"npm vs pnpm vs yarn","summary":"셋 다 같은 일을 합니다 — 라이브러리 설치. 선택은 취향이 아니라 팀 합의 의 문제입니다. 한 프로젝트엔 반드시 하나만."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"packages-ch5","code":"PKG-05","title":"lockfile과 재현성","summary":"lockfile은 \"누가 언제 설치해도 같은 의존성 트리가 나오게\" 만드는 장치입니다. \"내 PC만 됨\"을 막는 가장 직접적인 도구."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"packages-ch6","code":"PKG-06","title":"워크스페이스(모노레포) 간단","summary":"한 저장소 안에 여러 패키지(앱·라이브러리)를 두고 함께 관리하는 구조가 모노레포 입니다. npm·pnpm 모두 workspaces로 지원합니다 — 여기서는 개념만."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"packages-ch7","code":"PKG-07","title":"nvm — Node 버전 매니저","summary":"여기부터는 다른 범주 — 라이브러리가 아니라 Node 런타임 자체 의 버전을 바꾸는 도구입니다. nvm이 가장 오래되고 널리 알려진 선택지입니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"packages-ch8","code":"PKG-08","title":"mise — 폴리글랏 버전 매니저","summary":"mise는 Node만이 아니라 여러 언어의 런타임을 하나로 관리합니다 — nvm·pyenv·rbenv·SDKMAN을 한 도구로 대체. 디렉터리 진입 시 자동 전환이 기본이라 nvm의 두 단점을 동시에 해결합니다. 풀스택 프로젝트에서 Node와 Java 같은 여러 런타임을 함께 고정할 때 특히 유용합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"packages-ch9","code":"PKG-09","title":"치트시트","summary":"전부 외우지 말고, 헷갈릴 때 여기서 찾으세요. 두 범주의 구분만 머리에 박혀 있으면 나머지는 조회로 충분합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"doc-config","code":"SOURCE","title":"환경변수·설정","summary":"같은 빌드, 다른 환경 — 설정을 코드 밖으로 빼고 환경별로 분리하는 실무 가이드. Spring Boot 3.x 기준으로 application.yml·프로파일·환경변수 주입·시크릿 분리를 절차 중심으로 다룹니다. 프론트의 .env / process.env 감각이 있다면 그 대응을 짚어가며 읽으세요."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"config-ch1","code":"CONFIG-01","title":"왜 설정을 외부화하나","summary":"핵심 원칙 한 줄: \"한 번 빌드한 아티팩트를, 환경마다 다른 설정으로 실행한다.\" DB 주소·API 키가 코드에 박혀 있으면 환경이 바뀔 때마다 다시 빌드해야 합니다. 설정을 코드 밖으로 빼면 같은 .jar 하나로 local·staging·prod를 모두 돌립니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"config-ch2","code":"CONFIG-02","title":"application.yml vs application.properties","summary":"Spring Boot는 src/main/resources/ 의 application.properties 또는 application.yml 을 자동으로 읽습니다. 둘은 같은 설정을 표현하는 두 문법 일 뿐 — properties는 점( . ) 표기, yml은 들여쓰기 계층입니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"config-ch3","code":"CONFIG-03","title":"프로파일로 환경 분리","summary":"프로파일(profile)은 \"이 설정 묶음을 어느 환경에서 쓸지\" 이름표를 붙이는 메커니즘입니다. 공통은 application.yml 에 두고, 환경별 차이만 application-{profile}.yml 에 오버라이드합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"config-ch4","code":"CONFIG-04","title":"환경변수 주입","summary":"운영에서 값을 넣는 가장 흔한 통로는 환경변수입니다. Spring Boot는 relaxed binding 덕분에 OS 환경변수의 대문자·언더스코어 표기를 점 표기 프로퍼티로 알아서 매핑합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"config-ch5","code":"CONFIG-05","title":"설정 우선순위 — 누가 누구를 이기나","summary":"같은 키가 여러 곳에 있으면 누가 이길까. 핵심 원칙: \"바깥에서 주입한 것이 안에 박힌 것을 이긴다.\" 커맨드라인 인자가 가장 세고, jar 안의 application.yml 이 가장 약합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"config-ch6","code":"CONFIG-06","title":"코드에서 설정 읽기","summary":"주입한 설정을 자바 코드에서 꺼내는 길은 둘입니다 — 값 하나를 콕 집는 @Value , 관련 설정을 묶어 타입 안전하게 바인딩하는 @ConfigurationProperties ."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"config-ch7","code":"CONFIG-07","title":"시크릿 분리","summary":"비밀번호·API 키·토큰은 설정 중에서도 특별 취급입니다. 원칙 하나만 절대 지키세요 — 시크릿은 코드와 git에 절대 들어가지 않는다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"config-ch8","code":"CONFIG-08","title":"로컬 개발 설정","summary":"팀이 공유하는 설정과 개인 머신에만 있는 값을 구분하는 게 핵심입니다 — 공유 설정은 git에, 개인 시크릿·취향은 git 밖에."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"config-ch9","code":"CONFIG-09","title":"치트시트","summary":"자주 헷갈리는 규칙과 표기를 한 곳에. 외우기보다 \"이런 게 있다\"를 알아두고 필요할 때 찾으세요."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"doc-dbseed","code":"SOURCE","title":"DB 스키마·시딩","summary":"스키마를 안전하게 관리하고 로컬 데이터를 자동 복구하는 실무 가이드. \"실제로 어떻게 하나\"에 초점을 둡니다 — 누가 스키마를 소유하는지, 마이그레이션을 어떻게 쌓는지, 로컬 DB를 날려도 한 번의 재구동으로 복구되게 만드는 법까지. Spring Boot · JPA · Flyway · PostgreSQL 기준."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"dbseed-ch1","code":"SEED-01","title":"스키마는 누가 관리하나","summary":"먼저 결정할 한 가지: 테이블 구조의 단일 진실원천(source of truth)은 무엇인가. JPA 엔티티가 자동으로 테이블을 만들게 둘 것인가, 아니면 사람이 쓴 SQL 마이그레이션이 정본인가. 정답은 후자입니다. 이유부터 봅니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"dbseed-ch2","code":"SEED-02","title":"마이그레이션 도구 — Flyway","summary":"Flyway는 버전 매겨진 SQL 파일을 순서대로, 한 번씩만 적용하고 그 이력을 DB에 기록합니다. \"지금 이 DB가 몇 번 버전까지 와 있는가\"를 도구가 알기 때문에, 어떤 환경에서 시작하든 같은 최종 스키마에 도달합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"dbseed-ch3","code":"SEED-03","title":"마이그레이션 작성 패턴","summary":"마이그레이션은 결국 SQL입니다. 자주 쓰는 형태 몇 개와, 운영에서 다운타임 없이 바꾸는 사고법(expand-contract)을 봅니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"dbseed-ch4","code":"SEED-04","title":"로컬 시딩 방법 비교","summary":"시딩은 \"스키마(빈 테이블)에 개발용 데이터를 채우는\" 일입니다. 마이그레이션과는 목적이 다릅니다 — 마이그레이션은 구조 , 시딩은 샘플 데이터 . Spring 생태계에서 흔한 세 방법을 비교합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"dbseed-ch5","code":"SEED-05","title":"멱등 시더 작성","summary":"멱등(idempotent)은 몇 번 실행해도 결과가 같은 성질입니다. 시더가 멱등이면 \"DB를 날렸다가 재구동\" 한 번으로 항상 같은 깨끗한 상태로 돌아옵니다 — 안전한 비상 복구의 전제입니다. 멱등이 아니면 두 번째 실행에서 PK 충돌로 기동이 깨집니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"dbseed-ch6","code":"SEED-06","title":"로컬 리셋 워크플로우","summary":"로컬 데이터가 꼬였을 때 가장 빠른 회복은 \"깨끗이 지우고 처음부터 다시 세우기\"입니다. 멱등 시더(→ SEED-05)와 Flyway(→ SEED-02)가 갖춰져 있으면 이건 명령 몇 줄로 끝납니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"dbseed-ch7","code":"SEED-07","title":"테스트 데이터","summary":"테스트는 또 다른 환경입니다 — 빠르고, 격리되고, 매번 같은 상태여야 합니다. H2 같은 인메모리 DB는 빠르지만 Postgres와 SQL 방언이 달라 \"테스트는 통과하는데 운영에서 깨지는\" 함정을 만듭니다. 진짜 DB로 테스트하는 게 정석입니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"dbseed-ch8","code":"SEED-08","title":"치트시트","summary":"손에 붙여둘 핵심 개념과 한 줄 규칙. 헷갈리면 여기서 찾으세요."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"doc-cicd","code":"SOURCE","title":"CI/CD 배포","summary":"푸시하면 자동으로 빌드·테스트·배포 — 파이프라인을 손으로 짜보는 실무 가이드. 개념을 길게 설명하지 않고, 실제로 어떤 YAML을 어디에 두면 되는가 에 집중합니다. 각 단계마다 \"왜 이렇게 하는가\" 한 줄을 답니다. GitHub Actions 기준, Spring Boot(Gradle) + Docker 배포 흐름."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"cicd-ch1","code":"CICD-01","title":"CI/CD가 하는 일","summary":"한 줄로: CI는 \"합칠 때마다 자동으로 빌드·테스트해 깨졌는지 검증\" , CD는 \"검증 통과한 코드를 자동으로 배포\" . 사람이 손으로 하던 반복을 기계에 넘기는 것입니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"cicd-ch2","code":"CICD-02","title":"GitHub Actions 기본","summary":"GitHub Actions의 작업 단위는 workflow YAML 파일 하나입니다. 리포지토리 안 정해진 위치에 두면, GitHub가 트리거 조건에 맞춰 알아서 실행합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"cicd-ch3","code":"CICD-03","title":"빌드·테스트 워크플로우","summary":"가장 먼저 만들 워크플로우는 \"푸시·PR마다 빌드하고 테스트를 돌리는\" CI입니다. Spring Boot + Gradle 기준으로 실제 동작하는 ci.yml 을 통째로 봅니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"cicd-ch4","code":"CICD-04","title":"이미지 빌드·푸시","summary":"테스트가 통과하면 배포할 산출물 을 만듭니다. 컨테이너 기반 배포라면 그 산출물은 Docker 이미지이고, 레지스트리(이미지 저장소)에 푸시합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"cicd-ch5","code":"CICD-05","title":"시크릿·환경","summary":"토큰·비밀번호·DB 접속정보는 절대 YAML이나 코드에 평문으로 쓰지 않습니다 . GitHub repo Secrets에 저장하고, 워크플로우에선 ${{ secrets.X }} 로 참조만 합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"cicd-ch6","code":"CICD-06","title":"배포 트리거·전략","summary":"\"언제 배포할 것인가\"를 정하는 게 CD 설계의 핵심입니다. main 푸시마다? 태그를 달 때만? 사람 승인을 거쳐서? — 트리거와 게이트로 표현합니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"cicd-ch7","code":"CICD-07","title":"파이프라인 베스트 프랙티스","summary":"파이프라인은 짜는 것보다 유지하는 것 이 일입니다. 느리거나 자주 깨지는 CI는 사람들이 우회하기 시작하면서 가치가 사라집니다. 몇 가지 원칙."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"cicd-ch8","code":"CICD-08","title":"치트시트 — GitHub Actions 핵심","summary":"실무에서 반복 참조하는 조각들. 전부 외우지 말고 \"이런 게 있다\"만 알아두고 필요할 때 찾으세요."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"doc-logs","code":"SOURCE","title":"로그·커스텀 명령","summary":"로그에서 원인을 빠르게 찾고, 반복 작업을 명령 한 줄로 만드는 실무 가이드. 명령·스크립트가 중심이고, 각 단계엔 왜 그렇게 하는지 한 줄을 붙였습니다. macOS·zsh·Docker·Spring 환경 기준 — 리눅스 핸드북·관측가능성 핸드북과 함께 보세요."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"logs-ch1","code":"LOGTL-01","title":"로그를 어디서 보나","summary":"디버깅의 첫 질문은 항상 같습니다 — \"이 로그는 어디로 나가는가.\" 콘솔인가, 파일인가, 컨테이너 안인가, systemd가 받아가는가, 클라우드로 흘러가는가. 출처를 먼저 정해야 다음 명령이 정해집니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"logs-ch2","code":"LOGTL-02","title":"로그 필터링","summary":"로그는 보는 게 아니라 좁히는 것입니다. 수천 줄에서 의미 있는 줄은 보통 몇 개 — grep / rg 로 깎고, 실시간이면 tail -f | grep , 탐색이면 less +F 로 흐름과 검색을 오갑니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"logs-ch3","code":"LOGTL-03","title":"구조화(JSON) 로그 조회","summary":"로그가 JSON 한 줄(JSON Lines)이면 grep 으로 문자열을 긁는 대신 필드로 묻습니다 — \"level이 ERROR이고 traceId가 X인 줄\". jq 가 그 도구입니다. 상관관계 ID 하나로 한 요청의 전 구간을 꿰는 것이 핵심."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"logs-ch4","code":"LOGTL-04","title":"런타임 로그 레벨 변경","summary":"DEBUG 로그를 보려고 재배포하는 건 느리고 위험합니다. Spring Boot는 재시작 없이 특정 패키지의 로그 레벨을 바꿀 수 있습니다 — Actuator의 /loggers 엔드포인트. 평소엔 INFO, 문제 추적할 때만 그 패키지를 DEBUG로 올렸다 내립니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"logs-ch5","code":"LOGTL-05","title":"셸 alias·함수","summary":"같은 긴 명령을 하루에 열 번 친다면 그건 alias 나 function 으로 만들 신호입니다. 인자 없이 고정이면 alias, 인자를 받아야 하면 function. 그리고 ~/.zshrc 는 chezmoi로 관리합니다 — 손으로 직접 고치지 마세요(→ 리눅스 핸드북 LX-13)."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"logs-ch6","code":"LOGTL-06","title":"스크립트화","summary":"function이 한 줄로 안 끝나고 단계가 여럿이거나 팀과 공유해야 하면 .sh 파일로 만듭니다. 핵심은 세 가지 — shebang으로 인터프리터 명시, set -euo pipefail 로 실패 시 멈춤, 위험한 작업엔 가드. 스크립트는 조용히 실패하면 안 됩니다 ."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"logs-ch7","code":"LOGTL-07","title":"프로젝트 커스텀 명령","summary":"alias는 내 셸에만 있습니다. 팀이 공유해야 하는 명령은 저장소 안에 둡니다 — Gradle custom task, 또는 Makefile / just 로 명령 모음을. 새 팀원이 make up 한 줄로 환경을 띄울 수 있게 하는 것이 목표입니다."},{"docId":"practice-build-release","docLabel":"02 빌드·설정·릴리스 운영","groupLabel":"실무 도구","sectionId":"logs-ch8","code":"LOGTL-08","title":"치트시트 — 자주 쓰는 한 줄","summary":"로그 추적과 명령 자동화에서 반복되는 조합들. 외우기보다 \"이런 게 가능하다\"를 알아두고 필요할 때 찾으세요."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"bundle-index","code":"INDEX","title":"학습 로드맵","summary":"이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"career-readiness-gate","code":"GATE","title":"CAREER READINESS GATE","summary":"면접 전략·포지셔닝 답변 게이트 는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"career-answer-rubric","code":"RUBRIC","title":"ANSWER QUALITY RUBRIC","summary":"답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"career-pressure-loop","code":"LOOP","title":"PRESSURE RESPONSE LOOP","summary":"압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"career-evidence-packet","code":"EVIDENCE","title":"EVIDENCE PACKET","summary":"면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"career-final-drill","code":"DRILL","title":"FINAL 10 MINUTE DRILL","summary":"면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"doc-interview","code":"PART","title":"기술면접 개요","summary":""},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"interview-ch1","code":"IV-00","title":"사용 목적","summary":"상급 면접에서 면접관은 단순 지식량보다 “어떤 기준으로 판단하는가”를 봅니다. 그래서 각 문서는 짧게 말할 답변과 깊게 파고드는 꼬리질문 대응을 함께 제공합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"interview-ch2","code":"IV-01","title":"답변 레벨","summary":"면접에서 가장 위험한 것은 모르는 것이 아니라, 직접 한 일과 이론으로 아는 일을 같은 톤으로 말하는 것입니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"interview-ch3","code":"IV-02","title":"답변 구조","summary":""},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"interview-ch4","code":"IV-03","title":"문서별 사용법","summary":"처음부터 모든 문서를 읽지 말고, 면접 유형과 약점에 따라 순서를 정합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"interview-ch5","code":"IV-04","title":"연습 루프","summary":"면접 준비는 읽은 양보다 말해본 횟수로 결정됩니다. 같은 질문을 짧게 답하고, 꼬리질문에서 깊이를 여는 연습을 반복합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"interview-ch6","code":"IV-05","title":"모의면접 체크리스트","summary":"면접 준비의 마지막 단계는 더 많이 읽는 것이 아니라, 답변을 평가 가능한 형태로 캘리브레이션하는 것입니다. 아래 기준으로 답변을 녹음하고 스스로 채점합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"interview-ch7","code":"IV-06","title":"나쁜 답변 / 개선 답변 / 좋은 답변","summary":"면접 답변은 많이 아는 것보다, 질문의 핵심을 짧게 잡고 실무 판단으로 확장하는지가 중요합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"interview-ch8","code":"IV-07","title":"면접관 평가 루브릭","summary":"기술면접 답변은 정답 키워드보다 면접관이 어떤 위험을 줄이려 하는지 이해해야 합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"interview-ch9","code":"IV-08","title":"압박 질문 시뮬레이션","summary":"압박 질문은 후보자를 몰아붙이려는 절차가 아니라 답변의 경계와 증거를 확인하는 과정입니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"doc-company","code":"PART","title":"회사·직무별 면접 전략","summary":""},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q1","code":"STR-01","title":"Q. 역할 적합도는 어떻게 설득하나요?","summary":"역할 적합도는 “열심히 하겠습니다”가 아니라 회사가 해결해야 하는 문제와 내가 이미 다뤄본 문제의 구조가 맞는지 보여주는 것입니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q2","code":"STR-02","title":"Q. 면접 전 회사 리서치는 무엇을 봐야 하나요?","summary":"회사 리서치는 암기용 정보 수집이 아니라 면접에서 어떤 경험을 앞세울지 결정하는 작업입니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q3","code":"STR-03","title":"Q. SI/SM 회사 면접에서는 무엇을 강조하나요?","summary":"SI/SM은 빠른 기능 구현뿐 아니라 요구사항 해석, 레거시 이해, 운영 안정성, 고객 커뮤니케이션이 중요합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q4","code":"STR-04","title":"Q. SaaS 스타트업 면접에서는 어떤 신호가 강한가요?","summary":"SaaS 스타트업은 제품 속도, 고객 피드백, 실험, 운영 품질, 기술부채 균형을 함께 봅니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q5","code":"STR-05","title":"Q. B2B 어드민 포지션에서는 무엇을 강조해야 하나요?","summary":"B2B 어드민은 화려한 UI보다 정확한 권한, 대량 데이터 처리, 검증, 감사 가능성, 업무 흐름 안정성이 중요합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q6","code":"STR-06","title":"Q. 핀테크 포지션에서는 어떤 답변이 신뢰를 주나요?","summary":"핀테크는 속도보다 정합성, 보안, 감사 가능성, 규제 대응, 장애 시 영향 축소가 중요합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q7","code":"STR-07","title":"Q. 대규모 트래픽 회사에서는 무엇을 보여줘야 하나요?","summary":"대규모 트래픽 면접은 알고리즘 지식뿐 아니라 병목을 측정하고 단계적으로 제거하는 능력을 봅니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q8","code":"STR-08","title":"Q. 백엔드 전환 포지션에서는 부족한 경험을 어떻게 설명하나요?","summary":"전환 포지션에서는 못 해본 것을 숨기는 것보다 이미 해본 일의 구조를 서버 책임과 연결하는 것이 중요합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q9","code":"STR-09","title":"Q. 시니어 또는 상급 개발자 포지션에서는 어떤 기대치가 있나요?","summary":"상급 개발자는 더 어려운 코드를 혼자 많이 짜는 사람보다 모호한 문제를 구조화하고 팀의 실패 확률을 낮추는 사람입니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q10","code":"STR-10","title":"Q. 부족한 경험을 물으면 어떻게 답하나요?","summary":"부족한 경험은 숨길수록 위험합니다. 대신 경험의 경계를 정확히 밝히고 검증 가능한 접근법을 제시해야 합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q11","code":"STR-11","title":"Q. 마지막 역질문은 무엇을 물어야 하나요?","summary":"역질문은 관심 표현이 아니라 입사 후 실제로 풀 문제와 성공 기준을 확인하는 기회입니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q12","code":"STR-12","title":"핵심 질문 30선과 답변 훈련","summary":"회사·직무 전략은 답변 내용을 바꾸는 것이 아니라 같은 경험의 강조점을 조정하는 훈련입니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"company-q13","code":"STR-13","title":"회사별 검증 질문 30개","summary":"회사 유형별 전략은 키워드가 아니라 실제 검증 질문으로 연습해야 합니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"doc-personal","code":"PART","title":"개인화 개요","summary":""},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"personal-ch1","code":"PER-00","title":"포지셔닝","summary":""},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"personal-ch2","code":"PER-01","title":"대표 프로젝트 맵","summary":""},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"personal-ch3","code":"PER-02","title":"포지션별 우선순위","summary":""},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"personal-ch4","code":"PER-03","title":"경험 경계 문장","summary":"개인화 답변의 품질은 “무엇을 했는가”보다 “어디까지 직접 했고 어디부터 설계 지식인가”를 정확히 나누는 데서 결정됩니다."},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"personal-ch5","code":"PER-04","title":"면접 첫 3분","summary":""},{"docId":"career-strategy-foundation","docLabel":"00 면접 전략·커리어 포지셔닝","groupLabel":"면접·커리어","sectionId":"personal-ch6","code":"PER-05","title":"프로젝트별 실전 답변 카드","summary":"프로젝트 답변은 기술명보다 반복 개선과 실제 기여 증거가 먼저 보여야 합니다. 커밋 수는 성과를 과장하기 위한 숫자가 아니라, 장기간 유지보수와 반복 개선을 설명하는 보조 증거로만 사용합니다."},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"overview","code":"PART","title":"개인 이력 정리","summary":"CURATED INTERVIEW PATH: 이 문서는 면접 전략 문서와 기술 면접 문서 사이를 연결하는 개인 증거 원장입니다. 포지셔닝, 프로젝트, 타임라인, 경험 경계, 답변 카드를 한 흐름으로 묶어 30초 결론, 90초 확장, 압박 꼬리질문에 같은 증거로 답하게 만듭니다."},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"gate","code":"GATE","title":"CAREER READINESS GATE","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch1","code":"PH-01","title":"PERSONAL POSITIONING MAP","summary":"포지셔닝은 나를 멋지게 포장하는 문장이 아니라, 어떤 문제를 어떤 방식으로 해결해 온 사람인지 면접관이 빠르게 분류할 수 있게 하는 지도입니다."},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch2","code":"PH-02","title":"REPRESENTATIVE PROJECT MAP","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch3","code":"PH-03","title":"CAREER TIMELINE","summary":"전체 이력 타임라인은 연도 나열이 아니라 역량이 어떻게 확장됐는지 보여주는 구조여야 합니다."},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch4","code":"PH-04","title":"POPLE DETAIL","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch5","code":"PH-05","title":"GREENERY DETAIL","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch6","code":"PH-06","title":"HEMS DETAIL","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch7","code":"PH-07","title":"LCA DETAIL","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch8","code":"PH-08","title":"TaaS DETAIL","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch9","code":"PH-09","title":"INTERVIEW EVIDENCE MAP","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch10","code":"PH-10","title":"POSITION PRIORITY MATRIX","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch11","code":"PH-11","title":"EXPERIENCE BOUNDARY SENTENCES","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch12","code":"PH-12","title":"ANSWER CARDS","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"개인 이력 답변은 프로젝트 이름 나열이 아니라, 약한 표현을 구체 증거와 경계 문장으로 바꾸는 작업입니다. 아래 packet을 대표 답변마다 하나씩 채웁니다."},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch13","code":"PH-13","title":"FULL CAREER LEDGER","summary":""},{"docId":"career-personal-history","docLabel":"01 개인 이력 정리","groupLabel":"면접·커리어","sectionId":"ch14","code":"PH-14","title":"STRENGTH WEAKNESS APPEAL MATRIX","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"bundle-index","code":"INDEX","title":"학습 로드맵","summary":"이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"career-readiness-gate","code":"GATE","title":"CAREER READINESS GATE","summary":"프론트엔드·JS/TS 답변 게이트 는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"career-answer-rubric","code":"RUBRIC","title":"ANSWER QUALITY RUBRIC","summary":"답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"career-pressure-loop","code":"LOOP","title":"PRESSURE RESPONSE LOOP","summary":"압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"career-evidence-packet","code":"EVIDENCE","title":"EVIDENCE PACKET","summary":"면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"career-final-drill","code":"DRILL","title":"FINAL 10 MINUTE DRILL","summary":"면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"doc-feinterview","code":"PART","title":"프론트엔드 면접","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q0","code":"FE-00","title":"프론트엔드 답변 원칙","summary":"프론트엔드 답변은 기술명을 많이 말하는 것이 아니라 사용자 행동 하나가 React, 브라우저, 네트워크, 보안 경계를 지나며 어떤 비용과 실패를 만드는지 설명해야 합니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q1","code":"FE-01","title":"Q. 브라우저 렌더링 파이프라인을 설명해보세요.","summary":"브라우저는 HTML을 DOM으로, CSS를 CSSOM으로 파싱한 뒤 Render Tree를 만들고 Layout, Paint, Composite 순서로 화면을 그립니다. 면접에서 중요한 지점은 순서 암기가 아니라 어떤 변경이 layout까지 영향을 주고, 어떤 변경은 composite에서 끝나는지 구분하는 것입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q2","code":"FE-02","title":"Q. React 렌더링 최적화는 어떻게 하나요?","summary":"React 최적화는 memo를 붙이는 작업이 아니라 렌더링 원인, state 위치, props 참조 안정성, 리스트 key, 비싼 계산, 브라우저 렌더링 비용을 함께 보는 과정입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q3","code":"FE-03","title":"Q. 상태관리는 어떻게 설계하나요?","summary":"상태관리는 라이브러리 선택보다 경계 설정 문제입니다. 서버 상태, 클라이언트 UI 상태, form draft, URL state, 전역 app state를 섞으면 저장 취소, dirty check, validation, cache invalidation이 어려워집니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q4","code":"FE-04","title":"Q. CSR, SSR, SSG, ISR은 어떻게 선택하나요?","summary":"렌더링 전략은 페이지 성격, SEO, 초기 표시, 개인화, 데이터 변경 빈도, 서버 비용, hydration 비용으로 판단합니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q5","code":"FE-05","title":"Q. 웹 성능을 어떻게 측정하고 개선하나요?","summary":"성능은 번들 크기, 네트워크, 이미지, 렌더링, JavaScript long task, API 응답 구조가 함께 만드는 사용자 체감입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q6","code":"FE-06","title":"Q. 접근성은 실무에서 어떻게 챙기나요?","summary":"접근성은 나중에 붙이는 장식이 아니라 semantic HTML, 키보드 탐색, focus management, 명도 대비, 상태 전달을 포함한 컴포넌트 품질 기준입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q7","code":"FE-07","title":"Q. 프론트엔드 보안은 어떻게 보나요?","summary":"프론트엔드 보안은 XSS, CSRF, token storage, CORS, 민감정보 노출, 권한 우회를 클라이언트와 서버 경계로 나눠 보는 것입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q8","code":"FE-08","title":"Q. 테스트 전략은 어떻게 가져가나요?","summary":"프론트엔드 테스트는 컴포넌트가 렌더되는지 확인하는 것이 아니라 사용자가 중요한 흐름을 완료할 수 있는지, 실패 상태에서 회복할 수 있는지 검증하는 것입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q9","code":"FE-09","title":"Q. 서버 상태와 클라이언트 UI 상태는 왜 분리하나요?","summary":"서버 상태는 원격 원천 데이터의 캐시이고, UI 상태는 현재 화면의 표현과 상호작용 상태입니다. 둘을 섞으면 최신성, 저장 취소, optimistic update, 오류 복구가 어려워집니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q10","code":"FE-10","title":"Q. hydration mismatch는 왜 생기고 어떻게 막나요?","summary":"hydration mismatch는 서버가 만든 HTML과 클라이언트 첫 렌더 결과가 다를 때 생깁니다. 시간, 랜덤값, locale, 브라우저 전용 API, 인증 상태가 흔한 원인입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q11","code":"FE-11","title":"Q. 코드 스플리팅과 번들 최적화는 어떻게 하나요?","summary":"번들 최적화는 파일 크기를 무조건 줄이는 일이 아니라 초기 화면에 꼭 필요한 JavaScript를 줄이고 필요한 시점에 나눠 받게 하는 일입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q12","code":"FE-12","title":"Q. 디자인 시스템은 왜 중요하고 어떻게 운영하나요?","summary":"디자인 시스템은 예쁜 컴포넌트 모음이 아니라 제품 UI의 일관성, 접근성, 유지보수, 개발 속도를 관리하는 계약입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q13","code":"FE-13","title":"Q. 대용량 grid나 복잡한 입력 UI 성능은 어떻게 다루나요?","summary":"대용량 입력 UI는 렌더링 비용, validation 비용, 편집 상태, 저장 실패 복구가 결합된 문제입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q14","code":"FE-14","title":"Q. React Flow, Canvas, SVG, DOM 렌더링 차이는 어떻게 설명하나요?","summary":"렌더링 기술은 표현력, 상호작용, 접근성, 대량 렌더링, hit testing, 개발 복잡도의 trade-off로 선택합니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q15","code":"FE-15","title":"Q. 프론트엔드 장애나 버그는 어떤 순서로 디버깅하나요?","summary":"디버깅은 추측으로 코드를 바꾸는 일이 아니라 재현 조건, 계층 분리, 증거 수집, 최소 수정, 회귀 검증의 과정입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-q16","code":"FE-16","title":"핵심 질문 20선과 답변 훈련","summary":"아래 질문은 프론트엔드 면접에서 반복적으로 깊이를 확인하는 축입니다. 각 질문은 30초 답변으로 시작하고, 90초 확장에서 trade-off와 검증 방법을 붙입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-react-concurrent-ssr-drill","code":"FE-D1","title":"REACT CONCURRENT SSR DRILL","summary":"React 18 이후 면접에서는 렌더링 최적화보다 “동시성 기능이 사용자 경험과 서버 렌더링 경계에서 어떤 실패를 드러내는가”를 묻는 경우가 많습니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-frontend-security-cache-drill","code":"FE-D2","title":"FRONTEND SECURITY CACHE DRILL","summary":"프론트엔드 보안 질문은 XSS/CSRF 암기에서 끝나지 않고, 브라우저 정책과 캐시·리소스 우선순위가 실제 제품 위험에 어떤 영향을 주는지까지 이어집니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-frontend-causal-model","code":"FE-D3","title":"프론트엔드 개념 인과관계","summary":"프론트엔드 면접 답변이 암기처럼 들리는 이유는 React, 브라우저, 네트워크, 보안을 따로 말하기 때문입니다. 실제 사용자 경험은 이 네 계층이 연결되어 만들어집니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-frontend-expert-rendering-model","code":"FE-D4","title":"전문가 렌더링 모델: React에서 브라우저까지","summary":"프론트엔드 고급 면접은 React API를 얼마나 아는지가 아니라, 사용자 입력 하나가 상태 변경, React render, commit, browser layout/paint, network/cache, 보안 경계를 지나며 어떤 비용과 실패를 만드는지 설명할 수 있는지 봅니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-frontend-deep-answer-upgrade","code":"FE-D5","title":"DEEP ANSWER MODEL","summary":"프론트엔드 답변의 질은 API 이름을 많이 말하는지가 아니라 사용자 입력 하나가 React, 브라우저, 네트워크, 보안 경계를 지나며 어떤 비용과 실패를 만드는지 설명하는 능력으로 갈립니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"feinterview-frontend-project-evidence-answer-lab","code":"FE-D6","title":"PROJECT EVIDENCE ANSWER LAB","summary":"좋은 프론트엔드 면접 답변은 “기술을 안다”에서 멈추지 않고, 실제 장애나 개선 과제를 어떤 관찰로 발견했고 어떤 원인 가설을 세웠으며 어떤 지표로 결과를 증명했는지까지 이어집니다. 이 섹션은 경험을 과장하지 않으면서도 시니어답게 말할 수 있도록 사례를 증거 단위로 압축하는 훈련표입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"doc-jsts","code":"PART","title":"JavaScript·TypeScript 면접","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q1","code":"JT-01","title":"Q. execution context와 lexical environment를 설명해보세요.","summary":"execution context는 JavaScript 코드가 실행될 때 필요한 환경입니다. 변수 환경, lexical environment, outer reference, this binding이 포함됩니다. lexical environment는 식별자와 값의 매핑, 그리고 바깥 스코프 참조를 가진 구조입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q2","code":"JT-02","title":"Q. closure는 무엇이고 언제 문제가 되나요?","summary":"closure는 함수가 선언된 lexical environment를 기억해, 외부 함수 실행이 끝난 뒤에도 그 변수에 접근할 수 있는 구조입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q3","code":"JT-03","title":"Q. prototype, class, this, arrow function을 어떻게 설명하나요?","summary":"JavaScript 객체는 prototype chain을 통해 속성을 찾습니다. `class`는 prototype 기반 상속을 더 익숙한 문법으로 감싼 형태입니다. `this`는 호출 방식에 따라 결정되고 arrow function은 lexical this를 가집니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q4","code":"JT-04","title":"Q. event loop, microtask, macrotask를 설명해보세요.","summary":"JavaScript는 call stack이 비면 event loop가 task queue에서 작업을 가져옵니다. Promise callback은 microtask queue에 들어가고, timer나 IO callback은 macrotask 계열로 다뤄집니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q5","code":"JT-05","title":"Q. Promise와 async/await 오류 처리는 어떻게 하나요?","summary":"Promise는 비동기 작업의 eventual result를 표현합니다. async 함수는 항상 Promise를 반환하고, throw는 rejected Promise가 됩니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q6","code":"JT-06","title":"Q. TypeScript structural typing과 unknown vs any를 설명해보세요.","summary":"TypeScript는 이름이 아니라 구조가 맞으면 호환되는 structural typing을 사용합니다. `any`는 타입 검사를 끄고, `unknown`은 사용 전에 타입 좁히기를 요구합니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q7","code":"JT-07","title":"Q. generic, union/intersection, type guard, conditional type은 언제 쓰나요?","summary":"generic은 타입을 매개변수화해 재사용하면서 정보 손실을 줄입니다. union은 여러 가능성 중 하나, intersection은 여러 타입의 결합입니다. conditional type은 타입 수준 조건 분기입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q8","code":"JT-08","title":"나쁜 답변 / 개선 답변 / 좋은 답변","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q9","code":"JT-09","title":"JavaScript 런타임 실패 지도","summary":"JS 면접에서 전문성은 event loop 정의를 외우는 데서 나오지 않습니다. 브라우저와 Node 런타임에서 실제로 어떤 실패가 생기고, 어떤 증거로 좁히는지 말해야 합니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-q10","code":"JT-10","title":"TypeScript 타입 안전 경계","summary":"TypeScript 면접의 핵심은 타입 문법을 많이 아는 것이 아니라, 컴파일 타임 타입과 런타임 데이터의 경계를 정확히 구분하는 것입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"jsts-typescript-advanced-boundary","code":"JT-D1","title":"TYPESCRIPT ADVANCED BOUNDARY","summary":"고급 TypeScript 면접은 타입 퍼즐을 푸는 자리가 아니라, 컴파일러가 보장하는 영역과 런타임 검증이 필요한 영역을 정확히 나누는지 확인하는 자리입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"doc-personalfe","code":"PART","title":"프론트엔드 개발자 대응","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"personalfe-ch1","code":"FE-PER-00","title":"성장 서사","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"personalfe-ch2","code":"FE-PER-01","title":"핵심 강점","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"personalfe-ch3","code":"FE-PER-02","title":"대표 답변","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"personalfe-ch4","code":"FE-PER-03","title":"압박 질문","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"personalfe-ch5","code":"FE-PER-04","title":"포트폴리오 문장","summary":""},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"personalfe-ch6","code":"FE-PER-05","title":"대체 증거","summary":"성과 수치가 없을 때는 개선율을 만들지 말고, 작업 규모와 복잡도 증거를 제시합니다. 커밋 수는 성과가 아니라 “얼마나 오래, 얼마나 넓게 만졌는지”를 보여주는 보조 증거입니다."},{"docId":"career-frontend-interview","docLabel":"02 프론트엔드·JS/TS 면접","groupLabel":"면접·커리어","sectionId":"personalfe-ch7","code":"FE-PER-06","title":"심화 드릴 연결","summary":"심화 기술 질문을 받았을 때는 “알고 있습니다”가 아니라 본인 경험의 증거와 운영 관점으로 연결합니다. 아래 문장은 프론트엔드·JS/TS 원본 문서의 심화 섹션을 개인 답변으로 바꾸는 연결고리입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bundle-index","code":"INDEX","title":"학습 로드맵","summary":"이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"career-readiness-gate","code":"GATE","title":"CAREER READINESS GATE","summary":"백엔드·Java/Spring 답변 게이트 는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"career-answer-rubric","code":"RUBRIC","title":"ANSWER QUALITY RUBRIC","summary":"답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"career-pressure-loop","code":"LOOP","title":"PRESSURE RESPONSE LOOP","summary":"압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"career-evidence-packet","code":"EVIDENCE","title":"EVIDENCE PACKET","summary":"면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"career-final-drill","code":"DRILL","title":"FINAL 10 MINUTE DRILL","summary":"면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"doc-bedb","code":"PART","title":"백엔드·DB 면접","summary":""},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q1","code":"BD-01","title":"Q. 좋은 REST API 설계 원칙은 무엇인가요?","summary":"좋은 API는 예쁜 URL이 아니라 일관된 계약입니다. 리소스 중심 URL, HTTP 메서드 의미, 상태 코드, 에러 포맷, pagination, filtering, versioning, correlation ID까지 포함해야 운영 가능한 API가 됩니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q2","code":"BD-02","title":"Q. API 스펙이 자주 바뀔 때 어떻게 대응하나요?","summary":"API 변경 대응은 endpoint 교체가 아니라 계약 변경 관리입니다. response 구조, status 값, error format, loading/empty/error UI, backward compatibility를 함께 봐야 합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q3","code":"BD-03","title":"Q. Validation은 프론트와 백엔드 중 어디에서 처리하나요?","summary":"프론트 validation은 사용성을 위한 빠른 피드백이고, 백엔드 validation은 보안과 비즈니스 규칙의 최종 방어선입니다. DB 제약은 마지막 정합성 방어선입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q4","code":"BD-04","title":"Q. 인증과 인가는 무엇이 다르고 어떻게 설계하나요?","summary":"인증은 사용자가 누구인지 확인하는 것이고, 인가는 그 사용자가 어떤 리소스에 어떤 행동을 할 수 있는지 판단하는 것입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q5","code":"BD-05","title":"Q. 데이터 모델링은 어떤 기준으로 하나요?","summary":"데이터 모델링은 화면 구조를 DB에 그대로 옮기는 것이 아니라 도메인 규칙, 정합성, 조회 패턴, 변경 가능성을 구조화하는 일입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q6","code":"BD-06","title":"Q. 인덱스는 어떻게 설계하고 실행 계획에서 무엇을 보나요?","summary":"인덱스 답변은 “걸었다”가 아니라 query pattern, planner 선택, 배포 비용을 끝까지 설명해야 신뢰가 생깁니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q7","code":"BD-07","title":"Q. 트랜잭션 격리 수준은 어떻게 판단하나요?","summary":"격리 수준 답변은 현상 이름을 외우는 데서 끝내지 말고, 어떤 불변 조건이 깨지고 어떤 DB/애플리케이션 장치로 막을지까지 연결해야 합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q8","code":"BD-08","title":"Q. JPA N+1 문제는 왜 생기고 어떻게 해결하나요?","summary":"N+1은 처음 조회한 N개 entity의 연관 데이터를 접근할 때 추가 쿼리가 N번 발생하는 문제입니다. ORM의 lazy loading과 조회 패턴을 이해해야 합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q9","code":"BD-09","title":"Q. JWT와 Session은 어떻게 비교하나요?","summary":"JWT와 Session은 인증 상태를 어디에 두고 어떻게 검증, 만료, 철회할지에 대한 선택입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q10","code":"BD-10","title":"Q. RBAC와 ABAC는 어떻게 다르나요?","summary":"RBAC는 역할 기반, ABAC는 사용자·리소스·환경 속성 기반 인가 모델입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q11","code":"BD-11","title":"Q. 정규화와 비정규화는 어떻게 판단하나요?","summary":"정규화는 중복을 줄이고 정합성을 높이며, 비정규화는 조회 성능과 단순성을 위해 중복을 허용하는 선택입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q12","code":"BD-12","title":"Q. 낙관적 락과 비관적 락은 언제 쓰나요?","summary":"낙관적 락은 충돌이 드물다고 보고 저장 시 version으로 감지하고, 비관적 락은 충돌을 막기 위해 먼저 잠급니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q13","code":"BD-13","title":"Q. idempotency key는 왜 필요한가요?","summary":"네트워크 timeout이나 retry 때문에 같은 요청이 여러 번 도착해도 부작용이 한 번만 일어나게 하는 장치입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q14","code":"BD-14","title":"Q. API versioning과 backward compatibility는 어떻게 관리하나요?","summary":"API 변경 관리는 여러 client가 다른 속도로 배포되는 현실에서 계약을 깨지 않도록 운영하는 일입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q15","code":"BD-15","title":"Q. DB 제약과 애플리케이션 검증은 어떻게 나누나요?","summary":"애플리케이션 검증은 사용자에게 의미 있는 오류와 비즈니스 흐름을 제공하고, DB 제약은 동시성과 버그 상황에서도 마지막 정합성을 지킵니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q16","code":"BD-16","title":"Q. slow query는 어떤 순서로 대응하나요?","summary":"slow query 대응은 인덱스 추가부터가 아니라 재현, 실행 계획, 데이터 분포, lock, 애플리케이션 호출 패턴을 함께 보는 일입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q17","code":"BD-17","title":"핵심 질문 20선과 답변 훈련","summary":"백엔드·DB 면접은 “정답”보다 정합성, 동시성, 장애, 변경 관리의 판단 기준을 봅니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-q18","code":"BD-18","title":"백엔드·DB 개념 인과관계","summary":"백엔드 면접에서 개념을 이해한 답변은 요청 하나가 controller, service, transaction, DB lock, index, connection pool을 지나며 어떤 비용을 만드는지 설명합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"bedb-backend-deep-answer-upgrade","code":"BD-19","title":"DEEP ANSWER MODEL","summary":"백엔드 답변은 “API를 만들었다”가 아니라 요청이 transaction boundary, lock wait, connection pool, index plan, external dependency를 지나며 어떤 정합성과 지연을 만드는지 설명해야 깊이가 생깁니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"doc-javaspring","code":"PART","title":"Java·Spring·JPA 면접","summary":""},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q1","code":"JSJ-01","title":"Q. JVM, heap/stack, GC를 설명해보세요.","summary":"JVM은 Java bytecode를 실행하는 런타임입니다. heap은 객체가 저장되는 공유 메모리이고, stack은 thread마다 method call frame과 지역 변수를 저장합니다. GC는 heap에서 더 이상 참조되지 않는 객체를 회수합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q2","code":"JSJ-02","title":"Q. equals/hashCode는 왜 같이 구현해야 하나요?","summary":"`equals`는 논리적 동등성, `hashCode`는 hash 기반 collection에서 bucket을 찾는 값입니다. equals가 true인 객체는 같은 hashCode를 가져야 합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q3","code":"JSJ-03","title":"Q. Spring DI와 Bean lifecycle을 설명해보세요.","summary":"DI는 객체가 필요한 의존성을 직접 만들지 않고 외부 컨테이너가 주입하는 방식입니다. Spring Bean은 생성, 의존성 주입, 초기화 callback, 사용, 소멸 lifecycle을 가집니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q4","code":"JSJ-04","title":"Q. AOP, Filter vs Interceptor는 어떻게 다르나요?","summary":"AOP는 횡단 관심사를 proxy 기반으로 분리합니다. Filter는 Servlet container 레벨, Interceptor는 Spring MVC handler 전후, AOP는 method call 전후에 주로 개입합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q5","code":"JSJ-05","title":"Q. @Transactional propagation, rollback, self-invocation 문제를 설명해보세요.","summary":"`@Transactional`은 Spring AOP proxy를 통해 transaction 경계를 열고 commit/rollback을 관리합니다. propagation은 기존 transaction이 있을 때 새 method가 어떻게 참여할지 결정합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q6","code":"JSJ-06","title":"Q. JPA persistence context, dirty checking, flush를 설명해보세요.","summary":"persistence context는 entity를 관리하는 1차 cache이자 변경 감지 단위입니다. dirty checking은 관리 중인 entity의 변경을 transaction commit/flush 시점에 SQL로 반영하는 기능입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q7","code":"JSJ-07","title":"Q. lazy loading, Entity vs DTO, OSIV를 설명해보세요.","summary":"lazy loading은 연관 객체 접근 시점에 query를 실행합니다. DTO는 API 응답이나 화면 요구에 맞춘 데이터 구조이고 Entity는 도메인/영속성 모델입니다. OSIV는 view rendering까지 persistence context를 열어두는 설정입니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q8","code":"JSJ-08","title":"Q. Spring Security 인증/인가 흐름은 어떻게 설명하나요?","summary":"Spring Security는 filter chain에서 요청을 가로채 인증 정보를 만들고 SecurityContext에 저장한 뒤, 인가 단계에서 resource 접근 가능 여부를 판단합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q9","code":"JSJ-09","title":"Spring 프록시 실패 매트릭스","summary":"Spring 면접에서 어노테이션 이름만 말하면 얕습니다. 프록시가 어디에 생기고 어떤 호출은 프록시를 통과하지 않는지 설명해야 합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q10","code":"JSJ-10","title":"JPA 조회 실패 매트릭스","summary":"JPA 면접은 ORM 장점보다 숨겨진 SQL, persistence context, transaction 경계가 만드는 실패를 이해하는지 봅니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q11","code":"JSJ-11","title":"Java 백엔드 운영 디버깅 증거","summary":"백엔드 면접에서 깊이는 “아는 개념”보다 장애가 났을 때 어떤 증거를 볼지에서 드러납니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q12","code":"JSJ-12","title":"SPRING JPA FAILURE PLAYBOOK","summary":"Spring/JPA 면접에서는 “어노테이션을 안다”보다 실패 조건을 미리 알고 증거로 확인할 수 있는지가 더 중요합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q13","code":"JSJ-13","title":"Spring·JPA 개념 인과관계","summary":"Spring/JPA 답변이 얕아지는 이유는 어노테이션을 기능 스위치처럼 말하기 때문입니다. 실제로는 proxy, transaction boundary, persistence context, SQL 실행 시점이 연결되어 하나의 요청 경로를 만듭니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"javaspring-q14","code":"JSJ-14","title":"실전 장애 디버깅: Spring 요청 하나를 끝까지 추적하기","summary":"전문가 수준의 Java/Spring/JPA 답변은 어노테이션 동작을 설명하는 데서 끝나지 않습니다. 느린 요청 하나를 HTTP thread, transaction proxy, Hibernate SQL, Hikari pool, DB lock, GC까지 같은 타임라인으로 추적해야 합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"doc-personalbe","code":"PART","title":"백엔드 전환 대응","summary":""},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"personalbe-ch1","code":"BE-PER-00","title":"전환 포지셔닝","summary":""},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"personalbe-ch2","code":"BE-PER-01","title":"경험 분류","summary":""},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"personalbe-ch3","code":"BE-PER-02","title":"Spring/JPA/DB 연결","summary":""},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"personalbe-ch4","code":"BE-PER-03","title":"압박 대응","summary":""},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"personalbe-ch5","code":"BE-PER-04","title":"학습 계획","summary":""},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"personalbe-ch6","code":"BE-PER-05","title":"제한적이라는 말로 끝내지 않기","summary":"백엔드 전환 답변은 “경험이 제한적입니다”에서 멈추면 약합니다. 곧바로 어떤 기준으로 설계하고 검증할지 붙여야 합니다."},{"docId":"career-backend-interview","docLabel":"03 백엔드·Java/Spring 면접","groupLabel":"면접·커리어","sectionId":"personalbe-ch7","code":"BE-PER-06","title":"검증 가능한 서버 기능","summary":"백엔드 전환 답변은 “제한적입니다”에서 멈추면 약합니다. 제한적이라는 말로 끝내지 않기 위해, 작은 서버 기능을 직접 구현하고 검증 증거로 제시해야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"bundle-index","code":"INDEX","title":"학습 로드맵","summary":"이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"career-readiness-gate","code":"GATE","title":"CAREER READINESS GATE","summary":"CS·DB·보안 심화 답변 게이트 는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"career-answer-rubric","code":"RUBRIC","title":"ANSWER QUALITY RUBRIC","summary":"답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"career-pressure-loop","code":"LOOP","title":"PRESSURE RESPONSE LOOP","summary":"압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"career-evidence-packet","code":"EVIDENCE","title":"EVIDENCE PACKET","summary":"면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"career-final-drill","code":"DRILL","title":"FINAL 10 MINUTE DRILL","summary":"면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"doc-cs","code":"PART","title":"CS 기본기 면접","summary":""},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q1","code":"CS-01","title":"Q. Big-O 시간/공간 복잡도는 어떻게 설명하나요?","summary":"Big-O는 입력 크기가 커질 때 실행 시간이나 메모리 사용량이 어떻게 증가하는지 상한 관점으로 표현합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q2","code":"CS-02","title":"Q. Array/List/Map/Set/Heap/Queue/Stack/Tree/Graph는 언제 쓰나요?","summary":"자료구조 선택은 접근 패턴, 삽입/삭제 비용, 정렬 필요성, 중복 허용, 우선순위, 관계 표현에 따라 달라집니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q3","code":"CS-03","title":"Q. Hash collision은 무엇이고 왜 중요한가요?","summary":"Hash collision은 서로 다른 key가 같은 hash bucket에 배치되는 현상입니다. 충돌이 많으면 HashMap의 평균 O(1) 성능이 나빠집니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q4","code":"CS-04","title":"Q. BFS/DFS는 언제 쓰나요?","summary":"BFS는 가까운 노드부터 넓게 탐색하고, DFS는 한 경로를 깊게 탐색합니다. 그래프/트리 탐색의 기본입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q5","code":"CS-05","title":"Q. race condition, deadlock, mutex/semaphore를 설명해보세요.","summary":"race condition은 실행 순서에 따라 결과가 달라지는 문제입니다. deadlock은 둘 이상의 작업이 서로가 가진 자원을 기다리며 멈추는 상태입니다. mutex는 상호 배제, semaphore는 제한된 개수의 permit으로 동시 접근을 제어합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q6","code":"CS-06","title":"Q. process vs thread, context switching, memory, file descriptor를 설명해보세요.","summary":"process는 독립된 실행 단위와 주소 공간을 가지고, thread는 process 안에서 메모리를 공유하는 실행 흐름입니다. context switching은 CPU가 실행 대상을 바꾸며 상태를 저장/복원하는 비용입니다. file descriptor는 열린 파일, socket 같은 OS resource를 가리키는 핸들입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q7","code":"CS-07","title":"나쁜 답변 / 좋은 답변 비교","summary":""},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q8","code":"CS-08","title":"Q. CS 지식을 실제 장애·성능 현상과 어떻게 연결하나요?","summary":"면접에서 CS 기본기가 깊어 보이는 순간은 정의를 말할 때가 아니라, 운영 현상을 OS·네트워크·런타임 개념으로 분해할 때입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q9","code":"CS-09","title":"CS 면접 답변 심화 루브릭","summary":"암기 답변과 전문 답변은 같은 키워드를 쓰더라도 검증 가능한 근거를 붙이는지에서 갈립니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q10","code":"CS-10","title":"네트워크·메모리 압박 질문","summary":"CS 기본기 면접은 알고리즘만 묻지 않습니다. 웹 개발자에게는 네트워크, 메모리, 런타임 자원까지 연결해 묻는 경우가 많습니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q11","code":"CS-11","title":"동시성 검증 질문","summary":"동시성 답변은 lock 이름을 아는 것보다 불변식이 어떤 interleaving에서 깨지는지 설명하는 것이 핵심입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q12","code":"CS-12","title":"OS NETWORK INTERNALS DRILL","summary":"심화 CS 면접은 정의 암기에서 끝나지 않고, 요청 하나가 OS·네트워크·런타임을 지나며 어떤 비용과 실패 모드를 만드는지 시간순으로 설명하게 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q13","code":"CS-13","title":"핵심 질문 30선과 구체 답변 훈련","summary":"아래 질문은 키워드 암기가 아니라 면접장에서 바로 말할 수 있는 구체 상황형 질문입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"cs-q14","code":"CS-14","title":"CS 개념 인과관계","summary":"CS 답변은 용어 정의보다 “왜 그 현상이 생기는지”를 설명할 때 깊어집니다. 면접관이 보고 싶은 것은 Big-O, thread, TCP 같은 단어 자체가 아니라 그 개념으로 실제 성능과 장애를 분해하는 사고입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"doc-dbdeep","code":"PART","title":"DB 심화 면접","summary":""},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q1","code":"DBD-01","title":"Q. DB 심화 질문은 어떤 프레임으로 답하나요?","summary":"DB 답변은 기능 구현보다 데이터 정합성 요구, 읽기/쓰기 패턴, 동시성, 복구, 운영 변경 위험을 함께 설명해야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q2","code":"DBD-02","title":"Q. MVCC는 무엇이고 왜 필요한가요?","summary":"MVCC는 row version을 관리해 reader와 writer가 서로를 덜 막으면서 일관된 snapshot을 보게 하는 동시성 제어 방식입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q3","code":"DBD-03","title":"Q. 트랜잭션 격리 수준은 어떻게 선택하나요?","summary":"격리 수준은 transaction들이 서로의 중간 상태나 변경을 어느 정도 볼 수 있는지 정하는 정책입니다. 높을수록 anomaly는 줄지만 충돌과 retry 비용이 커질 수 있습니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q4","code":"DBD-04","title":"Q. 락과 deadlock은 어떻게 다루나요?","summary":"락은 동시 변경의 정합성을 지키기 위한 제어이고, deadlock은 transaction들이 서로가 가진 락을 기다리며 진행하지 못하는 상태입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q5","code":"DBD-05","title":"Q. lost update는 왜 생기고 어떻게 막나요?","summary":"lost update는 두 transaction이 같은 값을 읽고 각각 수정해 한쪽 변경이 사라지는 동시성 문제입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q6","code":"DBD-06","title":"Q. 느린 쿼리는 어떤 순서로 분석하나요?","summary":"느린 쿼리 대응은 감으로 인덱스를 추가하는 일이 아니라 실제 실행 계획, row 수 추정, I/O, sort, join 비용을 확인하는 과정입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q7","code":"DBD-07","title":"Q. 인덱스는 어떻게 설계하나요?","summary":"인덱스는 자주 쓰는 WHERE, JOIN, ORDER BY 패턴을 빠르게 하지만 write 비용과 저장 공간을 늘립니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q8","code":"DBD-08","title":"Q. 트랜잭션 경계는 어떻게 잡나요?","summary":"트랜잭션 경계는 함께 성공하거나 함께 실패해야 하는 비즈니스 정합성 단위입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q9","code":"DBD-09","title":"Q. Connection Pool은 왜 필요하고 어떤 문제가 생기나요?","summary":"Connection Pool은 DB connection 생성 비용을 줄이고 동시 접근을 제어하지만, 설정을 잘못하면 DB를 과부하시키거나 app request를 대기시킵니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q10","code":"DBD-10","title":"Q. WAL과 replication은 어떤 역할을 하나요?","summary":"WAL은 변경 내용을 데이터 파일보다 먼저 로그에 기록해 crash recovery와 replication의 기반이 됩니다. replication은 가용성과 읽기 확장을 돕지만 복구와 백업을 대체하지 않습니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q11","code":"DBD-11","title":"Q. 백업과 복구는 어떻게 검증하나요?","summary":"백업은 존재하는 것만으로 충분하지 않습니다. 실제 복구에 걸리는 시간, 복구된 데이터의 정합성, 운영 전환 절차를 검증해야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q12","code":"DBD-12","title":"Q. 무중단 DB migration은 어떻게 설계하나요?","summary":"무중단 migration은 구버전과 신버전 애플리케이션이 동시에 동작할 수 있도록 schema 변경을 backward compatible하게 나누는 방식입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q13","code":"DBD-13","title":"핵심 질문 35선과 답변 훈련","summary":"DB 심화 면접은 “데이터가 언제 깨질 수 있는가”와 “운영 중 어떻게 바꿀 것인가”를 묻습니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q14","code":"DBD-14","title":"MVCC INDEX PLAN DEEP DIVE","summary":"DB 심화 면접에서 강한 답변은 MVCC 내부, 인덱스 접근 조건, 실행 계획의 실제 수치를 한 문장 안에서 연결합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q15","code":"DBD-15","title":"DB 개념 인과관계","summary":"DB 심화 답변은 MVCC, index, isolation을 각각 외우는 것이 아니라 동시 읽기와 쓰기를 어떻게 동시에 허용하면서도 어떤 이상 현상이 남는가를 설명해야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"dbdeep-q16","code":"DBD-16","title":"실행계획 실전 해석: MVCC, 인덱스, 락을 함께 읽기","summary":"DB 심화 면접에서 전문가처럼 보이려면 “인덱스를 탔습니다”가 아니라 실행 계획의 rows, loops, buffers, lock wait, MVCC visibility를 같은 현상으로 읽어야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"doc-security","code":"PART","title":"보안 심화 면접","summary":""},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q1","code":"SEC-01","title":"Q. 보안 질문은 어떤 프레임으로 답하나요?","summary":"보안 답변은 취약점 이름보다 보호할 자산, 공격자가 조작할 수 있는 입력, 신뢰 경계, 서버 방어선, 탐지와 복구를 함께 설명해야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q2","code":"SEC-02","title":"Q. Threat Modeling은 어떻게 하나요?","summary":"Threat Modeling은 기능을 만들기 전에 공격자가 어떤 경로로 어떤 자산을 해칠 수 있는지 구조적으로 보는 활동입니다. OWASP Top 10은 이 위협을 코드 리뷰와 테스트 체크리스트로 구체화할 때 유용한 기준입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q3","code":"SEC-03","title":"Q. IDOR와 접근 제어 취약점은 어떻게 막나요?","summary":"IDOR는 사용자가 식별자를 바꿔 다른 사용자의 리소스에 접근하는 취약점입니다. 방어는 id를 숨기는 것이 아니라 서버가 actor, action, resource 관계를 검증하는 것입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q4","code":"SEC-04","title":"Q. 인증과 세션 관리는 어떻게 설계하나요?","summary":"인증은 사용자가 누구인지 확인하는 것이고, 세션 관리는 그 인증 상태를 안전하게 유지하고 종료하는 체계입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q5","code":"SEC-05","title":"Q. OAuth2와 OIDC는 어떻게 다르나요?","summary":"OAuth2는 권한 위임 프레임워크이고, OIDC는 OAuth2 위에 identity layer를 얹어 로그인과 사용자 정보를 표준화한 프로토콜입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q6","code":"SEC-06","title":"Q. JWT는 어떻게 검증해야 안전한가요?","summary":"JWT는 서명된 claim 묶음이며, 안전하려면 서명뿐 아니라 issuer, audience, expiry, algorithm, key rotation, revoke 전략을 함께 검증해야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q7","code":"SEC-07","title":"Q. XSS와 CSRF는 어떻게 다르고 어떻게 막나요?","summary":"XSS는 공격자 입력이 브라우저에서 스크립트로 실행되는 문제이고, CSRF는 사용자의 인증 상태를 이용해 원치 않는 요청을 보내는 문제입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q8","code":"SEC-08","title":"Q. SQL Injection과 Command Injection은 어떻게 막나요?","summary":"Injection은 사용자 입력이 명령이나 쿼리의 데이터가 아니라 구조로 해석될 때 발생합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q9","code":"SEC-09","title":"Q. SSRF는 왜 위험하고 어떻게 방어하나요?","summary":"SSRF는 서버가 공격자가 지정한 URL로 요청을 보내게 되어 내부망, metadata endpoint, admin service에 접근할 수 있는 취약점입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q10","code":"SEC-10","title":"Q. 비밀번호와 Secret은 어떻게 저장하나요?","summary":"비밀번호는 복호화 가능한 암호화가 아니라 password hashing으로 저장하고, secret은 저장·주입·회전·감사 체계를 갖춰야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q11","code":"SEC-11","title":"Q. Multi-tenant SaaS에서 보안상 가장 중요한 것은 무엇인가요?","summary":"Multi-tenant 보안의 핵심은 tenant isolation입니다. 한 고객의 사용자나 관리자가 다른 고객의 데이터에 접근하지 못해야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q12","code":"SEC-12","title":"Q. 감사 로그는 일반 로그와 어떻게 다르나요?","summary":"감사 로그는 디버깅 로그가 아니라 누가, 언제, 어떤 권한으로, 어떤 대상에, 어떤 변경을 했는지 추적하는 보안 증거입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q13","code":"SEC-13","title":"Q. 보안 사고가 발생하면 어떤 순서로 대응하나요?","summary":"보안 사고 대응은 탐지, 격리, 영향 범위 산정, 증거 보존, 근절, 복구, 고지, 재발 방지의 순서로 진행합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q14","code":"SEC-14","title":"핵심 질문 40선과 답변 훈련","summary":"보안 심화 면접은 방어 기술명을 외우는 것보다 공격 경로와 서버 방어선을 끝까지 추적하는 훈련입니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q15","code":"SEC-15","title":"공격 경로 기반 답변","summary":"보안 면접에서 전문성은 방어 기술명을 나열하는 데서 나오지 않습니다. 공격자가 어디서 들어와 어떤 권한 경계를 넘어 어떤 sink에 도달하는지 추적해야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q16","code":"SEC-16","title":"EXPLOIT CHAIN VALIDATION","summary":"보안 심화 답변은 취약점 하나를 고립해서 말하지 않고, 공격자가 여러 약점을 연결해 실제 영향에 도달하는지 검증하는 방식으로 구성해야 합니다."},{"docId":"career-core-deep-dive","docLabel":"04 CS·DB·보안 심화 면접","groupLabel":"면접·커리어","sectionId":"security-q17","code":"SEC-17","title":"보안 개념 인과관계","summary":"보안 답변은 취약점 이름을 맞히는 것이 아니라 공격자가 신뢰 경계를 어떻게 넘고, 어떤 sink에 도달하며, 어떤 통제로 그 경로를 끊는지 설명해야 깊어집니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"bundle-index","code":"INDEX","title":"학습 로드맵","summary":"이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"career-readiness-gate","code":"GATE","title":"CAREER READINESS GATE","summary":"인프라·분산·클라우드 답변 게이트 는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"career-answer-rubric","code":"RUBRIC","title":"ANSWER QUALITY RUBRIC","summary":"답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"career-pressure-loop","code":"LOOP","title":"PRESSURE RESPONSE LOOP","summary":"압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"career-evidence-packet","code":"EVIDENCE","title":"EVIDENCE PACKET","summary":"면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"career-final-drill","code":"DRILL","title":"FINAL 10 MINUTE DRILL","summary":"면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"doc-infra","code":"PART","title":"인프라·운영 면접","summary":""},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q1","code":"IO-01","title":"Q. 브라우저에서 서버까지 요청 흐름을 설명해보세요.","summary":"웹 요청은 함수 호출이 아니라 DNS, TCP, TLS, HTTP, CDN/LB, 서버, DB, 캐시를 지나는 실패 가능한 경로입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q2","code":"IO-02","title":"Q. CDN과 cache-control은 어떻게 설계하나요?","summary":"CDN은 사용자 가까운 edge에서 정적 자산이나 cacheable response를 제공해 latency와 origin 부하를 줄입니다. 핵심은 무엇을 얼마나 오래 캐시해도 되는지입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q3","code":"IO-03","title":"Q. Docker와 Kubernetes를 어떻게 설명하나요?","summary":"Docker는 애플리케이션과 런타임 의존성을 이미지로 패키징하고, Kubernetes는 컨테이너를 스케줄링, 복구, 확장, 서비스 디스커버리, rollout하는 플랫폼입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q4","code":"IO-04","title":"Q. CI/CD와 무중단 배포는 어떻게 보나요?","summary":"CI/CD는 자동 배포 버튼이 아니라 변경을 검증하고, 추적하고, 안전하게 사용자에게 전달하고, 나빠지면 되돌리는 시스템입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q5","code":"IO-05","title":"Q. 로그, 메트릭, 트레이스는 각각 어떤 역할을 하나요?","summary":"로그는 사건의 상세 기록, 메트릭은 시스템 상태의 숫자 흐름, 트레이스는 요청이 여러 서비스와 계층을 지나간 경로입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q6","code":"IO-06","title":"Q. DNS, TCP, TLS, HTTP는 요청에서 어떤 역할을 하나요?","summary":"웹 요청은 이름 해석, 연결 수립, 암호화 협상, 애플리케이션 프로토콜 처리로 나뉩니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q7","code":"IO-07","title":"Q. CORS는 왜 생기고 어떻게 해결하나요?","summary":"CORS는 브라우저가 다른 origin 요청을 제한하는 Same-Origin Policy를 서버가 명시적으로 완화하는 메커니즘입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q8","code":"IO-08","title":"Q. readiness와 liveness는 어떻게 다르나요?","summary":"readiness는 트래픽 수신 가능 여부, liveness는 프로세스를 재시작해야 할 정도로 비정상인지 판단합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q9","code":"IO-09","title":"Q. 무중단 배포와 rollback은 어떻게 설계하나요?","summary":"무중단 배포는 새 버전을 천천히 투입하고, 문제가 보이면 빠르게 되돌릴 수 있도록 배포 단위와 호환성을 관리하는 것입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q10","code":"IO-10","title":"Q. RED, USE, Golden Signals는 무엇인가요?","summary":"관측 지표를 서비스 관점과 리소스 관점으로 나눠 장애를 빠르게 감지하고 좁히는 프레임입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q11","code":"IO-11","title":"Q. 장애가 나면 무엇부터 확인하나요?","summary":"장애 초동 대응은 원인 추측보다 영향 범위 파악, 완화, 최근 변경 확인, 계층별 분리 순서가 중요합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q12","code":"IO-12","title":"Q. postmortem에는 무엇을 남겨야 하나요?","summary":"postmortem은 비난 문서가 아니라 장애를 조직 지식으로 바꾸고 재발 가능성을 줄이는 문서입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q13","code":"IO-13","title":"핵심 질문 20선과 답변 훈련","summary":"인프라·운영 면접은 “어디서 장애가 났는가”를 계층별로 좁히는 사고를 봅니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q14","code":"IO-14","title":"계층별 장애 추적 루틴","summary":"인프라 면접에서 “서버가 안 됩니다”라는 질문은 정답을 맞히는 문제가 아니라, 원인을 계층별로 배제하는 능력을 보는 문제입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-q15","code":"IO-15","title":"K8S CLOUD SENIOR DRILL","summary":"시니어 인프라 질문은 Kubernetes 리소스 이름을 아는지보다 트래픽, 확장, 장애 허용, 권한, 암호화, 재해복구가 한 흐름에서 깨질 때 어떻게 판단하는지를 봅니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"infra-infra-deep-answer-upgrade","code":"IO-16","title":"DEEP ANSWER MODEL","summary":"인프라 답변은 서비스 이름을 맞히는 것이 아니라 사용자의 요청이 DNS, TLS, CDN/WAF, Load Balancer, App, DB pool 중 어디까지 도달했는지 증거로 좁히는 능력을 보여줘야 합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"doc-distributed","code":"PART","title":"분산 시스템 면접","summary":""},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q1","code":"DS-01","title":"Q. 캐시는 왜 어렵나요?","summary":"캐시는 응답을 빠르게 하지만 최신성 문제를 만듭니다. 어려운 지점은 캐시 적중률보다 무효화와 일관성입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q2","code":"DS-02","title":"Q. 비동기 처리와 큐는 언제 쓰나요?","summary":"비동기 처리는 즉시 응답이 필요 없는 작업을 요청-응답 경로에서 분리해 latency와 결합도를 낮추는 선택입니다. 대신 운영 복잡도가 생깁니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q3","code":"DS-03","title":"Q. Retry, timeout, idempotency는 어떻게 설계하나요?","summary":"분산 호출은 실패할 수 있으므로 timeout과 retry가 필요하지만, retry는 중복 실행을 만들 수 있어 idempotency가 함께 필요합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q4","code":"DS-04","title":"Q. Consistency와 availability는 어떻게 판단하나요?","summary":"모든 데이터를 항상 강하게 일치시키는 것은 비쌉니다. 도메인별로 즉시 맞아야 하는 데이터와 eventual consistency를 허용할 수 있는 데이터를 나눠야 합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q5","code":"DS-05","title":"Q. Saga와 Outbox는 왜 쓰나요?","summary":"서비스가 분리되면 하나의 DB 트랜잭션으로 모든 변경을 묶기 어렵습니다. Saga와 Outbox는 분산된 변경의 정합성을 현실적으로 관리하는 패턴입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q6","code":"DS-06","title":"Q. cache invalidation 전략은 어떻게 잡나요?","summary":"cache invalidation은 캐시에 무엇을 언제 지울지 정하는 문제이며 최신성, 성능, 구현 복잡도의 trade-off입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q7","code":"DS-07","title":"Q. 메시지 순서 보장은 어떻게 다루나요?","summary":"분산 메시징에서 순서 보장은 partition, key, consumer 병렬성, retry 정책에 의해 깨질 수 있습니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q8","code":"DS-08","title":"Q. circuit breaker는 언제 필요한가요?","summary":"circuit breaker는 실패 중인 의존성에 계속 요청을 보내 장애를 증폭시키지 않도록 호출을 빠르게 차단하는 패턴입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q9","code":"DS-09","title":"Q. degraded mode는 어떻게 설계하나요?","summary":"degraded mode는 일부 의존성이 실패해도 핵심 기능을 제한된 품질로 계속 제공하는 전략입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q10","code":"DS-10","title":"Q. microservices는 언제 적절하고 언제 과한가요?","summary":"MSA는 기술 구조가 아니라 팀 경계, 데이터 소유권, 배포 독립성, 장애 격리를 위한 조직적 선택입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q11","code":"DS-11","title":"Q. read-your-writes는 왜 중요하고 어떻게 보장하나요?","summary":"read-your-writes는 사용자가 방금 쓴 데이터를 바로 다시 읽을 수 있게 하는 사용자 체감 정합성입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q12","code":"DS-12","title":"핵심 질문 20선과 답변 훈련","summary":"분산 시스템 면접에서는 정답보다 “어떤 일관성을 포기하고 어떤 복구 장치를 둘 것인가”를 봅니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q13","code":"DS-13","title":"정합성 실패 매트릭스","summary":"분산 시스템 답변은 “정합성을 보장합니다”보다 어떤 정합성을 어느 범위에서 포기하거나 보정하는지 말해야 전문적으로 들립니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q14","code":"DS-14","title":"분산 장애 답변 구조","summary":"장애 시나리오 질문에서는 기술명보다 blast radius를 줄이는 순서가 중요합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q15","code":"DS-15","title":"DISTRIBUTED CONSISTENCY SENIOR DRILL","summary":"시니어 분산 시스템 질문은 “eventual consistency입니다”로 끝나지 않습니다. 어떤 연산이 linearizability를 요구하고, 어떤 연산은 quorum·consensus·reconciliation 비용을 감수할 가치가 있는지 설명해야 합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q16","code":"DS-16","title":"분산 시스템 개념 인과관계","summary":"분산 시스템 답변은 “Kafka, Redis, Saga를 씁니다”로 시작하면 암기처럼 들립니다. 먼저 네트워크가 실패하고, 시간이 어긋나고, 같은 메시지가 두 번 처리될 수 있다는 전제를 세운 뒤 패턴을 도출해야 합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-q17","code":"DS-17","title":"분산 정합성 사례: 주문·결제·재고 플로우","summary":"분산 시스템을 전문가처럼 설명하려면 패턴 이름이 아니라 실패가 실제로 어디서 생기는지 말해야 합니다. 주문·결제·재고 플로우는 retry, idempotency, outbox, saga, reconciliation을 한 번에 설명하기 좋은 사례입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"distributed-distributed-deep-answer-upgrade","code":"DS-18","title":"DEEP ANSWER MODEL","summary":"분산 시스템 답변은 패턴 이름이 아니라 네트워크 실패, 중복 처리, 순서 역전, partial failure를 어떤 기록과 복구 루프로 수렴시키는지 설명해야 합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"doc-cloud","code":"PART","title":"클라우드 기본 면접","summary":""},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q1","code":"CLD-01","title":"Q. 클라우드를 쓴다는 것은 어떤 운영 책임을 바꾸는 것인가요?","summary":"클라우드는 서버를 빌리는 서비스가 아니라 인프라의 일부 책임을 공급자에게 위임하고, 애플리케이션·데이터·권한·설정 책임을 개발 조직이 명확히 가져가는 운영 모델입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q2","code":"CLD-02","title":"Q. VPC, subnet, public/private 배치를 설명해보세요.","summary":"VPC는 클라우드 안의 논리적 네트워크 경계이고, subnet은 그 경계 안에서 CIDR과 가용 영역 단위로 리소스를 배치하는 영역입니다. public/private 구분은 이름이 아니라 route table과 노출 정책으로 결정됩니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q3","code":"CLD-03","title":"Q. Internet Gateway, NAT Gateway, route table은 어떻게 다르나요?","summary":"Internet Gateway는 VPC와 인터넷 사이의 출입구이고, NAT Gateway는 private subnet 리소스의 outbound 인터넷 접근을 제공합니다. route table은 패킷을 어디로 보낼지 정하는 규칙입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q4","code":"CLD-04","title":"Q. Security Group과 NACL은 어떻게 다르고 어떻게 설계하나요?","summary":"Security Group은 리소스 단위의 stateful firewall이고, NACL은 subnet 단위의 stateless 방화벽입니다. 대부분의 애플리케이션 접근 제어는 SG를 중심으로 설계하고, NACL은 넓은 네트워크 방어선으로 보조합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q5","code":"CLD-05","title":"Q. Load Balancer는 단순 트래픽 분산 외에 어떤 역할을 하나요?","summary":"Load Balancer는 트래픽 분산뿐 아니라 health check, TLS termination, routing, rollout 안정성, 장애 격리의 중심 컴포넌트입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q6","code":"CLD-06","title":"Q. IAM과 Secret 관리는 어떻게 설명하나요?","summary":"IAM은 누가 어떤 리소스에 어떤 action을 할 수 있는지 정의하는 권한 시스템입니다. secret 관리는 비밀값을 코드, 이미지, 로그에 노출하지 않고 저장·주입·회전·감사하는 운영 체계입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q7","code":"CLD-07","title":"Q. Managed DB를 쓸 때 무엇을 여전히 직접 책임져야 하나요?","summary":"Managed DB는 운영 부담을 줄이지만 데이터 모델, 쿼리 성능, 권한, 백업 정책, 복구 검증, 마이그레이션 안정성은 애플리케이션 팀의 책임으로 남습니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q8","code":"CLD-08","title":"Q. Object Storage와 CDN은 언제 쓰고 어떤 보안 이슈가 있나요?","summary":"Object Storage는 파일과 정적 객체 저장에 적합하고, CDN은 사용자 가까운 edge에서 콘텐츠를 캐싱해 latency와 origin 부하를 줄입니다. 핵심은 공개 범위와 캐시 무효화 정책입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q9","code":"CLD-09","title":"Q. Queue와 Event 서비스를 클라우드에서 쓰는 이유는 무엇인가요?","summary":"Queue와 Event 서비스는 요청 처리와 후속 작업을 분리해 peak 부하를 흡수하고, 실패한 작업을 재시도하며, 시스템 간 결합도를 낮춥니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q10","code":"CLD-10","title":"Q. 고가용성과 DR은 어떻게 설명하나요?","summary":"고가용성은 평상시 장애를 견디는 설계이고, DR은 큰 장애 후 서비스를 복구하는 계획입니다. 둘 다 RTO와 RPO 기준이 있어야 합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q11","code":"CLD-11","title":"Q. 클라우드 비용이 갑자기 증가하면 어떤 순서로 확인하나요?","summary":"클라우드 cost estimation은 compute뿐 아니라 NAT, egress, managed DB I/O, object request, log ingest/storage, autoscaling, retry 폭주까지 함께 계산하는 작업입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q12","code":"CLD-12","title":"Q. 클라우드 장애 대응에서 무엇을 먼저 보나요?","summary":"클라우드 장애 대응은 공급자 장애인지, 우리 설정/배포 문제인지, 네트워크/권한/용량 문제인지 계층별로 좁히는 과정입니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q13","code":"CLD-13","title":"핵심 질문 30선과 답변 훈련","summary":"클라우드 면접은 서비스 이름보다 경계, 책임, 장애, 비용을 묶어 말하는 훈련이 필요합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q14","code":"CLD-14","title":"K8S CLOUD SENIOR DRILL","summary":"클라우드 시니어 면접에서는 managed service 이름보다 네트워크 경계, workload 노출, autoscaling 신호, 권한 위임, 암호화 키, 복구 훈련을 하나의 운영 모델로 설명해야 합니다."},{"docId":"career-infra-distributed-cloud","docLabel":"05 인프라·분산·클라우드 면접","groupLabel":"면접·커리어","sectionId":"cloud-q15","code":"CLD-15","title":"클라우드 개념 인과관계","summary":"클라우드 면접에서 서비스 이름을 나열하면 얕게 들립니다. 트래픽이 어떤 경계를 통과하고, 어떤 책임이 cloud provider에서 application team으로 넘어오는지 설명해야 합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"bundle-index","code":"INDEX","title":"학습 로드맵","summary":"이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"career-readiness-gate","code":"GATE","title":"CAREER READINESS GATE","summary":"시스템 설계·프로젝트 답변 게이트 는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"career-answer-rubric","code":"RUBRIC","title":"ANSWER QUALITY RUBRIC","summary":"답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"career-pressure-loop","code":"LOOP","title":"PRESSURE RESPONSE LOOP","summary":"압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"career-evidence-packet","code":"EVIDENCE","title":"EVIDENCE PACKET","summary":"면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"career-final-drill","code":"DRILL","title":"FINAL 10 MINUTE DRILL","summary":"면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"doc-system","code":"PART","title":"시스템 설계 면접","summary":""},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch1","code":"SD-00","title":"공통 답변 흐름","summary":"요구사항을 묻기 전에 기술 스택부터 말하면 약합니다. 면접관은 정답 구조보다 사고 순서를 봅니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-q1","code":"SD-01","title":"Q. 관리자 대시보드를 설계해보세요.","summary":"관리자 대시보드는 단순 목록 화면이 아니라 검색, 필터, 권한, 감사 로그, 대량 데이터, 실패 상태, 운영 액션을 포함한 업무 도구입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-q2","code":"SD-02","title":"Q. 대형 Data Grid 입력 시스템을 설계해보세요.","summary":"대형 grid는 렌더링 문제와 데이터 정합성 문제가 동시에 있습니다. 화면 cell state와 저장 가능한 domain model을 분리해야 합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-q3","code":"SD-03","title":"Q. 실시간 대시보드를 설계해보세요.","summary":"실시간은 항상 WebSocket이 답이 아닙니다. 정확도, 지연 허용치, 업데이트 빈도, 사용자 수, reconnect 비용으로 polling, SSE, WebSocket을 고릅니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-q4","code":"SD-04","title":"Q. 복잡한 multi-step form을 설계해보세요.","summary":"복잡한 form은 입력 필드 묶음이 아니라 상태 전이와 validation, 임시 저장, 권한, 서버 검증이 결합된 workflow입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-q5","code":"SD-05","title":"Q. 인증 기반 앱을 설계해보세요.","summary":"인증 기반 앱은 로그인 화면만이 아니라 session lifecycle, token refresh, 권한별 route/action, 만료 UX, 보안 정책을 포함합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-q6","code":"SD-06","title":"Q. Excel 업로드와 validation 시스템을 설계해보세요.","summary":"Excel 업로드는 파일 처리 기능이 아니라 외부 비정형 입력을 도메인 데이터로 안전하게 변환하는 workflow입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-q7","code":"SD-07","title":"Q. 무한 스크롤 피드를 설계해보세요.","summary":"무한 스크롤은 pagination UX가 아니라 정렬 안정성, cursor, 중복 제거, 캐시, 접근성, SEO를 함께 보는 설계 문제입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-q8","code":"SD-08","title":"Q. 운영 장애 복구용 admin tool을 설계해보세요.","summary":"운영 도구는 강력한 권한을 가진 위험한 UI이므로 권한, 감사 로그, dry-run, 승인, rollback 가능성이 핵심입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-q9","code":"SD-09","title":"Q. 글로벌 다국어 서비스를 설계해보세요.","summary":"다국어 서비스는 문자열 치환만이 아니라 locale, timezone, currency, number format, fallback, 번역 workflow를 포함합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch2","code":"SD-10","title":"화이트보드 진행 순서","summary":"시스템 설계 면접은 바로 컴포넌트를 그리는 시험이 아닙니다. 면접관 신호를 보면서 요구사항을 좁히고, 비기능 요구사항과 운영 리스크를 구조화하는 과정입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch3","code":"SD-11","title":"Capacity estimation","summary":"시스템 설계에서 Capacity estimation은 정확한 숫자 맞히기가 아니라, 어떤 가정으로 병목을 추정하고 어떤 지점부터 구조가 달라지는지 말하는 훈련입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch4","code":"SD-12","title":"고가용성·DR","summary":"고가용성·DR 질문은 “서버를 여러 대 둔다”보다 어떤 실패를 가정하고, 어느 수준의 중단과 데이터 손실을 허용하는지 설명하는 문제입니다. 먼저 SPOF를 찾고 RPO/RTO를 숫자로 합의한 뒤 구조를 선택합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch5","code":"SD-13","title":"설계 리뷰 게이트","summary":"시스템 설계 면접에서 좋은 답변은 그림을 많이 그리는 답변이 아니라, 빠뜨리면 장애가 되는 결정을 순서대로 닫아 가는 답변입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch6","code":"SD-14","title":"Trade-off Matrix","summary":"면접관은 특정 기술을 골랐는지가 아니라, 왜 그 선택이 현재 제약에서 합리적인지 봅니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch7","code":"SD-15","title":"SYSTEM DESIGN PRESSURE DRILL","summary":"압박 질문에서는 예쁜 아키텍처보다 숫자 가정, 병목 추정, 정합성 선택, 실패 대응, rollout/backfill/rollback 순서를 빠르게 닫는 능력을 봅니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch8","code":"SD-16","title":"시스템 설계 핵심 질문 20선","summary":"시스템 설계 핵심 질문은 요구사항을 닫는 질문, 숫자를 세우는 질문, 실패를 가정하는 질문, 출시 순서를 검증하는 질문으로 나눠 준비합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch9","code":"SD-17","title":"시스템 설계 개념 인과관계","summary":"시스템 설계 답변이 외운 티가 나는 이유는 기술 선택이 원인 없이 튀어나오기 때문입니다. 좋은 답변은 요구사항의 압력이 어떤 병목을 만들고, 그 병목 때문에 어떤 구조를 선택하며, 그 선택이 다시 어떤 비용을 만드는지 설명합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-ch10","code":"SD-18","title":"완성형 시스템 설계 사례: 대용량 B2B 관리자 데이터 처리","summary":"전문가 수준의 시스템 설계 답변은 여러 주제를 따로 말하지 않습니다. 하나의 문제를 두고 요구사항, 트래픽, 데이터 모델, API, DB, 캐시, 큐, 장애, 배포를 같은 인과관계 안에서 연결합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"system-system-design-deep-answer-upgrade","code":"SD-19","title":"DEEP ANSWER MODEL","summary":"시스템 설계 답변은 컴포넌트 나열이 아니라 요구사항 압력이 capacity estimation, bottleneck, 데이터 모델, API 계약, rollout, rollback 전략을 어떻게 결정하는지 보여주는 과정입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"doc-project","code":"PART","title":"프로젝트 심층 면접","summary":""},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q1","code":"PJ-01","title":"Q. 가장 복잡했던 프로젝트를 설명해보세요.","summary":"복잡한 프로젝트 답변은 “큰 프로젝트였습니다”가 아니라 왜 복잡했는지 구조적으로 설명해야 합니다. 도메인 규칙, 데이터 흐름, 상태 전이, API 계약, 검증, 운영 이슈 중 무엇이 어려웠는지 분리합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q2","code":"PJ-02","title":"Q. Excel, Key-in, Data Grid 입력을 단일 상태로 통합한다는 것은 무엇인가요?","summary":"입력 채널은 다르지만 저장과 검증의 대상이 되는 도메인 데이터는 하나여야 합니다. channel-specific parsing과 common domain state를 분리합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q3","code":"PJ-03","title":"Q. Flow Editor의 node/edge 상태는 어떻게 관리했나요?","summary":"Flow Editor는 화면상의 graph state와 저장 가능한 domain graph를 분리해야 합니다. 사용자의 드래그와 연결선은 UI state이지만 서버에는 도메인 식별자와 관계가 저장됩니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q4","code":"PJ-04","title":"Q. API 전환 프로젝트에서 무엇이 어려웠나요?","summary":"API 전환은 endpoint만 바꾸는 작업이 아니라 화면이 의존하던 데이터 계약, error handling, loading/empty state, status mapping을 함께 바꾸는 작업입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q5","code":"PJ-05","title":"Q. 중복 요청이나 무한 렌더링은 어떻게 디버깅했나요?","summary":"운영 이슈 답변은 “고쳤다”보다 재현 조건을 좁히고 원인을 계층별로 분리한 과정을 보여줘야 합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q6","code":"PJ-06","title":"Q. 복잡한 B2B 도메인을 어떻게 학습했나요?","summary":"도메인 학습 답변은 열심히 공부했다가 아니라 용어, 규칙, 예외, 사용자 업무 흐름을 어떻게 구조화했는지 보여줘야 합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q7","code":"PJ-07","title":"Q. Data Grid column definition을 어떻게 관리했나요?","summary":"column definition은 표시 설정이 아니라 입력, 변환, 검증, 권한, 저장 payload를 잇는 계약입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q8","code":"PJ-08","title":"Q. validation error를 cell, row, page 단위로 어떻게 보여줬나요?","summary":"validation UX는 오류를 알려주는 것이 아니라 사용자가 오류 위치로 이동해 수정하고 다시 저장할 수 있게 만드는 흐름입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q9","code":"PJ-09","title":"Q. React Flow 성능 문제는 어떻게 봐야 하나요?","summary":"Flow editor 성능은 노드 수, 커스텀 노드 렌더링, props 안정성, store 구독 범위, drag 중 업데이트 비용으로 나눠 봅니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q10","code":"PJ-10","title":"Q. 파일 업로드/다운로드 이슈는 어떻게 해결했나요?","summary":"파일 기능은 UI 이벤트가 아니라 크기, 타입, 인코딩, 보안, 진행률, 실패 복구, 서버 저장 정책을 포함합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q11","code":"PJ-11","title":"Q. i18n key와 Storybook은 어떻게 운영했나요?","summary":"i18n과 Storybook은 문서 도구가 아니라 UI 품질과 변경 관리를 돕는 운영 자산입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q12","code":"PJ-12","title":"Q. 프론트엔드 중심 지원자가 백엔드/API 질문을 받으면 어떻게 답하나요?","summary":"경험의 경계를 지키면서도 API 계약, 데이터 흐름, validation, 장애 진단을 이해한다는 것을 보여줘야 합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q13","code":"PJ-13","title":"프로젝트 답변 템플릿","summary":"프로젝트 심층 면접은 “무엇을 만들었나”보다 “왜 그렇게 판단했고, 무엇을 검증했나”를 봅니다. 답변은 문제 → 제약 → 선택지 → 선택 이유 → 실패/트레이드오프 → 검증 결과 순서로 준비합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q14","code":"PJ-14","title":"실제 샘플 답변","summary":""},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q15","code":"PJ-15","title":"프로젝트 깊이 증거 장부","summary":"프로젝트 면접은 경험담이 아니라 의사결정의 증거를 검증하는 자리입니다. 직접 한 범위, 제약, 대안, 결과 수치를 분리해 준비해야 합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q16","code":"PJ-16","title":"프로젝트 핵심 질문 20선","summary":"프로젝트 면접은 경험의 진짜 깊이를 확인하기 위해 같은 이야기를 문제, 선택, 검증, 실패, 협업 관점에서 반복해 파고듭니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q17","code":"PJ-17","title":"PROJECT EVIDENCE QUALITY RUBRIC","summary":"좋은 프로젝트 답변은 기억에 의존하지 않고 검증 가능한 증거를 붙입니다. 증거는 강도가 다르므로 PR, ADR, metric, before-after, 장애기록, QA ticket, 사용자 피드백을 등급별로 준비합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-q18","code":"PJ-18","title":"프로젝트 답변 인과관계","summary":"프로젝트 답변은 사용 기술 목록이 아니라 문제가 있었고, 제약 때문에 선택지가 갈렸고, 내가 선택한 방식이 어떤 결과를 만들었다는 구조여야 합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"project-project-deep-answer-upgrade","code":"PJ-19","title":"DEEP ANSWER MODEL","summary":"프로젝트 심층 답변은 경험담이 아니라 project depth ledger입니다. 면접관은 personal contribution, trade-off, 실패, 증거를 통해 실제 판단 깊이를 확인합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"doc-personalfull","code":"PART","title":"풀스택 개발자 대응","summary":""},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"personalfull-ch1","code":"FS-PER-00","title":"전략","summary":""},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"personalfull-ch2","code":"FS-PER-01","title":"서버 경계 경험","summary":""},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"personalfull-ch3","code":"FS-PER-02","title":"답변 템플릿","summary":""},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"personalfull-ch4","code":"FS-PER-03","title":"위험한 표현","summary":""},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"personalfull-ch5","code":"FS-PER-04","title":"학습 연결","summary":"풀스택 면접에서는 아래 문서와 답변을 연결해서 말합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"personalfull-ch6","code":"FS-PER-05","title":"강점 전환 문장","summary":"풀스택 답변의 핵심은 프론트 경험을 그대로 나열하지 않고, 경험을 서버 협업 역량으로 전환해 말하는 것입니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"personalfull-ch7","code":"FS-PER-06","title":"서버 협업 역량","summary":"풀스택 면접에서는 프론트 경험을 서버 흉내로 바꾸지 말고, 경험을 서버 협업 역량으로 전환해서 말합니다."},{"docId":"career-system-project","docLabel":"06 시스템 설계·프로젝트 심층","groupLabel":"면접·커리어","sectionId":"personalfull-ch8","code":"FS-PER-07","title":"압박 질문 연결","summary":"풀스택 포지션에서는 인프라·분산·클라우드·시스템 설계 질문을 “직접 전부 운영했다”로 과장하지 말고, 프론트 경험이 닿은 API 계약과 운영 경계에서 정확히 연결합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"bundle-index","code":"INDEX","title":"학습 로드맵","summary":"이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"career-readiness-gate","code":"GATE","title":"CAREER READINESS GATE","summary":"컬처·협업 답변 게이트 는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"career-answer-rubric","code":"RUBRIC","title":"ANSWER QUALITY RUBRIC","summary":"답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"career-pressure-loop","code":"LOOP","title":"PRESSURE RESPONSE LOOP","summary":"압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"career-evidence-packet","code":"EVIDENCE","title":"EVIDENCE PACKET","summary":"면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"career-final-drill","code":"DRILL","title":"FINAL 10 MINUTE DRILL","summary":"면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"doc-behavioral","code":"PART","title":"컬처·압박 면접","summary":""},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q1","code":"BP-01","title":"Q. 자기소개를 해주세요.","summary":"자기소개는 경력 요약이 아니라 면접 전체의 프레임을 여는 답변입니다. 내가 어떤 문제를 잘 푸는 개발자인지 한 문장으로 잡아야 합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q2","code":"BP-02","title":"Q. 왜 이직하려고 하나요?","summary":"이직 사유는 불만 설명이 아니라 다음 환경에서 더 잘 발휘하고 싶은 역량과 성장 방향을 말하는 질문입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q3","code":"BP-03","title":"Q. 실패했던 기술 선택은 무엇인가요?","summary":"실패 경험은 약점 고백이 아니라 판단 기준이 어떻게 발전했는지 보여주는 질문입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q4","code":"BP-04","title":"Q. 협업 갈등이나 설득 경험을 말해보세요.","summary":"갈등 질문은 성격을 묻는 것이 아니라 목표 충돌을 사실과 선택지로 정리해 합의로 이끌 수 있는지 보는 질문입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q5","code":"BP-05","title":"Q. 압박 질문에는 어떻게 대응하나요?","summary":"압박 질문은 공격이 아니라 답변의 신뢰도와 경계를 확인하는 과정입니다. 짧게 인정하고 기준을 다시 세운 뒤 증거 또는 검증 방법으로 이동합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q6","code":"BP-06","title":"Q. 왜 우리 회사인가요?","summary":"지원 동기는 회사 칭찬이 아니라 회사가 풀고 있는 문제와 내 경험이 만나는 지점을 말해야 합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q7","code":"BP-07","title":"Q. 가장 자랑스러운 프로젝트는 무엇인가요?","summary":"자랑스러운 프로젝트는 규모보다 본인의 판단과 결과가 선명한 프로젝트여야 합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q8","code":"BP-08","title":"Q. 일정이 부족할 때 어떻게 대응하나요?","summary":"일정 압박 답변은 야근 의지가 아니라 범위 조정, 위험 공개, 품질 기준 유지 능력을 보는 질문입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q9","code":"BP-09","title":"Q. 과한 설계라는 피드백을 받으면 어떻게 하나요?","summary":"과한 설계 피드백은 방어할 문제가 아니라 현재 규모와 변경 가능성에 맞는 최소 구조를 다시 찾는 과정입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q10","code":"BP-10","title":"Q. 멘토링이나 리더십 경험이 있나요?","summary":"리더십은 직급이 아니라 팀이 더 나은 결정을 반복할 수 있게 기준과 피드백 루프를 만드는 행동입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q11","code":"BP-11","title":"Q. 본인을 상급 개발자라고 볼 수 있는 근거는 무엇인가요?","summary":"상급 개발자 근거는 연차가 아니라 문제 정의, trade-off 판단, 운영 책임, 타인에게 설명 가능한 기준입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q12","code":"BP-12","title":"Q. 직접 해본 게 맞나요?","summary":"이 질문은 공격이 아니라 경험의 경계를 확인하는 질문입니다. 직접 담당 범위와 협업/학습 범위를 분리해야 합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q13","code":"BP-13","title":"Q. 수치가 있나요?","summary":"수치 질문은 성과 과장을 잡는 질문입니다. 수치가 없으면 없다고 말하고 대체 증거를 제시해야 합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q14","code":"BP-14","title":"Q. 백엔드 경험이 부족한 것 아닌가요?","summary":"부족한 영역은 인정하되, 서버와 데이터 흐름을 이해하고 협업에서 어떤 가치를 냈는지 보여줘야 합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q15","code":"BP-15","title":"Q. 마지막으로 하고 싶은 말은 무엇인가요?","summary":"마지막 한마디는 새 정보를 길게 추가하는 시간이 아니라 면접 전체의 핵심 메시지를 다시 고정하는 시간입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q16","code":"BP-16","title":"압박 질문 대응 루프","summary":"압박 질문은 지원자를 공격하려는 시간이 아니라 답변의 신뢰 경계를 확인하는 시간입니다. 방어적으로 길게 말하기보다 짧게 인정하고, 경계를 세운 뒤, 검증 계획으로 닫습니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q17","code":"BP-17","title":"STAR 답변 품질 기준","summary":"STAR는 형식이 아니라 면접관이 사실관계, 판단 기준, 개인 기여를 검증할 수 있게 만드는 구조입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-q18","code":"BP-18","title":"압박 면접 시뮬레이션","summary":"압박 질문은 인성을 떠보는 질문처럼 보여도 실제로는 책임 경계와 신뢰도를 확인합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"behavioral-behavioral-deep-answer-upgrade","code":"BP-19","title":"DEEP ANSWER MODEL","summary":"컬처 답변은 좋은 태도 묘사가 아니라 실제 상황에서 어떤 decision evidence를 만들고, conflict boundary를 어떻게 설정했는지 보여주는 답변이어야 합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"doc-git","code":"PART","title":"Git·협업·코드리뷰 면접","summary":""},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q1","code":"GIT-01","title":"Q. 개발 협업을 잘한다는 것은 무엇이라고 보나요?","summary":"협업은 태도 문제가 아니라 변경을 다른 사람이 이해하고 검증하고 되돌릴 수 있게 만드는 엔지니어링 능력입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q2","code":"GIT-02","title":"Q. 좋은 commit 단위는 어떻게 정하나요?","summary":"좋은 commit은 나중에 변경 이유를 추적하고, 문제가 생겼을 때 revert하거나 bisect할 수 있는 의미 단위입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q3","code":"GIT-03","title":"Q. merge와 rebase는 언제 선택하나요?","summary":"merge와 rebase의 차이는 히스토리 모양과 이력 보존 방식입니다. 정답은 팀의 워크플로와 공유 여부에 따라 달라집니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q4","code":"GIT-04","title":"Q. revert, reset, restore는 어떻게 구분하나요?","summary":"복구 명령은 이력을 보존할지, 브랜치 포인터를 옮길지, 작업 디렉터리 파일만 되돌릴지에 따라 선택합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q5","code":"GIT-05","title":"Q. PR은 얼마나 작아야 하고 무엇을 써야 하나요?","summary":"PR 크기는 라인 수가 아니라 리뷰어가 한 번에 이해해야 하는 의사결정 수로 판단합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q6","code":"GIT-06","title":"Q. 코드리뷰에서 무엇을 우선순위로 보나요?","summary":"코드리뷰는 취향 교정이 아니라 결함, 요구사항 누락, 운영 위험, 유지보수 비용을 줄이는 활동입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q7","code":"GIT-07","title":"Q. Git conflict가 나면 어떻게 해결하나요?","summary":"충돌 해결은 양쪽 코드를 기계적으로 합치는 일이 아니라 두 변경의 의도를 이해하고 최종 동작을 다시 검증하는 일입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q8","code":"GIT-08","title":"Q. 브랜치 전략은 어떻게 선택하나요?","summary":"브랜치 전략은 팀 규모, 배포 빈도, 테스트 자동화 수준, 릴리즈 안정화 방식에 따라 달라집니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q9","code":"GIT-09","title":"Q. release와 rollback을 Git 관점에서 어떻게 관리하나요?","summary":"배포는 코드가 main에 merge되는 순간이 아니라 어떤 commit, artifact, config, migration이 운영에 반영됐는지 추적하는 과정입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q10","code":"GIT-10","title":"Q. ADR은 언제 쓰고 무엇을 남기나요?","summary":"ADR은 Architecture Decision Record로, 나중에 되돌아볼 비용이 큰 기술 결정의 맥락과 trade-off를 짧게 남기는 문서입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q11","code":"GIT-11","title":"Q. 기술부채는 어떻게 설명하고 관리하나요?","summary":"기술부채는 마음에 들지 않는 코드가 아니라 미래 변경 비용과 장애 가능성을 증가시키는 선택의 누적입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q12","code":"GIT-12","title":"핵심 질문 30선과 답변 훈련","summary":"Git·협업 면접은 도구 사용법보다 변경 관리 능력을 검증합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q13","code":"GIT-13","title":"운영 변경 관리 답변","summary":"Git 협업 면접은 commit 명령어보다 운영에 나간 변경을 추적하고 되돌릴 수 있는지 확인합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q14","code":"GIT-14","title":"코드 리뷰 코멘트 품질","summary":"좋은 리뷰는 취향을 강요하는 행위가 아니라 결함 가능성과 유지보수 비용을 낮추는 협업 장치입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q15","code":"GIT-15","title":"실제 코드리뷰 코멘트 예시","summary":"코드리뷰 면접에서는 리뷰 철학보다 실제 문장 품질을 보여주는 편이 강합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"git-q16","code":"GIT-16","title":"협업·변경관리 인과관계","summary":"협업 면접에서 좋은 답변은 성격이 좋다는 말이 아니라 변경 위험을 작게 만들고 검증 가능한 상태로 전달하는 과정을 설명하는 것입니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"doc-personalb2b","code":"PART","title":"B2B·SaaS 어드민 대응","summary":""},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"personalb2b-ch1","code":"ADM-PER-00","title":"최강 포지션","summary":""},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"personalb2b-ch2","code":"ADM-PER-01","title":"경험 증거","summary":""},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"personalb2b-ch3","code":"ADM-PER-02","title":"운영자 UX","summary":"B2B 어드민 답변은 사용자 편의성보다 업무 정확성과 오조작 방지를 중심에 둬야 합니다."},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"personalb2b-ch4","code":"ADM-PER-03","title":"대표 답변","summary":""},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"personalb2b-ch5","code":"ADM-PER-04","title":"회사별 조정","summary":""},{"docId":"career-culture-collaboration","docLabel":"07 컬처·협업·코드리뷰","groupLabel":"면접·커리어","sectionId":"personalb2b-ch6","code":"ADM-PER-05","title":"B2B·SaaS 도메인 깊이","summary":"B2B SaaS 어드민 면접은 Data Grid나 관리자 화면 경험만으로 충분하지 않습니다. 고객별 권한, 감사 가능성, 데이터 보존, 운영자 실수 방지까지 말해야 합니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"bundle-index","code":"INDEX","title":"학습 로드맵","summary":"이 문서는 아래 원문을 면접 학습 흐름에 맞게 이어 읽도록 구성했습니다. 각 파트는 개념 이해, 압박 질문, 답변 근거를 확인하는 기준점으로 사용합니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"career-readiness-gate","code":"GATE","title":"CAREER READINESS GATE","summary":"코딩테스트 답변 게이트 는 이 문서를 읽은 뒤 실제 면접에서 바로 말할 수 있어야 하는 산출물 기준입니다. 목표는 더 많이 읽는 것이 아니라, 질문을 받았을 때 30초 결론과 90초 확장을 증거와 함께 말하는 상태를 만드는 것입니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"career-answer-rubric","code":"RUBRIC","title":"ANSWER QUALITY RUBRIC","summary":"답변 품질은 유창함이 아니라 검증 가능성으로 판단합니다. 아래 기준으로 녹음 답변을 채점하고, 약한 답변은 결론, 근거, 증거 순서로 다시 작성합니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"career-pressure-loop","code":"LOOP","title":"PRESSURE RESPONSE LOOP","summary":"압박 질문은 틀리게 만들기 위한 질문이 아니라 답변의 경계와 증거를 확인하는 질문입니다. 당황했을 때는 답변을 확장하지 말고 구조를 되찾습니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"career-evidence-packet","code":"EVIDENCE","title":"EVIDENCE PACKET","summary":"면접 답변은 기억이 아니라 증거로 보강합니다. 각 문서에서 최소 하나의 대표 답변을 만들고, 아래 산출물을 붙여 실제 경험과 설계 지식의 경계를 명확히 합니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"A급 답변은 좋은 의도보다 개선 전후가 분명합니다. 아래 packet을 답변 카드마다 하나씩 채워, 약한 표현을 실제 산출물과 검증 가능한 문장으로 바꿉니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"career-final-drill","code":"DRILL","title":"FINAL 10 MINUTE DRILL","summary":"면접 직전에는 새 내용을 추가하지 않습니다. 이미 준비한 답변의 결론, 경계, 증거만 빠르게 복구합니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"doc-coding","code":"PART","title":"코딩테스트 패턴","summary":""},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q1","code":"CODE-01","title":"Q. 코딩테스트 문제를 받으면 어떤 순서로 접근하나요?","summary":"면접관은 정답만 보지 않습니다. 문제 조건을 해석하고, 가능한 복잡도를 정하고, 풀이 후보를 비교하고, 엣지 케이스를 검증하는 사고 과정을 봅니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q2","code":"CODE-02","title":"Q. 시간복잡도와 공간복잡도는 어떻게 판단하나요?","summary":"복잡도는 코드 줄 수가 아니라 입력 크기가 커질 때 수행 횟수와 추가 메모리가 어떻게 증가하는지 설명하는 도구입니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q3","code":"CODE-03","title":"Q. 배열과 정렬 문제는 어떤 신호를 보고 접근하나요?","summary":"배열 문제는 인덱스, 순서, 중복, 구간, 정렬 가능성의 문제입니다. 정렬은 구조를 단순하게 만들지만 원래 순서를 잃는 비용이 있습니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q4","code":"CODE-04","title":"Q. 투 포인터는 언제 쓰고 왜 O(N)이 되나요?","summary":"투 포인터는 두 인덱스를 움직이며 후보 범위를 줄이거나 구간을 유지하는 방식입니다. 각 포인터가 되돌아가지 않고 총 N번 정도만 움직이면 O(N)이 됩니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q5","code":"CODE-05","title":"Q. 슬라이딩 윈도우는 어떤 문제에 적합한가요?","summary":"슬라이딩 윈도우는 연속된 구간의 상태를 유지하며 최대/최소 길이, 합, 빈도, 조건 만족 여부를 갱신하는 패턴입니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q6","code":"CODE-06","title":"Q. HashMap과 Set은 어떤 문제에서 강한가요?","summary":"HashMap과 Set은 존재 여부, 빈도, 이전 위치, 보수 값, 그룹핑을 빠르게 확인할 때 사용합니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q7","code":"CODE-07","title":"Q. 스택과 큐는 어떤 문제 신호에서 선택하나요?","summary":"스택은 최근 항목을 되돌아보는 LIFO 구조이고, 큐는 먼저 들어온 항목을 먼저 처리하는 FIFO 구조입니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q8","code":"CODE-08","title":"Q. 이분탐색은 정렬 배열 외에 어디에 쓰나요?","summary":"이분탐색은 정렬 배열뿐 아니라 “답이 x일 때 가능한가”가 true/false로 단조성을 가지는 결정 문제에도 적용됩니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q9","code":"CODE-09","title":"Q. DFS와 BFS는 어떻게 선택하나요?","summary":"DFS는 깊게 탐색하며 경로, 연결성, 백트래킹에 자연스럽고 BFS는 같은 비용의 간선에서 최단 거리와 level-order 탐색에 적합합니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q10","code":"CODE-10","title":"Q. 백트래킹은 완전탐색과 어떻게 다른가요?","summary":"백트래킹은 가능한 모든 후보를 탐색하되, 더 이상 답이 될 수 없는 부분 경로를 조기에 포기하는 완전탐색 기법입니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q11","code":"CODE-11","title":"Q. DP 문제는 어떻게 상태를 정의하나요?","summary":"DP는 중복 부분 문제와 최적 부분 구조가 있을 때 상태를 정의하고 이전 상태로 현재 답을 계산하는 방식입니다. 가장 어려운 부분은 dp[i]의 의미를 한 문장으로 고정하는 것입니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q12","code":"CODE-12","title":"Q. 그리디는 언제 정당화할 수 있나요?","summary":"그리디는 매 순간의 최선 선택이 전체 최적해로 이어질 때 쓸 수 있습니다. 정당화 없이 “큰 것부터” 고르면 위험합니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q13","code":"CODE-13","title":"Q. 면접 중 코드가 틀리면 어떻게 디버깅하나요?","summary":"면접 중 디버깅은 침묵하고 찍는 것이 아니라, 작은 입력으로 invariant를 확인하고 경계 조건을 좁히는 커뮤니케이션입니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q14","code":"CODE-14","title":"핵심 질문 40선과 답변 훈련","summary":"코딩테스트 면접은 패턴 암기가 아니라 “왜 이 패턴이 맞는가”를 설명하는 훈련입니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q15","code":"CODE-15","title":"알고리즘 정당성 설명 루브릭","summary":"코딩 면접에서 고득점 답변은 코드가 맞는 것뿐 아니라 왜 맞는지, 언제 깨지는지, 비용이 얼마인지 설명합니다."},{"docId":"career-coding-test","docLabel":"08 코딩테스트 패턴","groupLabel":"면접·커리어","sectionId":"coding-q16","code":"CODE-16","title":"알고리즘 패턴 인과관계","summary":"코딩테스트 답변이 외운 것처럼 보이는 이유는 문제 신호에서 패턴이 도출되는 과정을 건너뛰기 때문입니다. 먼저 완전탐색이 왜 안 되는지 말하고, 어떤 성질 때문에 후보를 버릴 수 있는지 설명해야 합니다."},{"docId":"career-ai-native-portfolio","docLabel":"09 AI Native 포트폴리오","groupLabel":"면접·커리어","sectionId":"parts","code":"PART","title":"CURATED INTERVIEW PATH","summary":"이 문서는 기존 커리어 문서의 30초 결론, 90초 확장, 압박 꼬리질문 구조를 AI Native 증거에 맞게 재구성합니다."},{"docId":"career-ai-native-portfolio","docLabel":"09 AI Native 포트폴리오","groupLabel":"면접·커리어","sectionId":"ch1","code":"PORT-01","title":"AI Native 포트폴리오","summary":""},{"docId":"career-ai-native-portfolio","docLabel":"09 AI Native 포트폴리오","groupLabel":"면접·커리어","sectionId":"ch2","code":"PORT-02","title":"JD 키워드 매핑","summary":""},{"docId":"career-ai-native-portfolio","docLabel":"09 AI Native 포트폴리오","groupLabel":"면접·커리어","sectionId":"ch3","code":"PORT-03","title":"Portfolio evidence pack","summary":""},{"docId":"career-ai-native-portfolio","docLabel":"09 AI Native 포트폴리오","groupLabel":"면접·커리어","sectionId":"ch4","code":"PORT-04","title":"30초/90초 답변 카드","summary":"문서 검색 기능에서 30개 golden query를 만들고 recall@5와 citation precision을 릴리스 기준으로 뒀습니다. prompt 변경 때마다 baseline/candidate report를 남겼고, prompt injection fixture를 회귀 테스트에 포함했습니다."},{"docId":"career-ai-native-portfolio","docLabel":"09 AI Native 포트폴리오","groupLabel":"면접·커리어","sectionId":"career-output-packet","code":"OUTPUT","title":"CAREER OUTPUT PACKET","summary":"AI Native 포트폴리오는 “AI를 썼다”는 문장이 아니라, 평가·보안·운영 증거가 붙은 답변 산출물로 방어해야 합니다."},{"docId":"career-ai-native-portfolio","docLabel":"09 AI Native 포트폴리오","groupLabel":"면접·커리어","sectionId":"ch5","code":"PORT-05","title":"README 구조","summary":""}];
